INSERT INTO public.questions VALUES ('2ab3b95d-00c0-429d-a6c8-5085713ac3ff', 'ad654df2-2eb4-481e-a237-10b2c2ad0960', 'matrix', 'Questions 14–19', NULL, '<p>Which paragraph contains the following information? Choose the correct letter, A–I, in boxes14–19.</p>
', 'classification', 'null', 'null', 'null', '{"layoutType": "simple", "legendTitle": null, "matrixItems": [{"itemText": "A reference to studies based on the same level of calorie reduction with different animals\t", "correctCategoryLetter": "B"}, {"itemText": "A comment that some control monkeys in one study reached an older age than normal for animals of their kind\t", "correctCategoryLetter": "G"}, {"itemText": "Distinctions between the types of food in each study that may have led to a contrast in findings\t", "correctCategoryLetter": "E"}, {"itemText": "Examples of health problems which monkeys on calorie-restricted diets were less likely to get\t", "correctCategoryLetter": "C"}, {"itemText": "A researcher’s negative opinion of a calorie-restricted diet\t", "correctCategoryLetter": "A"}, {"itemText": "A reference to the stage in the monkeys’ lives at which research commenced in one study\t", "correctCategoryLetter": "D"}], "matrixCategories": [{"categoryText": "A", "categoryLetter": "A"}, {"categoryText": "B", "categoryLetter": "B"}, {"categoryText": "C", "categoryLetter": "C"}, {"categoryText": "D", "categoryLetter": "D"}, {"categoryText": "E", "categoryLetter": "E"}, {"categoryText": "F", "categoryLetter": "F"}, {"categoryText": "G", "categoryLetter": "G"}, {"categoryText": "H", "categoryLetter": "H"}, {"categoryText": "I", "categoryLetter": "I"}]}', '[{"content": "<p><strong>14. a reference to studies based on the same level of calorie reduction with different animals</strong></p>\n<ul>\n<li><strong>Đáp án:</strong> <strong>B</strong></li>\n<li><strong>Dẫn chứng:</strong> (Đoạn B) “In <strong>mice</strong>, many experiments had come to the same finding: feed them a diet with <strong>30% fewer calories</strong>… The monkey trials were set up in a similar way: researchers… <strong>cut it by 30%</strong>…”</li>\n</ul>\n<p><strong>15. a comment that some control monkeys in one study reached an older age than normal for animals of their kind</strong></p>\n<ul>\n<li><strong>Đáp án:</strong> <strong>G</strong></li>\n<li><strong>Dẫn chứng:</strong> (Đoạn G) “Indeed, Anderson points out that several of the NIA control monkeys have lived past the age of 40, <strong>far exceeding the 27-year average lifespan</strong> for captive rhesus monkeys.”</li>\n</ul>\n<p><strong>16. distinctions between the types of food in each study that may have led to a contrast in findings</strong></p>\n<ul>\n<li><strong>Đáp án:</strong> <strong>E</strong></li>\n<li><strong>Dẫn chứng:</strong> (Đoạn E) “The Wisconsin monkeys were given highly processed food high in <strong>sucrose</strong>… the NIA diet was based on <strong>whole grains, fish oils, and was very low in sugar</strong>.”</li>\n</ul>\n<p><strong>17. examples of health problems which monkeys on calorie-restricted diets were less likely to get</strong></p>\n<ul>\n<li><strong>Đáp án:</strong> <strong>C</strong></li>\n<li><strong>Dẫn chứng:</strong> (Đoạn C) “…the lean monkeys were living longer and suffering less from the diseases of ageing: <strong>diabetes, heart disease and brain diseases</strong>.”</li>\n</ul>\n<p><strong>18. a researcher’s negative opinion of a calorie-restricted diet</strong></p>\n<ul>\n<li><strong>Đáp án:</strong> <strong>A</strong></li>\n<li><strong>Dẫn chứng:</strong> (Đoạn A) “Rozalyn Anderson… says the research is not intended as a recommendation of calorie restriction. ‘I find the idea <strong>monumentally unattractive</strong>!’ she says.”</li>\n</ul>\n<p><strong>19. a reference to the stage in the monkeys’ lives at which research commenced in one study</strong></p>\n<ul>\n<li><strong>Đáp án:</strong> <strong>D</strong></li>\n<li><strong>Dẫn chứng:</strong> (Đoạn D) “The Wisconsin study began with monkeys in <strong>early adulthood</strong>.”</li>\n</ul>\n"}]', 0);
INSERT INTO public.questions VALUES ('6e0b18d0-0691-4097-8936-5eaf190b3e98', 'ad654df2-2eb4-481e-a237-10b2c2ad0960', 'matrix', 'Questions 20–23', NULL, '<p>Look at the following statements and the list of researchers below. Match each statement with the correct researcher, A, B or C.<br /><em><strong>NB </strong>You may use any letter more than once.</em></p>
', 'classification', 'null', 'null', 'null', '{"layoutType": "standard", "legendTitle": "List of researchers", "matrixItems": [{"itemText": "It is good that the two studies took dissimilar approaches\t", "correctCategoryLetter": "A"}, {"itemText": "Neither study used diets that are typical for monkeys.\t", "correctCategoryLetter": "C"}, {"itemText": "Calorie restriction is a method of finding out about health issues connected with ageing.\t", "correctCategoryLetter": "A"}, {"itemText": "Calorie reduction will have a positive effect on people who have unhealthy diets.\t", "correctCategoryLetter": "B"}], "matrixCategories": [{"categoryText": "Rozalyn Anderson", "categoryLetter": "A"}, {"categoryText": "Julie Mattison", "categoryLetter": "B"}, {"categoryText": "Leonie Heilbronn", "categoryLetter": "C"}]}', '[{"content": "<p><strong>20. It is good that the two studies took dissimilar approaches.</strong></p>\n<ul>\n<li><strong>Đáp án:</strong> <strong>A</strong> (Rozalyn Anderson)</li>\n<li><strong>Dẫn chứng:</strong> (Đoạn I) “The fact the two studies were set up differently… — <strong>I think we will gain maximally from that</strong>.’”</li>\n</ul>\n<p><strong>21. Neither study used diets that are typical for monkeys.</strong></p>\n<ul>\n<li><strong>Đáp án:</strong> <strong>C</strong> (Leonie Heilbronn)</li>\n<li><strong>Dẫn chứng:</strong> (Đoạn H) “However, <strong>neither group had the right notion of a standard diet</strong> according to Leonie Heilbronn…”</li>\n</ul>\n<p><strong>22. Calorie restriction is a method of finding out about health issues connected with ageing.</strong></p>\n<ul>\n<li><strong>Đáp án:</strong> <strong>A</strong> (Rozalyn Anderson)</li>\n<li><strong>Dẫn chứng:</strong> (Đoạn A) “‘We study it because it is so effective at delaying ageing and <strong>the onset of age-related disease</strong>.’”</li>\n</ul>\n<p><strong>23. Calorie reduction will have a positive effect on people who have unhealthy diets.</strong></p>\n<ul>\n<li><strong>Đáp án:</strong> <strong>B</strong> (Julie Mattison)</li>\n<li><strong>Dẫn chứng:</strong> (Đoạn F) “Julie Mattison… observes that <strong>an overweight person who goes to a fast food restaurant every day will obviously benefit</strong> if their calories are cut back by 30%.”</li>\n</ul>\n"}]', 1);
INSERT INTO public.questions VALUES ('4022feda-4df3-460b-9655-43f3dacfbdf0', 'ad654df2-2eb4-481e-a237-10b2c2ad0960', 'fillup', 'Questions 24–26', '<p>Complete the summary below.</p>
<p>Write <strong>ONE WORD ONLY</strong> from the passage for each answer.</p>
<p><strong>Agreement between the two studies on calorie restriction in rhesus monkeys</strong></p>
<p>The two studies were in agreement that it is beneficial to cut calories, in terms of health. Monkeys whose calories were restricted suffered fewer diseases that are associated with the {ageing} process. Anderson and Mattison have undertaken research to determine if a calorie-restricted diet increases primates’ {lifespan} Although there is a {conflict} between the two sets of data, Anderson believes they will help researchers reach a better understanding.</p>
', NULL, 'gap_filling', 'null', 'null', 'null', 'null', '[{"content": "<p><strong>24. Monkeys whose calories were restricted suffered fewer diseases that are associated with the ageing process.</strong></p>\n<ul>\n<li><strong>Đáp án:</strong> <strong>ageing</strong></li>\n<li><strong>Dẫn chứng:</strong> (Đoạn I) “…fewer diseases that are associated with the <strong>ageing</strong> process.”</li>\n</ul>\n<p><strong>25. Anderson and Mattison have undertaken research to determine if a calorie-restricted diet increases primates’ lifespan.</strong></p>\n<ul>\n<li><strong>Đáp án:</strong> <strong>lifespan</strong></li>\n<li><strong>Dẫn chứng:</strong> (Đoạn I) “As to the question of whether calorie restriction extends <strong>lifespan</strong> in primates…”</li>\n</ul>\n<p><strong>26. Although there is a conflict between the two sets of data, Anderson believes they will help researchers reach a better understanding.</strong></p>\n<ul>\n<li><strong>Đáp án:</strong> <strong>conflict</strong></li>\n<li><strong>Dẫn chứng:</strong> (Đoạn I) “The current data <strong>conflict</strong> will ultimately provide deeper insights…”</li>\n</ul>\n"}]', 2);
INSERT INTO public.questions VALUES ('30426d95-dd16-49e4-aa93-c734542ad5bf', '47409170-c42a-437d-aefb-dca7ce0f9fa0', 'matrix', 'Questions 27-32', NULL, '<p>Look at the following statements (Questions 27-32) and the list of people or groups below.</p>
<p>Choose each statement with the correct person or group, A, B, C or D.</p>', 'other', 'null', 'null', 'null', '{"layoutType": "standard", "legendTitle": "List of options", "matrixItems": [{"itemText": "The elderly would benefit from drug containers that do not require force to open them.", "correctCategoryLetter": "C"}, {"itemText": "Adapting packaging for the blind may disadvantage people who can see.", "correctCategoryLetter": "D"}, {"itemText": " Specially designed containers have not been able to eliminate drugs being swallowed accidentally.", "correctCategoryLetter": "B"}, {"itemText": " Designers have to consider how drugs are used in the home.", "correctCategoryLetter": "A"}, {"itemText": "Governing bodies need to compare different drug containers rather than studying individual ones.", "correctCategoryLetter": "D"}, {"itemText": " Information provided with medicine is not listed in the right order.", "correctCategoryLetter": "C"}], "matrixCategories": [{"categoryText": "Thea Swayne", "categoryLetter": "A"}, {"categoryText": "The Child Accident Prevention Trust", "categoryLetter": "B"}, {"categoryText": "Richard Mawle", "categoryLetter": "C"}, {"categoryText": "Karel van der Waarde", "categoryLetter": "D"}]}', '[{"content": "<p><strong class=\"\" data-path-to-node=\"2\" data-index-in-node=\"0\">27. The elderly would benefit from drug containers that do not require force to open them.</strong></p>\n<ul data-path-to-node=\"3\">\n<li><strong class=\"\" data-path-to-node=\"3,0,0\" data-index-in-node=\"0\">Đáp án:</strong> <strong class=\"\" data-path-to-node=\"3,0,0\" data-index-in-node=\"8\">C (Richard Mawle)</strong></li>\n<li><strong class=\"\" data-path-to-node=\"3,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong><span class=\"\"> Đoạn </span><em class=\"\" data-path-to-node=\"3,1,0\" data-index-in-node=\"16\">Safety and compliance</em><span class=\"\">,</span><span class=\"\"> dòng 4-6:</span><span class=\"\"> “Richard Mawle…</span><span class=\"\"> feels it is not just children who are blocked by child-proof closures.</span><span class=\"\"> ‘Many child-resistant packs are based on strength but </span><strong class=\"\" data-path-to-node=\"3,1,0\" data-index-in-node=\"192\">older people may have the same level of strength as a child</strong><span class=\"\">,</span><span class=\"\">’ he explained…</span><span class=\"\">“</span></li>\n<li><strong class=\"\" data-path-to-node=\"3,2,0\" data-index-in-node=\"0\">Giải thích:</strong><span class=\"\"> Richard Mawle nhận định các thiết kế nắp chống trẻ em hiện nay dựa quá nhiều vào sức mạnh cơ bắp (lực mở),</span><span class=\"\"> điều này vô tình gây khó khăn cho người già vì thể lực của họ có thể suy giảm xuống mức tương đương trẻ em.</span></li>\n</ul>\n<p><strong class=\"\" data-path-to-node=\"4\" data-index-in-node=\"0\">28. Adapting packaging for the blind may disadvantage people who can see.</strong></p>\n<ul data-path-to-node=\"5\">\n<li><strong class=\"\" data-path-to-node=\"5,0,0\" data-index-in-node=\"0\">Đáp án:</strong> <strong class=\"\" data-path-to-node=\"5,0,0\" data-index-in-node=\"8\">D (Karel van der Waarde)</strong></li>\n<li><strong class=\"\" data-path-to-node=\"5,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong><span class=\"\"> Đoạn </span><em class=\"\" data-path-to-node=\"5,1,0\" data-index-in-node=\"16\">Design principles and guidelines</em><span class=\"\">,</span><span class=\"\"> dòng 10-12:</span><span class=\"\"> “…</span><span class=\"\">according to Karel van der Waarde…</span><span class=\"\"> ‘it is not known how much visually impaired patients will benefit nor </span><strong class=\"\" data-path-to-node=\"5,1,0\" data-index-in-node=\"173\">how much the reading of visually able patients will be impaired</strong><span class=\"\">’.</span><span class=\"\">“</span></li>\n<li><strong class=\"\" data-path-to-node=\"5,2,0\" data-index-in-node=\"0\">Giải thích:</strong><span class=\"\"> Van der Waarde hoài nghi về quy định in chữ Braille lên bao bì,</span><span class=\"\"> vì việc này có thể gây cản trở hoặc làm khó khăn cho việc đọc thông tin của những người có thị lực bình thường.</span></li>\n</ul>\n<p><strong class=\"\" data-path-to-node=\"6\" data-index-in-node=\"0\">29. Specially designed containers have not been able to eliminate drugs being swallowed accidentally.</strong></p>\n<ul data-path-to-node=\"7\">\n<li><strong class=\"\" data-path-to-node=\"7,0,0\" data-index-in-node=\"0\">Đáp án:</strong> <strong class=\"\" data-path-to-node=\"7,0,0\" data-index-in-node=\"8\">B (The Child Accident Prevention Trust)</strong></li>\n<li><strong class=\"\" data-path-to-node=\"7,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong><span class=\"\"> Đoạn </span><em class=\"\" data-path-to-node=\"7,1,0\" data-index-in-node=\"16\">Safety and compliance</em><span class=\"\">,</span><span class=\"\"> dòng 2-3:</span><span class=\"\"> “According to the Child Accident Prevention Trust…</span> <strong class=\"\" data-path-to-node=\"7,1,0\" data-index-in-node=\"102\">although child-resistant lids have helped, they are not yet fully effective</strong><span class=\"\">.</span><span class=\"\">“</span></li>\n<li><strong class=\"\" data-path-to-node=\"7,2,0\" data-index-in-node=\"0\">Giải thích:</strong><span class=\"\"> Tổ chức này đưa ra dữ liệu thực tế cho thấy các loại hộp được thiết kế đặc biệt (nắp chống trẻ em) vẫn chưa thể loại bỏ hoàn toàn việc trẻ em vô tình nuốt nhầm thuốc.</span></li>\n</ul>\n<p><strong class=\"\" data-path-to-node=\"8\" data-index-in-node=\"0\">30. Designers have to consider how drugs are used in the home.</strong></p>\n<ul data-path-to-node=\"9\">\n<li><strong class=\"\" data-path-to-node=\"9,0,0\" data-index-in-node=\"0\">Đáp án:</strong> <strong class=\"\" data-path-to-node=\"9,0,0\" data-index-in-node=\"8\">A (Thea Swayne)</strong></li>\n<li><strong class=\"\" data-path-to-node=\"9,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong><span class=\"\"> Đoạn </span><em class=\"\" data-path-to-node=\"9,1,0\" data-index-in-node=\"16\">Design considerations</em><span class=\"\">,</span><span class=\"\"> dòng cuối:</span><span class=\"\"> “…</span><span class=\"\">real situations in which medicines are used include a parent giving a cough medicine to a child in the middle of the night; </span><strong class=\"\" data-path-to-node=\"9,1,0\" data-index-in-node=\"178\">packaging should be designed for moments such as these</strong><span class=\"\">…</span><span class=\"\">“</span></li>\n<li><strong class=\"\" data-path-to-node=\"9,2,0\" data-index-in-node=\"0\">Giải thích:</strong><span class=\"\"> Thea Swayne cho rằng nhà thiết kế cần tính đến bối cảnh sử dụng thuốc tại gia đình (ví dụ:</span><span class=\"\"> uống thuốc trong bóng tối lúc nửa đêm) thay vì chỉ thiết kế cho môi trường lý tưởng như bệnh viện.</span></li>\n</ul>\n<p><strong class=\"\" data-path-to-node=\"10\" data-index-in-node=\"0\">31. Governing bodies need to compare different drug containers rather than studying individual ones.</strong></p>\n<ul data-path-to-node=\"11\">\n<li><strong class=\"\" data-path-to-node=\"11,0,0\" data-index-in-node=\"0\">Đáp án:</strong> <strong class=\"\" data-path-to-node=\"11,0,0\" data-index-in-node=\"8\">D (Karel van der Waarde)</strong></li>\n<li><strong class=\"\" data-path-to-node=\"11,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong><span class=\"\"> Đoạn </span><em class=\"\" data-path-to-node=\"11,1,0\" data-index-in-node=\"16\">Design principles and guidelines</em><span class=\"\">,</span><span class=\"\"> dòng 14-15:</span><span class=\"\"> “‘They [regulatory authorities] do not look at the use of packaging in a practical context – </span><strong class=\"\" data-path-to-node=\"11,1,0\" data-index-in-node=\"155\">they only see one box at a time and not several together</strong><span class=\"\"> as pharmacists would do,</span><span class=\"\">’ he said.</span><span class=\"\">“</span></li>\n<li><strong class=\"\" data-path-to-node=\"11,2,0\" data-index-in-node=\"0\">Giải thích:</strong><span class=\"\"> Van der Waarde phê phán các cơ quan quản lý vì họ chỉ kiểm tra từng hộp thuốc đơn lẻ mà thiếu việc đặt chúng cạnh nhau để so sánh độ nhiễu/nhầm lẫn thông tin như trong thực tế.</span></li>\n</ul>\n<p><strong class=\"\" data-path-to-node=\"12\" data-index-in-node=\"0\">32. Information provided with medicine is not listed in the right order.</strong></p>\n<ul data-path-to-node=\"13\">\n<li><strong data-path-to-node=\"13,0,0\" data-index-in-node=\"0\">Đáp án:</strong> <strong data-path-to-node=\"13,0,0\" data-index-in-node=\"8\">C (Richard Mawle)</strong></li>\n<li><strong data-path-to-node=\"13,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> Đoạn <em data-path-to-node=\"13,1,0\" data-index-in-node=\"16\">Safety and compliance</em>, dòng cuối: “Mawle… said: ‘There can be an awful lot of junk at the beginning of PILs. For example, <strong data-path-to-node=\"13,1,0\" data-index-in-node=\"140\">why are company details towards the beginning… when what might be more vital for the patient is…</strong>’”</li>\n<li><strong data-path-to-node=\"13,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Richard Mawle chỉ ra rằng thứ tự thông tin trong tờ hướng dẫn sử dụng đang bị ngược, đưa những thông tin ít quan trọng (như chi tiết công ty) lên đầu thay vì các cảnh báo an toàn cấp thiết cho bệnh nhân.</li>\n</ul>"}]', 0);
INSERT INTO public.questions VALUES ('eece24bc-0eb1-44f5-929f-96683525b9c0', '47409170-c42a-437d-aefb-dca7ce0f9fa0', 'matching', 'Questions 33–37', NULL, '<p>Complete the summery using the list of words, <strong>A-G,</strong> below.</p>
', 'matching_features', 'null', 'null', '{"layoutType": "summary", "summaryText": "<p class=\"ql-align-center\" style=\"text-align: center;\"><strong>Packaging design in the pharmaceutical industry</strong></p>\r\n<p><strong>Over-the-counter drugs</strong></p>\r\n<p>First, a proposal is written by the {E marketing team}. Then several designs are produced by the {C external design team} . Finally, selected designs are shown to {A consumers}.</p>\r\n<p><strong>Prescription-only drugs</strong></p>\r\n<p>The {D in-house design team} create the design. The design is then passed to {B design engineers}.</p>", "answerOptions": [{"optionText": "A consumers"}, {"optionText": "B design engineers"}, {"optionText": "C external design team"}, {"optionText": "D in-house design team"}, {"optionText": "E marketing team"}, {"optionText": "F pharmaceutical industry"}], "matchingItems": null}', 'null', '[{"content": "<p data-path-to-node=\"3\"><strong data-path-to-node=\"3\" data-index-in-node=\"0\">33. E (marketing team)</strong></p>\n<ul data-path-to-node=\"4\">\n<li>\n<p data-path-to-node=\"4,0,0\"><strong data-path-to-node=\"4,0,0\" data-index-in-node=\"0\">Vị trí:</strong> Đoạn 2, dòng 5.</p>\n</li>\n<li>\n<p data-path-to-node=\"4,1,0\"><strong data-path-to-node=\"4,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “The <strong data-path-to-node=\"4,1,0\" data-index-in-node=\"16\">marketing team</strong> prepares the initial brief…”</p>\n</li>\n<li>\n<p data-path-to-node=\"4,2,0\"><strong data-path-to-node=\"4,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Trong bài, “initial brief” (bản tóm tắt yêu cầu ban đầu) tương ứng với “proposal” (đề xuất) trong câu hỏi. Đội ngũ marketing là bộ phận đưa ra yêu cầu này đầu tiên.</p>\n</li>\n</ul>\n<p data-path-to-node=\"5\"><strong data-path-to-node=\"5\" data-index-in-node=\"0\">34. C (external design team)</strong></p>\n<ul data-path-to-node=\"6\">\n<li>\n<p data-path-to-node=\"6,0,0\"><strong data-path-to-node=\"6,0,0\" data-index-in-node=\"0\">Vị trí:</strong> Đoạn 2, dòng 3-4.</p>\n</li>\n<li>\n<p data-path-to-node=\"6,1,0\"><strong data-path-to-node=\"6,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…these [over-the-counter medicines] are usually commissioned from an <strong data-path-to-node=\"6,1,0\" data-index-in-node=\"83\">external design team</strong>.”</p>\n</li>\n<li>\n<p data-path-to-node=\"6,2,0\"><strong data-path-to-node=\"6,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Khác với thuốc kê đơn, thuốc không kê đơn cần sự bắt mắt nên thường được giao cho các đơn vị thiết kế bên ngoài thực hiện.</p>\n</li>\n</ul>\n<p data-path-to-node=\"7\"><strong data-path-to-node=\"7\" data-index-in-node=\"0\">35. A (consumers)</strong></p>\n<ul data-path-to-node=\"8\">\n<li>\n<p data-path-to-node=\"8,0,0\"><strong data-path-to-node=\"8,0,0\" data-index-in-node=\"0\">Vị trí:</strong> Đoạn 2, dòng 6-7.</p>\n</li>\n<li>\n<p data-path-to-node=\"8,1,0\"><strong data-path-to-node=\"8,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “Two or three of these [designs] are then tested on a <strong data-path-to-node=\"8,1,0\" data-index-in-node=\"65\">consumer group</strong>.”</p>\n</li>\n<li>\n<p data-path-to-node=\"8,2,0\"><strong data-path-to-node=\"8,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Sau khi có các bản thiết kế, chúng sẽ được đem đi thử nghiệm trên các nhóm người tiêu dùng (consumers) để đánh giá hiệu quả.</p>\n</li>\n</ul>\n<p data-path-to-node=\"11\"><strong data-path-to-node=\"11\" data-index-in-node=\"0\">36. D (in-house design team)</strong></p>\n<ul data-path-to-node=\"12\">\n<li>\n<p data-path-to-node=\"12,0,0\"><strong data-path-to-node=\"12,0,0\" data-index-in-node=\"0\">Vị trí:</strong> Đoạn 2, dòng 8.</p>\n</li>\n<li>\n<p data-path-to-node=\"12,1,0\"><strong data-path-to-node=\"12,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “In contrast, most designs for prescription-only products are created <strong data-path-to-node=\"12,1,0\" data-index-in-node=\"81\">in-house</strong>.”</p>\n</li>\n<li>\n<p data-path-to-node=\"12,2,0\"><strong data-path-to-node=\"12,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Đối với các sản phẩm thuốc kê đơn, quy trình thiết kế thường được thực hiện bởi đội ngũ thiết kế nội bộ (in-house design team) của chính công ty dược đó.</p>\n</li>\n</ul>\n<p data-path-to-node=\"13\"><strong data-path-to-node=\"13\" data-index-in-node=\"0\">37. B (design engineers)</strong></p>\n<ul data-path-to-node=\"14\">\n<li>\n<p data-path-to-node=\"14,0,0\"><strong data-path-to-node=\"14,0,0\" data-index-in-node=\"0\">Vị trí:</strong> Đoạn 2, dòng 9-10.</p>\n</li>\n<li>\n<p data-path-to-node=\"14,1,0\"><strong data-path-to-node=\"14,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…applying the house design and then handing it over to <strong data-path-to-node=\"14,1,0\" data-index-in-node=\"69\">design engineers</strong>…”</p>\n</li>\n<li>\n<p data-path-to-node=\"14,2,0\"><strong data-path-to-node=\"14,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Sau khi đội nội bộ hoàn tất thiết kế, họ sẽ chuyển giao (hand over) bản thiết kế đó cho các kỹ sư thiết kế (design engineers) để đưa vào sản xuất mà thường không qua bước thử nghiệm trên người dùng.</p>\n</li>\n</ul>\n"}]', 1);
INSERT INTO public.questions VALUES ('faa70a83-9041-4720-8407-7ac86f842485', 'af9e1aa1-98de-4a97-a877-30634b830e40', 'fillup', 'Questions 21–23', '<p class="MsoNormal">Complete the sentences below.</p>
<p class="MsoNormal">Write <strong>ONE WORD ONLY </strong>from the passage for each answer.</p>
<p class="MsoNormal"> Commedia dell’arte actors used {Masks} to disguise their real identities.</p>
<p class="MsoNormal"> Harlequinades combined elements of a 16th-century art form with a {Poem} written many centuries earlier.</p>
<p class="MsoNormal"> In early 19th-century pantomimes, {Policemen} were often victims of the Clown’s activities.</p>
', NULL, 'gap_filling', 'null', 'null', 'null', 'null', '[{"content": "<p><strong data-path-to-node=\"1\" data-index-in-node=\"0\">21. Masks</strong></p>\n<ul data-path-to-node=\"2\">\n<li><strong data-path-to-node=\"2,0,0\" data-index-in-node=\"0\">Dẫn chứng</strong>: Đoạn 2, câu 3: &#8220;Distinctive <strong data-path-to-node=\"2,0,0\" data-index-in-node=\"39\">masks</strong> enabled audiences to recognise the people in these stories immediately; they also allowed actors to be rude or disrespectful without fear of being recognised.&#8221;</li>\n<li><strong data-path-to-node=\"2,1,0\" data-index-in-node=\"0\">Giải thích</strong>: Các diễn viên kịch Commedia dell’arte sử dụng những chiếc mặt nạ đặc trưng để khán giả nhận diện nhân vật, đồng thời giúp họ che giấu danh tính thật (disguise real identities) để có thể diễn những hành động khiếm nhã mà không sợ bị phát hiện.</li>\n</ul>\n<p><strong data-path-to-node=\"4\" data-index-in-node=\"0\">22. Poem</strong></p>\n<ul data-path-to-node=\"5\">\n<li><strong data-path-to-node=\"5,0,0\" data-index-in-node=\"0\">Dẫn chứng</strong>: Đoạn 3, câu 2: &#8220;Among the most popular performances were harlequinades, a new kind of entertainment which interwove Ovid’s first-century Latin <strong data-path-to-node=\"5,0,0\" data-index-in-node=\"154\">poem</strong> Metamorphoses with aspects of the Italian commedia.&#8221;</li>\n<li><strong data-path-to-node=\"5,1,0\" data-index-in-node=\"0\">Giải thích</strong>: Kịch Harlequinades là sự kết hợp giữa các yếu tố của kịch Ý (Commedia dell’arte &#8211; nghệ thuật thế kỷ 16) với bài thơ &#8220;Metamorphoses&#8221; (viết từ thế kỷ thứ 1, tức là nhiều thế kỷ trước đó).</li>\n</ul>\n<p><strong data-path-to-node=\"7\" data-index-in-node=\"0\">23. Policemen</strong></p>\n<ul data-path-to-node=\"8\">\n<li><strong data-path-to-node=\"8,0,0\" data-index-in-node=\"0\">Dẫn chứng</strong>: Đoạn 5, câu 4: &#8220;His anarchic activities included chasing and imprisoning <strong data-path-to-node=\"8,0,0\" data-index-in-node=\"84\">policemen</strong> and stealing gigantic quantities of sausages.&#8221;</li>\n<li><strong data-path-to-node=\"8,1,0\" data-index-in-node=\"0\">Giải thích</strong>: Trong các buổi diễn đầu thế kỷ 19, nhân vật Chú hề (Clown) của Grimaldi thường thực hiện các hành động nổi loạn nhắm vào cảnh sát (<strong data-path-to-node=\"8,1,0\" data-index-in-node=\"143\">policemen</strong>) như đuổi bắt và tống giam họ, biến họ thành nạn nhân trong các trò đùa của mình.</li>\n</ul>\n"}]', 1);
INSERT INTO public.questions VALUES ('89f7d3fe-ba02-4de6-a9f3-ca75e2f354ca', '4cb4d677-00f1-4333-a2b8-fb13e7bf50de', 'fillup', 'Questions 31 - 40', '<p>Complete the notes below,</p>
<p>Write <strong>ONE WORD ONLY</strong> for each answer.</p>
<p><span style="font-size: 12pt;"><strong data-start="92" data-end="115">Economics and Trust</strong></span></p>
<p>Trust relies on the stranger’s {kindness}</p>
<p>The understanding of trust can reduce {poverty}</p>
<p><strong data-start="215" data-end="239">How to measure trust</strong></p>
<p>• People’s ability of recognizing a person’s {face}</p>
<p>• Oxytocin will be released when {interaction} occurs</p>
<p><strong data-start="356" data-end="389">Experiments: two participants</strong></p>
<p>• The first participant decides whether to lend the money or not.</p>
<p>• The second participant has no {obligation} to return the money.</p>
<p>• Trust involves a {process}, so it is conditional.</p>
<p>• If animals have {cooperation}, they will be seen to have oxytocin.</p>
<p><strong data-start="654" data-end="675">Nash equilibrium:</strong></p>
<p>• Participants have no {expectations} that the other person would change his or her decision.</p>
<p>• People under stress have {high} levels of oxytocin.</p>
<p>• Oxytocin is a social {glue}</p>
', NULL, 'fill-in-the-blank', 'null', 'null', 'null', 'null', '[{"content": "<p class=\"MsoNormal\"><strong>PART 4</strong></p>\n<p class=\"MsoNormal\"><strong>Lecturer:</strong> The development of trust is an essential social tool, allowing people to form productive and meaningful relationships, both at a professional and personal level. Trust is indispensable in friendship, love, families, and organizations, and plays a key role in economic exchange and politics.</p>\n<p class=\"MsoNormal\">Much recent evidence indicates that trust contributes to economic, political, and social success. When we make contacts with strangers, such as doing business with the clients who we meet for the first time, our trust in them can only rely on their <span style=\"text-decoration: underline; background-color: #ffe786;\"><strong>(31) kindness</strong></span>. So from our own judgment or the comments from other people, we can have a rough idea if the stranger is trustworthy.</p>\n<p class=\"MsoNormal\">Trust is important because it is the basis around which all human relationships evolve. Without trust, there can be no relationship. Trust can come naturally or it can be manifested. Believe it or not, reducing the chance of suffering from <span style=\"text-decoration: underline; background-color: #ffe786;\"><strong>(32) poverty</strong></span> is to understand trust, because when you trust other people, you can have more support and resources.</p>\n<p class=\"MsoNormal\">However, our ability to trust others varies from individual to individual, just like different people’s ability of recognizing a person’s <span style=\"text-decoration: underline; background-color: #ffe786;\"><strong>(33) face</strong></span> is not the same. Bonds of trust are also extremely fragile. The study demonstrates how oxytocin can facilitate social interactions after trust has been violated. Luckily, oxytocin in our body has the ability to inspire trust in and among people. This chemical is released whenever <span style=\"text-decoration: underline; background-color: #ffe786;\"><strong>(34) interaction</strong></span> happens between people.</p>\n<p class=\"MsoNormal\">To study social interactions, economists and more recently neuroscientists take advantage of a simple experiment. Two participants play the so-called “trust game”. The first participant is faced with the decision to keep a sum of money or share it with the second participant, who has no <span style=\"text-decoration: underline; background-color: #ffe786;\"><strong>(35) obligation</strong></span> to give the money back. In this game, the first person is left with an important social dilemma: to trust or not to trust.</p>\n<p class=\"MsoNormal\">Trust is not something that naturally occurs when two people meet for the first time. It involves a <span style=\"text-decoration: underline; background-color: #ffe786;\"><strong>(36) process</strong>.</span> One person has to show the quality of being trustworthy to the other person. This can be achieved by certain behaviours and communication; therefore, trust is conditional.</p>\n<p class=\"MsoNormal\">Oxytocin does not only exist in human beings; animals also have this gift, and it can be seen when they have <span style=\"text-decoration: underline; background-color: #ffe786;\"><strong>(37) cooperation</strong></span> with each other. Oxytocin in monkeys, for example, allows them to work together to find food and to fight against enemies.</p>\n<p class=\"MsoNormal\">The Nash equilibrium’s game theory: the first participant will make the best decision he can with no <span style=\"text-decoration: underline;\"><strong>(38) expectations</strong></span> that the second participant would change his decision. The second participant will do the same, so the outcome depends on the decision of the other person.</p>\n<p class=\"MsoNormal\">The oxytocin level doesn’t stay the same in a person’s body. Studies have found that people who are under a lot of stress would have <span style=\"text-decoration: underline; background-color: #ffe786;\"><strong>(39) high</strong></span> levels of oxytocin. Oxytocin causes a substantial increase in trust among humans, thereby greatly increasing the benefits from social interactions. To sum up, oxytocin is like a kind of social <span style=\"text-decoration: underline; background-color: #ffe786;\"><strong>(40) glue</strong> </span>that is helpful in social bonding. Further research is needed to explore oxytocin and trust…</p>\n<p class=\"MsoNormal\">\n"}]', 0);
INSERT INTO public.questions VALUES ('89765bba-341a-45a3-9190-5cb716907e9b', '72c5dbc1-5a97-4756-9650-4555dfcd7901', 'matrix', 'Questions 1–4', '', '<p>Write the correct letter <strong>A–H</strong> in boxes 1–4 on your answer sheet.</p>
<p><strong>NB</strong>: You may use any letter more than once.</p>', 'choose_a_title', 'null', 'null', 'null', '{"layoutType": "simple", "matrixItems": [{"itemText": "The reason why museum directors need to constantly alter and update their exhibits.", "correctCategoryLetter": "C"}, {"itemText": "Mention of the length of time people will queue up to see a blockbuster.", "correctCategoryLetter": "A"}, {"itemText": "Terms that people have used when referring to blockbusters.", "correctCategoryLetter": "D"}, {"itemText": "The various ways that institutions like museums get financial support.", "correctCategoryLetter": "C"}], "matrixCategories": [{"categoryText": "A", "categoryLetter": "A"}, {"categoryText": "B", "categoryLetter": "B"}, {"categoryText": "C", "categoryLetter": "C"}, {"categoryText": "D", "categoryLetter": "D"}, {"categoryText": "E", "categoryLetter": "E"}, {"categoryText": "F", "categoryLetter": "F"}, {"categoryText": "G", "categoryLetter": "G"}, {"categoryText": "H", "categoryLetter": "H"}]}', '[{"content": "<p data-path-to-node=\"7\"><strong data-path-to-node=\"7\" data-index-in-node=\"0\">1. The reason why museum directors need to constantly alter and update their exhibits. — {C}</strong></p>\n<ul data-path-to-node=\"8\">\n<li>\n<p data-path-to-node=\"8,0,0\"><strong data-path-to-node=\"8,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"8,0,0\" data-index-in-node=\"11\">“Maintaining and increasing visitor levels is thus paramount and involves not only creating or hiring blockbuster exhibitions but providing <strong data-path-to-node=\"8,0,0\" data-index-in-node=\"151\">regular exhibition changes and innovations</strong>.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"8,1,0\"><strong data-path-to-node=\"8,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Vì bảo tàng hoạt động dưới hệ thống đa nguồn vốn (plural funding), việc duy trì và tăng lượng khách là ưu tiên hàng đầu (<strong data-path-to-node=\"8,1,0\" data-index-in-node=\"133\">paramount</strong>). Để làm được điều đó, họ phải liên tục thay đổi và đổi mới các buổi triển lãm.</p>\n</li>\n</ul>\n<p data-path-to-node=\"9\"><strong data-path-to-node=\"9\" data-index-in-node=\"0\">2. Mention of the length of time people will queue up to see a blockbuster. — {A}</strong></p>\n<ul data-path-to-node=\"10\">\n<li>\n<p data-path-to-node=\"10,0,0\"><strong data-path-to-node=\"10,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"10,0,0\" data-index-in-node=\"11\">“A blockbuster is a ‘large-scale loan exhibition that people who normally don’t go to museums will <strong data-path-to-node=\"10,0,0\" data-index-in-node=\"110\">stand in line for hours</strong> to see’…”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"10,1,0\"><strong data-path-to-node=\"10,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “Stand in line for hours” (xếp hàng hàng giờ đồng hồ) chính là thông tin về khoảng thời gian (length of time) mà mọi người sẵn sàng chờ đợi (queue up) để xem triển lãm.</p>\n</li>\n</ul>\n<p data-path-to-node=\"11\"><strong data-path-to-node=\"11\" data-index-in-node=\"0\">3. Terms that people have used when referring to blockbusters. — {D}</strong></p>\n<ul data-path-to-node=\"12\">\n<li>\n<p data-path-to-node=\"12,0,0\"><strong data-path-to-node=\"12,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"12,0,0\" data-index-in-node=\"11\">“…the words that are starting to appear in some descriptions of blockbusters are <strong data-path-to-node=\"12,0,0\" data-index-in-node=\"94\">‘less scholarly,’ ‘non-elitist,’ and ‘populist’</strong>…”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"12,1,0\"><strong data-path-to-node=\"12,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Các từ (words/terms) được dùng để gọi hoặc mô tả về blockbuster bao gồm: ít tính học thuật (less scholarly), không dành cho giới thượng lưu (non-elitist) và mang tính đại chúng (populist).</p>\n</li>\n</ul>\n<p data-path-to-node=\"13\"><strong data-path-to-node=\"13\" data-index-in-node=\"0\">4. The various ways that institutions like museums get financial support. — {C}</strong></p>\n<ul data-path-to-node=\"14\">\n<li>\n<p data-path-to-node=\"14,0,0\"><strong data-path-to-node=\"14,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"14,0,0\" data-index-in-node=\"11\">“Museums… currently operate under a system of <strong data-path-to-node=\"14,0,0\" data-index-in-node=\"59\">plural funding</strong>: revenue raised through <strong data-path-to-node=\"14,0,0\" data-index-in-node=\"98\">contributions by federal, state, and/or local governments</strong>, combined with revenue raised through <strong data-path-to-node=\"14,0,0\" data-index-in-node=\"194\">admission charges and other activities</strong>.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"14,1,0\"><strong data-path-to-node=\"14,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Đoạn C liệt kê các cách thức (various ways) bảo tàng nhận hỗ trợ tài chính (financial support): từ ngân sách chính phủ các cấp cho đến phí vào cửa và các hoạt động kinh doanh khác.</p>\n</li>\n</ul>"}]', 0);
INSERT INTO public.questions VALUES ('40ca8739-5e50-4c91-bf6d-f4306cf53dfb', 'd5972479-525b-4626-9e9a-994b9279c819', 'radio', 'Questions 1-6', NULL, '<p>Choose <strong>TRUE </strong>if the statement agrees with the information given in the text, choose <strong>FALSE </strong>if the statement contradicts the information, or choose <strong>NOT GIVEN </strong>if there is no information on this.</p>
', 'multiple_choice_single', '[{"correct": 1, "options": [{"content": "TRUE"}, {"content": "FALSE"}, {"content": "NOT GIVEN"}], "question": "The name Katherine Mansfield, that appears on the writer’s book, was exactly the same as her origin name"}, {"correct": 2, "options": [{"content": "TRUE"}, {"content": "FALSE"}, {"content": "NOT GIVEN"}], "question": "Mansfield won a prize for a story she wrote for the High School Reporter."}, {"correct": 0, "options": [{"content": "TRUE"}, {"content": "FALSE"}, {"content": "NOT GIVEN"}], "question": "How Pearl Button Was Kidnapped portrayed Maori people in a favorable way."}, {"correct": 1, "options": [{"content": "TRUE"}, {"content": "FALSE"}, {"content": "NOT GIVEN"}], "question": "When Mansfield was at Queen’s college, she planned to be a professional writer."}, {"correct": 1, "options": [{"content": "TRUE"}, {"content": "FALSE"}, {"content": "NOT GIVEN"}], "question": "Mansfield was unpopular with the other students at Queen’s college"}, {"correct": 0, "options": [{"content": "TRUE"}, {"content": "FALSE"}, {"content": "NOT GIVEN"}], "question": "In London, Mansfield showed little interest in politics."}]', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"4\"><strong class=\"\" data-path-to-node=\"4\" data-index-in-node=\"0\">1. The name Katherine Mansfield, that appears on the writer’s book, was exactly the same as her origin name.</strong></p>\n<ul data-path-to-node=\"5\">\n<li>\n<p data-path-to-node=\"5,0,0\"><strong class=\"\" data-path-to-node=\"5,0,0\" data-index-in-node=\"0\">Đáp án:</strong> <strong class=\"\" data-path-to-node=\"5,0,0\" data-index-in-node=\"8\">FALSE</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"5,1,0\"><strong class=\"\" data-path-to-node=\"5,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong><span class=\"\"> Đoạn 1,</span><span class=\"\"> dòng 1-3:</span><span class=\"\"> &#8220;Katherine Mansfield </span><strong class=\"\" data-path-to-node=\"5,1,0\" data-index-in-node=\"50\">Beauchamp Murry</strong><span class=\"\"> was born&#8230;</span><span class=\"\"> using the </span><strong class=\"\" data-path-to-node=\"5,1,0\" data-index-in-node=\"88\">pen name</strong><span class=\"\"> of Katherine Mansfield.</span><span class=\"\">&#8220;</span></p>\n</li>\n<li>\n<p data-path-to-node=\"5,2,0\"><strong class=\"\" data-path-to-node=\"5,2,0\" data-index-in-node=\"0\">Giải thích:</strong><span class=\"\"> Tên thật của bà có thêm họ &#8220;Beauchamp Murry&#8221;.</span><span class=\"\"> Katherine Mansfield chỉ là bút danh (</span><em class=\"\" data-path-to-node=\"5,2,0\" data-index-in-node=\"95\">pen name</em><span class=\"\">).</span><span class=\"\"> Vì vậy,</span><span class=\"\"> tên trên sách không &#8220;giống hệt&#8221; (</span><em class=\"\" data-path-to-node=\"5,2,0\" data-index-in-node=\"147\">exactly the same</em><span class=\"\">) tên khai sinh.</span></p>\n</li>\n</ul>\n<p data-path-to-node=\"6\"><strong class=\"\" data-path-to-node=\"6\" data-index-in-node=\"0\">2. Mansfield won a prize for a story she wrote for the High School Reporter.</strong></p>\n<ul data-path-to-node=\"7\">\n<li>\n<p data-path-to-node=\"7,0,0\"><strong class=\"\" data-path-to-node=\"7,0,0\" data-index-in-node=\"0\">Đáp án:</strong> <strong class=\"\" data-path-to-node=\"7,0,0\" data-index-in-node=\"8\">NOT GIVEN</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"7,1,0\"><strong class=\"\" data-path-to-node=\"7,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong><span class=\"\"> Đoạn 2,</span><span class=\"\"> dòng 1-2:</span><span class=\"\"> &#8220;Her first published stories appeared in the High Sotho Reporter and the Wellington Girls High School magazine&#8230;</span><span class=\"\">&#8220;</span></p>\n</li>\n<li>\n<p data-path-to-node=\"7,2,0\"><strong class=\"\" data-path-to-node=\"7,2,0\" data-index-in-node=\"0\">Giải thích:</strong><span class=\"\"> Bài đọc chỉ nói bà có truyện được </span><strong class=\"\" data-path-to-node=\"7,2,0\" data-index-in-node=\"46\">đăng</strong><span class=\"\"> (</span><em class=\"\" data-path-to-node=\"7,2,0\" data-index-in-node=\"52\">published</em><span class=\"\">) trên tờ báo này,</span><span class=\"\"> tuyệt nhiên không nhắc đến việc bà có được giải thưởng (</span><em class=\"\" data-path-to-node=\"7,2,0\" data-index-in-node=\"136\">prize</em><span class=\"\">) nào hay không.</span></p>\n</li>\n</ul>\n<p data-path-to-node=\"8\"><strong class=\"\" data-path-to-node=\"8\" data-index-in-node=\"0\">3. How Pearl Button Was Kidnapped portrayed Maori people in a favorable way.</strong></p>\n<ul data-path-to-node=\"9\">\n<li>\n<p data-path-to-node=\"9,0,0\"><strong class=\"\" data-path-to-node=\"9,0,0\" data-index-in-node=\"0\">Đáp án:</strong> <strong class=\"\" data-path-to-node=\"9,0,0\" data-index-in-node=\"8\">TRUE</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"9,1,0\"><strong class=\"\" data-path-to-node=\"9,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong><span class=\"\"> Đoạn 2,</span><span class=\"\"> dòng cuối:</span><span class=\"\"> &#8220;&#8230;</span><span class=\"\">interest in the Maori people&#8230;</span><span class=\"\"> who were often portrayed in a </span><strong class=\"\" data-path-to-node=\"9,1,0\" data-index-in-node=\"96\">sympathetic light</strong><span class=\"\"> in her later stories,</span><span class=\"\"> such as How Pearl Button Was Kidnapped.</span><span class=\"\">&#8220;</span></p>\n</li>\n<li>\n<p data-path-to-node=\"9,2,0\"><strong class=\"\" data-path-to-node=\"9,2,0\" data-index-in-node=\"0\">Giải thích:</strong><span class=\"\"> Cụm từ &#8220;in a sympathetic light&#8221; (dưới góc nhìn đồng cảm/đáng mến) đồng nghĩa với &#8220;in a favorable way&#8221; (một cách thuận lợi/tốt đẹp).</span></p>\n</li>\n</ul>\n<p data-path-to-node=\"10\"><strong class=\"\" data-path-to-node=\"10\" data-index-in-node=\"0\">4. When Mansfield was at Queen’s college, she planned to be a professional writer.</strong></p>\n<ul data-path-to-node=\"11\">\n<li>\n<p data-path-to-node=\"11,0,0\"><strong class=\"\" data-path-to-node=\"11,0,0\" data-index-in-node=\"0\">Đáp án:</strong> <strong class=\"\" data-path-to-node=\"11,0,0\" data-index-in-node=\"8\">FALSE</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"11,1,0\"><strong class=\"\" data-path-to-node=\"11,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong><span class=\"\"> Đoạn 3,</span><span class=\"\"> dòng 2-4:</span><span class=\"\"> &#8220;Mansfield recommended playing the cello,</span><span class=\"\"> an occupation that she believed,</span><span class=\"\"> during her time at Queens,</span><span class=\"\"> she would </span><strong class=\"\" data-path-to-node=\"11,1,0\" data-index-in-node=\"141\">take up professionally</strong><span class=\"\">.</span><span class=\"\">&#8220;</span></p>\n</li>\n<li>\n<p data-path-to-node=\"11,2,0\"><strong class=\"\" data-path-to-node=\"11,2,0\" data-index-in-node=\"0\">Giải thích:</strong><span class=\"\"> Trong thời gian học tại Queen&#8217;s College,</span><span class=\"\"> dự định nghề nghiệp của bà là trở thành một </span><strong class=\"\" data-path-to-node=\"11,2,0\" data-index-in-node=\"97\">nghệ sĩ Cello chuyên nghiệp</strong><span class=\"\">,</span><span class=\"\"> không phải nhà văn.</span> Mãi đến năm 1906 (đoạn 4), bà mới quyết tâm trở thành người viết lách chuyên nghiệp.</p>\n</li>\n</ul>\n<p data-path-to-node=\"12\"><strong data-path-to-node=\"12\" data-index-in-node=\"0\">5. Mansfield was unpopular with the other students at Queen’s college.</strong></p>\n<ul data-path-to-node=\"13\">\n<li>\n<p data-path-to-node=\"13,0,0\"><strong data-path-to-node=\"13,0,0\" data-index-in-node=\"0\">Đáp án:</strong> <strong data-path-to-node=\"13,0,0\" data-index-in-node=\"8\">FALSE</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"13,1,0\"><strong data-path-to-node=\"13,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> Đoạn 3, dòng 7-8: &#8220;&#8230;she was <strong data-path-to-node=\"13,1,0\" data-index-in-node=\"41\">appreciated</strong> amongst fellow students at Queens for her lively and charismatic approach&#8230;&#8221;</p>\n</li>\n<li>\n<p data-path-to-node=\"13,2,0\"><strong data-path-to-node=\"13,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Việc được bạn bè cùng trường &#8220;trân trọng&#8221; (<em data-path-to-node=\"13,2,0\" data-index-in-node=\"55\">appreciated</em>) và có lối sống &#8220;lôi cuốn&#8221; (<em data-path-to-node=\"13,2,0\" data-index-in-node=\"95\">charismatic</em>) chứng tỏ bà rất được yêu mến, trái ngược với từ &#8220;unpopular&#8221; (không được lòng mọi người).</p>\n</li>\n</ul>\n<p data-path-to-node=\"14\"><strong data-path-to-node=\"14\" data-index-in-node=\"0\">6. In London, Mansfield showed little interest in politics.</strong></p>\n<ul data-path-to-node=\"15\">\n<li>\n<p data-path-to-node=\"15,0,0\"><strong data-path-to-node=\"15,0,0\" data-index-in-node=\"0\">Đáp án:</strong> <strong data-path-to-node=\"15,0,0\" data-index-in-node=\"8\">TRUE</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"15,1,0\"><strong data-path-to-node=\"15,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> Đoạn 3, dòng 10-12: &#8220;Mansfield <strong data-path-to-node=\"15,1,0\" data-index-in-node=\"42\">did not become involved in much political activity</strong> when she lived in London&#8230; did not actively support the suffragette movement&#8230;&#8221;</p>\n</li>\n<li>\n<p data-path-to-node=\"15,2,0\"><strong data-path-to-node=\"15,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Việc không tham gia nhiều vào các hoạt động chính trị và không ủng hộ phong trào đòi quyền bầu cử của phụ nữ xác nhận bà &#8220;ít quan tâm đến chính trị&#8221; (<em data-path-to-node=\"15,2,0\" data-index-in-node=\"162\">showed little interest</em>).</p>\n</li>\n</ul>\n"}]', 0);
INSERT INTO public.questions VALUES ('5b41ac90-3697-4837-9256-adbcb0432e4b', 'd5972479-525b-4626-9e9a-994b9279c819', 'fillup', 'Questions 7-13', '<div class="s-block-item s-repeatable-item s-block-sortable-item s-blog-post-section blog-section">
<div class="container">
<div class="sixteen columns">
<div class="s-blog-section-inner">
<div class="s-component s-text ">
<div class="">
<div class="s-component-content s-font-body" style="text-align: left;">
<p>Complete the notes below</p>
<p>Write <strong>ONE WORD AND/OR A NUMBER</strong> from the passage for each answer.</p>
</div>
<p class="s-component-content s-font-body" style="text-align: center;"><strong>Katherine Mansfield’s adult years</strong>      <strong> </strong></p>
<div class="s-component-content s-font-body">
<p><strong>{1906}</strong></p>
<ul>
<li>
<p>Moved from England back to New Zealand.</p>
</li>
<li>
<p>First paid writing work was in a publication based in <strong> {Australia}</strong></p>
</li>
<li>
<p>Her <strong> {Family} </strong>and the New Zealand way of life made her feel dissatisfied.</p>
</li>
</ul>
<p>1908: Returned to London.</p>
<p>1911-1919:</p>
<ul>
<li>
<p>Met John Middleton Murry in 1911. <strong> </strong></p>
</li>
<li>
<p><strong>{Bankruptcy} </strong>perverted Mansfield and Murry from staying together in Paris</p>
</li>
<li>
<p>Spent time with distinguished <strong> {Writers} </strong></p>
</li>
<li>
<p>From 1916, tuberculosis restricted the time she spent in London.</p>
</li>
</ul>
<p>1920:</p>
<ul>
<li>
<p>Her <strong>{Reputation}</strong> was consolidated when <em>Bliss and Other Stories</em> was published.Wrote several stories at “Villa Isola Bella.”1923-1924:</p>
</li>
<li>
<p>Mansfield’s <strong> {Husband}</strong> published more of her works after her death.</p>
</li>
</ul>
</div>
</div>
</div>
</div>
</div>
</div>
</div>
', NULL, 'gap_filling', 'null', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"2\"><strong data-path-to-node=\"2\" data-index-in-node=\"0\">7. 1906</strong></p>\n<ul data-path-to-node=\"3\">\n<li>\n<p data-path-to-node=\"3,0,0\"><strong data-path-to-node=\"3,0,0\" data-index-in-node=\"0\">Vị trí:</strong> Đoạn 4, dòng 1-2.</p>\n</li>\n<li>\n<p data-path-to-node=\"3,1,0\"><strong data-path-to-node=\"3,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “After finishing her schooling in England, she returned to her New Zealand home in <strong data-path-to-node=\"3,1,0\" data-index-in-node=\"94\">1906</strong>…”</p>\n</li>\n<li>\n<p data-path-to-node=\"3,2,0\"><strong data-path-to-node=\"3,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Văn bản ghi rõ mốc thời gian bà rời Anh để quay về New Zealand là năm 1906.</p>\n</li>\n</ul>\n<p data-path-to-node=\"4\"><strong data-path-to-node=\"4\" data-index-in-node=\"0\">8. Australia</strong></p>\n<ul data-path-to-node=\"5\">\n<li>\n<p data-path-to-node=\"5,0,0\"><strong data-path-to-node=\"5,0,0\" data-index-in-node=\"0\">Vị trí:</strong> Đoạn 4, dòng 3.</p>\n</li>\n<li>\n<p data-path-to-node=\"5,1,0\"><strong data-path-to-node=\"5,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “She had several works published in <strong data-path-to-node=\"5,1,0\" data-index-in-node=\"47\">Australia</strong> in a magazine called Native Companion which was her first paid writing work…”</p>\n</li>\n<li>\n<p data-path-to-node=\"5,2,0\"><strong data-path-to-node=\"5,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Công việc viết lách được trả lương đầu tiên của bà là cho một tạp chí nằm ở nước Úc (Australia).</p>\n</li>\n</ul>\n<p data-path-to-node=\"6\"><strong data-path-to-node=\"6\" data-index-in-node=\"0\">9. family</strong></p>\n<ul data-path-to-node=\"7\">\n<li>\n<p data-path-to-node=\"7,0,0\"><strong data-path-to-node=\"7,0,0\" data-index-in-node=\"0\">Vị trí:</strong> Đoạn 4, dòng 6.</p>\n</li>\n<li>\n<p data-path-to-node=\"7,1,0\"><strong data-path-to-node=\"7,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “Mansfield rapidly grew discontented with the provincial New Zealand lifestyle, and with her <strong data-path-to-node=\"7,1,0\" data-index-in-node=\"104\">family</strong>.”</p>\n</li>\n<li>\n<p data-path-to-node=\"7,2,0\"><strong data-path-to-node=\"7,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Cụm từ “discontented with” đồng nghĩa với “dissatisfied” (không hài lòng/thất vọng). Hai thứ khiến bà không hài lòng là lối sống ở New Zealand và gia đình (family) của mình.</p>\n</li>\n</ul>\n<p data-path-to-node=\"8\"><strong data-path-to-node=\"8\" data-index-in-node=\"0\">10. bankruptcy</strong></p>\n<ul data-path-to-node=\"9\">\n<li>\n<p data-path-to-node=\"9,0,0\"><strong data-path-to-node=\"9,0,0\" data-index-in-node=\"0\">Vị trí:</strong> Đoạn 5, dòng 5-6.</p>\n</li>\n<li>\n<p data-path-to-node=\"9,1,0\"><strong data-path-to-node=\"9,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “Their attempt to set up as writers in Paris was cut short by Murry’s <strong data-path-to-node=\"9,1,0\" data-index-in-node=\"81\">bankruptcy</strong>, which resulted from the failure of this and other journals.”</p>\n</li>\n<li>\n<p data-path-to-node=\"9,2,0\"><strong data-path-to-node=\"9,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Việc kinh doanh các tạp chí văn học thất bại đã dẫn đến sự phá sản (bankruptcy) của Murry, gây khó khăn cho cuộc sống của hai người.</p>\n</li>\n</ul>\n<p data-path-to-node=\"10\"><strong data-path-to-node=\"10\" data-index-in-node=\"0\">11. writers</strong></p>\n<ul data-path-to-node=\"11\">\n<li>\n<p data-path-to-node=\"11,0,0\"><strong data-path-to-node=\"11,0,0\" data-index-in-node=\"0\">Vị trí:</strong> Đoạn 6, dòng 2.</p>\n</li>\n<li>\n<p data-path-to-node=\"11,1,0\"><strong data-path-to-node=\"11,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “She and Murry developed close contact with other well-known <strong data-path-to-node=\"11,1,0\" data-index-in-node=\"72\">writers</strong> of the time such as DH Lawrence…”</p>\n</li>\n<li>\n<p data-path-to-node=\"11,2,0\"><strong data-path-to-node=\"11,2,0\" data-index-in-node=\"0\">Giải thích:</strong> “Distinguished” (kiệt xuất/lừng danh) đồng nghĩa với “well-known”. Bà đã dành thời gian và giữ liên lạc mật thiết với những nhà văn (writers) nổi tiếng khác.</p>\n</li>\n</ul>\n<p data-path-to-node=\"12\"><strong data-path-to-node=\"12\" data-index-in-node=\"0\">12. reputation</strong></p>\n<ul data-path-to-node=\"13\">\n<li>\n<p data-path-to-node=\"13,0,0\"><strong data-path-to-node=\"13,0,0\" data-index-in-node=\"0\">Vị trí:</strong> Đoạn 6, dòng cuối.</p>\n</li>\n<li>\n<p data-path-to-node=\"13,1,0\"><strong data-path-to-node=\"13,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…it was the publication of Bliss and Other Stories in 1920 that was to solidify Mansfield’s <strong data-path-to-node=\"13,1,0\" data-index-in-node=\"106\">reputation</strong> as a writer.”</p>\n</li>\n<li>\n<p data-path-to-node=\"13,2,0\"><strong data-path-to-node=\"13,2,0\" data-index-in-node=\"0\">Giải thích:</strong> “Solidify” đồng nghĩa với “consolidated” (củng cố/làm vững chắc). Việc xuất bản tập truyện “Bliss and Other Stories” đã khẳng định vị thế và danh tiếng (reputation) của bà.</p>\n</li>\n</ul>\n<p data-path-to-node=\"14\"><strong data-path-to-node=\"14\" data-index-in-node=\"0\">13. husband</strong></p>\n<ul data-path-to-node=\"15\">\n<li>\n<p data-path-to-node=\"15,0,0\"><strong data-path-to-node=\"15,0,0\" data-index-in-node=\"0\">Vị trí:</strong> Đoạn cuối, dòng 2-3.</p>\n</li>\n<li>\n<p data-path-to-node=\"15,1,0\"><strong data-path-to-node=\"15,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “After her death her <strong data-path-to-node=\"15,1,0\" data-index-in-node=\"32\">husband</strong>, Murry, took on the task of editing and publishing her works.”</p>\n</li>\n<li>\n<p data-path-to-node=\"15,2,0\"><strong data-path-to-node=\"15,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Sau khi bà qua đời, chính người chồng (husband) của bà là Murry đã tiếp tục biên tập và cho xuất bản các tác phẩm còn lại.</p>\n</li>\n</ul>\n"}]', 1);
INSERT INTO public.questions VALUES ('6aa39f52-fcc5-4277-bcda-0b7d19077ccc', 'af9e1aa1-98de-4a97-a877-30634b830e40', 'matching', 'Questions 14–20', NULL, '<p>Reading Passage 2 has seven paragraphs.</p>
<p>Choose the correct heading for each paragraph from the list of headings below.</p>
<p>Choose the correct number, i-viii, in boxes 14-20</p>
', 'matching_features', 'null', 'null', '{"layoutType": "heading", "summaryText": null, "answerOptions": [{"optionText": "i A character who provoked sympathy and amusement"}, {"optionText": "ii Outdoor performances with a standard set of"}, {"optionText": "iii Pantomime as a means of focusing on political issues"}, {"optionText": "iv Discovering pantomime at a young age"}, {"optionText": "v A way of dealing with a negative attitude toward pantomime"}, {"optionText": "vi An explanation of how a pantomime character appeals to modern audiences"}, {"optionText": "vii Debate about the origins of pantomime"}, {"optionText": "viii A successful merging of artistic sources"}], "matchingItems": null}', 'null', '[{"content": "<p data-path-to-node=\"2\"><strong data-path-to-node=\"2\" data-index-in-node=\"0\">14. Đoạn 1: iv Discovering pantomime at a young age</strong></p>\n<ul data-path-to-node=\"3\">\n<li>\n<p data-path-to-node=\"3,0,0\"><strong data-path-to-node=\"3,0,0\" data-index-in-node=\"0\">Dịch nghĩa</strong>: Khám phá kịch pantomime khi còn nhỏ.</p>\n</li>\n<li>\n<p data-path-to-node=\"3,1,0\"><strong data-path-to-node=\"3,1,0\" data-index-in-node=\"0\">Dẫn chứng</strong>: &#8220;For many <strong data-path-to-node=\"3,1,0\" data-index-in-node=\"21\">British children</strong>, their <strong data-path-to-node=\"3,1,0\" data-index-in-node=\"45\">first family trip</strong> to see a pantomime&#8230; is their <strong data-path-to-node=\"3,1,0\" data-index-in-node=\"94\">introduction</strong> to the magic of the theatre.&#8221;</p>\n</li>\n<li>\n<p data-path-to-node=\"3,2,0\"><strong data-path-to-node=\"3,2,0\" data-index-in-node=\"0\">Giải thích</strong>: Đoạn này nói về việc trẻ em Anh lần đầu tiếp xúc với nghệ thuật sân khấu thông qua các buổi diễn pantomime vào dịp Giáng sinh.</p>\n</li>\n</ul>\n<p data-path-to-node=\"4\"><strong data-path-to-node=\"4\" data-index-in-node=\"0\">15. Đoạn 2: ii Outdoor performances with a standard set of characters</strong></p>\n<ul data-path-to-node=\"5\">\n<li>\n<p data-path-to-node=\"5,0,0\"><strong data-path-to-node=\"5,0,0\" data-index-in-node=\"0\">Dịch nghĩa</strong>: Các buổi biểu diễn ngoài trời với một nhóm nhân vật chuẩn mực.</p>\n</li>\n<li>\n<p data-path-to-node=\"5,1,0\"><strong data-path-to-node=\"5,1,0\" data-index-in-node=\"0\">Dẫn chứng</strong>: &#8220;These improvised shows took place in <strong data-path-to-node=\"5,1,0\" data-index-in-node=\"49\">streets and marketplaces</strong>&#8230; Distinctive masks enabled audiences to <strong data-path-to-node=\"5,1,0\" data-index-in-node=\"116\">recognise the people</strong> in these stories immediately&#8230; rich old men&#8230; young lovers&#8230; quick-witted servants.&#8221;</p>\n</li>\n<li>\n<p data-path-to-node=\"5,2,0\"><strong data-path-to-node=\"5,2,0\" data-index-in-node=\"0\">Giải thích</strong>: Đoạn văn mô tả bối cảnh biểu diễn ở đường phố/chợ (ngoài trời) và liệt kê các loại nhân vật điển hình (old men, lovers, servants) mà khán giả nhìn là nhận ra ngay.</p>\n</li>\n</ul>\n<p data-path-to-node=\"6\"><strong data-path-to-node=\"6\" data-index-in-node=\"0\">16. Đoạn 3: viii A successful merging of artistic sources</strong></p>\n<ul data-path-to-node=\"7\">\n<li>\n<p data-path-to-node=\"7,0,0\"><strong data-path-to-node=\"7,0,0\" data-index-in-node=\"0\">Dịch nghĩa</strong>: Một sự pha trộn thành công các nguồn nghệ thuật.</p>\n</li>\n<li>\n<p data-path-to-node=\"7,1,0\"><strong data-path-to-node=\"7,1,0\" data-index-in-node=\"0\">Dẫn chứng</strong>: &#8220;&#8230;interwove Ovid’s&#8230; poem Metamorphoses with aspects of the Italian commedia&#8230; <strong data-path-to-node=\"7,1,0\" data-index-in-node=\"94\">cleverly mixed</strong> spectacle, music, ballet and myth&#8230;&#8221;</p>\n</li>\n<li>\n<p data-path-to-node=\"7,2,0\"><strong data-path-to-node=\"7,2,0\" data-index-in-node=\"0\">Giải thích</strong>: Đoạn này mô tả cách John Rich kết hợp (mix/interweave) nhiều yếu tố từ thơ ca La Mã, kịch Ý, âm nhạc và vũ ba-lê để tạo nên kịch pantomime hiện đại.</p>\n</li>\n</ul>\n<p data-path-to-node=\"8\"><strong data-path-to-node=\"8\" data-index-in-node=\"0\">17. Đoạn 4: v A way of dealing with a negative attitude toward pantomime</strong></p>\n<ul data-path-to-node=\"9\">\n<li>\n<p data-path-to-node=\"9,0,0\"><strong data-path-to-node=\"9,0,0\" data-index-in-node=\"0\">Dịch nghĩa</strong>: Một cách để đối phó với thái độ tiêu cực đối với pantomime.</p>\n</li>\n<li>\n<p data-path-to-node=\"9,1,0\"><strong data-path-to-node=\"9,1,0\" data-index-in-node=\"0\">Dẫn chứng</strong>: &#8220;Critics <strong data-path-to-node=\"9,1,0\" data-index-in-node=\"20\">bitterly attacked</strong> pantomimes&#8230; David Garrick&#8230; tactic was to set about changing pantomime’s cultural identity, partly by <strong data-path-to-node=\"9,1,0\" data-index-in-node=\"143\">confining shows to his theatre’s Christmas season</strong>.&#8221;</p>\n</li>\n<li>\n<p data-path-to-node=\"9,2,0\"><strong data-path-to-node=\"9,2,0\" data-index-in-node=\"0\">Giải thích</strong>: Khi bị các nhà phê bình chỉ trích là đe dọa kịch chính thống, Garrick đã đối phó bằng cách đưa pantomime vào mùa lễ hội Giáng sinh để biến nó thành một hình thức giải trí nhẹ nhàng, không còn là mối đe dọa.</p>\n</li>\n</ul>\n<p data-path-to-node=\"10\"><strong data-path-to-node=\"10\" data-index-in-node=\"0\">18. Đoạn 5: iii Pantomime as a means of focusing on political issues</strong></p>\n<ul data-path-to-node=\"11\">\n<li>\n<p data-path-to-node=\"11,0,0\"><strong data-path-to-node=\"11,0,0\" data-index-in-node=\"0\">Dịch nghĩa</strong>: Pantomime như một phương tiện để tập trung vào các vấn đề chính trị.</p>\n</li>\n<li>\n<p data-path-to-node=\"11,1,0\"><strong data-path-to-node=\"11,1,0\" data-index-in-node=\"0\">Dẫn chứng</strong>: &#8220;&#8230;a world of comic <strong data-path-to-node=\"11,1,0\" data-index-in-node=\"32\">revenge against a highly repressive government</strong>. Grimaldi became one of the great <strong data-path-to-node=\"11,1,0\" data-index-in-node=\"113\">satirists</strong> of his age&#8230; commentaries on everything from the <strong data-path-to-node=\"11,1,0\" data-index-in-node=\"173\">ruling classes</strong> to fashion&#8230;&#8221;</p>\n</li>\n<li>\n<p data-path-to-node=\"11,2,0\"><strong data-path-to-node=\"11,2,0\" data-index-in-node=\"0\">Giải thích</strong>: Đoạn này nói về nhân vật Chú hề (Clown) của Grimaldi, người sử dụng kịch để châm biếm chính phủ áp bức và các tầng lớp thống trị (vấn đề chính trị).</p>\n</li>\n</ul>\n<p data-path-to-node=\"12\"><strong data-path-to-node=\"12\" data-index-in-node=\"0\">19. Đoạn 6: i A character who provoked sympathy and amusement</strong></p>\n<ul data-path-to-node=\"13\">\n<li>\n<p data-path-to-node=\"13,0,0\"><strong data-path-to-node=\"13,0,0\" data-index-in-node=\"0\">Dịch nghĩa</strong>: Một nhân vật khơi dậy sự đồng cảm và sự vui vẻ.</p>\n</li>\n<li>\n<p data-path-to-node=\"13,1,0\"><strong data-path-to-node=\"13,1,0\" data-index-in-node=\"0\">Dẫn chứng</strong>: &#8220;&#8230;the pantomime ‘Dame’: a tired housewife&#8230; Leno developed a persona whose theatrical power comes from the <strong data-path-to-node=\"13,1,0\" data-index-in-node=\"121\">locking together of compassion and laughter</strong>.&#8221;</p>\n</li>\n<li>\n<p data-path-to-node=\"13,2,0\"><strong data-path-to-node=\"13,2,0\" data-index-in-node=\"0\">Giải thích</strong>: Nhân vật &#8220;Dame&#8221; (quý bà &#8211; do nam đóng) khiến khán giả vừa cười (laughter/amusement) vừa thương cảm (compassion/sympathy) vì hoàn cảnh nghèo khó của cô ấy.</p>\n</li>\n</ul>\n<p data-path-to-node=\"14\"><strong data-path-to-node=\"14\" data-index-in-node=\"0\">20. Đoạn 7: vi An explanation of how a pantomime character appeals to modern audiences</strong></p>\n<ul data-path-to-node=\"15\">\n<li>\n<p data-path-to-node=\"15,0,0\"><strong data-path-to-node=\"15,0,0\" data-index-in-node=\"0\">Dịch nghĩa</strong>: Giải thích cách một nhân vật pantomime thu hút khán giả hiện đại.</p>\n</li>\n<li>\n<p data-path-to-node=\"15,1,0\"><strong data-path-to-node=\"15,1,0\" data-index-in-node=\"0\">Dẫn chứng</strong>: &#8220;Pantomimes are as <strong data-path-to-node=\"15,1,0\" data-index-in-node=\"30\">popular today</strong> as they have ever been&#8230; Her comical conversations with the audience <strong data-path-to-node=\"15,1,0\" data-index-in-node=\"114\">cut across the boundaries</strong> between performers and spectators, drawing us into her chaotic world.&#8221;</p>\n</li>\n<li>\n<p data-path-to-node=\"15,2,0\"><strong data-path-to-node=\"15,2,0\" data-index-in-node=\"0\">Giải thích</strong>: Đoạn cuối giải thích sức hút của nhân vật Dame đối với khán giả ngày nay thông qua việc phá vỡ khoảng cách giữa sân khấu và người xem, tạo ra sự gắn kết cộng đồng.</p>\n</li>\n</ul>\n"}]', 0);
INSERT INTO public.questions VALUES ('267a04a7-4426-4de2-afd5-ec7a623370d2', '72c5dbc1-5a97-4756-9650-4555dfcd7901', 'fillup', 'Questions 5–8', '<p>Complete the sentences below.</p>
<p>Choose <strong>NO MORE THAN THREE WORDS</strong> from the passage for each answer.</p>
<p>Write your answers in boxes 5–8 on your answer sheet.</p>
<ul>
<li>
<p>These days, museum visitors tend to be referred to as {customers}.</p>
</li>
<li>
<p>Museum curators now need {public relation skills} rather than academic qualifications.</p>
</li>
<li>
<p>The linking of a range of public institutions that entertain the public is known as {museology}.</p>
</li>
<li>
<p>There is discussion about whether museums can be regarded in the same way as other {tourist attractions}.</p>
</li>
</ul>', NULL, 'summary_completion', 'null', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"4\"><strong data-path-to-node=\"4\" data-index-in-node=\"0\">5. These days, museum visitors tend to be referred to as {customers}. — {C}</strong></p>\n<ul data-path-to-node=\"5\">\n<li>\n<p data-path-to-node=\"5,0,0\"><strong data-path-to-node=\"5,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn C):</strong> <em data-path-to-node=\"5,0,0\" data-index-in-node=\"20\">“In addition, the visiting public have become known as <strong data-path-to-node=\"5,0,0\" data-index-in-node=\"75\">customers</strong> rather than visitors…”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"5,1,0\"><strong data-path-to-node=\"5,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “Referred to as” (được gọi là) đồng nghĩa với “become known as”. Bài đọc khẳng định công chúng đến thăm bảo tàng giờ đây được coi là khách hàng (<strong data-path-to-node=\"5,1,0\" data-index-in-node=\"157\">customers</strong>) thay vì chỉ là khách tham quan thông thường.</p>\n</li>\n</ul>\n<p data-path-to-node=\"6\"><strong data-path-to-node=\"6\" data-index-in-node=\"0\">6. Museum curators now need {public relations skills} rather than academic qualifications. — {C}</strong></p>\n<ul data-path-to-node=\"7\">\n<li>\n<p data-path-to-node=\"7,0,0\"><strong data-path-to-node=\"7,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn C):</strong> <em data-path-to-node=\"7,0,0\" data-index-in-node=\"20\">“…being a museum director no longer requires an Arts degree—but <strong data-path-to-node=\"7,0,0\" data-index-in-node=\"86\">public relations skills</strong> are essential if the museum is going to compete…”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"7,1,0\"><strong data-path-to-node=\"7,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “Academic qualifications” (bằng cấp học thuật) ở đây tương ứng với “Arts degree”. Ngược lại, kỹ năng quan hệ công chúng (<strong data-path-to-node=\"7,1,0\" data-index-in-node=\"133\">public relations skills</strong>) lại trở nên thiết yếu (essential/need) trong bối cảnh cạnh tranh hiện nay.</p>\n</li>\n</ul>\n<p data-path-to-node=\"8\"><strong data-path-to-node=\"8\" data-index-in-node=\"0\">7. The linking of a range of public institutions that entertain the public is known as {museology}. — {D}</strong></p>\n<ul data-path-to-node=\"9\">\n<li>\n<p data-path-to-node=\"9,0,0\"><strong data-path-to-node=\"9,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn D):</strong> <em data-path-to-node=\"9,0,0\" data-index-in-node=\"20\">“The convergence of museums, the heritage industry, tourism, profit-making, and pleasure-giving has resulted in the new <strong data-path-to-node=\"9,0,0\" data-index-in-node=\"140\">‘museology.’</strong>“</em></p>\n</li>\n<li>\n<p data-path-to-node=\"9,1,0\"><strong data-path-to-node=\"9,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “The linking of a range of public institutions” (Sự liên kết/hội tụ của các tổ chức công) chính là cụm “The convergence of museums, heritage industry…”. Kết quả của sự hội tụ này được gọi là tân bảo tàng học (<strong data-path-to-node=\"9,1,0\" data-index-in-node=\"223\">museology</strong>).</p>\n</li>\n</ul>\n<p data-path-to-node=\"10\"><strong data-path-to-node=\"10\" data-index-in-node=\"0\">8. There is discussion about whether museums can be regarded in the same way as other {tourist attractions}. — {D}</strong></p>\n<ul data-path-to-node=\"11\">\n<li>\n<p data-path-to-node=\"11,0,0\"><strong data-path-to-node=\"11,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn D):</strong> <em data-path-to-node=\"11,0,0\" data-index-in-node=\"20\">“This has given rise to much debate about whether it is appropriate to see museums primarily as <strong data-path-to-node=\"11,0,0\" data-index-in-node=\"116\">tourist attractions</strong>.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"11,1,0\"><strong data-path-to-node=\"11,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “Discussion” (thảo luận) tương ứng với “debate” (tranh luận). Câu hỏi đang đặt ra là liệu có phù hợp hay không khi xem bảo tàng như là các điểm thu hút khách du lịch (<strong data-path-to-node=\"11,1,0\" data-index-in-node=\"179\">tourist attractions</strong>).</p>\n</li>\n</ul>"}]', 1);
INSERT INTO public.questions VALUES ('c7a696e7-6fb0-4196-b31c-e1bb91b4f5ed', 'af9e1aa1-98de-4a97-a877-30634b830e40', 'matrix', 'Questions 24–26', NULL, '<p>Look at the following statements (Questions 24-26) and the list of people below.</p>
<p>Match each statement with the correct person.</p>
', 'other', 'null', 'null', 'null', '{"layoutType": "standard", "legendTitle": null, "matrixItems": [{"itemText": "His performances focused on the situation of the less wealthy sections of society.", "correctCategoryLetter": "D"}, {"itemText": "He introduced elements of the supernatural to the pantomime genre.", "correctCategoryLetter": "A"}, {"itemText": "His pantomime character was never seen to be punished for his on-stage crimes.", "correctCategoryLetter": "C"}], "matrixCategories": [{"categoryText": "John Rich", "categoryLetter": "A"}, {"categoryText": "David Garrick", "categoryLetter": "B"}, {"categoryText": "Joseph Grimaldi", "categoryLetter": "C"}, {"categoryText": "Dan Leno", "categoryLetter": "D"}]}', '[{"content": "<p><strong data-path-to-node=\"1\" data-index-in-node=\"0\">24. His performances focused on the situation of the less wealthy sections of society.</strong> (Các màn trình diễn của ông tập trung vào hoàn cảnh của những tầng lớp ít giàu có trong xã hội.)</p>\n<ul data-path-to-node=\"2\">\n<li><strong data-path-to-node=\"2,0,0\" data-index-in-node=\"0\">Đáp án: D. Dan Leno</strong></li>\n<li><strong data-path-to-node=\"2,1,0\" data-index-in-node=\"0\">Dẫn chứng</strong>: Đoạn 6, câu 3: &#8220;Dan Leno was the celebrated performer who created and played this talkative and eccentric <strong data-path-to-node=\"2,1,0\" data-index-in-node=\"117\">working-class woman</strong>, a mother facing the <strong data-path-to-node=\"2,1,0\" data-index-in-node=\"158\">difficulties of poverty</strong>, which he and his audiences knew all too well.&#8221;</li>\n<li><strong data-path-to-node=\"2,2,0\" data-index-in-node=\"0\">Giải thích</strong>: Dan Leno đóng vai một người phụ nữ thuộc tầng lớp lao động (working-class) và phải đối mặt với sự nghèo đói (poverty). Đây chính là những nhóm người &#8220;ít giàu có&#8221; (less wealthy) trong xã hội.</li>\n</ul>\n<hr data-path-to-node=\"3\" />\n<p><strong data-path-to-node=\"4\" data-index-in-node=\"0\">25. He introduced elements of the supernatural to the pantomime genre.</strong> (Ông đã đưa các yếu tố siêu nhiên vào thể loại kịch pantomime.)</p>\n<ul data-path-to-node=\"5\">\n<li><strong data-path-to-node=\"5,0,0\" data-index-in-node=\"0\">Đáp án: A. John Rich</strong></li>\n<li><strong data-path-to-node=\"5,1,0\" data-index-in-node=\"0\">Dẫn chứng</strong>: Đoạn 3, câu 4: &#8220;<strong data-path-to-node=\"5,1,0\" data-index-in-node=\"27\">Amazing transformations</strong> happened at the touch of a <strong data-path-to-node=\"5,1,0\" data-index-in-node=\"78\">magic wand</strong>, with mechanical serpents and flying vehicles.&#8221;</li>\n<li><strong data-path-to-node=\"5,2,0\" data-index-in-node=\"0\">Giải thích</strong>: John Rich đã đưa vào các màn trình diễn sự biến hóa kỳ ảo bằng gậy phép (magic wand) và các phương tiện bay, những thứ này được coi là các yếu tố siêu nhiên (supernatural).</li>\n</ul>\n<hr data-path-to-node=\"6\" />\n<p><strong data-path-to-node=\"7\" data-index-in-node=\"0\">26. His pantomime character was never seen to be punished for his on-stage crimes.</strong> (Nhân vật kịch pantomime của ông không bao giờ bị trừng phạt vì những tội ác/hành động sai trái trên sân khấu.)</p>\n<ul data-path-to-node=\"8\">\n<li><strong data-path-to-node=\"8,0,0\" data-index-in-node=\"0\">Đáp án: C. Joseph Grimaldi</strong></li>\n<li><strong data-path-to-node=\"8,1,0\" data-index-in-node=\"0\">Dẫn chứng</strong>: Đoạn 5, câu 4-5: &#8220;His anarchic activities included chasing and imprisoning policemen and stealing&#8230; But the <strong data-path-to-node=\"8,1,0\" data-index-in-node=\"120\">Clown was never caught or sent to jail</strong>.&#8221;</li>\n<li><strong data-path-to-node=\"8,2,0\" data-index-in-node=\"0\">Giải thích</strong>: Nhân vật Chú hề (Clown) của Grimaldi thực hiện các hành động phạm pháp (stealing, imprisoning policemen) nhưng &#8220;không bao giờ bị bắt hay tống giam&#8221;, tức là không bị trừng phạt (not punished).</li>\n</ul>\n"}]', 2);
INSERT INTO public.questions VALUES ('755d30e8-3ede-414a-bae8-616e7f0de9c6', '47409170-c42a-437d-aefb-dca7ce0f9fa0', 'radio', 'Questions 38-40', NULL, '<p>Choose the correct answer.</p>
', 'multiple_choice_single', '[{"correct": 1, "options": [{"content": "a printing error"}, {"content": "the style of print"}, {"content": "an incorrect label"}, {"content": "the shape of the bottle"}], "question": "In the accident mentioned in the passage, what was the ‘design consideration’ that caused a drug to be given incorrectly?"}, {"correct": 2, "options": [{"content": "Consumers would dislike this option."}, {"content": "Drug containers would all look too similar."}, {"content": "People would pay more attention to label information."}, {"content": "Partially sighted people would find these colours more helpful."}], "question": "What do some people say about the use of only black and white as a design feature?"}, {"correct": 0, "options": [{"content": "to show that progress is being made in pharmaceutical packaging design"}, {"content": "to give an example of pharmaceutical design problems that can cause accidents"}, {"content": "to prove that a lot of work still needs to be done to improve pharmaceutical packaging design"}, {"content": "to point out that patients need to be more informed about pharmaceutical products"}], "question": "Why does the writer refer to ‘the popper’ and ‘Pluspoint’?"}]', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"2\"><strong data-path-to-node=\"2\" data-index-in-node=\"0\">38. In the accident mentioned in the passage, what was the ‘design consideration’ that caused a drug to be given incorrectly?</strong></p>\n<ul data-path-to-node=\"3\">\n<li>\n<p data-path-to-node=\"3,0,0\"><strong data-path-to-node=\"3,0,0\" data-index-in-node=\"0\">Đáp án: the style of print</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"3,1,0\"><strong data-path-to-node=\"3,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> Đoạn <strong data-path-to-node=\"3,1,0\" data-index-in-node=\"16\">Design considerations</strong>, dòng 6-7: “Investigations following this tragedy attributed some blame to the <strong data-path-to-node=\"3,1,0\" data-index-in-node=\"117\">poor choice of typescript</strong> used on the drug container.”</p>\n</li>\n<li>\n<p data-path-to-node=\"3,2,0\"><strong data-path-to-node=\"3,2,0\" data-index-in-node=\"0\">Giải thích:</strong> “Typescript” chính là kiểu chữ hay phong cách in ấn (<strong data-path-to-node=\"3,2,0\" data-index-in-node=\"65\">style of print</strong>). Cuộc điều tra vụ tai nạn (tiêm nhầm thuốc vào tủy sống thay vì tĩnh mạch) đã chỉ ra rằng việc lựa chọn kiểu chữ không phù hợp trên nhãn thuốc là một nguyên nhân gây nhầm lẫn.</p>\n</li>\n</ul>\n<p data-path-to-node=\"4\"><strong data-path-to-node=\"4\" data-index-in-node=\"0\">39. What do some people say about the use of only black and white as a design feature?</strong></p>\n<ul data-path-to-node=\"5\">\n<li>\n<p data-path-to-node=\"5,0,0\"><strong data-path-to-node=\"5,0,0\" data-index-in-node=\"0\">Đáp án: People would pay more attention to label information.</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"5,1,0\"><strong data-path-to-node=\"5,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> Đoạn <strong data-path-to-node=\"5,1,0\" data-index-in-node=\"16\">Design principles and guidelines</strong>, dòng 4-6: “One argument is that if all packaging was white with black lettering, <strong data-path-to-node=\"5,1,0\" data-index-in-node=\"131\">people would have no choice but to read every box carefully</strong>.”</p>\n</li>\n<li>\n<p data-path-to-node=\"5,2,0\"><strong data-path-to-node=\"5,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Một số ý kiến cho rằng nếu tất cả bao bì chỉ có hai màu đen trắng, người dùng sẽ không bị xao nhãng bởi màu sắc và bắt buộc phải đọc kỹ các thông tin ghi trên nhãn (<strong data-path-to-node=\"5,2,0\" data-index-in-node=\"177\">pay more attention to label information</strong>).</p>\n</li>\n</ul>\n<p data-path-to-node=\"6\"><strong data-path-to-node=\"6\" data-index-in-node=\"0\">40. Why does the writer refer to ‘the popper’ and ‘Pluspoint’?</strong></p>\n<ul data-path-to-node=\"7\">\n<li>\n<p data-path-to-node=\"7,0,0\"><strong data-path-to-node=\"7,0,0\" data-index-in-node=\"0\">Đáp án: to show that progress is being made in pharmaceutical packaging design</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"7,1,0\"><strong data-path-to-node=\"7,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> Đoạn <strong data-path-to-node=\"7,1,0\" data-index-in-node=\"16\">Innovation</strong>, dòng 1-2: “On a <strong data-path-to-node=\"7,1,0\" data-index-in-node=\"44\">positive note</strong>, a recent <strong data-path-to-node=\"7,1,0\" data-index-in-node=\"68\">innovation</strong> exhibition revealed several <strong data-path-to-node=\"7,1,0\" data-index-in-node=\"107\">new designs</strong>. ‘The popper’ aims to… and ‘Pluspoint’ is…”</p>\n</li>\n<li>\n<p data-path-to-node=\"7,2,0\"><strong data-path-to-node=\"7,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Tác giả nhắc đến “The popper” (dụng cụ giúp người đau khớp lấy thuốc) và “Pluspoint” (bút tiêm adrenaline nhỏ gọn) trong phần “Innovation” (Sự đổi mới) để chứng minh rằng ngành thiết kế bao bì dược phẩm đang có những bước tiến triển tích cực (<strong data-path-to-node=\"7,2,0\" data-index-in-node=\"255\">progress is being made</strong>).</p>\n</li>\n</ul>\n"}]', 2);
INSERT INTO public.questions VALUES ('ebca5778-d952-4fd2-920f-d36e5aac964b', '17f17493-09b2-4398-9692-ff581b8c8baa', 'matrix', 'Questions 27-32.', NULL, '<p class="MsoNormal">Reading Passage 3 has seven paragraphs, <strong>A-G</strong>.</p>
<p class="MsoNormal">Which paragraph contains the following information?</p>
<p class="MsoNormal">Choose the correct letter, <strong>A-G</strong>, in boxes 27-32.</p>', 'other', 'null', 'null', 'null', '{"layoutType": "simple", "legendTitle": null, "matrixItems": [{"itemText": "a description of how a contestant remembers complex sequences", "correctCategoryLetter": "D"}, {"itemText": "an example of how one person’s memory was improved over time", "correctCategoryLetter": "G"}, {"itemText": "a description of a memorizing competition", "correctCategoryLetter": "A"}, {"itemText": "a commonly held belief about memory that many experts say is unproven", "correctCategoryLetter": "E"}, {"itemText": "a reference to the first recorded use of memorizing through location", "correctCategoryLetter": "B"}, {"itemText": "a reference to an unusual condition which results in improved memory", "correctCategoryLetter": "F"}], "matrixCategories": [{"categoryText": "A", "categoryLetter": "A"}, {"categoryText": "B", "categoryLetter": "B"}, {"categoryText": "C", "categoryLetter": "C"}, {"categoryText": "D", "categoryLetter": "D"}, {"categoryText": "E", "categoryLetter": "E"}, {"categoryText": "F", "categoryLetter": "F"}, {"categoryText": "G", "categoryLetter": "G"}]}', '[{"content": "<p data-path-to-node=\"2\"><strong data-path-to-node=\"2\" data-index-in-node=\"0\">27. A description of how a contestant remembers complex sequences: D</strong></p>\n<ul data-path-to-node=\"3\">\n<li>\n<p data-path-to-node=\"3,0,0\"><strong data-path-to-node=\"3,0,0\" data-index-in-node=\"0\">Dịch nghĩa</strong>: Mô tả về cách một thí sinh ghi nhớ các chuỗi dữ liệu phức tạp.</p>\n</li>\n<li>\n<p data-path-to-node=\"3,1,0\"><strong data-path-to-node=\"3,1,0\" data-index-in-node=\"0\">Dẫn chứng</strong>: Đoạn D, câu 3: “When Cooke commits a deck to memory, he does it <strong data-path-to-node=\"3,1,0\" data-index-in-node=\"75\">three cards in one go</strong>, with every three-card group forming a <strong data-path-to-node=\"3,1,0\" data-index-in-node=\"136\">composite picture of a person doing something to an object</strong>.”</p>\n</li>\n<li>\n<p data-path-to-node=\"3,2,0\"><strong data-path-to-node=\"3,2,0\" data-index-in-node=\"0\">Giải thích</strong>: Đoạn D giải thích kỹ thuật cụ thể (Person-Verb-Object) mà Ed Cooke sử dụng để biến các chuỗi quân bài phức tạp thành những hình ảnh sinh động nhằm ghi nhớ dễ dàng hơn.</p>\n</li>\n</ul>\n<hr data-path-to-node=\"4\">\n<p data-path-to-node=\"5\"><strong data-path-to-node=\"5\" data-index-in-node=\"0\">28. An example of how one person’s memory was improved over time: G</strong></p>\n<ul data-path-to-node=\"6\">\n<li>\n<p data-path-to-node=\"6,0,0\"><strong data-path-to-node=\"6,0,0\" data-index-in-node=\"0\">Dịch nghĩa</strong>: Một ví dụ về việc trí nhớ của một người đã được cải thiện theo thời gian như thế nào.</p>\n</li>\n<li>\n<p data-path-to-node=\"6,1,0\"><strong data-path-to-node=\"6,1,0\" data-index-in-node=\"0\">Dẫn chứng</strong>: Đoạn G, câu 2: “During <strong data-path-to-node=\"6,1,0\" data-index-in-node=\"34\">two years of experimentation</strong>, S.V. <strong data-path-to-node=\"6,1,0\" data-index-in-node=\"69\">increased his ability</strong> to recall numbers from seven to <strong data-path-to-node=\"6,1,0\" data-index-in-node=\"123\">over eighty</strong>.”</p>\n</li>\n<li>\n<p data-path-to-node=\"6,2,0\"><strong data-path-to-node=\"6,2,0\" data-index-in-node=\"0\">Giải thích</strong>: Đoạn G đưa ra số liệu cụ thể về sự tiến bộ của S.V. sau 2 năm luyện tập, từ việc chỉ nhớ được 7 con số lên đến hơn 80 con số.</p>\n</li>\n</ul>\n<hr data-path-to-node=\"7\">\n<p data-path-to-node=\"8\"><strong data-path-to-node=\"8\" data-index-in-node=\"0\">29. A description of a memorizing competition: A</strong></p>\n<ul data-path-to-node=\"9\">\n<li>\n<p data-path-to-node=\"9,0,0\"><strong data-path-to-node=\"9,0,0\" data-index-in-node=\"0\">Dịch nghĩa</strong>: Một mô tả về một cuộc thi ghi nhớ.</p>\n</li>\n<li>\n<p data-path-to-node=\"9,1,0\"><strong data-path-to-node=\"9,1,0\" data-index-in-node=\"0\">Dẫn chứng</strong>: Đoạn A, câu 1 &amp; 4: “The Examinations School at Oxford University is where… <strong data-path-to-node=\"9,1,0\" data-index-in-node=\"88\">34 contestants gathered at the World Memory Championships</strong>… Reciting poems, memorizing digit sequences… are just a few of the tasks that test the limits…”</p>\n</li>\n<li>\n<p data-path-to-node=\"9,2,0\"><strong data-path-to-node=\"9,2,0\" data-index-in-node=\"0\">Giải thích</strong>: Đoạn A thiết lập bối cảnh của cuộc thi Vô địch Trí nhớ Thế giới, mô tả địa điểm tổ chức (Oxford) và các phần thi mà thí sinh phải thực hiện.</p>\n</li>\n</ul>\n<hr data-path-to-node=\"10\">\n<p data-path-to-node=\"11\"><strong data-path-to-node=\"11\" data-index-in-node=\"0\">30. A commonly held belief about memory that many experts say is unproven: E</strong></p>\n<ul data-path-to-node=\"12\">\n<li>\n<p data-path-to-node=\"12,0,0\"><strong data-path-to-node=\"12,0,0\" data-index-in-node=\"0\">Dịch nghĩa</strong>: Một niềm tin phổ biến về trí nhớ mà nhiều chuyên gia nói rằng chưa được chứng minh.</p>\n</li>\n<li>\n<p data-path-to-node=\"12,1,0\"><strong data-path-to-node=\"12,1,0\" data-index-in-node=\"0\">Dẫn chứng</strong>: Đoạn E, câu 1 &amp; 2: “The term <strong data-path-to-node=\"12,1,0\" data-index-in-node=\"40\">‘photographic memory’</strong> is frequently used… Yet, most researchers agree there is <strong data-path-to-node=\"12,1,0\" data-index-in-node=\"121\">no proof that such a memory truly exists</strong>.”</p>\n</li>\n<li>\n<p data-path-to-node=\"12,2,0\"><strong data-path-to-node=\"12,2,0\" data-index-in-node=\"0\">Giải thích</strong>: Đoạn E thảo luận về khái niệm “trí nhớ chụp ảnh” — một điều mà công chúng rất tin tưởng nhưng các nhà khoa học lại khẳng định là không có bằng chứng xác thực (unproven/myth).</p>\n</li>\n</ul>\n<hr data-path-to-node=\"13\">\n<p data-path-to-node=\"14\"><strong data-path-to-node=\"14\" data-index-in-node=\"0\">31. A reference to the first recorded use of memorizing through location: B</strong></p>\n<ul data-path-to-node=\"15\">\n<li>\n<p data-path-to-node=\"15,0,0\"><strong data-path-to-node=\"15,0,0\" data-index-in-node=\"0\">Dịch nghĩa</strong>: Đề cập đến lần sử dụng đầu tiên được ghi chép lại về việc ghi nhớ thông qua vị trí.</p>\n</li>\n<li>\n<p data-path-to-node=\"15,1,0\"><strong data-path-to-node=\"15,1,0\" data-index-in-node=\"0\">Dẫn chứng</strong>: Đoạn B, câu 1: “…loci method, reportedly <strong data-path-to-node=\"15,1,0\" data-index-in-node=\"54\">originating in 477 BC with the Greek poet Simonides of Ceos</strong>.”</p>\n</li>\n<li>\n<p data-path-to-node=\"15,2,0\"><strong data-path-to-node=\"15,2,0\" data-index-in-node=\"0\">Giải thích</strong>: Đoạn B xác nhận phương pháp Loci (nhớ bằng vị trí) bắt nguồn từ năm 477 TCN bởi Simonides. Đây là mốc thời gian đầu tiên được ghi nhận.</p>\n</li>\n</ul>\n<hr data-path-to-node=\"16\">\n<p data-path-to-node=\"17\"><strong data-path-to-node=\"17\" data-index-in-node=\"0\">32. A reference to an unusual condition which results in improved memory: F</strong></p>\n<ul data-path-to-node=\"18\">\n<li>\n<p data-path-to-node=\"18,0,0\"><strong data-path-to-node=\"18,0,0\" data-index-in-node=\"0\">Dịch nghĩa</strong>: Đề cập đến một tình trạng bất thường dẫn đến việc cải thiện trí nhớ.</p>\n</li>\n<li>\n<p data-path-to-node=\"18,1,0\"><strong data-path-to-node=\"18,1,0\" data-index-in-node=\"0\">Dẫn chứng</strong>: Đoạn F, câu 2: “Shereshevski also experienced <strong data-path-to-node=\"18,1,0\" data-index-in-node=\"57\">synesthesia</strong>, a rare <strong data-path-to-node=\"18,1,0\" data-index-in-node=\"77\">sensory condition</strong> where the senses are interconnected, which <strong data-path-to-node=\"18,1,0\" data-index-in-node=\"138\">significantly improved his memorization ability</strong>.”</p>\n</li>\n<li>\n<p data-path-to-node=\"18,2,0\"><strong data-path-to-node=\"18,2,0\" data-index-in-node=\"0\">Giải thích</strong>: Đoạn F nói về hiện tượng “synesthesia” (chứng cảm giác kèm) — một tình trạng thần kinh hiếm gặp giúp Shereshevski ghi nhớ thông tin một cách cực kỳ sống động và bền vững.</p>\n</li>\n</ul>"}]', 0);
INSERT INTO public.questions VALUES ('25c469f4-4feb-45cf-821f-5b6fd05f4ba9', '033f24bb-314e-4d0a-bcca-27eeb2afafb9', 'fillup', 'Questions 1-10', '<p>Complete the notes below.</p>
<p>Write <strong>ONE WORD AND/OR A NUMBER</strong> for each answer.</p>
<table style="width: 78.174%; height: 1204.8px; border-collapse: collapse; border: 1px solid #000000;" border="1" data-path-to-node="4">
