INSERT INTO public.questions VALUES ('946f3187-794a-4dfd-988a-9e87e1625902', '9de8c968-7092-49be-bf3b-c9a23bb1bdbd', 'fillup', 'Questions 8–13', '<p class="MsoNormal" style="margin-bottom: 0in; line-height: 115%; background: white; vertical-align: baseline;"><span style="font-family: ''Arial'',sans-serif; mso-fareast-font-family: ''Times New Roman''; color: #15191e; mso-font-kerning: 0pt; mso-ligatures: none;">Complete the notes below.</span></p>
<p class="MsoNormal" style="margin-bottom: 0in; line-height: 115%; background: white; vertical-align: baseline;"><span style="font-family: ''Arial'',sans-serif; mso-fareast-font-family: ''Times New Roman''; color: #15191e; mso-font-kerning: 0pt; mso-ligatures: none;">Write <strong><span style="border: none windowtext 1.0pt; mso-border-alt: none windowtext 0in; padding: 0in;">NO MORE THAN TWO WORDS</span></strong> from the passage for each answer.</span><strong><span style="font-size: 14.0pt; mso-bidi-font-size: 12.0pt; line-height: 115%; font-family: ''Arial'',sans-serif; mso-fareast-font-family: ''Times New Roman''; color: #15191e; border: none windowtext 1.0pt; mso-border-alt: none windowtext 0in; padding: 0in; mso-font-kerning: 0pt; mso-ligatures: none;"> </span></strong></p>
<p><strong><span style="font-size: 14.0pt; mso-bidi-font-size: 12.0pt; line-height: 115%; font-family: ''Arial'',sans-serif; mso-fareast-font-family: ''Times New Roman''; color: #15191e; border: none windowtext 1.0pt; mso-border-alt: none windowtext 0in; padding: 0in; mso-font-kerning: 0pt; mso-ligatures: none;">Lizard Island study</span></strong></p>
<p class="MsoNormal" style="margin-bottom: 0in; line-height: 115%; background: white; vertical-align: baseline;"><strong><span style="font-family: ''Arial'',sans-serif; mso-fareast-font-family: ''Times New Roman''; color: #15191e; border: none windowtext 1.0pt; mso-border-alt: none windowtext 0in; padding: 0in; mso-font-kerning: 0pt; mso-ligatures: none;">Aim:</span></strong></p>
<ul style="margin-top: 0in;" type="circle">
<li class="MsoNormal" style="color: #15191e; margin-bottom: 0in; line-height: 115%; mso-list: l2 level1 lfo1; tab-stops: list .5in; background: white; vertical-align: baseline;"><span style="font-family: ''Arial'',sans-serif; mso-fareast-font-family: ''Times New Roman''; mso-font-kerning: 0pt; mso-ligatures: none;">to study the relationship between predator and prey in juvenile reef fish</span></li>
</ul>
<p class="MsoNormal" style="margin-bottom: 0in; line-height: 115%; background: white; vertical-align: baseline;"><strong><span style="font-family: ''Arial'',sans-serif; mso-fareast-font-family: ''Times New Roman''; color: #15191e; border: none windowtext 1.0pt; mso-border-alt: none windowtext 0in; padding: 0in; mso-font-kerning: 0pt; mso-ligatures: none;">Problems:</span></strong></p>
<p class="MsoNormal" style="margin-bottom: 0in; line-height: 115%; background: white; vertical-align: baseline;"><span style="font-family: ''Arial'',sans-serif; mso-fareast-font-family: ''Times New Roman''; color: #15191e; mso-font-kerning: 0pt; mso-ligatures: none;">i) time-change of habitat takes place in summer and is linked to the {new moon}</span></p>
<p class="MsoNormal" style="margin-bottom: 0in; line-height: 115%; background: white; vertical-align: baseline;"><span style="font-family: ''Arial'',sans-serif; mso-fareast-font-family: ''Times New Roman''; color: #15191e; mso-font-kerning: 0pt; mso-ligatures: none;">ii) working conditions</span></p>
<p class="MsoNormal" style="margin-bottom: 0in; line-height: 115%; background: white; vertical-align: baseline;"><span style="font-family: ''Arial'',sans-serif; mso-fareast-font-family: ''Times New Roman''; color: #15191e; mso-font-kerning: 0pt; mso-ligatures: none;">iii) adaptation-difficult to move and settle fish into the {laboratory}</span></p>
<p class="MsoNormal" style="margin-bottom: 0in; line-height: 115%; background: white; vertical-align: baseline;"><strong><span style="font-family: ''Arial'',sans-serif; mso-fareast-font-family: ''Times New Roman''; color: #15191e; border: none windowtext 1.0pt; mso-border-alt: none windowtext 0in; padding: 0in; mso-font-kerning: 0pt; mso-ligatures: none;">Method:</span></strong></p>
<ul style="margin-top: 0in;" type="circle">
<li class="MsoNormal" style="color: #15191e; margin-bottom: 0in; line-height: 115%; mso-list: l1 level1 lfo2; tab-stops: list .5in; background: white; vertical-align: baseline;"><span style="font-family: ''Arial'',sans-serif; mso-fareast-font-family: ''Times New Roman''; mso-font-kerning: 0pt; mso-ligatures: none;"><span style="color: #15191e;">larval fish are drawn into a special trap with the aid of {artificial light}</span></span></li>
</ul>
<ul style="margin-top: 0in;" type="circle">
<li class="MsoNormal" style="margin-bottom: 0in; line-height: 115%; background: white; vertical-align: baseline;"><span style="font-family: ''Arial'',sans-serif; mso-fareast-font-family: ''Times New Roman''; mso-font-kerning: 0pt; mso-ligatures: none;">{predatory fish} <span style="color: #15191e;">are also collected</span></span></li>
</ul>
<ul style="margin-top: 0in;" type="circle">
<li class="MsoNormal" style="color: #15191e; margin-bottom: 0in; line-height: 115%; mso-list: l1 level1 lfo4; tab-stops: list .5in; background: white; vertical-align: baseline;"><span style="font-family: ''Arial'',sans-serif; mso-fareast-font-family: ''Times New Roman''; mso-font-kerning: 0pt; mso-ligatures: none;">both undergo trials</span></li>
</ul>
<p class="MsoNormal" style="margin-bottom: 0in; line-height: 115%; background: white; vertical-align: baseline;"><strong><span style="font-family: ''Arial'',sans-serif; mso-fareast-font-family: ''Times New Roman''; color: #15191e; border: none windowtext 1.0pt; mso-border-alt: none windowtext 0in; padding: 0in; mso-font-kerning: 0pt; mso-ligatures: none;">Possible reasons why ‘bigger’ is not always ‘better’:</span></strong></p>
<ul style="margin-top: 0in;" type="circle">
<li class="MsoNormal" style="color: #15191e; margin-bottom: 0in; line-height: 115%; mso-list: l0 level1 lfo5; tab-stops: list .5in; background: white; vertical-align: baseline;"><span style="font-family: ''Arial'',sans-serif; mso-fareast-font-family: ''Times New Roman''; mso-font-kerning: 0pt; mso-ligatures: none;">the number and type of predatory fish on the reef can vary from place to place</span></li>
</ul>
<ul style="margin-top: 0in;" type="circle">
<li class="MsoNormal" style="margin-bottom: 0in; line-height: 115%; background: white; vertical-align: baseline;"><span style="font-family: ''Arial'',sans-serif; mso-fareast-font-family: ''Times New Roman''; mso-font-kerning: 0pt; mso-ligatures: none;"><span style="color: #15191e;">physical features (e.g.</span> <span style="border: none windowtext 1.0pt; mso-border-alt: none windowtext 0in; padding: 0in;"><span style="color: #15191e;">{mouth size}</span></span></span><span style="font-family: ''Tahoma'',sans-serif; mso-fareast-font-family: ''Times New Roman''; mso-font-kerning: 0pt; mso-ligatures: none;">) </span><span style="font-family: ''Arial'',sans-serif; mso-fareast-font-family: ''Times New Roman''; mso-font-kerning: 0pt; mso-ligatures: none;">affect which prey a predator can eat</span></li>
</ul>
<ul style="margin-top: 0in;" type="circle">
<li class="MsoNormal" style="color: #15191e; margin-bottom: 0in; line-height: 115%; mso-list: l0 level1 lfo7; tab-stops: list .5in; background: white; vertical-align: baseline;"><span style="font-family: ''Arial'',sans-serif; mso-fareast-font-family: ''Times New Roman''; mso-font-kerning: 0pt; mso-ligatures: none;"><span style="color: #15191e;">optimal foraging theory suggests that the most common choice of prey should be {medium} </span></span><span style="font-family: ''Arial'',sans-serif; mso-fareast-font-family: ''Times New Roman''; mso-font-kerning: 0pt; mso-ligatures: none;">in size</span></li>
</ul>
<ul style="margin-top: 0in;" type="circle">
<li class="MsoNormal" style="color: #15191e; margin-bottom: 0in; line-height: 115%; mso-list: l0 level1 lfo8; tab-stops: list .5in; background: white; vertical-align: baseline;"><span style="font-family: ''Arial'',sans-serif; mso-fareast-font-family: ''Times New Roman''; mso-font-kerning: 0pt; mso-ligatures: none;">large juvenile fish may swim slowly and so may be targeted more often</span></li>
</ul>
', NULL, 'gap_filling', NULL, NULL, '{"layoutType": ["standard"], "summaryText": null, "answerOptions": null, "matchingItems": null}', '{"layoutType": ["standard"], "legendTitle": null, "matrixItems": null, "matrixCategories": null}', '[{"content": "<p>8. i) time-change of habitat takes place in summer and is linked to the <strong>new moon</strong>.</p>\n<ul>\n<li><strong>Đáp án:</strong> <strong>new moon</strong></li>\n<li><strong>Dẫn chứng:</strong> (Đoạn 4) “…settlement usually occurs within 2–3 days of a <strong>new moon</strong> during the warmer summer months.”</li>\n</ul>\n<p>9. iii) adaptation-difficult to move and settle fish into the <strong>laboratory</strong>.</p>\n<ul>\n<li><strong>Đáp án:</strong> <strong>laboratory</strong></li>\n<li><strong>Dẫn chứng:</strong> (Đoạn 4) “…combined with the difficulties associated with working underwater, transporting fish and adapting them to the <strong>laboratory</strong>…”</li>\n</ul>\n<p>10. larval fish are drawn into a special trap with the aid of <strong>artificial light</strong>.</p>\n<ul>\n<li><strong>Đáp án:</strong> <strong>artificial light</strong></li>\n<li><strong>Dẫn chứng:</strong> (Đoạn 4) “We collect the larval fish immediately prior to settlement using purpose-built traps that use <strong>artificial light</strong> to attract…”</li>\n</ul>\n<p>11. <strong>predatory fish</strong> are also collected.</p>\n<ul>\n<li><strong>Đáp án:</strong> <strong>predatory fish</strong></li>\n<li><strong>Dẫn chứng:</strong> (Đoạn 4) “These fish are subsequently transported to an aquarium, along with <strong>predatory fish</strong>, before being used in a series of aquarium and field-based trials.”</li>\n</ul>\n<p>12. physical features (e.g. <strong>mouth size</strong>) affect which prey a predator can eat.</p>\n<ul>\n<li><strong>Đáp án:</strong> <strong>mouth size</strong></li>\n<li><strong>Dẫn chứng:</strong> (Đoạn 6) “This relationship is driven by physical characteristics of predators, such as <strong>mouth size</strong>…”</li>\n</ul>\n<p>13. optimal foraging theory suggests that the most common choice of prey should be <strong>medium</strong> in size.</p>\n<ul>\n<li><strong>Đáp án:</strong> <strong>medium</strong></li>\n<li><strong>Dẫn chứng:</strong> (Đoạn 7) “This usually results in a preference for <strong>medium</strong>-sized prey.”</li>\n</ul>\n"}]', 2);
INSERT INTO public.questions VALUES ('62cd92a8-60db-4d19-b57a-bc3202fa142d', '3d515b65-71d6-4925-9fac-a72d6f3d6c5e', 'checkbox', 'Questions 17-18', '', '<div class="quests-inner-desc">
<div class="txt">Choose <strong>TWO</strong> correct answers.</div>
</div>
<div class="quests-list">
<div id="1310" class="quests-item quests-numctn quests-item-history quests-skip" data-question-id="407" data-numctn="17" data-count="17" data-quest="17-18" data-choices="2">
<div class="tt-head">
<p class="tt"><span class="numquest">17-18</span> Which TWO types of accommodation are available on a weekly basis?</p>
</div>
</div>
</div>', 'list_selection', 'null', '[{"correct": false, "option_text": "lighthouse"}, {"correct": true, "option_text": "hostel"}, {"correct": false, "option_text": "castle"}, {"correct": true, "option_text": "cottages"}, {"correct": false, "option_text": "bed and breakfast"}]', 'null', 'null', 'null', 1);
INSERT INTO public.questions VALUES ('71ece7a9-2b76-4df4-abc1-8bd089fca606', 'b912e56f-7fb0-4900-ae9e-21d3d63fef37', 'matrix', 'Questions 21–23', NULL, '<p>Choose the correct packaging development, A–F, for each company.</p>', 'classification', 'null', 'null', 'null', '{"layoutType": "standard", "legendTitle": "List of options", "matrixItems": [{"itemText": "KFC", "correctCategoryLetter": "E"}, {"itemText": "Loliware", "correctCategoryLetter": "D"}, {"itemText": "Tomorrow Machine", "correctCategoryLetter": "A"}], "matrixCategories": [{"categoryText": "a container that gets bigger under certain conditions", "categoryLetter": "A"}, {"categoryText": "packaging that vanishes in hot water", "categoryLetter": "B"}, {"categoryText": "a material that prevents the waste of sticky condiments", "categoryLetter": "C"}, {"categoryText": "packaging made from a vegetable product", "categoryLetter": "D"}, {"categoryText": "a sweet container for hot drinks", "categoryLetter": "E"}, {"categoryText": "round, flavourless containers that can be consumed", "categoryLetter": "F"}]}', '[{"content": "<p><strong data-path-to-node=\"1\" data-index-in-node=\"0\">21. KFC: E (a sweet container for hot drinks)</strong></p>\n<ul data-path-to-node=\"2\">\n<li><strong data-path-to-node=\"2,0,0\" data-index-in-node=\"0\">Vị trí:</strong> Đoạn 3, dòng 2–4.</li>\n<li><strong data-path-to-node=\"2,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> &#8220;The fried chicken chain <strong data-path-to-node=\"2,1,0\" data-index-in-node=\"36\">KFC</strong>, for example, is experimenting with an <strong data-path-to-node=\"2,1,0\" data-index-in-node=\"79\">edible coffee-cup</strong>. Made from a <strong data-path-to-node=\"2,1,0\" data-index-in-node=\"110\">hard cookie lined with heat-resistant white chocolate</strong>&#8230;&#8221;</li>\n<li><strong data-path-to-node=\"2,2,0\" data-index-in-node=\"0\">Giải thích:</strong> KFC đang thử nghiệm loại cốc đựng cà phê (hot drinks) có thể ăn được. Cấu tạo của chiếc cốc này từ bánh quy và sô-cô-la trắng, vốn là những nguyên liệu ngọt (sweet). Do đó, đây là một vật chứa đồ uống nóng có vị ngọt.</li>\n</ul>\n<p><strong data-path-to-node=\"3\" data-index-in-node=\"0\">22. Loliware: D (packaging made from a vegetable product)</strong></p>\n<ul data-path-to-node=\"4\">\n<li><strong data-path-to-node=\"4,0,0\" data-index-in-node=\"0\">Vị trí:</strong> Đoạn 3, dòng 9–10.</li>\n<li><strong data-path-to-node=\"4,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> &#8220;And last year, the company [<strong data-path-to-node=\"4,1,0\" data-index-in-node=\"40\">Loliware</strong>] introduced edible cupcake wrappers made from <strong data-path-to-node=\"4,1,0\" data-index-in-node=\"95\">potato starch</strong>.&#8221;</li>\n<li><strong data-path-to-node=\"4,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Công ty Loliware đã giới thiệu loại màng bọc bánh cupcake ăn được làm từ tinh bột khoai tây (<strong data-path-to-node=\"4,2,0\" data-index-in-node=\"105\">potato starch</strong>). Khoai tây là một loại sản phẩm thực vật (vegetable product), khớp hoàn toàn với mô tả ở lựa chọn D.</li>\n</ul>\n<p><strong data-path-to-node=\"5\" data-index-in-node=\"0\">23. Tomorrow Machine: A (a container that gets bigger under certain conditions)</strong></p>\n<ul data-path-to-node=\"6\">\n<li><strong data-path-to-node=\"6,0,0\" data-index-in-node=\"0\">Vị trí:</strong> Đoạn 7, dòng cuối.</li>\n<li><strong data-path-to-node=\"6,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> &#8220;<strong data-path-to-node=\"6,1,0\" data-index-in-node=\"12\">Tomorrow Machine</strong> is also working on a <strong data-path-to-node=\"6,1,0\" data-index-in-node=\"50\">compressed tiny package that expands into a full-size bowl</strong> when hot water is added.&#8221;</li>\n<li><strong data-path-to-node=\"6,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Công ty Tomorrow Machine đang nghiên cứu loại bao bì siêu nén (tiny package) có khả năng nở ra (expands/gets bigger) thành một chiếc bát kích cỡ bình thường khi gặp điều kiện nhất định là có nước nóng (hot water) đổ vào.</li>\n</ul>\n"}]', 1);
INSERT INTO public.questions VALUES ('32d24bd9-2686-4b8e-9dc7-7c741df144e4', '3d515b65-71d6-4925-9fac-a72d6f3d6c5e', 'checkbox', 'Questions 19–20', '', '<div class="quests-inner-desc">
<div class="txt">Choose <strong>TWO</strong> correct answers.</div>
</div>
<div class="quests-list">
<div id="1311" class="quests-item quests-numctn quests-item-history quests-skip" data-question-id="408" data-numctn="19" data-count="19" data-quest="19-20" data-choices="2">
<div class="tt-head">
<p class="tt"><span class="numquest">19-20</span> Which TWO benefits can all the members get?</p>
</div>
</div>
</div>', 'list_selection', 'null', '[{"correct": false, "option_text": "free entry to some castles"}, {"correct": true, "option_text": "subscription of Scottish magazines"}, {"correct": false, "option_text": "discount of apartment rent"}, {"correct": true, "option_text": "free visitor guide"}, {"correct": false, "option_text": "free parking"}]', 'null', 'null', 'null', 2);
INSERT INTO public.questions VALUES ('ee970510-d21c-43b9-b713-58276e593b78', '2c3ad16d-88b5-497f-a8ce-bc9b03da1423', 'fillup', 'Questions 5 – 8 ', '<p>Answer the questions below.</p>
<p>Choose <strong>NO MORE THAN TWO WORDS </strong>from the passage for each answer.</p>
<p>What name was given to the traditional technique of seed-sowing?</p>
<p>{broadcasting}</p>
<p>What type of agriculture gave Tull inspiration on his second tour of Europe?</p>
<p>{vine-growing methods}</p>
<p>What traditional addition to soil did Tull believe to be unnecessary?</p>
<p>{manure}</p>
<p>What animals did Tull recommend farmers should use to pull their machinery?</p>
<p>{horses}</p>
', NULL, 'gap_filling', 'null', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"15\"><strong data-path-to-node=\"15\" data-index-in-node=\"0\">5. What name was given to the traditional technique of seed-sowing?</strong></p>\n<ul data-path-to-node=\"16\">\n<li>\n<p data-path-to-node=\"16,0,0\"><strong data-path-to-node=\"16,0,0\" data-index-in-node=\"0\">Đáp án:</strong> <strong data-path-to-node=\"16,0,0\" data-index-in-node=\"8\">broadcasting</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"16,1,0\"><strong data-path-to-node=\"16,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> Đoạn 2, dòng 4: &#8220;&#8230;in a traditional method known as <strong data-path-to-node=\"16,1,0\" data-index-in-node=\"64\">broadcasting</strong>.&#8221;</p>\n</li>\n<li>\n<p data-path-to-node=\"16,2,0\"><strong data-path-to-node=\"16,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Phương pháp gieo hạt thủ công bằng cách tung hạt ngẫu nhiên trên cánh đồng được gọi là &#8220;broadcasting&#8221;.</p>\n</li>\n</ul>\n<p data-path-to-node=\"17\"><strong data-path-to-node=\"17\" data-index-in-node=\"0\">6. What type of agriculture gave Tull inspiration on his second tour of Europe?</strong></p>\n<ul data-path-to-node=\"18\">\n<li>\n<p data-path-to-node=\"18,0,0\"><strong data-path-to-node=\"18,0,0\" data-index-in-node=\"0\">Đáp án:</strong> <strong data-path-to-node=\"18,0,0\" data-index-in-node=\"8\">vine-growing methods</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"18,1,0\"><strong data-path-to-node=\"18,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> Đoạn 4, dòng 3: &#8220;Following practices he had observed in the <strong data-path-to-node=\"18,1,0\" data-index-in-node=\"71\">vine-growing methods</strong> of southern Europe&#8230;&#8221;</p>\n</li>\n<li>\n<p data-path-to-node=\"18,2,0\"><strong data-path-to-node=\"18,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Khi quan sát cách trồng nho ở Nam Âu, Tull đã nảy ra ý tưởng dùng sức vật kéo để xới đất giữa các hàng cây.</p>\n</li>\n</ul>\n<p data-path-to-node=\"19\"><strong data-path-to-node=\"19\" data-index-in-node=\"0\">7. What traditional addition to soil did Tull believe to be unnecessary?</strong></p>\n<ul data-path-to-node=\"20\">\n<li>\n<p data-path-to-node=\"20,0,0\"><strong data-path-to-node=\"20,0,0\" data-index-in-node=\"0\">Đáp án:</strong> <strong data-path-to-node=\"20,0,0\" data-index-in-node=\"8\">manure</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"20,1,0\"><strong data-path-to-node=\"20,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> Đoạn 4, dòng 6: &#8220;&#8230;and so eliminate the need for <strong data-path-to-node=\"20,1,0\" data-index-in-node=\"61\">manure</strong> to be used to fertilize the soil.&#8221;</p>\n</li>\n<li>\n<p data-path-to-node=\"20,2,0\"><strong data-path-to-node=\"20,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Tull sai lầm khi tin rằng việc xới đất kỹ sẽ giải phóng đủ chất dinh dưỡng, khiến việc bón phân chuồng (manure) trở nên không cần thiết.</p>\n</li>\n</ul>\n<p data-path-to-node=\"21\"><strong data-path-to-node=\"21\" data-index-in-node=\"0\">8. What animals did Tull recommend farmers should use to pull their machinery?</strong></p>\n<ul data-path-to-node=\"22\">\n<li>\n<p data-path-to-node=\"22,0,0\"><strong data-path-to-node=\"22,0,0\" data-index-in-node=\"0\">Đáp án:</strong> <strong data-path-to-node=\"22,0,0\" data-index-in-node=\"8\">horses</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"22,1,0\"><strong data-path-to-node=\"22,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> Đoạn 5, dòng 4: &#8220;Tull also advocated the use of <strong data-path-to-node=\"22,1,0\" data-index-in-node=\"59\">horses</strong> over the oxen more traditionally used&#8230;&#8221;</p>\n</li>\n<li>\n<p data-path-to-node=\"22,2,0\"><strong data-path-to-node=\"22,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Tull khuyến khích dùng ngựa (horses) thay vì bò kéo (oxen) truyền thống để tăng hiệu quả.</p>\n</li>\n</ul>\n"}]', 1);
INSERT INTO public.questions VALUES ('e5bc6d59-b9cf-4d91-9d88-1f711cea4e08', '25fe44bf-bad5-4e27-b3c3-9259eae07e9e', 'fillup', 'Questions 14–17', '<p data-section-id="1lzk6qv" data-start="17" data-end="48">Complete the summary below.</p>
<p data-start="49" data-end="106">Write <strong>ONE WORD ONLY</strong> from the passage for each answer.</p>
<p data-section-id="gfztrg" data-start="108" data-end="130"><span style="font-size: 14pt;"><strong>Insomnia in the USA</strong></span></p>
<p data-start="132" data-end="523">Last year the high number of {prescriptions} doctors gave their patients highlights the fact that insomnia is a serious issue in the USA. It is evidently responsible for a number of serious traffic {accidents} and has a considerable effect on company {productivity}. A lack of sleep can also have a harmful effect on different relationships, although there are no statistics on this.</p>
<p data-start="525" data-end="710">Unfortunately, there is insufficient official funding given to research into sleep problems, and the {training} given at medical school is also insufficient to deal with insomnia.</p>', NULL, 'summary_completion', 'null', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"4\"><strong data-path-to-node=\"4\" data-index-in-node=\"0\">14. prescriptions — {...the high number of prescriptions doctors gave...}</strong></p>\n<ul data-path-to-node=\"5\">\n<li>\n<p data-path-to-node=\"5,0,0\"><strong data-path-to-node=\"5,0,0\" data-index-in-node=\"0\">Dẫn chứng câu tốt nhất:</strong> &gt; <em data-path-to-node=\"5,0,0\" data-index-in-node=\"26\">“Fifty-six million prescriptions for sleeping medication were handed out by doctors in America last year.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"5,1,0\"><strong data-path-to-node=\"5,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Đoạn văn tóm tắt nói về số lượng lớn thứ mà bác sĩ đưa cho bệnh nhân vào năm ngoái. Bài đọc chỉ ra đó là 56 triệu đơn thuốc (<strong data-path-to-node=\"5,1,0\" data-index-in-node=\"137\">prescriptions</strong>) cho các loại thuốc ngủ được phân phát bởi các bác sĩ ở Mỹ.</p>\n</li>\n</ul>\n<p data-path-to-node=\"6\"><strong data-path-to-node=\"6\" data-index-in-node=\"0\">15. accidents — {...responsible for a number of serious traffic accidents...}</strong></p>\n<ul data-path-to-node=\"7\">\n<li>\n<p data-path-to-node=\"7,0,0\"><strong data-path-to-node=\"7,0,0\" data-index-in-node=\"0\">Dẫn chứng câu tốt nhất:</strong> &gt; <em data-path-to-node=\"7,0,0\" data-index-in-node=\"26\">“The Institute of Medicine... estimates nearly 20 percent of all major accidents on the road are associated with driver sleepiness.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"7,1,0\"><strong data-path-to-node=\"7,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Cụm từ \"traffic accidents\" (tai nạn giao thông) tương ứng với cụm từ \"accidents on the road\" (tai nạn trên đường phố) trong bài đọc do tình trạng buồn ngủ của tài xế gây ra. Từ cần điền là danh từ số nhiều <strong data-path-to-node=\"7,1,0\" data-index-in-node=\"218\">accidents</strong>.</p>\n</li>\n</ul>\n<p data-path-to-node=\"8\"><strong data-path-to-node=\"8\" data-index-in-node=\"0\">16. productivity — {...has a considerable effect on company productivity.}</strong></p>\n<ul data-path-to-node=\"9\">\n<li>\n<p data-path-to-node=\"9,0,0\"><strong data-path-to-node=\"9,0,0\" data-index-in-node=\"0\">Dẫn chứng câu tốt nhất:</strong> &gt; <em data-path-to-node=\"9,0,0\" data-index-in-node=\"26\">“The loss in terms of productivity within the workplace is even higher, costing billions.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"9,1,0\"><strong data-path-to-node=\"9,1,0\" data-index-in-node=\"0\">Giải thích:</strong> \"Effect on company...\" (ảnh hưởng tới... của công ty) tương ứng với cụm từ \"loss in terms of productivity within the workplace\" (sự tổn thất về mặt năng suất tại nơi làm việc). Từ cần điền là danh từ <strong data-path-to-node=\"9,1,0\" data-index-in-node=\"212\">productivity</strong>.</p>\n</li>\n</ul>\n<p data-path-to-node=\"10\"><strong data-path-to-node=\"10\" data-index-in-node=\"0\">17. training — {...and the training given at medical school is also insufficient...}</strong></p>\n<ul data-path-to-node=\"11\">\n<li>\n<p data-path-to-node=\"11,0,0\"><strong data-path-to-node=\"11,0,0\" data-index-in-node=\"0\">Dẫn chứng câu tốt nhất:</strong> &gt; <em data-path-to-node=\"11,0,0\" data-index-in-node=\"26\">“Currently most medical school students get no more than four hours of training on sleep disorders; some get none.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"11,1,0\"><strong data-path-to-node=\"11,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Câu hỏi nói về thứ được cung cấp ở trường y bị thiếu thốn, không đủ (<em data-path-to-node=\"11,1,0\" data-index-in-node=\"81\">insufficient</em>). Bài đọc viết các sinh viên trường y hiện chỉ nhận được không quá 4 tiếng tập huấn/đào tạo (<strong data-path-to-node=\"11,1,0\" data-index-in-node=\"187\">training</strong>) về các chứng rối loạn giấc ngủ.</p>\n</li>\n</ul>"}]', 0);
INSERT INTO public.questions VALUES ('361e2c4b-05f0-463b-8c48-86ce32a4ceba', '627cc1ed-b0d3-4630-aee6-1fef5d44f653', 'radio', 'Questions 1-5', NULL, '<p>Choose <strong>TRUE </strong>if the statement agrees with the information <strong>FALSE </strong>if the statement contradicts the information <strong>NOT</strong> <strong>GIVEN </strong>if there is no information on this</p>
', 'multiple_choice_single', '[{"correct": 1, "options": [{"content": "TRUE"}, {"content": "FALSE"}, {"content": "NOT GIVEN"}], "question": "The early Spanish called potato as the Incan name ''Chuño''."}, {"correct": 1, "options": [{"content": "TRUE"}, {"content": "FALSE"}, {"content": "NOT GIVEN"}], "question": "The purpose of Spanish coming to Peru was to find potatoes."}, {"correct": 2, "options": [{"content": "TRUE"}, {"content": "FALSE"}, {"content": "NOT GIVEN"}], "question": "The Spanish believed that the potato had the same nutrients as other vegetables."}, {"correct": 0, "options": [{"content": "TRUE"}, {"content": "FALSE"}, {"content": "NOT GIVEN"}], "question": "Peasants at that time did not like to eat potatoes because they were ugly,"}, {"correct": 0, "options": [{"content": "TRUE"}, {"content": "FALSE"}, {"content": "NOT GIVEN"}], "question": "The popularity of potatoes in the UK was due to food shortages during the war."}]', NULL, '{"layoutType": ["standard"], "summaryText": null, "answerOptions": null, "matchingItems": null}', '{"layoutType": ["standard"], "legendTitle": null, "matrixItems": null, "matrixCategories": null}', '[{"content": "<p>1. The early Spanish called potato as the Incan name ‘Chuño’.</p>\n<ul data-path-to-node=\"3\">\n<li>\n<p data-path-to-node=\"3,0,0\"><strong class=\"\">Đáp án: FALSE</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"3,1,0\"><strong class=\"\">Dẫn chứng:</strong><span class=\"\"> (Đoạn 2) “Early Spanish chroniclers who misused the Indian word </span><strong class=\"\">batata</strong><span class=\"\"> (sweet potato) as the name for the potato noted the importance of the tuber to the Incan Empire.</span><span class=\"\"> The Incas had learned to preserve the potato…</span><span class=\"\"> into a substance called </span><strong class=\"\">Chuño</strong><span class=\"\">.</span><span class=\"\">“</span></p>\n</li>\n<li>\n<p data-path-to-node=\"3,2,0\"><strong class=\"\">Giải thích:</strong><span class=\"\"> Người Tây Ban Nha dùng nhầm từ </span><strong class=\"\">“batata”</strong><span class=\"\"> (khoai lang) để gọi củ khoai tây,</span><span class=\"\"> chứ không phải dùng từ “Chuño” (tên món khoai tây nghiền bảo quản của người Inca).</span></p>\n</li>\n</ul>\n<p>2. The purpose of Spanish coming to Peru was to find potatoes.</p>\n<ul data-path-to-node=\"5\">\n<li>\n<p data-path-to-node=\"5,0,0\"><strong class=\"\">Đáp án: FALSE</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"5,1,0\"><strong class=\"\">Dẫn chứng:</strong><span class=\"\"> (Đoạn 3) “The Spanish conquistadors first encountered the potato when they arrived in Peru in 1532 </span><strong class=\"\">in search of gold</strong><span class=\"\">…</span><span class=\"\">“</span></p>\n</li>\n<li>\n<p data-path-to-node=\"5,2,0\"><strong class=\"\">Giải thích:</strong><span class=\"\"> Mục đích chính của người Tây Ban Nha là tìm kiếm </span><strong class=\"\">vàng</strong><span class=\"\"> (gold),</span><span class=\"\"> không phải khoai tây.</span></p>\n</li>\n</ul>\n<p>3. The Spanish believed that the potato had the same nutrients as other vegetables.</p>\n<ul data-path-to-node=\"7\">\n<li>\n<p data-path-to-node=\"7,0,0\"><strong class=\"\">Đáp án: NOT GIVEN</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"7,1,0\"><strong class=\"\">Dẫn chứng:</strong><span class=\"\"> (Đoạn 3) “…</span><span class=\"\">they did gradually begin to use potatoes as </span><strong class=\"\">basic rations</strong><span class=\"\"> aboard their ships.</span><span class=\"\">“</span></p>\n</li>\n<li>\n<p data-path-to-node=\"7,2,0\"><strong class=\"\">Giải thích:</strong><span class=\"\"> Văn bản chỉ nói người Tây Ban Nha dùng khoai tây làm khẩu phần cơ bản,</span> <strong class=\"\">không đề cập</strong><span class=\"\"> đến niềm tin của họ về giá trị dinh dưỡng của khoai tây so với các loại rau củ khác.</span></p>\n</li>\n</ul>\n<p>4. Peasants at that time did not like to eat potatoes because they were ugly.</p>\n<ul data-path-to-node=\"9\">\n<li>\n<p data-path-to-node=\"9,0,0\"><strong class=\"\">Đáp án: TRUE</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"9,1,0\"><strong class=\"\">Dẫn chứng:</strong><span class=\"\"> (Đoạn 4) “Even peasants refused to eat from a plant that produced </span><strong class=\"\">ugly, misshapen tubers</strong><span class=\"\">…</span><span class=\"\">“</span></p>\n</li>\n<li>\n<p data-path-to-node=\"9,2,0\"><strong class=\"\">Giải thích:</strong><span class=\"\"> Người nông dân từ chối ăn khoai tây vì chúng xấu xí và méo mó (ugly,</span><span class=\"\"> misshapen tubers).</span></p>\n</li>\n</ul>\n<p>5. The popularity of potatoes in the UK was due to food shortages during the war.</p>\n<ul data-path-to-node=\"11\">\n<li>\n<p data-path-to-node=\"11,0,0\"><strong class=\"\">Đáp án: TRUE</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"11,1,0\"><strong class=\"\">Dẫn chứng:</strong><span class=\"\"> (Đoạn 5) “Potatoes did not become a staple until,</span><span class=\"\"> during the </span><strong class=\"\">food shortages associated with the Revolutionary Wars</strong><span class=\"\">,</span><span class=\"\"> the English government began to officially encourage potato cultivation.</span><span class=\"\">“</span></p>\n</li>\n<li>\n<p data-path-to-node=\"11,2,0\"><strong class=\"\">Giải thích:</strong><span class=\"\"> Khoai tây trở thành lương thực chính ở Anh trong thời kỳ </span><strong class=\"\">thiếu lương thực liên quan đến chiến tranh</strong><span class=\"\">.</span></p>\n</li>\n</ul>\n"}]', 0);
INSERT INTO public.questions VALUES ('dfdec21f-9a1f-49d3-ba16-5bbea3e41e2a', 'b912e56f-7fb0-4900-ae9e-21d3d63fef37', 'fillup', 'Questions 24–26', '<p>Complete the sentences below.</p>
<p>Choose <strong>ONE WORD ONLY</strong> from the passage for each answer.</p>
<p>In Japan, {paper} has been used as edible packaging for years.</p>
<p>Liquiglide reduces food waste, especially in bottles containing various {sauces}.</p>
<p>Tomorrow Machine is planning to use solid {sugar} as a container for oil.</p>', NULL, 'summary_completion', 'null', 'null', 'null', 'null', '[{"content": "<div class=\"flex flex-col text-sm pb-25\">\n<article class=\"text-token-text-primary w-full focus:outline-none [--shadow-height:45px] has-data-writing-block:pointer-events-none has-data-writing-block:-mt-(--shadow-height) has-data-writing-block:pt-(--shadow-height) [&amp;:has([data-writing-block])&gt;*]:pointer-events-auto scroll-mt-[calc(var(--header-height)+min(200px,max(70px,20svh)))]\" dir=\"auto\" tabindex=\"-1\" data-turn-id=\"request-69861932-a1f4-839e-be3d-cf1ccf1fc500-45\" data-testid=\"conversation-turn-86\" data-scroll-anchor=\"true\" data-turn=\"assistant\">\n<div class=\"text-base my-auto mx-auto pb-10 [--thread-content-margin:--spacing(4)] @w-sm/main:[--thread-content-margin:--spacing(6)] @w-lg/main:[--thread-content-margin:--spacing(16)] px-(--thread-content-margin)\">\n<div class=\"[--thread-content-max-width:40rem] @w-lg/main:[--thread-content-max-width:48rem] mx-auto max-w-(--thread-content-max-width) flex-1 group/turn-messages focus-visible:outline-hidden relative flex w-full min-w-0 flex-col agent-turn\" tabindex=\"-1\">\n<div class=\"flex max-w-full flex-col grow\">\n<div class=\"min-h-8 text-message relative flex w-full flex-col items-end gap-2 text-start break-words whitespace-normal [.text-message+&amp;]:mt-1\" dir=\"auto\" data-message-author-role=\"assistant\" data-message-id=\"13ad8cc0-d0f9-461b-8a9f-a95951e2c907\" data-message-model-slug=\"gpt-5-2\">\n<div class=\"flex w-full flex-col gap-1 empty:hidden first:pt-[1px]\">\n<div class=\"markdown prose dark:prose-invert w-full wrap-break-word light markdown-new-styling\">\n<p data-path-to-node=\"1\"><strong data-path-to-node=\"1\" data-index-in-node=\"0\">24 In Japan, {paper} has been used as edible packaging for years.</strong></p>\n<ul data-path-to-node=\"2\">\n<li>\n<p data-path-to-node=\"2,0,0\"><strong data-path-to-node=\"2,0,0\" data-index-in-node=\"0\">Vị trí:</strong> Cuối đoạn 3.</p>\n</li>\n<li>\n<p data-path-to-node=\"2,1,0\"><strong data-path-to-node=\"2,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “Even with these new advances, one decade-old edible invention continues to see great success – the <strong data-path-to-node=\"2,1,0\" data-index-in-node=\"111\">clear paper</strong> used to wrap <strong data-path-to-node=\"2,1,0\" data-index-in-node=\"136\">Japanese</strong> Botan Rice Candy.”</p>\n</li>\n<li>\n<p data-path-to-node=\"2,2,0\"><strong data-path-to-node=\"2,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài đọc đề cập đến một phát minh đã có từ hàng thập kỷ và vẫn đang thành công tại Nhật Bản, đó là loại <strong data-path-to-node=\"2,2,0\" data-index-in-node=\"115\">giấy (paper)</strong> trong suốt dùng để gói kẹo gạo (Botan Rice Candy) mà người dùng có thể ăn luôn được.</p>\n</li>\n</ul>\n<p data-path-to-node=\"3\"><strong data-path-to-node=\"3\" data-index-in-node=\"0\">25 Liquiglide reduces food waste, especially in bottles containing various {sauces}.</strong></p>\n<ul data-path-to-node=\"4\">\n<li>\n<p data-path-to-node=\"4,0,0\"><strong data-path-to-node=\"4,0,0\" data-index-in-node=\"0\">Vị trí:</strong> Đoạn 4, dòng 1-3.</p>\n</li>\n<li>\n<p data-path-to-node=\"4,1,0\"><strong data-path-to-node=\"4,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “Another development has been nonstick packaging, which can eliminate the 3 to 15 percent of <strong data-path-to-node=\"4,1,0\" data-index-in-node=\"104\">sauces</strong> left inside traditional bottles, like those last trails of ketchup and mayonnaise…”</p>\n</li>\n<li>\n<p data-path-to-node=\"4,2,0\"><strong data-path-to-node=\"4,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Công nghệ Liquiglide tạo ra bề mặt siêu trơn giúp các loại <strong data-path-to-node=\"4,2,0\" data-index-in-node=\"71\">nước sốt (sauces)</strong> như tương cà hay sốt mayonnaise không bị dính lại trong chai. Điều này giúp giảm thiểu đáng kể lượng thực phẩm bị lãng phí.</p>\n</li>\n</ul>\n<p data-path-to-node=\"5\"><strong data-path-to-node=\"5\" data-index-in-node=\"0\">26 Tomorrow Machine is planning to use solid {sugar} as a container for oil.</strong></p>\n<ul data-path-to-node=\"6\">\n<li>\n<p data-path-to-node=\"6,0,0\"><strong data-path-to-node=\"6,0,0\" data-index-in-node=\"0\">Vị trí:</strong> Đoạn 6, dòng 4-5.</p>\n</li>\n<li>\n<p data-path-to-node=\"6,1,0\"><strong data-path-to-node=\"6,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “Tomorrow Machine, a Swedish design firm, has plans for three disappearing packages: an <strong data-path-to-node=\"6,1,0\" data-index-in-node=\"99\">oil bottle</strong> made from <strong data-path-to-node=\"6,1,0\" data-index-in-node=\"120\">hardened sugar</strong> that cracks open like an egg…”</p>\n</li>\n<li>\n<p data-path-to-node=\"6,2,0\"><strong data-path-to-node=\"6,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Công ty Tomorrow Machine đang lên kế hoạch cho các loại bao bì tự biến mất, trong đó có chai đựng dầu làm từ <strong data-path-to-node=\"6,2,0\" data-index-in-node=\"121\">đường (sugar)</strong> đã được làm cứng (solid/hardened). Loại chai này có thể đập vỡ ra giống như vỏ trứng sau khi dùng xong.</p>\n</li>\n</ul>\n</div>\n</div>\n</div>\n</div>\n</div>\n</div>\n</article>\n</div>"}]', 2);
INSERT INTO public.questions VALUES ('fd388f99-ce6d-4638-87f1-5052733a360f', '2c3ad16d-88b5-497f-a8ce-bc9b03da1423', 'radio', 'Questions 9 – 13 ', NULL, '<p>Choose <strong>TRUE </strong>if the statement agrees with the information . <strong>FALSE </strong>if the statement contradicts the information . <strong>NOT GIVEN </strong>if there is no information on this</p>', 'multiple_choice_single', '[{"correct": 2, "options": [{"content": "TRUE"}, {"content": "FALSE"}, {"content": "NOT GIVEN"}], "question": "Tull was employed in the legal profession before taking up farming."}, {"correct": 0, "options": [{"content": "TRUE"}, {"content": "FALSE"}, {"content": "NOT GIVEN"}], "question": "The staff on Tull''s farm were unwilling to follow his instructions."}, {"correct": 0, "options": [{"content": "TRUE"}, {"content": "FALSE"}, {"content": "NOT GIVEN"}], "question": "Tull reduced the amount of weeds in his Wheatfield. "}, {"correct": 1, "options": [{"content": "TRUE"}, {"content": "FALSE"}, {"content": "NOT GIVEN"}], "question": "Tull lived to see his ideas finally accepted. "}, {"correct": 2, "options": [{"content": "TRUE"}, {"content": "FALSE"}, {"content": "NOT GIVEN"}], "question": "Tull''s original book, published in 1731, sold very few copies."}]', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"25\"><strong data-path-to-node=\"25\" data-index-in-node=\"0\">9. Tull was employed in the legal profession before taking up farming.</strong> </p>\n<ul>\n<li style=\"line-height: 1.5;\"><strong data-path-to-node=\"28,0,0\" data-index-in-node=\"0\">Đáp án: </strong><strong>NOT GIVEN</strong> </li>\n<li style=\"line-height: 1.5;\"><strong>Dẫn chứng</strong> (Đoạn 1)<strong>:</strong> “He studied first at Oxford University and then at the Inns of Court, London, in preparation for a legal or political career. However, his health issues forced him to postpone these plans, and after qualifying as a barrister in 1699… the young Tull married, then began farming with his father…”</li>\n<li style=\"line-height: 1.5;\"><strong>Giải thích: </strong>Bài đọc chỉ cho biết Tull học để chuẩn bị cho nghề luật/chính trị và sau đó đủ điều kiện trở thành một barrister (luật sư). Tuy nhiên, bài không hề nói ông thực sự làm việc hay được tuyển dụng trong ngành luật trước khi chuyển sang làm nông. Vì vậy, thông tin trong câu hỏi không được đề cập rõ trong bài.</li>\n</ul>\n<p data-path-to-node=\"27\"><strong data-path-to-node=\"27\" data-index-in-node=\"0\">10. The staff on Tull’s farm were unwilling to follow his instructions.</strong></p>\n<ul data-path-to-node=\"28\">\n<li>\n<p data-path-to-node=\"28,0,0\"><strong data-path-to-node=\"28,0,0\" data-index-in-node=\"0\">Đáp án:</strong> <strong data-path-to-node=\"28,0,0\" data-index-in-node=\"8\">TRUE</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"28,1,0\"><strong data-path-to-node=\"28,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> Đoạn 2, dòng 7: “…his frustration with their <strong data-path-to-node=\"28,1,0\" data-index-in-node=\"58\">lack of co-operation</strong> prompted him to invent a machine…”</p>\n</li>\n<li>\n<p data-path-to-node=\"28,2,0\"><strong data-path-to-node=\"28,2,0\" data-index-in-node=\"0\">Giải thích:</strong> “Lack of co-operation” (thiếu sự hợp tác) đồng nghĩa với việc nhân viên không sẵn lòng làm theo chỉ dẫn của ông.</p>\n</li>\n</ul>\n<p data-path-to-node=\"3\"><strong data-path-to-node=\"3\" data-index-in-node=\"0\">11. Tull reduced the amount of weeds in his wheatfield.</strong></p>\n<ul>\n<li data-path-to-node=\"4\"><strong data-path-to-node=\"4\" data-index-in-node=\"0\">Đáp án:</strong> TRUE</li>\n<li data-path-to-node=\"5\"><strong data-path-to-node=\"5\" data-index-in-node=\"0\">Vị trí:</strong> Đoạn 4, dòng 9–10.</li>\n<li data-path-to-node=\"6\"><strong data-path-to-node=\"6\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…it is more likely that it was the turning over and pulverisation of the soil that <strong data-path-to-node=\"6\" data-index-in-node=\"97\">cut down on the volume of weeds</strong> competing with the seed.”</li>\n<li data-path-to-node=\"7\"><strong data-path-to-node=\"7\" data-index-in-node=\"0\">Giải thích:</strong> Mặc dù Tull nhầm lẫn về việc xới đất tạo ra chất dinh dưỡng, nhưng bài đọc xác nhận rằng hành động này của ông thực tế đã <strong data-path-to-node=\"7\" data-index-in-node=\"134\">“cut down on the volume of weeds”</strong> (cắt giảm khối lượng cỏ dại). Cụm từ này đồng nghĩa hoàn toàn với <strong data-path-to-node=\"7\" data-index-in-node=\"234\">“reduced the amount of weeds”</strong> trong câu hỏi. Kết quả này được minh chứng qua việc ông có thể trồng lúa mì liên tiếp 13 năm trên cùng một cánh đồng nhờ kiểm soát được sự cạnh tranh của cỏ dại.</li>\n</ul>\n<p data-path-to-node=\"31\"><strong data-path-to-node=\"31\" data-index-in-node=\"0\">12. Tull lived to see his ideas finally accepted.</strong></p>\n<ul data-path-to-node=\"32\">\n<li>\n<p data-path-to-node=\"32,0,0\"><strong data-path-to-node=\"32,0,0\" data-index-in-node=\"0\">Đáp án:</strong> <strong data-path-to-node=\"32,0,0\" data-index-in-node=\"8\">FALSE</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"32,1,0\"><strong data-path-to-node=\"32,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> Đoạn 5, dòng 6-10: “…resistance to his revolutionary theories persisted for many decades. Another century would pass before his eventual vindication… in his lifetime Tull’s methods… were dismissed and ridiculed…”</p>\n</li>\n<li>\n<p data-path-to-node=\"32,2,0\"><strong data-path-to-node=\"32,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Trong suốt cuộc đời mình, ý tưởng của Tull bị chế giễu và bác bỏ. Phải tận một thế kỷ sau khi ông mất, chúng mới được công nhận và chấp nhận rộng rãi.</p>\n</li>\n</ul>\n<p data-path-to-node=\"33\"><strong data-path-to-node=\"33\" data-index-in-node=\"0\">13. Tull’s original book, published in 1731, sold very few copies.</strong></p>\n<ul data-path-to-node=\"34\">\n<li>\n<p data-path-to-node=\"34,0,0\"><strong data-path-to-node=\"34,0,0\" data-index-in-node=\"0\">Đáp án:</strong> <strong data-path-to-node=\"34,0,0\" data-index-in-node=\"8\">NOT GIVEN</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"34,1,0\"><strong data-path-to-node=\"34,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> Đoạn 5, dòng 6: “The book caused great controversy khi nó xuất hiện…”</p>\n</li>\n<li>\n<p data-path-to-node=\"34,2,0\"><strong data-path-to-node=\"34,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài đọc chỉ nói cuốn sách gây ra “tranh cãi lớn” (great controversy), nhưng không hề đề cập đến số lượng bản in được bán ra là nhiều hay ít.</p>\n</li>\n</ul>"}]', 2);
INSERT INTO public.questions VALUES ('e216ea61-424b-47fb-bbff-382bfc0bcc9a', '6feae6d2-538b-40db-b43e-89fb79f9191d', 'fillup', 'Questions 21–30', '<div class="quests-inner-desc">
<div class="txt">
<p>Complete the notes below.</p>
<p>Write <strong>NO MORE THAN THREE WORDS AND/OR A NUMBER</strong> for each answer.</p>
</div>
</div>
<div class="quests-des">
<div class="content-write">
<p><span style="font-size: 14pt;"><strong>Possible Course Change</strong></span></p>
<p>Name of student:                Sally Layman</p>
<p>Current course:                 {Economic History}</p>
<p>Date started:                      <span class="fill-history-correct">{last September}</span></p>
<p>Courses interested in: 1st choice  {Politics}</p>
<p>2nd choice  {Philosophy}</p>
<div dir="ltr" align="left">
<div class="choice-table-wrap">
<table class="choice-table" style="border-collapse: collapse; border-spacing: 1px; border: 1px solid #000000;" border="1"><colgroup> <col width="190"> <col width="174"> <col width="231"></colgroup>
<tbody>
<tr>
<td style="border-width: 1px; padding: 1px; border-color: #000000;">
<p dir="ltr"><strong>Problem</strong></p>
</td>
<td style="border-width: 1px; padding: 1px; border-color: #000000;">
<p dir="ltr"><strong>Strategies tried</strong></p>
</td>
<td style="border-width: 1px; padding: 1px; border-color: #000000;">
<p dir="ltr"><strong>Further strategies suggested</strong></p>
</td>
</tr>
<tr>
<td style="border-width: 1px; padding: 1px; border-color: #000000;">
<p dir="ltr">finds  {lectures difficult| the lectures difficult}</p>
</td>
<td style="border-width: 1px; padding: 1px; border-color: #000000;">
<p dir="ltr">recording them</p>
</td>
<td style="border-width: 1px; padding: 1px; border-color: #000000;">
<p dir="ltr">join other students in</p>
<p dir="ltr">a  <span class="fill-history-correct">{discussion group}</span></p>
</td>
</tr>
<tr>
<td style="border-width: 1px; padding: 1px; border-color: #000000;">
<p dir="ltr">{not enough tutorials}</p>
</td>
<td style="border-width: 1px; padding: 1px; border-color: #000000;">
<p dir="ltr">talking to tutor</p>
</td>
<td style="border-width: 1px; padding: 1px; border-color: #000000;">
<p dir="ltr">arrange meetings in advance</p>
</td>
</tr>
<tr>
<td style="border-width: 1px; padding: 1px; border-color: #000000;">
<p dir="ltr">bad assignment</p>
</td>
<td style="border-width: 1px; padding: 1px; border-color: #000000;">
<p dir="ltr">more background reading</p>
</td>
<td style="border-width: 1px; padding: 1px; border-color: #000000;">
<p dir="ltr">visit <span class="fill-history-correct">{student services}</span></p>
</td>
</tr>
</tbody>
</table>
</div>
</div>
<p>Date for next meeting:</p>
<p><span class="fill-history-correct">{17th of February |17 February| February 17| 17th February| 17 February}</span> at 3.30 p. m.</p>
<p>With:  <span class="fill-history-correct">{senior advisor| senior adviser}</span></p>
</div>
</div>', '', 'summary_completion', 'null', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"2\"><strong data-path-to-node=\"2\" data-index-in-node=\"0\">PART 3: COURSE CHANGE DISCUSSION</strong></p>\n<p data-path-to-node=\"3\"><strong class=\"\" data-path-to-node=\"3\" data-index-in-node=\"0\">Sally:</strong><span class=\"\"> Excuse me,</span><span class=\"\"> Professor.</span><span class=\"\"> Can I talk to you for a minute?</span></p>\n<p data-path-to-node=\"4\"><strong class=\"\" data-path-to-node=\"4\" data-index-in-node=\"0\">Professor:</strong><span class=\"\"> Yes,</span><span class=\"\"> do come in.</span><span class=\"\"> So,</span><span class=\"\"> you’re Sally Lehmann,</span><span class=\"\"> that’s it?</span><span class=\"\"> You want to discuss with me changing courses,</span><span class=\"\"> right?</span></p>\n<p data-path-to-node=\"5\"><strong class=\"\" data-path-to-node=\"5\" data-index-in-node=\"0\">Sally:</strong><span class=\"\"> Yes,</span><span class=\"\"> alright.</span></p>\n<p data-path-to-node=\"6\"><strong class=\"\" data-path-to-node=\"6\" data-index-in-node=\"0\">Professor:</strong><span class=\"\"> What course are you doing at present,</span><span class=\"\"> Sally?</span></p>\n<p data-path-to-node=\"7\"><strong class=\"\" data-path-to-node=\"7\" data-index-in-node=\"0\">Sally:</strong><span class=\"\"> It’s </span><strong class=\"\" data-path-to-node=\"7\" data-index-in-node=\"12\">(Q21) Economic History</strong><span class=\"\">.</span></p>\n<p data-path-to-node=\"8\"><strong class=\"\" data-path-to-node=\"8\" data-index-in-node=\"0\">Professor:</strong><span class=\"\"> OK.</span><span class=\"\"> And when did you begin this course?</span></p>\n<p data-path-to-node=\"9\"><strong class=\"\" data-path-to-node=\"9\" data-index-in-node=\"0\">Sally:</strong><span class=\"\"> Let me think…</span><span class=\"\"> um,</span><span class=\"\"> it was </span><strong class=\"\" data-path-to-node=\"9\" data-index-in-node=\"34\">(Q22) last September</strong><span class=\"\">,</span><span class=\"\"> right.</span></p>\n<p data-path-to-node=\"10\"><strong class=\"\" data-path-to-node=\"10\" data-index-in-node=\"0\">Professor:</strong><span class=\"\"> Good.</span><span class=\"\"> Before we talk through all your problems with the course,</span><span class=\"\"> I want to know what courses you’d like to change to.</span></p>\n<p data-path-to-node=\"11\"><strong class=\"\" data-path-to-node=\"11\" data-index-in-node=\"0\">Sally:</strong><span class=\"\"> Well,</span><span class=\"\"> there are several courses that I thought about,</span><span class=\"\"> but my first choice would be </span><strong class=\"\" data-path-to-node=\"11\" data-index-in-node=\"90\">(Q23) Politics</strong><span class=\"\">.</span></p>\n<p data-path-to-node=\"12\"><strong class=\"\" data-path-to-node=\"12\" data-index-in-node=\"0\">Professor:</strong><span class=\"\"> Oh,</span><span class=\"\"> it’s one of the most popular courses in our college.</span></p>\n<p data-path-to-node=\"13\"><strong class=\"\" data-path-to-node=\"13\" data-index-in-node=\"0\">Sally:</strong><span class=\"\"> Yes,</span><span class=\"\"> I know.</span></p>\n<p data-path-to-node=\"14\"><strong class=\"\" data-path-to-node=\"14\" data-index-in-node=\"0\">Professor:</strong><span class=\"\"> So it means there might not be places available.</span></p>\n<p data-path-to-node=\"15\"><strong class=\"\" data-path-to-node=\"15\" data-index-in-node=\"0\">Sally:</strong><span class=\"\"> That’s right.</span></p>\n<p data-path-to-node=\"16\"><strong class=\"\" data-path-to-node=\"16\" data-index-in-node=\"0\">Professor:</strong><span class=\"\"> I’ll still make a note of that,</span><span class=\"\"> but it’s better to give another option.</span></p>\n<p data-path-to-node=\"17\"><strong class=\"\" data-path-to-node=\"17\" data-index-in-node=\"0\">Sally:</strong><span class=\"\"> Well,</span><span class=\"\"> I’ve thought of changing the course entirely to Business Studies,</span><span class=\"\"> but then I realised it is new to me,</span><span class=\"\"> so I think </span><strong class=\"\" data-path-to-node=\"17\" data-index-in-node=\"127\">(Q24) Philosophy</strong><span class=\"\"> might be a better choice.</span></p>\n<hr class=\"\" data-path-to-node=\"18\">\n<p data-path-to-node=\"19\"><strong data-path-to-node=\"19\" data-index-in-node=\"0\">PROBLEMS &amp; STRATEGIES (Questions 25–30)</strong></p>\n<p data-path-to-node=\"20\"><strong class=\"\" data-path-to-node=\"20\" data-index-in-node=\"0\">Professor:</strong><span class=\"\"> Okay,</span><span class=\"\"> that’s useful to know.</span><span class=\"\"> Then let’s talk through any problems you’ve been having at the moment and see if there is any possibility for us to offer help.</span><span class=\"\"> After all,</span><span class=\"\"> with all the efforts that you’ve made already,</span><span class=\"\"> it’ll be a pity to give up the present course and completely start a new one.</span></p>\n<p data-path-to-node=\"21\"><strong class=\"\" data-path-to-node=\"21\" data-index-in-node=\"0\">Sally:</strong><span class=\"\"> Yes,</span><span class=\"\"> I agree with that.</span><span class=\"\"> I’ve learned something valuable about economic history.</span></p>\n<p data-path-to-node=\"22\"><strong class=\"\" data-path-to-node=\"22\" data-index-in-node=\"0\">Professor:</strong><span class=\"\"> Good.</span><span class=\"\"> Well,</span><span class=\"\"> let’s talk about your problems.</span><span class=\"\"> What do you think is your significant difficulty in the course?</span></p>\n<p data-path-to-node=\"23\"><strong class=\"\" data-path-to-node=\"23\" data-index-in-node=\"0\">Sally:</strong><span class=\"\"> Well,</span><span class=\"\"> I have to say,</span><span class=\"\"> the biggest problem is that the </span><strong class=\"\" data-path-to-node=\"23\" data-index-in-node=\"60\">(Q25) lectures are difficult</strong><span class=\"\">.</span></p>\n<p data-path-to-node=\"24\"><strong class=\"\" data-path-to-node=\"24\" data-index-in-node=\"0\">Professor:</strong><span class=\"\"> Okay.</span><span class=\"\"> And have you tried something to overcome this problem?</span></p>\n<p data-path-to-node=\"25\"><strong class=\"\" data-path-to-node=\"25\" data-index-in-node=\"0\">Sally:</strong><span class=\"\"> Yes,</span><span class=\"\"> I have.</span><span class=\"\"> I tried recording the lectures because I couldn’t follow what the lecturer said.</span></p>\n<p data-path-to-node=\"26\"><strong class=\"\" data-path-to-node=\"26\" data-index-in-node=\"0\">Professor:</strong><span class=\"\"> Yes,</span><span class=\"\"> that’s a good idea.</span><span class=\"\"> And did you find it helped?</span></p>\n<p data-path-to-node=\"27\"><strong class=\"\" data-path-to-node=\"27\" data-index-in-node=\"0\">Sally:</strong><span class=\"\"> To a certain extent but…</span></p>\n<p data-path-to-node=\"28\"><strong class=\"\" data-path-to-node=\"28\" data-index-in-node=\"0\">Professor:</strong><span class=\"\"> Well,</span><span class=\"\"> recording is a good strategy,</span><span class=\"\"> but I also advise you to take part in the </span><strong class=\"\" data-path-to-node=\"28\" data-index-in-node=\"89\">(Q26) discussion group</strong><span class=\"\"> with other fellow students to discuss the lectures and exchange ideas with them.</span></p>\n<p data-path-to-node=\"29\"><strong class=\"\" data-path-to-node=\"29\" data-index-in-node=\"0\">Sally:</strong><span class=\"\"> Yes,</span><span class=\"\"> I’ve seen some of my classmates doing that.</span><span class=\"\"> I’ll ask them if I can join.</span></p>\n<p data-path-to-node=\"30\"><strong class=\"\" data-path-to-node=\"30\" data-index-in-node=\"0\">Professor:</strong><span class=\"\"> Good,</span><span class=\"\"> I’m sure you’ll find it helps.</span><span class=\"\"> And any other problems?</span></p>\n<p data-path-to-node=\"31\"><strong class=\"\" data-path-to-node=\"31\" data-index-in-node=\"0\">Sally:</strong><span class=\"\"> Yes.</span><span class=\"\"> The second problem is,</span><span class=\"\"> I think there are </span><strong class=\"\" data-path-to-node=\"31\" data-index-in-node=\"53\">(Q27) not enough tutorials</strong><span class=\"\"> for this course.</span></p>\n<p data-path-to-node=\"32\"><strong class=\"\" data-path-to-node=\"32\" data-index-in-node=\"0\">Professor:</strong><span class=\"\"> OK,</span><span class=\"\"> I think you can talk to your tutor about this.</span></p>\n<p data-path-to-node=\"33\"><strong class=\"\" data-path-to-node=\"33\" data-index-in-node=\"0\">Sally:</strong><span class=\"\"> Yes,</span><span class=\"\"> I did that,</span><span class=\"\"> but the tutor is so busy that I must wait until she is available.</span></p>\n<p data-path-to-node=\"34\"><strong class=\"\" data-path-to-node=\"34\" data-index-in-node=\"0\">Professor:</strong><span class=\"\"> Why don’t you try arranging meetings ahead of time?</span></p>\n<p data-path-to-node=\"35\"><strong class=\"\" data-path-to-node=\"35\" data-index-in-node=\"0\">Sally:</strong><span class=\"\"> Well,</span><span class=\"\"> I can try this way.</span></p>\n<p data-path-to-node=\"36\"><strong class=\"\" data-path-to-node=\"36\" data-index-in-node=\"0\">Professor:</strong><span class=\"\"> Good.</span><span class=\"\"> But I suppose the thing that made me upset recently is my poor assignment grade.</span></p>\n<p data-path-to-node=\"37\"><strong class=\"\" data-path-to-node=\"37\" data-index-in-node=\"0\">Sally:</strong><span class=\"\"> Oh,</span><span class=\"\"> the grade is an important issue.</span><span class=\"\"> Well,</span><span class=\"\"> I think I’ve tried my best to achieve a good score.</span><span class=\"\"> I did more background reading than before for the last assignment we just submitted.</span></p>\n<p data-path-to-node=\"38\"><strong class=\"\" data-path-to-node=\"38\" data-index-in-node=\"0\">Professor:</strong><span class=\"\"> Good,</span><span class=\"\"> and did you feel that helped?</span></p>\n<p data-path-to-node=\"39\"><strong class=\"\" data-path-to-node=\"39\" data-index-in-node=\"0\">Sally:</strong><span class=\"\"> Oh yes,</span><span class=\"\"> I think so.</span></p>\n<p data-path-to-node=\"40\"><strong class=\"\" data-path-to-node=\"40\" data-index-in-node=\"0\">Professor:</strong><span class=\"\"> Well,</span><span class=\"\"> I think you can try another strategy,</span><span class=\"\"> which is to visit </span><strong class=\"\" data-path-to-node=\"40\" data-index-in-node=\"73\">(Q28) student services</strong><span class=\"\">,</span><span class=\"\"> which offer a lot of helpful advice on assignment preparation.</span></p>\n<p data-path-to-node=\"41\"><strong class=\"\" data-path-to-node=\"41\" data-index-in-node=\"0\">Sally:</strong><span class=\"\"> Oh,</span><span class=\"\"> I’ve never heard about that.</span></p>\n<p data-path-to-node=\"42\"><strong class=\"\" data-path-to-node=\"42\" data-index-in-node=\"0\">Professor:</strong><span class=\"\"> I’ll give you a booklet with details on this.</span><span class=\"\"> You’ll find it well worth trying.</span></p>\n<p data-path-to-node=\"43\"><strong class=\"\" data-path-to-node=\"43\" data-index-in-node=\"0\">Sally:</strong><span class=\"\"> OK,</span><span class=\"\"> I’ll certainly try it.</span></p>\n<p data-path-to-node=\"44\"><strong class=\"\" data-path-to-node=\"44\" data-index-in-node=\"0\">Professor:</strong><span class=\"\"> OK,</span><span class=\"\"> that’s all the problems.</span><span class=\"\"> Well,</span><span class=\"\"> I’ve made a record of our discussions and suggested strategies.</span><span class=\"\"> Typically,</span><span class=\"\"> we advise you to try out these suggestions for a short period and then come back to discuss the situation to see whether it is improved.</span><span class=\"\"> If not,</span><span class=\"\"> we will start considering alternative courses.</span></p>\n<p data-path-to-node=\"45\"><strong class=\"\" data-path-to-node=\"45\" data-index-in-node=\"0\">Sally:</strong><span class=\"\"> OK.</span><span class=\"\"> When shall I come back?</span></p>\n<p data-path-to-node=\"46\"><strong class=\"\" data-path-to-node=\"46\" data-index-in-node=\"0\">Professor:</strong><span class=\"\"> How about in a month’s time?</span></p>\n<p data-path-to-node=\"47\"><strong class=\"\" data-path-to-node=\"47\" data-index-in-node=\"0\">Sally:</strong><span class=\"\"> Okay,</span><span class=\"\"> that will be on the </span><strong class=\"\" data-path-to-node=\"47\" data-index-in-node=\"33\">(Q29) 17th of February</strong><span class=\"\"> (17 February).</span><span class=\"\"> How about half past three in the afternoon?</span><span class=\"\"> Is that alright for you?</span></p>\n<p data-path-to-node=\"48\"><strong class=\"\" data-path-to-node=\"48\" data-index-in-node=\"0\">Professor:</strong><span class=\"\"> Yes,</span><span class=\"\"> sure.</span><span class=\"\"> And where shall I meet you?</span> I’m afraid I will be on leave at that time, but I’ll leave this record to our <strong data-path-to-node=\"48\" data-index-in-node=\"128\">(Q30) senior advisor</strong>, and you will meet with him then in this office.</p>\n<p data-path-to-node=\"49\"><strong data-path-to-node=\"49\" data-index-in-node=\"0\">Sally:</strong> OK, good.</p>\n<p data-path-to-node=\"50\"><strong data-path-to-node=\"50\" data-index-in-node=\"0\">Professor:</strong> That’s it. Let’s see whether things can improve, Sally. OK?</p>\n<p data-path-to-node=\"51\"><strong data-path-to-node=\"51\" data-index-in-node=\"0\">Sally:</strong> Thanks very much. My pleasure, bye.</p>"}]', 0);
INSERT INTO public.questions VALUES ('d0ca429b-cee7-4a6f-b087-34a284b856a7', 'a9ae40e8-ea16-461f-b107-21307b1f3c03', 'fillup', 'Questions 15 – 20', '<p>Complete the sentences below.</p>
<p>Choose <strong>NO MORE THAN TWO WORDS</strong> from the text for each answer.</p>
<p>Write your answers in boxes 15-20 on your answer sheet.</p>
<p><br>Antenatal care may involve attending {parenting classes } as well as medical appointments.</p>
<p> Maternity benefits begin {automatically} if a woman is off work with an illness connected to her pregnancy, shortly before the birth of the baby.</p>
<p> A woman whose job is in a {factory} must take 4 weeks’ maternity leave.</p>
<p> It is the employer’s responsibility to assess {risks} to a pregnant woman at work.</p>
<p> A pregnant woman is entitled to time off with {full pay} when her employer is unable to eliminate workplace dangers.</p>
<p> Where there is a dispute with the employer concerning risks, a pregnant employee should talk to a {union representative} in the first instance.</p>', '', 'summary_completion', 'null', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"3\"><strong data-path-to-node=\"3\" data-index-in-node=\"0\">15. Antenatal care may involve attending {parenting classes} as well as medical appointments.</strong></p>\n<ul data-path-to-node=\"4\">\n<li>\n<p data-path-to-node=\"4,0,0\"><strong data-path-to-node=\"4,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"4,0,0\" data-index-in-node=\"11\">“‘Antenatal care’ isn’t just a visit to the doctor – it can include <strong data-path-to-node=\"4,0,0\" data-index-in-node=\"79\">parenting classes</strong> if they’ve been recommended by a midwife…”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"4,1,0\"><strong data-path-to-node=\"4,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài đọc giải thích chăm sóc tiền sản không chỉ là đi khám bác sĩ mà còn bao gồm cả các lớp học làm cha mẹ. Cụm “as well as” trong câu hỏi tương ứng với cấu trúc “isn’t just… it can include…” trong bài.</p>\n</li>\n</ul>\n<p data-path-to-node=\"5\"><strong data-path-to-node=\"5\" data-index-in-node=\"0\">16. Maternity benefits begin {automatically} if a woman is off work with an illness connected to her pregnancy, shortly before the birth of the baby.</strong></p>\n<ul data-path-to-node=\"6\">\n<li>\n<p data-path-to-node=\"6,0,0\"><strong data-path-to-node=\"6,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"6,0,0\" data-index-in-node=\"11\">“If the employee is off work for a pregnancy-related illness in the 4 weeks before the baby is due, maternity leave and Statutory Maternity Pay will start <strong data-path-to-node=\"6,0,0\" data-index-in-node=\"166\">automatically</strong>…”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"6,1,0\"><strong data-path-to-node=\"6,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “Shortly before the birth” tương ứng với khoảng thời gian “4 weeks before the baby is due”. Khi đó, các quyền lợi (benefits) sẽ bắt đầu một cách tự động.</p>\n</li>\n</ul>\n<p data-path-to-node=\"7\"><strong data-path-to-node=\"7\" data-index-in-node=\"0\">17. A woman whose job is in a {factory} must take 4 weeks’ maternity leave.</strong></p>\n<ul data-path-to-node=\"8\">\n<li>\n<p data-path-to-node=\"8,0,0\"><strong data-path-to-node=\"8,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"8,0,0\" data-index-in-node=\"11\">“…she must take 2 weeks off after the baby is born – unless her workplace is a <strong data-path-to-node=\"8,0,0\" data-index-in-node=\"92\">factory</strong>, in which case it is 4 weeks.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"8,1,0\"><strong data-path-to-node=\"8,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Thông thường chỉ cần nghỉ 2 tuần, nhưng bài đọc đưa ra một ngoại lệ duy nhất là môi trường nhà máy (factory) thì bắt buộc phải nghỉ 4 tuần.</p>\n</li>\n</ul>\n<p data-path-to-node=\"9\"><strong data-path-to-node=\"9\" data-index-in-node=\"0\">18. It is the employer’s responsibility to assess {risks} to a pregnant woman at work.</strong></p>\n<ul data-path-to-node=\"10\">\n<li>\n<p data-path-to-node=\"10,0,0\"><strong data-path-to-node=\"10,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"10,0,0\" data-index-in-node=\"11\">“When the employee tells her employer she’s pregnant, the employer should evaluate the <strong data-path-to-node=\"10,0,0\" data-index-in-node=\"98\">risks</strong> to the woman and her baby.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"10,1,0\"><strong data-path-to-node=\"10,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Từ “evaluate” (đánh giá) trong bài đồng nghĩa với từ “assess” trong câu hỏi. Trách nhiệm này thuộc về chủ lao động (employer).</p>\n</li>\n</ul>\n<p data-path-to-node=\"11\"><strong data-path-to-node=\"11\" data-index-in-node=\"0\">19. A pregnant woman is entitled to time off with {full pay} when her employer is unable to eliminate workplace dangers.</strong></p>\n<ul data-path-to-node=\"12\">\n<li>\n<p data-path-to-node=\"12,0,0\"><strong data-path-to-node=\"12,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"12,0,0\" data-index-in-node=\"11\">“If this is not possible [to eliminate risks], the employee should be given leave on <strong data-path-to-node=\"12,0,0\" data-index-in-node=\"96\">full pay</strong>.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"12,1,0\"><strong data-path-to-node=\"12,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “Unable to eliminate workplace dangers” tương ứng với “If this is not possible”. Trong trường hợp đó, người lao động được nghỉ mà vẫn hưởng nguyên lương (full pay).</p>\n</li>\n</ul>\n<p data-path-to-node=\"13\"><strong data-path-to-node=\"13\" data-index-in-node=\"0\">20. Where there is a dispute with the employer concerning risks, a pregnant employee should talk to a {union representative} in the first instance.</strong></p>\n<ul data-path-to-node=\"14\">\n<li>\n<p data-path-to-node=\"14,0,0\"><strong data-path-to-node=\"14,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"14,0,0\" data-index-in-node=\"11\">“A pregnant employee who thinks she’s at risk, but her employer disagrees, should consult her <strong data-path-to-node=\"14,0,0\" data-index-in-node=\"105\">union representative</strong>.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"14,1,0\"><strong data-path-to-node=\"14,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Một sự bất đồng ý kiến (disagree) chính là một cuộc tranh chấp (dispute). “In the first instance” (đầu tiên/trước tiên) tương ứng với việc đây là người đầu tiên cần tham khảo ý kiến (consult).</p>\n</li>\n</ul>"}]', 0);
INSERT INTO public.questions VALUES ('326c1474-b32c-44e4-a4da-1ae4187ca7a0', 'ec5eba5c-c820-4975-b4cd-340623a2ed46', 'radio', 'Questions 1-7', '', '<p>Choose <strong>TRUE</strong> – if the statement agrees with the information, <strong>FALSE</strong> – if the statement contradicts the information, <strong>NOT GIVEN</strong> – if there is no information on this</p>', 'true_false_not_given', '[{"correct": 2, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "Many of the RFDS doctors work as volunteers."}, {"correct": 1, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "RFDS dentists make trips to outback communities each month"}, {"correct": 2, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "RFDS dentists are accompanied on their journeys to remote areas by a dental nurse."}, {"correct": 0, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "RFDS dentists must provide a wide range of dental services."}, {"correct": 1, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "Rural dental patients are more informed about oral hygiene than urban patients."}, {"correct": 2, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "RFDS dentists educate patients about good eating habits."}, {"correct": 0, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "Urban Australians generally have better teeth because their water is treated."}]', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"3\"><strong data-path-to-node=\"3\" data-index-in-node=\"0\">. Many of the RFDS doctors work as volunteers. — {NOT GIVEN}</strong></p>\n<ul data-path-to-node=\"4\">\n<li>\n<p data-path-to-node=\"4,0,0\"><strong data-path-to-node=\"4,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong> “This non-profit organisation is the oldest and largest airborne health service…” (Đoạn 2)</p>\n</li>\n<li>\n<p data-path-to-node=\"4,1,0\"><strong data-path-to-node=\"4,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài đọc chỉ nói RFDS là tổ chức phi lợi nhuận (<em data-path-to-node=\"4,1,0\" data-index-in-node=\"59\">non-profit</em>), nhưng <strong data-path-to-node=\"4,1,0\" data-index-in-node=\"78\">không hề đề cập</strong> đến việc các bác sĩ ở đây làm việc tình nguyện hay được trả lương.</p>\n</li>\n</ul>\n<p data-path-to-node=\"5\"><strong data-path-to-node=\"5\" data-index-in-node=\"0\">2. RFDS dentists make trips to outback communities each month. — {FALSE}</strong></p>\n<ul data-path-to-node=\"6\">\n<li>\n<p data-path-to-node=\"6,0,0\"><strong data-path-to-node=\"6,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong> “RFDS dentists might only visit a community <strong data-path-to-node=\"6,0,0\" data-index-in-node=\"55\">once every few months, or sometimes once per year</strong>.” (Đoạn 4)</p>\n</li>\n<li>\n<p data-path-to-node=\"6,1,0\"><strong data-path-to-node=\"6,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài đọc nói họ có thể chỉ đến vài tháng một lần hoặc mỗi năm một lần, không phải là tháng nào cũng đi (<em data-path-to-node=\"6,1,0\" data-index-in-node=\"115\">each month</em>).</p>\n</li>\n</ul>\n<p data-path-to-node=\"7\"><strong data-path-to-node=\"7\" data-index-in-node=\"0\">3. RFDS dentists are accompanied on their journeys… by a dental nurse. — {NOT GIVEN}</strong></p>\n<ul data-path-to-node=\"8\">\n<li>\n<p data-path-to-node=\"8,0,0\"><strong data-path-to-node=\"8,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong> Không có thông tin trong bài.</p>\n</li>\n<li>\n<p data-path-to-node=\"8,1,0\"><strong data-path-to-node=\"8,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài đọc có nhắc đến bác sĩ, y tá và nha sĩ nói chung trong vùng, nhưng <strong data-path-to-node=\"8,1,0\" data-index-in-node=\"83\">không nói rõ</strong> liệu khi bay đi làm nhiệm vụ thì nha sĩ có y tá đi kèm hay không.</p>\n</li>\n</ul>\n<p data-path-to-node=\"9\"><strong data-path-to-node=\"9\" data-index-in-node=\"0\">4. RFDS dentists must provide a wide range of dental services. — {TRUE}</strong></p>\n<ul data-path-to-node=\"10\">\n<li>\n<p data-path-to-node=\"10,0,0\"><strong data-path-to-node=\"10,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong> “RFDS dentists need to be <strong data-path-to-node=\"10,0,0\" data-index-in-node=\"37\">‘all-rounders’</strong>. They need to be able to do <strong data-path-to-node=\"10,0,0\" data-index-in-node=\"80\">all kinds of dental procedures</strong>…” (Đoạn 6)</p>\n</li>\n<li>\n<p data-path-to-node=\"10,1,0\"><strong data-path-to-node=\"10,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “All-rounders” (người đa năng) và “all kinds of procedures” tương ứng với “a wide range of services”.</p>\n</li>\n</ul>\n<p data-path-to-node=\"11\"><strong data-path-to-node=\"11\" data-index-in-node=\"0\">5. Rural dental patients are more informed about oral hygiene than urban patients. — {FALSE}</strong></p>\n<ul data-path-to-node=\"12\">\n<li>\n<p data-path-to-node=\"12,0,0\"><strong data-path-to-node=\"12,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong> “…people living in these areas also <strong data-path-to-node=\"12,0,0\" data-index-in-node=\"49\">receive less education</strong> about good dental hygiene than their <strong data-path-to-node=\"12,0,0\" data-index-in-node=\"109\">city counterparts</strong> do.” (Đoạn 8)</p>\n</li>\n<li>\n<p data-path-to-node=\"12,1,0\"><strong data-path-to-node=\"12,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Người dân vùng sâu vùng xa nhận được ít giáo dục về vệ sinh răng miệng hơn người dân thành phố, trái ngược với ý “more informed” (hiểu biết hơn).</p>\n</li>\n</ul>\n<p data-path-to-node=\"13\"><strong data-path-to-node=\"13\" data-index-in-node=\"0\">6. RFDS dentists educate patients about good eating habits. — {NOT GIVEN}</strong></p>\n<ul data-path-to-node=\"14\">\n<li>\n<p data-path-to-node=\"14,0,0\"><strong data-path-to-node=\"14,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong> “…educate their patients on good oral hygiene, such as <strong data-path-to-node=\"14,0,0\" data-index-in-node=\"68\">tooth brushing and flossing</strong>.” (Đoạn 9)</p>\n</li>\n<li>\n<p data-path-to-node=\"14,1,0\"><strong data-path-to-node=\"14,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài đọc có nói về giáo dục vệ sinh răng miệng (đánh răng, dùng chỉ nha khoa), nhưng <strong data-path-to-node=\"14,1,0\" data-index-in-node=\"96\">không nhắc đến</strong> việc giáo dục về thói quen ăn uống (<em data-path-to-node=\"14,1,0\" data-index-in-node=\"147\">eating habits</em>).</p>\n</li>\n</ul>\n<p data-path-to-node=\"15\"><strong data-path-to-node=\"15\" data-index-in-node=\"0\">7. Urban Australians generally have better teeth because their water is treated. — {TRUE}</strong></p>\n<ul data-path-to-node=\"16\">\n<li>\n<p data-path-to-node=\"16,0,0\"><strong data-path-to-node=\"16,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong> “City dwellers in Australia use water supplies that have been <strong data-path-to-node=\"16,0,0\" data-index-in-node=\"73\">fluoridated</strong>, and their <strong data-path-to-node=\"16,0,0\" data-index-in-node=\"96\">rates of tooth decay are lower</strong> because of this.” (Đoạn 10)</p>\n</li>\n<li>\n<p data-path-to-node=\"16,1,0\"><strong data-path-to-node=\"16,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “Treated” ở đây là việc thêm Fluoride vào nước. Việc tỉ lệ sâu răng thấp hơn đồng nghĩa với việc họ có răng tốt hơn.</p>\n</li>\n</ul>"}]', 0);
INSERT INTO public.questions VALUES ('069dae53-8f03-45c8-8ad1-4950483546d7', 'ada91f17-376e-44a9-807d-945801ca29c5', 'fillup', 'Questions 31–40', '<p>Complete the notes below.<br data-start="104" data-end="107">Write <strong>ONE WORD ONLY</strong> for each answer.</p>
<h3 style="text-align: center;" data-start="154" data-end="211"><strong data-start="154" data-end="211">Research in the area around the Chembe Bird Sanctuary</strong></h3>
<p data-start="66" data-end="130"><strong data-start="70" data-end="130">The importance of birds of prey to the local communities</strong></p>
<p data-start="132" data-end="368">They destroy <strong data-start="145" data-end="151">{rats} </strong> and other rodents.<br data-start="170" data-end="173">They help to prevent farmers from being bitten by <strong data-start="223" data-end="229">{snakes } </strong>.<br data-start="230" data-end="233">They have been an important part of the local culture for many years.<br data-start="302" data-end="305">They now support the economy by encouraging <strong data-start="349" data-end="355">{tourism } </strong> in the area.</p>
<p data-start="375" data-end="415"><strong data-start="379" data-end="415">Falling numbers of birds of prey</strong></p>
<p data-start="417" data-end="455">The birds may be accidentally killed</p>
<ul data-start="456" data-end="660">
<li data-start="456" data-end="503">
<p data-start="458" data-end="503">by <strong data-start="461" data-end="467">{traffic} </strong> when they are hunting or sleeping</p>
</li>
<li data-start="504" data-end="660">
<p data-start="506" data-end="660">by electrocution from contact with power lines, especially at times when there is a lot of <strong data-start="597" data-end="603">{rain} </strong><br data-start="603" data-end="606">Local farmers may illegally shoot them or <strong data-start="648" data-end="654">{poison} </strong> them.</p>
</li>
</ul>
<p data-start="667" data-end="721"><strong data-start="671" data-end="721">Ways of protecting chickens from birds of prey</strong></p>
<p data-start="723" data-end="852">Clearing away vegetation from the area (unhelpful)<br data-start="773" data-end="776">Providing a <strong data-start="788" data-end="794">{building} </strong> for chickens (expensive)<br data-start="819" data-end="822">Frightening birds of prey by</p>
<ul data-start="853" data-end="965">
<li data-start="853" data-end="873">
<p data-start="855" data-end="873">keeping a <strong data-start="865" data-end="871">{dog}</strong><strong data-start="865" data-end="871"> </strong></p>
</li>
<li data-start="874" data-end="965">
<p data-start="876" data-end="965">making a <strong data-start="885" data-end="891">{noise} </strong>, e.g. with metal objects<br data-start="916" data-end="919">A {combination } of methods is usually most effective.</p>
</li>
</ul>
', NULL, 'gap_filling', NULL, NULL, '{"layoutType": ["standard"], "summaryText": null, "answerOptions": null, "matchingItems": null}', '{"layoutType": ["standard"], "legendTitle": null, "matrixItems": null, "matrixCategories": null}', '[{"content": "<p>SPEAKER: We&#8217;ve been looking at different types of conflicts that may arise between wildlife and humans at the boundaries of protected areas, such as national parks and animal sanctuaries.</p>\n<p>I&#8217;d like to illustrate this by telling you about some research that I&#8217;ve been involved in recently in the Central African country of Zambia, in the area around the Chembe Bird Sanctuary, which contains over 300 of the listed birds of Zambia.</p>\n<p>These include a number of birds of prey, such as eagles, hawks and owls, that live by hunting and killing other birds and animals. </p>\n<p>Now, most of the people living in the local communities near to the bird sanctuary are small-scale farmers, and these birds of prey provide important social and ecological benefits to them. </p>\n<p>For example, a lot of damage can be caused to farmers&#8217; crops by rodents, such as rats, which would consume the crops as they grow in the fields, as well as after harvesting if they weren&#8217;t hunted and killed by the birds. (Question 31)</p>\n<p>And the predatory habits of these birds also protect farmers in other ways. For example, a major danger to rural workers is snakes, whose bite may be dangerous or even fatal, and birds of prey have a major role in keeping their populations under control. (Question 32)</p>\n<p>Local people have always been aware of these benefits, and for years, even before the sanctuary was opened in 1973, the birds played a key role in the culture of the region. (Question 33)</p>\n<p>However, more recently, the sanctuary and its birds have also become increasingly important to the community in economic terms, because at present, after a relatively slow start, tourism has become an important source of revenue for them. (Question 34)</p>\n<p>Mối đe dọa đối với Chim Săn Mồi (Questions 35–38)</p>\n<p>However, although these birds of prey are protected by the government, their numbers are falling. Some of these deaths are accidental.</p>\n<p>Fatalities occur when birds alight on roads to catch and eat their prey, and are hit by fast-moving traffic. (Question 35) Drivers in Zambia have to take special care at night, as birds may regard the quieter roads as safe places to sleep.</p>\n<p>Accidental deaths may also occur if these birds fly close to high-voltage power lines, as they may be electrocuted. (Question 36) This is a particular danger in the heavy rain, which can occur in the region in the months from December to April.</p>\n<p>And local farmers also pose a threat to these birds. As well as growing crops, small-scale farmers in the area also rear chickens. These provide food for the farmers&#8217; families, as well as being an important source of income. But they&#8217;re also an easy target for birds of prey, and so farmers may shoot these birds, which is illegal but understandable. (Question 37) Or they may poison the birds, which again is illegal and can have negative effects on the ecosystem. (Question 38)</p>\n<p>Các Phương pháp Bảo vệ Gà (Questions 39–40)</p>\n<p>So how else can farmers protect their chickens from birds of prey? Some people believe that to prevent the predators from settling near the area where the chickens are kept, it&#8217;s best to keep this area free from vegetation. But in fact, this is counterproductive, as it means the chickens have no cover to hide in, and they&#8217;ll be easier for the birds to see. (Question 39)</p>\n<p>Another possibility would be to prevent the chickens from going outside at all, and to keep them safe from predators inside a building. But this would cost far too much to be a practical solution.</p>\n<p>Nearly all the farmers reported that they spent a lot of time and effort trying to frighten off the birds of prey without actually harming them. Most of the farmers had at least one dog, and said this was a big help at scaring away the predators. </p>\n<p>Some of the farmers also reported that during the breeding season, when the chickens were particularly vulnerable, they encouraged their children to watch over the chickens and to hit pans with a metal spoon, so that the resulting noise would succeed in driving away birds that were trying to seize the young chicks.</p>\n<p>None of these methods was 100% effective, so as a result the village people told us that rather than just using one method, they were forced to use a combination for them to have any effect. (Question 40) And even so, these birds of prey remain a major threat to the chickens&#8217; survival, and cause considerable economic loss to farmers.</p>\n<p>So, we looked at the possibility of a longer term solution.</p>\n"}, {"content": "<p>1</p>\n"}, {"content": "<p>1</p>\n"}, {"content": "<p>1</p>\n"}, {"content": "<p>1</p>\n"}, {"content": "<p>1</p>\n"}, {"content": "<p>1</p>\n"}, {"content": "<p>1</p>\n"}, {"content": "<p>1</p>\n"}, {"content": "<p>1</p>\n"}]', 0);
INSERT INTO public.questions VALUES ('6b296124-18ff-4e00-a7ce-3e2325a2269b', '94007714-bf06-44e6-ac1d-fcd4de86da29', 'matrix', 'Questions 14–18', '', '<p><span class="fontstyle0">Write the correct letter, </span><strong><span class="fontstyle2">A–G</span></strong><span class="fontstyle0">, in boxes 14–18 on your answer sheet.</span></p>
<p><strong><span class="fontstyle2">NB </span></strong><span class="fontstyle0">You may use any letter more than once</span> </p>', 'choose_a_title', 'null', 'null', 'null', '{"layoutType": "simple", "matrixItems": [{"itemText": "a comparison of children’s reactions towards different robots", "correctCategoryLetter": "D"}, {"itemText": "a speculation about ways robots may be able to communicate", "correctCategoryLetter": "F"}, {"itemText": "a description of changes in the way the children physically handled a robot", "correctCategoryLetter": "D"}, {"itemText": "a comparison between people’s connections with animals and their connections with robots", "correctCategoryLetter": "A"}, {"itemText": "an account of the way one robot was programmed", "correctCategoryLetter": "C"}], "matrixCategories": [{"categoryText": "A", "categoryLetter": "A"}, {"categoryText": "B", "categoryLetter": "B"}, {"categoryText": "C", "categoryLetter": "C"}, {"categoryText": "D", "categoryLetter": "D"}, {"categoryText": "E", "categoryLetter": "E"}, {"categoryText": "F", "categoryLetter": "F"}, {"categoryText": "G", "categoryLetter": "G"}]}', '[{"content": "<p data-path-to-node=\"4\"><strong data-path-to-node=\"4\" data-index-in-node=\"0\">14. D — {a comparison of children’s reactions towards different robots}</strong></p>\n<ul data-path-to-node=\"5\">\n<li>\n<p data-path-to-node=\"5,0,0\"><strong data-path-to-node=\"5,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"5,0,0\" data-index-in-node=\"11\">“Another <strong data-path-to-node=\"5,0,0\" data-index-in-node=\"20\">robot-like toy named Robby</strong>, which resembled QRIO but did not move, <strong data-path-to-node=\"5,0,0\" data-index-in-node=\"87\">was used as a control</strong> in the study. <strong data-path-to-node=\"5,0,0\" data-index-in-node=\"123\">While hugging of QRIO increased, hugging of Robby decreased</strong> throughout the study. Furthermore, when QRIO laid down on the floor, caretaking behaviors were frequently observed <strong data-path-to-node=\"5,0,0\" data-index-in-node=\"298\">toward QRIO but seldom toward Robby</strong>.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"5,1,0\"><strong data-path-to-node=\"5,1,0\" data-index-in-node=\"0\">Giải thích:</strong> \"Different robots\" ở đây là robot di động QRIO và món đồ chơi dạng robot bất động tên là Robby. Đoạn D tiến hành so sánh đối chiếu (<em data-path-to-node=\"5,1,0\" data-index-in-node=\"144\">a comparison / used as a control</em>) phản ứng của trẻ: ôm QRIO tăng lên nhưng ôm Robby lại giảm đi, hay trẻ biết chăm sóc khi QRIO ngã nhưng hiếm khi làm vậy với Robby.</p>\n</li>\n</ul>\n<p data-path-to-node=\"6\"><strong data-path-to-node=\"6\" data-index-in-node=\"0\">15. F — {a speculation about ways robots may be able to communicate}</strong></p>\n<ul data-path-to-node=\"7\">\n<li>\n<p data-path-to-node=\"7,0,0\"><strong data-path-to-node=\"7,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"7,0,0\" data-index-in-node=\"11\">“A robotic tutor could <strong data-path-to-node=\"7,0,0\" data-index-in-node=\"34\">react on the spot to social cues and approximate social skills like facial expression and eye gaze</strong>, they said.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"7,1,0\"><strong data-path-to-node=\"7,1,0\" data-index-in-node=\"0\">Giải thích:</strong> \"Ways robots may be able to communicate\" (những cách thức mà robot có thể giao tiếp) được cụ thể hóa bằng các kỹ năng xã hội (<em data-path-to-node=\"7,1,0\" data-index-in-node=\"138\">social skills</em>) như biểu cảm khuôn mặt (<em data-path-to-node=\"7,1,0\" data-index-in-node=\"177\">facial expression</em>) và ánh mắt (<em data-path-to-node=\"7,1,0\" data-index-in-node=\"208\">eye gaze</em>). Từ \"could\" mang tính chất dự đoán, suy đoán (<strong data-path-to-node=\"7,1,0\" data-index-in-node=\"264\">a speculation</strong>) về năng lực giao tiếp của các phiên bản robot tiến tiến trong tương lai.</p>\n</li>\n</ul>\n<p data-path-to-node=\"8\"><strong data-path-to-node=\"8\" data-index-in-node=\"0\">16. D — {a description of changes in the way the children physically handled a robot}</strong></p>\n<ul data-path-to-node=\"9\">\n<li>\n<p data-path-to-node=\"9,0,0\"><strong data-path-to-node=\"9,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"9,0,0\" data-index-in-node=\"11\">“The most important aspect of interaction was <strong data-path-to-node=\"9,0,0\" data-index-in-node=\"57\">touch</strong>, Tanaka said. <strong data-path-to-node=\"9,0,0\" data-index-in-node=\"77\">At first, the toddlers would touch the robot on its face, but later on they would touch it only on its hands and arms</strong>, like they would with other humans.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"9,1,0\"><strong data-path-to-node=\"9,1,0\" data-index-in-node=\"0\">Giải thích:</strong> \"Physically handled\" (giao tiếp/chạm vào bằng thể chất) tương ứng với hành động chạm (<em data-path-to-node=\"9,1,0\" data-index-in-node=\"98\">touch</em>). Đoạn văn mô tả rất rõ sự thay đổi theo thời gian (<em data-path-to-node=\"9,1,0\" data-index-in-node=\"156\">changes / At first... but later on</em>): lúc đầu trẻ sờ vào mặt robot, nhưng về sau chuyển sang chỉ chạm vào tay và cánh tay giống như cách giao tiếp giữa người với người.</p>\n</li>\n</ul>\n<p data-path-to-node=\"10\"><strong data-path-to-node=\"10\" data-index-in-node=\"0\">17. A — {a comparison between people’s connections with animals and their connections with robots}</strong></p>\n<ul data-path-to-node=\"11\">\n<li>\n<p data-path-to-node=\"11,0,0\"><strong data-path-to-node=\"11,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"11,0,0\" data-index-in-node=\"11\">“In practice, commercially available <strong data-path-to-node=\"11,0,0\" data-index-in-node=\"48\">robots seldom cross the 10-hour barrier</strong>... This observation is in <strong data-path-to-node=\"11,0,0\" data-index-in-node=\"114\">sharp contrast to the long-term interactions and bonding that commonly develop between humans and their pets</strong>.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"11,1,0\"><strong data-path-to-node=\"11,1,0\" data-index-in-node=\"0\">Giải thích:</strong> \"Connections\" (sự gắn kết/mối quan hệ) đồng nghĩa với các từ \"interactions and bonding\". Đoạn A làm một phép so sánh tương phản (<strong data-path-to-node=\"11,1,0\" data-index-in-node=\"141\">a comparison / in sharp contrast</strong>) giữa việc con người nhanh chán robot (dưới 10 tiếng) với mối quan hệ gắn kết bền chặt, lâu dài giữa con người và thú cưng/động vật nuôi (<strong data-path-to-node=\"11,1,0\" data-index-in-node=\"312\">animals / pets</strong>).</p>\n</li>\n</ul>\n<p data-path-to-node=\"12\"><strong data-path-to-node=\"12\" data-index-in-node=\"0\">18. C — {an account of the way one robot was programmed}</strong></p>\n<ul data-path-to-node=\"13\">\n<li>\n<p data-path-to-node=\"13,0,0\"><strong data-path-to-node=\"13,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"13,0,0\" data-index-in-node=\"11\">“The researchers <strong data-path-to-node=\"13,0,0\" data-index-in-node=\"28\">sent instructions to the robot about every two minutes to do things like giggle, dance, sit down, fall down, or walk</strong> in a certain direction.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"13,1,0\"><strong data-path-to-node=\"13,1,0\" data-index-in-node=\"0\">Giải thích:</strong> \"The way one robot was programmed\" (cách một con robot được lập trình/điều khiển) được thuật lại bằng việc các nhà nghiên cứu gửi các chỉ dẫn (<em data-path-to-node=\"13,1,0\" data-index-in-node=\"155\">sent instructions</em>) định kỳ mỗi 2 phút một lần để ép robot thực hiện các chuỗi hành vi cụ thể (kích động cười, nhảy múa, ngồi xuống, ngã...).</p>\n</li>\n</ul>"}]', 0);
INSERT INTO public.questions VALUES ('cd5d9c16-2df4-4c47-a713-44580af9d00f', '94007714-bf06-44e6-ac1d-fcd4de86da29', 'matrix', 'Questions 19–23', '', '<p>Write the correct letter, <strong>A-D</strong>, in boxes 19–23 on your answer sheet.</p>
<p><strong>NB </strong>You may use any letter more than once. </p>', 'choose_a_title', 'null', 'null', 'null', '{"layoutType": "standard", "legendTitle": "List of People", "matrixItems": [{"itemText": "In future, robots will not only have to think, but also to show feelings.", "correctCategoryLetter": "B"}, {"itemText": "It is uncertain whether more contact between people and robots will be beneficial.", "correctCategoryLetter": "C"}, {"itemText": "Very young children have not yet developed ideas about robots.", "correctCategoryLetter": "A"}, {"itemText": "Robots need to perform a wide variety of actions for people to relate to them.", "correctCategoryLetter": "D"}, {"itemText": "Using robots as an aid in schools may have many benefits", "correctCategoryLetter": "A"}], "matrixCategories": [{"categoryText": "Fumihide Tanaka", "categoryLetter": "A"}, {"categoryText": "Javier R. Movellan", "categoryLetter": "B"}, {"categoryText": "Ronald Arkin", "categoryLetter": "C"}, {"categoryText": "David Powers", "categoryLetter": "D"}]}', '[{"content": "<p data-path-to-node=\"4\"><strong data-path-to-node=\"4\" data-index-in-node=\"0\">19. B (Movellan) — {In future, robots will not only have to think, but also to show feelings.}</strong></p>\n<ul data-path-to-node=\"5\">\n<li>\n<p data-path-to-node=\"5,0,0\"><strong data-path-to-node=\"5,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn F):</strong> <em data-path-to-node=\"5,0,0\" data-index-in-node=\"20\">“‘It is becoming clear that, to achieve this goal, we are going to <strong data-path-to-node=\"5,0,0\" data-index-in-node=\"87\">endow machines with something similar to emotion, not just traditional forms of intelligence</strong>,’ said <strong data-path-to-node=\"5,0,0\" data-index-in-node=\"187\">Movellan</strong>.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"5,1,0\"><strong data-path-to-node=\"5,1,0\" data-index-in-node=\"0\">Giải thích:</strong> \"In future\" tương ứng với mục đích đạt được mục tiêu trong tương lai (<em data-path-to-node=\"5,1,0\" data-index-in-node=\"82\">to achieve this goal</em>). \"Think\" tương ứng với trí thông minh truyền thống (<em data-path-to-node=\"5,1,0\" data-index-in-node=\"156\">traditional forms of intelligence</em>), và \"show feelings\" (thể hiện cảm xúc) đồng nghĩa với việc ban cho máy móc thứ gì đó tương tự như cảm xúc (<strong data-path-to-node=\"5,1,0\" data-index-in-node=\"298\">something similar to emotion</strong>). Người phát biểu luận điểm này là <strong data-path-to-node=\"5,1,0\" data-index-in-node=\"362\">Movellan</strong>.</p>\n</li>\n</ul>\n<p data-path-to-node=\"6\"><strong data-path-to-node=\"6\" data-index-in-node=\"0\">20. C (Arkin) — {It is uncertain whether more contact between people and robots will be beneficial.}</strong></p>\n<ul data-path-to-node=\"7\">\n<li>\n<p data-path-to-node=\"7,0,0\"><strong data-path-to-node=\"7,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn G):</strong> <em data-path-to-node=\"7,0,0\" data-index-in-node=\"20\">“But he [<strong data-path-to-node=\"7,0,0\" data-index-in-node=\"29\">Arkin</strong>] also <strong data-path-to-node=\"7,0,0\" data-index-in-node=\"41\">cautioned that researchers do not yet understand the consequences of increased human/robot interaction</strong>. ‘Studying how robots and humans work together can give us <strong data-path-to-node=\"7,0,0\" data-index-in-node=\"203\">insight into whether this is a good thing or a bad thing for society</strong>,’ Arkin said.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"7,1,0\"><strong data-path-to-node=\"7,1,0\" data-index-in-node=\"0\">Giải thích:</strong> \"More contact\" (tiếp xúc nhiều hơn) đồng nghĩa với \"increased interaction\". Cụm từ \"uncertain whether... will be beneficial\" (không chắc chắn liệu có lợi ích hay không) tương ứng hoàn toàn với lời cảnh báo chưa hiểu rõ hậu quả (<em data-path-to-node=\"7,1,0\" data-index-in-node=\"240\">do not yet understand the consequences</em>) và cần nghiên cứu xem đó là điều tốt hay điều xấu cho xã hội (<em data-path-to-node=\"7,1,0\" data-index-in-node=\"342\">whether this is a good thing or a bad thing</em>). Người phát biểu là <strong data-path-to-node=\"7,1,0\" data-index-in-node=\"407\">Arkin</strong>.</p>\n</li>\n</ul>\n<p data-path-to-node=\"8\"><strong data-path-to-node=\"8\" data-index-in-node=\"0\">21. A (Tanaka) — {Very young children have not yet developed ideas about robots.}</strong></p>\n<ul data-path-to-node=\"9\">\n<li>\n<p data-path-to-node=\"9,0,0\"><strong data-path-to-node=\"9,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn B):</strong> <em data-path-to-node=\"9,0,0\" data-index-in-node=\"20\">“‘<strong data-path-to-node=\"9,0,0\" data-index-in-node=\"22\">Children of toddler age</strong> were chosen because they <strong data-path-to-node=\"9,0,0\" data-index-in-node=\"71\">have no preconceived notions of robots</strong>,’ according to <strong data-path-to-node=\"9,0,0\" data-index-in-node=\"125\">Tanaka</strong>.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"9,1,0\"><strong data-path-to-node=\"9,1,0\" data-index-in-node=\"0\">Giải thích:</strong> \"Very young children\" (trẻ em còn rất nhỏ) tương ứng với trẻ ở độ tuổi biết đi (<em data-path-to-node=\"9,1,0\" data-index-in-node=\"92\">children of toddler age</em> - từ 18 đến 24 tháng tuổi). Cụm từ \"have not yet developed ideas\" (chưa hình thành/phát triển các ý niệm) đồng nghĩa với việc không có các quan niệm định kiến từ trước (<strong data-path-to-node=\"9,1,0\" data-index-in-node=\"285\">have no preconceived notions</strong>). Người đưa ra nhận định này là <strong data-path-to-node=\"9,1,0\" data-index-in-node=\"346\">Tanaka</strong>.</p>\n</li>\n</ul>\n<p data-path-to-node=\"10\"><strong data-path-to-node=\"10\" data-index-in-node=\"0\">22. D (Powers) — {Robots need to perform a wide variety of actions for people to relate to them.}</strong></p>\n<ul data-path-to-node=\"11\">\n<li>\n<p data-path-to-node=\"11,0,0\"><strong data-path-to-node=\"11,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn G):</strong> <em data-path-to-node=\"11,0,0\" data-index-in-node=\"20\">“Associate Professor <strong data-path-to-node=\"11,0,0\" data-index-in-node=\"41\">David Powers</strong>... commented, ‘In this study, it is clearly demonstrated that a limited range of robot behaviors... is <strong data-path-to-node=\"11,0,0\" data-index-in-node=\"157\">nowhere near as important to human/robot interaction as being able to make appropriate responses from a broad repertoire of behaviors</strong>.’”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"11,1,0\"><strong data-path-to-node=\"11,1,0\" data-index-in-node=\"0\">Giải thích:</strong> \"Relate to them / human/robot interaction\" (sự tương tác/gắn kết giữa người và robot). Để đạt được điều này, robot cần thực hiện được một danh mục hành vi rộng lớn/đa dạng (<strong data-path-to-node=\"11,1,0\" data-index-in-node=\"185\">a broad repertoire of behaviors</strong>), điều này đồng nghĩa với cụm từ <strong data-path-to-node=\"11,1,0\" data-index-in-node=\"250\">\"a wide variety of actions\"</strong> trong câu hỏi. Người phát biểu là <strong data-path-to-node=\"11,1,0\" data-index-in-node=\"312\">Powers</strong>.</p>\n</li>\n</ul>\n<p data-path-to-node=\"12\"><strong data-path-to-node=\"12\" data-index-in-node=\"0\">23. A (Tanaka) — {Using robots as an aid in schools may have many benefits.}</strong></p>\n<ul data-path-to-node=\"13\">\n<li>\n<p data-path-to-node=\"13,0,0\"><strong data-path-to-node=\"13,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn F):</strong> <em data-path-to-node=\"13,0,0\" data-index-in-node=\"20\">“‘It <strong data-path-to-node=\"13,0,0\" data-index-in-node=\"25\">could have great potential in educational settings, assisting teachers and enriching the classroom environment</strong>,’ <strong data-path-to-node=\"13,0,0\" data-index-in-node=\"138\">Tanaka</strong> said.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"13,1,0\"><strong data-path-to-node=\"13,1,0\" data-index-in-node=\"0\">Giải thích:</strong> \"Using robots as an aid in schools\" (sử dụng robot như một công cụ hỗ trợ ở trường học) tương ứng với cụm \"educational settings, assisting teachers\" (môi trường giáo dục, hỗ trợ giáo viên). \"May have many benefits\" (có thể có nhiều lợi ích) đồng nghĩa với việc có tiềm năng to lớn (<strong data-path-to-node=\"13,1,0\" data-index-in-node=\"294\">could have great potential</strong>). Người phát biểu là <strong data-path-to-node=\"13,1,0\" data-index-in-node=\"342\">Tanaka</strong> (đáp án A được dùng lại 2 lần).</p>\n</li>\n</ul>"}]', 1);
INSERT INTO public.questions VALUES ('05575d7d-5d01-40d2-8b35-1124bd3c9fbe', '94007714-bf06-44e6-ac1d-fcd4de86da29', 'fillup', 'Questions 24–26', '<p><span class="fontstyle0">Complete the sentences below.</span></p>
<p><span class="fontstyle0">Choose </span><span class="fontstyle2"><strong>ONE WORD ONLY</strong> </span><span class="fontstyle0">from the passage for each answer.</span></p>
<p><span class="fontstyle0">Write your answers in boxes 24–26 on your answer sheet.</span></p>
<ul>
<li>
<p><span class="fontstyle4">Until recently, robots that were best at holding people’s attention were those that acted<br>as {storytellers} .</span></p>
</li>
<li>
<p><span class="fontstyle4">The children responded to the QRIO robot as a friend or a {peer} rather than as a<br>toy.</span></p>
</li>
<li>
<p><span class="fontstyle4">Arkin expected that the children would show {affection} towards the QRIO robot.</span> </p>
</li>
</ul>', NULL, 'summary_completion', 'null', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"3\"><strong data-path-to-node=\"3\" data-index-in-node=\"0\">24. storytellers — {Until recently, robots that were best at holding people’s attention were those that acted as storytellers.}</strong></p>\n<ul data-path-to-node=\"4\">\n<li>\n<p data-path-to-node=\"4,0,0\"><strong data-path-to-node=\"4,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn A):</strong> <em data-path-to-node=\"4,0,0\" data-index-in-node=\"20\">“The <strong data-path-to-node=\"4,0,0\" data-index-in-node=\"25\">most successful robots so far have been storytellers</strong>, but they have only been able to <strong data-path-to-node=\"4,0,0\" data-index-in-node=\"111\">maintain human interest for a limited time</strong>...”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"4,1,0\"><strong data-path-to-node=\"4,1,0\" data-index-in-node=\"0\">Giải thích:</strong> \"Until recently / so far\" (cho đến gần đây/từ trước đến nay). Cụm từ \"best at holding people’s attention\" (tốt nhất trong việc giữ sự chú ý của con người) đồng nghĩa với cụm \"most successful... to maintain human interest\" (thành công nhất để duy trì sự hứng thú của con người). Những robot làm tốt việc này nhất chính là những robot kể chuyện (<strong data-path-to-node=\"4,1,0\" data-index-in-node=\"356\">storytellers</strong>).</p>\n</li>\n</ul>\n<p data-path-to-node=\"5\"><strong data-path-to-node=\"5\" data-index-in-node=\"0\">25. peer — {The children responded to the QRIO robot as a friend or a peer rather than as a toy.}</strong></p>\n<ul data-path-to-node=\"6\">\n<li>\n<p data-path-to-node=\"6,0,0\"><strong data-path-to-node=\"6,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn E):</strong> <em data-path-to-node=\"6,0,0\" data-index-in-node=\"20\">“Overall, the interaction between children and the robot improved over time and <strong data-path-to-node=\"6,0,0\" data-index-in-node=\"100\">the children progressively treated it more as a peer than a plaything</strong>.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"6,1,0\"><strong data-path-to-node=\"6,1,0\" data-index-in-node=\"0\">Giải thích:</strong> \"Responded to... rather than as a toy\" (phản hồi/đối xử như là... hơn là một món đồ chơi) tương ứng hoàn toàn với cụm \"treated it more as a... than a plaything\". Từ đồng nghĩa với \"friend\" (bạn bè) cần điền vào khoảng trống ở đây là bạn đồng lứa (<strong data-path-to-node=\"6,1,0\" data-index-in-node=\"259\">peer</strong>).</p>\n</li>\n</ul>\n<p data-path-to-node=\"7\"><strong data-path-to-node=\"7\" data-index-in-node=\"0\">26. affection — {Arkin expected that the children would show affection towards the QRIO robot.}</strong></p>\n<ul data-path-to-node=\"8\">\n<li>\n<p data-path-to-node=\"8,0,0\"><strong data-path-to-node=\"8,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn G):</strong> <em data-path-to-node=\"8,0,0\" data-index-in-node=\"20\">“<strong data-path-to-node=\"8,0,0\" data-index-in-node=\"21\">Ronald Arkin was not surprised by the affection demonstrated by the toddlers toward the robot</strong>.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"8,1,0\"><strong data-path-to-node=\"8,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Việc ông Arkin \"không cảm thấy ngạc nhiên\" (<em data-path-to-node=\"8,1,0\" data-index-in-node=\"56\">was not surprised</em>) trước một hành động nào đó đồng nghĩa với việc ông ấy đã lường trước/kỳ vọng điều đó sẽ xảy ra (<strong data-path-to-node=\"8,1,0\" data-index-in-node=\"171\">expected</strong>). Thứ mà ông ấy đã dự đoán trước được chính là tình cảm/sự yêu mến (<strong data-path-to-node=\"8,1,0\" data-index-in-node=\"248\">affection</strong>) mà những đứa trẻ dành cho robot.</p>\n</li>\n</ul>"}]', 2);
INSERT INTO public.questions VALUES ('4aa46573-123b-4b57-96c6-d6f41fdafcfc', '7e1877f2-1970-4021-a964-a176ae473713', 'matrix', 'Questions 1–5', '', '<p id="p-rc_821c9e86eacb317b-432" data-path-to-node="5"><span class="citation-23547 citation-23548">Write the correct letter, </span><strong><span class="citation-23547 citation-23548">A–F</span></strong><span class="citation-23547 citation-23548 citation-end-23548">, in boxes 1–5 on your answer sheet.</span></p>
<p id="p-rc_821c9e86eacb317b-433" data-path-to-node="6"><strong><span class="citation-23545 citation-23546">NB</span></strong> <span class="citation-23545 citation-23546 citation-end-23546">You may use any letter more than once.</span></p>', 'choose_a_title', 'null', 'null', 'null', '{"layoutType": "simple", "matrixItems": [{"itemText": "Cup sizes are more generous than you might expect.", "correctCategoryLetter": "C"}, {"itemText": "Recent changes are likely to have a negative impact.", "correctCategoryLetter": "E"}, {"itemText": "It needs better signage for customers.", "correctCategoryLetter": "F"}, {"itemText": "It has a strong local customer base.", "correctCategoryLetter": "C"}, {"itemText": "It deserves the public praise it has received.", "correctCategoryLetter": "B"}], "matrixCategories": [{"categoryText": "A", "categoryLetter": "A"}, {"categoryText": "B", "categoryLetter": "B"}, {"categoryText": "C", "categoryLetter": "C"}, {"categoryText": "D", "categoryLetter": "D"}, {"categoryText": "E", "categoryLetter": "E"}, {"categoryText": "F", "categoryLetter": "F"}]}', '[{"content": "<p data-path-to-node=\"3\"><strong data-path-to-node=\"3\" data-index-in-node=\"0\">1. Cup sizes are more generous than you might expect. — {C: Billy Ding’s Café}</strong></p>\n<ul data-path-to-node=\"4\">\n<li>\n<p data-path-to-node=\"4,0,0\"><strong data-path-to-node=\"4,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong> “…washed down with the <strong data-path-to-node=\"4,0,0\" data-index-in-node=\"36\">biggest ‘small’ coffee we’ve ever had!</strong>“</p>\n</li>\n<li>\n<p data-path-to-node=\"4,1,0\"><strong data-path-to-node=\"4,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “More generous” (lớn hơn/hào phóng hơn) tương ứng với việc họ gọi một ly cỡ “nhỏ” nhưng thực tế nó lại là ly cà phê lớn nhất mà họ từng thấy.</p>\n</li>\n</ul>\n<p data-path-to-node=\"5\"><strong data-path-to-node=\"5\" data-index-in-node=\"0\">2. Recent changes are likely to have a negative impact. — {E: Chocolotta’s}</strong></p>\n<ul data-path-to-node=\"6\">\n<li>\n<p data-path-to-node=\"6,0,0\"><strong data-path-to-node=\"6,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong> “The last few times, however, we’ve noticed that the rolls have less filling and the coffee tastes watery. …this will only lead to <strong data-path-to-node=\"6,0,0\" data-index-in-node=\"144\">customers going elsewhere</strong>.”</p>\n</li>\n<li>\n<p data-path-to-node=\"6,1,0\"><strong data-path-to-node=\"6,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “Recent changes” là việc giảm nhân bánh và cà phê loãng đi. “Negative impact” (tác động tiêu cực) chính là việc khách hàng sẽ bỏ đi nơi khác.</p>\n</li>\n</ul>\n<p data-path-to-node=\"7\"><strong data-path-to-node=\"7\" data-index-in-node=\"0\">3. It needs better signage for customers. — {F: Café Soloist}</strong></p>\n<ul data-path-to-node=\"8\">\n<li>\n<p data-path-to-node=\"8,0,0\"><strong data-path-to-node=\"8,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong> “There was <strong data-path-to-node=\"8,0,0\" data-index-in-node=\"22\">nothing outside to indicate that it was there</strong>, which would have been <strong data-path-to-node=\"8,0,0\" data-index-in-node=\"91\">helpful!</strong>“</p>\n</li>\n<li>\n<p data-path-to-node=\"8,1,0\"><strong data-path-to-node=\"8,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “Signage” (biển hiệu/chỉ dẫn) là thứ quán này đang thiếu vì bên ngoài không có gì cho thấy quán nằm ở đó, khiến khách khó tìm.</p>\n</li>\n</ul>\n<p data-path-to-node=\"9\"><strong data-path-to-node=\"9\" data-index-in-node=\"0\">4. It has a strong local customer base. — {C: Billy Ding’s Café}</strong></p>\n<ul data-path-to-node=\"10\">\n<li>\n<p data-path-to-node=\"10,0,0\"><strong data-path-to-node=\"10,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong> “…it quickly became clear to us that this is a place that <strong data-path-to-node=\"10,0,0\" data-index-in-node=\"71\">residents in the area use regularly</strong>.”</p>\n</li>\n<li>\n<p data-path-to-node=\"10,1,0\"><strong data-path-to-node=\"10,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “Local customer base” (lượng khách địa phương) được thể hiện qua việc cư dân vùng này (residents) sử dụng quán thường xuyên.</p>\n</li>\n</ul>\n<p data-path-to-node=\"11\"><strong data-path-to-node=\"11\" data-index-in-node=\"0\">5. It deserves the public praise it has received. — {B: Cafélingo}</strong></p>\n<ul data-path-to-node=\"12\">\n<li>\n<p data-path-to-node=\"12,0,0\"><strong data-path-to-node=\"12,0,0\" data-index-in-node=\"0\">Trích dẫn:</strong> “<strong data-path-to-node=\"12,0,0\" data-index-in-node=\"12\">Local media are right</strong> in saying that this café makes the <strong data-path-to-node=\"12,0,0\" data-index-in-node=\"69\">best cup of coffee in town</strong>…”</p>\n</li>\n<li>\n<p data-path-to-node=\"12,1,0\"><strong data-path-to-node=\"12,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “Public praise” là lời khen từ truyền thông địa phương (local media). Người viết khẳng định họ nói đúng, tức là quán xứng đáng với lời khen đó.</p>\n</li>\n</ul>"}]', 0);
INSERT INTO public.questions VALUES ('d7a44752-6dee-4bed-98e6-aa8c1dafdd38', '557154f0-bc0c-42d2-adfc-d6753e8dd64f', 'radio', 'Questions 1–7', '', '<p data-path-to-node="5,0,0">Choose<strong data-path-to-node="5,0,0" data-index-in-node="0"> TRUE</strong> if the statement agrees with the information.<strong data-path-to-node="5,1,0" data-index-in-node="0">FALS<span class="citation-4444 citation-4445 citation-4446 citation-4447 citation-4448 citation-4449 citation-4450">E</span></strong><span class="citation-4444 citation-4445 citation-4446 citation-4447 citation-4448 citation-4449 citation-4450 citation-end-4450"> if the statement contradicts the information,</span><strong data-path-to-node="5,2,0" data-index-in-node="0"><span class="citation-4437 citation-4438 citation-4439 citation-4440 citation-4441 citation-4442 citation-4443">NOT GIVEN</span></strong><span class="citation-4437 citation-4438 citation-4439 citation-4440 citation-4441 citation-4442 citation-4443 citation-end-4443"> if there is no information on this</span></p>
<p id="p-rc_7a928e36d3c9eadf-63" data-path-to-node="5,1,0"><span class="citation-4437 citation-end-4437"><sup class="superscript" data-turn-source-index="14"><!----></sup></span></p>
<div class="source-inline-chip-container ng-star-inserted"><!----><!----></div>
<!----><!----><!----><!----><!----><!----><!----><!---->
<p> </p>', 'true_false_not_given', '[{"correct": 1, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "People had expected Andy Murray to become the world’s top tennis player for at least five years before 2016."}, {"correct": 1, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "The change that Andy Murray made to his rackets attracted a lot of attention."}, {"correct": 2, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "Most of the world’s top players take a professional racket stringer on tour with them."}, {"correct": 1, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "Mike and Bob Bryan use rackets that are light in comparison to the majority of rackets."}, {"correct": 2, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "Werner Fischer played with a spaghetti-strung racket that he designed himself."}, {"correct": 0, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "The weather can affect how professional players adjust the strings on their rackets."}, {"correct": 0, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "It was believed that the change Pete Sampras made to his rackets contributed to his strong serve."}]', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"4\"><strong data-path-to-node=\"4\" data-index-in-node=\"0\">1. People had expected Andy Murray to become the world’s top tennis player for at least five years before 2016. — {FALSE}</strong></p>\n<ul data-path-to-node=\"5\">\n<li>\n<p data-path-to-node=\"5,0,0\"><strong data-path-to-node=\"5,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 1):</strong> <em data-path-to-node=\"5,0,0\" data-index-in-node=\"20\">\"Yet five years previously, he had been regarded as a <strong data-path-to-node=\"5,0,0\" data-index-in-node=\"74\">talented outsider who entered but never won</strong> the major tournaments.\"</em></p>\n</li>\n<li>\n<p data-path-to-node=\"5,1,0\"><strong data-path-to-node=\"5,1,0\" data-index-in-node=\"0\">Giải thích:</strong> 5 năm trước khi lên số 1 (tức năm 2011), Murray chỉ được coi là một \"kẻ ngoài cuộc tài năng\" nhưng chưa bao giờ thắng giải lớn. Điều này trái ngược hoàn toàn với việc mọi người \"kỳ vọng\" ông trở thành tay vợt hàng đầu thế giới từ lúc đó.</p>\n</li>\n</ul>\n<p data-path-to-node=\"6\"><strong data-path-to-node=\"6\" data-index-in-node=\"0\">2. The change that Andy Murray made to his rackets attracted a lot of attention. — {FALSE}</strong></p>\n<ul data-path-to-node=\"7\">\n<li>\n<p data-path-to-node=\"7,0,0\"><strong data-path-to-node=\"7,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 2):</strong> <em data-path-to-node=\"7,0,0\" data-index-in-node=\"20\">\"Another change was <strong data-path-to-node=\"7,0,0\" data-index-in-node=\"40\">so subtle as to pass more or less unnoticed</strong>... in 2012 he switched to a synthetic string for the mains.\"</em></p>\n</li>\n<li>\n<p data-path-to-node=\"7,1,0\"><strong data-path-to-node=\"7,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài đọc nói thay đổi này rất \"tinh tế\" (subtle) và \"hầu như không bị nhận ra\" (unnoticed). Câu hỏi nói nó \"thu hút nhiều sự chú ý\" (attracted a lot of attention) là sai.</p>\n</li>\n</ul>\n<p data-path-to-node=\"8\"><strong data-path-to-node=\"8\" data-index-in-node=\"0\">3. Most of the world’s top players take a professional racket stringer on tour with them. — {NOT GIVEN}</strong></p>\n<ul data-path-to-node=\"9\">\n<li>\n<p data-path-to-node=\"9,0,0\"><strong data-path-to-node=\"9,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 3):</strong> Có nhắc đến Colin Triplow là một thợ căng vợt chuyên nghiệp (professional racket stringer) tại Anh để lấy ý kiến chuyên gia.</p>\n</li>\n<li>\n<p data-path-to-node=\"9,1,0\"><strong data-path-to-node=\"9,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài đọc <strong data-path-to-node=\"9,1,0\" data-index-in-node=\"20\">không hề đề cập</strong> đến việc phần lớn các tay vợt hàng đầu có mang theo thợ căng vợt riêng khi đi thi đấu (on tour) hay không.</p>\n</li>\n</ul>\n<p data-path-to-node=\"10\"><strong data-path-to-node=\"10\" data-index-in-node=\"0\">4. Mike and Bob Bryan use rackets that are light in comparison to the majority of rackets. — {FALSE}</strong></p>\n<ul data-path-to-node=\"11\">\n<li>\n<p data-path-to-node=\"11,0,0\"><strong data-path-to-node=\"11,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 3):</strong> <em data-path-to-node=\"11,0,0\" data-index-in-node=\"20\">\"The rackets they use now <strong data-path-to-node=\"11,0,0\" data-index-in-node=\"46\">weigh more than the average model</strong>...\"</em></p>\n</li>\n<li>\n<p data-path-to-node=\"11,1,0\"><strong data-path-to-node=\"11,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Vợt của anh em nhà Bryan \"nặng hơn mức trung bình\", trái ngược với ý \"nhẹ\" (light) trong câu hỏi.</p>\n</li>\n</ul>\n<p data-path-to-node=\"12\"><strong data-path-to-node=\"12\" data-index-in-node=\"0\">5. Werner Fischer played with a spaghetti-strung racket that he designed himself. — {NOT GIVEN}</strong></p>\n<ul data-path-to-node=\"13\">\n<li>\n<p data-path-to-node=\"13,0,0\"><strong data-path-to-node=\"13,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 5):</strong> <em data-path-to-node=\"13,0,0\" data-index-in-node=\"20\">\"Racket modifications mainly date back to the 1970s, when the amateur German tennis player Werner Fischer started playing with the <strong data-path-to-node=\"13,0,0\" data-index-in-node=\"151\">so-called spaghetti-strung racket</strong>.\"</em></p>\n</li>\n<li>\n<p data-path-to-node=\"13,1,0\"><strong data-path-to-node=\"13,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài đọc có nói Werner Fischer chơi loại vợt này, nhưng <strong data-path-to-node=\"13,1,0\" data-index-in-node=\"67\">không nói rõ</strong> ông ấy có phải là người tự thiết kế (designed himself) ra nó hay không.</p>\n</li>\n</ul>\n<p data-path-to-node=\"14\"><strong data-path-to-node=\"14\" data-index-in-node=\"0\">6. The weather can affect how professional players adjust the strings on their rackets. — {TRUE}</strong></p>\n<ul data-path-to-node=\"15\">\n<li>\n<p data-path-to-node=\"15,0,0\"><strong data-path-to-node=\"15,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 6):</strong> <em data-path-to-node=\"15,0,0\" data-index-in-node=\"20\">\"They [strings and tension] will continually change depending on various factors including the court surface, <strong data-path-to-node=\"15,0,0\" data-index-in-node=\"130\">climatic conditions</strong>, and game styles.\"</em></p>\n</li>\n<li>\n<p data-path-to-node=\"15,1,0\"><strong data-path-to-node=\"15,1,0\" data-index-in-node=\"0\">Giải thích:</strong> \"Climatic conditions\" chính là thời tiết (weather). Bài đọc xác nhận thời tiết là một yếu tố ảnh hưởng đến việc điều chỉnh dây vợt.</p>\n</li>\n</ul>\n<p data-path-to-node=\"16\"><strong data-path-to-node=\"16\" data-index-in-node=\"0\">7. It was believed that the change Pete Sampras made to his rackets contributed to his strong serve. — {TRUE}</strong></p>\n<ul data-path-to-node=\"17\">\n<li>\n<p data-path-to-node=\"17,0,0\"><strong data-path-to-node=\"17,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 9):</strong> <em data-path-to-node=\"17,0,0\" data-index-in-node=\"20\">\"...much of the <strong data-path-to-node=\"17,0,0\" data-index-in-node=\"36\">serving power of US professional player Pete Sampras was attributed to the addition of four to five lead weights</strong> onto his rackets...\"</em></p>\n</li>\n<li>\n<p data-path-to-node=\"17,1,0\"><strong data-path-to-node=\"17,1,0\" data-index-in-node=\"0\">Giải thích:</strong> \"Serving power\" tương ứng với \"strong serve\". Việc ông thêm tạ chì vào vợt được tin là đã đóng góp (attributed to) vào cú giao bóng mạnh mẽ của ông.</p>\n</li>\n</ul>"}]', 0);
INSERT INTO public.questions VALUES ('c4a48e5f-b030-495a-af40-26fc7eb7810f', '25fe44bf-bad5-4e27-b3c3-9259eae07e9e', 'matrix', 'Questions 18–23', '', '<p data-section-id="1723hv1" data-start="866" data-end="921">Which paragraph contains the following information?</p>
<p data-start="923" data-end="958">Choose the correct letter, <strong>A</strong><strong data-start="950" data-end="957">–</strong><strong>I</strong>.</p>', 'choose_a_title', 'null', 'null', 'null', '{"layoutType": "simple", "matrixItems": [{"itemText": "a mention of different cultural approaches to dealing with insomnia", "correctCategoryLetter": "H"}, {"itemText": "indications that sleep has a positive effect on health", "correctCategoryLetter": "E"}, {"itemText": "the effects of different kinds of sleep on mental performance", "correctCategoryLetter": "C"}, {"itemText": "reasons why various species of animal sleep in different ways", "correctCategoryLetter": "B"}, {"itemText": "the suggestion that sleep allows us to get rid of insignificant information", "correctCategoryLetter": "D"}, {"itemText": "a description of how the brain responds when a person stops breathing", "correctCategoryLetter": "G"}], "matrixCategories": [{"categoryText": "A", "categoryLetter": "A"}, {"categoryText": "B", "categoryLetter": "B"}, {"categoryText": "C", "categoryLetter": "C"}, {"categoryText": "D", "categoryLetter": "D"}, {"categoryText": "E", "categoryLetter": "E"}, {"categoryText": "F", "categoryLetter": "F"}, {"categoryText": "G", "categoryLetter": "G"}, {"categoryText": "H", "categoryLetter": "H"}, {"categoryText": "I", "categoryLetter": "I"}]}', '[{"content": "<p data-path-to-node=\"14\"><strong data-path-to-node=\"14\" data-index-in-node=\"0\">18. H — a mention of different cultural approaches to dealing with insomnia</strong></p>\n<ul data-path-to-node=\"15\">\n<li>\n<p data-path-to-node=\"15,0,0\"><strong data-path-to-node=\"15,0,0\" data-index-in-node=\"0\">Dẫn chứng câu tốt nhất:</strong> &gt; <em data-path-to-node=\"15,0,0\" data-index-in-node=\"26\">“Acupuncture may help. It has long had this role in Asian medicine and is being studied at the University of Pittsburgh sleep center now. Typically in the US, insomnia is treated in two ways.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"15,1,0\"><strong data-path-to-node=\"15,1,0\" data-index-in-node=\"0\">Giải thích:</strong> \"Different cultural approaches\" (các phương pháp tiếp cận văn hóa khác nhau) được thể hiện qua việc đoạn H đối chiếu giữa châm cứu của y học phương Đông/Châu Á (<em data-path-to-node=\"15,1,0\" data-index-in-node=\"173\">Asian medicine</em>) và các biện pháp dùng thuốc ngủ Tây y thông thường tại Mỹ (<em data-path-to-node=\"15,1,0\" data-index-in-node=\"248\">Typically in the US</em>).</p>\n</li>\n</ul>\n<p data-path-to-node=\"16\"><strong data-path-to-node=\"16\" data-index-in-node=\"0\">19. E — indications that sleep has a positive effect on health</strong></p>\n<ul data-path-to-node=\"17\">\n<li>\n<p data-path-to-node=\"17,0,0\"><strong data-path-to-node=\"17,0,0\" data-index-in-node=\"0\">Dẫn chứng câu tốt nhất:</strong> &gt; <em data-path-to-node=\"17,0,0\" data-index-in-node=\"26\">“Some researchers have found that sleep deprivation impedes wound healing in rats, and others have suggested that sleep helps boost the immune system and control infection.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"17,1,0\"><strong data-path-to-node=\"17,1,0\" data-index-in-node=\"0\">Giải thích:</strong> \"Positive effect on health\" (tác động tích cực tới sức khỏe) tương ứng với việc giấc ngủ giúp thúc đẩy hệ thống miễn dịch và kiểm soát nhiễm trùng (<em data-path-to-node=\"17,1,0\" data-index-in-node=\"160\">boost the immune system and control infection</em>), còn thiếu ngủ sẽ làm cản trở quá trình lành vết thương.</p>\n</li>\n</ul>\n<p data-path-to-node=\"18\"><strong data-path-to-node=\"18\" data-index-in-node=\"0\">20. C — the effects of different kinds of sleep on mental performance</strong></p>\n<ul data-path-to-node=\"19\">\n<li>\n<p data-path-to-node=\"19,0,0\"><strong data-path-to-node=\"19,0,0\" data-index-in-node=\"0\">Dẫn chứng câu tốt nhất:</strong> &gt; <em data-path-to-node=\"19,0,0\" data-index-in-node=\"26\">“They found that those who had engaged in REM sleep subsequently performed better in pattern recognition tasks, such as grammar, while those who slept deeply were better at memorization.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"19,1,0\"><strong data-path-to-node=\"19,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Đoạn C chỉ ra tác động của các loại giấc ngủ khác nhau (<em data-path-to-node=\"19,1,0\" data-index-in-node=\"68\">different kinds of sleep</em> bao gồm giấc ngủ REM và ngủ sâu <em data-path-to-node=\"19,1,0\" data-index-in-node=\"125\">deeply</em>) đối với hiệu suất trí tuệ (<em data-path-to-node=\"19,1,0\" data-index-in-node=\"160\">mental performance</em> bao gồm làm nhiệm vụ nhận diện cấu trúc ngữ pháp và khả năng ghi nhớ <em data-path-to-node=\"19,1,0\" data-index-in-node=\"248\">memorization</em>).</p>\n</li>\n</ul>\n<p data-path-to-node=\"20\"><strong data-path-to-node=\"20\" data-index-in-node=\"0\">21. B — reasons why various species of animal sleep in different ways</strong></p>\n<ul data-path-to-node=\"21\">\n<li>\n<p data-path-to-node=\"21,0,0\"><strong data-path-to-node=\"21,0,0\" data-index-in-node=\"0\">Dẫn chứng câu tốt nhất:</strong> &gt; <em data-path-to-node=\"21,0,0\" data-index-in-node=\"26\">“We know that all mammals sleep, and that there are some insects and reptiles that only half sleep, in order to remain aware of their environment and predators.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"21,1,0\"><strong data-path-to-node=\"21,1,0\" data-index-in-node=\"0\">Giải thích:</strong> \"Various species of animal\" tương ứng với động vật có vú, côn trùng và bò sát (<em data-path-to-node=\"21,1,0\" data-index-in-node=\"91\">mammals, insects and reptiles</em>). \"Sleep in different ways\" (ngủ theo cách khác nhau) là có loài ngủ hết, có loài chỉ ngủ một nửa (<em data-path-to-node=\"21,1,0\" data-index-in-node=\"220\">only half sleep</em>). Lý do (<em data-path-to-node=\"21,1,0\" data-index-in-node=\"245\">reasons</em>) cho việc này là để duy trì nhận biết về môi trường và tránh kẻ săn mồi (<em data-path-to-node=\"21,1,0\" data-index-in-node=\"326\">remain aware of their environment and predators</em>).</p>\n</li>\n</ul>\n<p data-path-to-node=\"22\"><strong data-path-to-node=\"22\" data-index-in-node=\"0\">22. D — the suggestion that sleep allows us to get rid of insignificant information</strong></p>\n<ul data-path-to-node=\"23\">\n<li>\n<p data-path-to-node=\"23,0,0\"><strong data-path-to-node=\"23,0,0\" data-index-in-node=\"0\">Dẫn chứng câu tốt nhất:</strong> &gt; <em data-path-to-node=\"23,0,0\" data-index-in-node=\"26\">“So the purpose of sleep may be to help us remember what''s important, by letting us forget what''s not.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"23,1,0\"><strong data-path-to-node=\"23,1,0\" data-index-in-node=\"0\">Giải thích:</strong> \"Get rid of insignificant information\" (loại bỏ thông tin không quan trọng) đồng nghĩa hoàn toàn với cụm từ cho phép chúng ta quên đi những thứ không quan trọng (<strong data-path-to-node=\"23,1,0\" data-index-in-node=\"174\">letting us forget what''s not [important]</strong>) dựa trên nghiên cứu xóa bỏ các khớp thần kinh thừa thãi của Giulio Tononi.</p>\n</li>\n</ul>\n<p data-path-to-node=\"24\"><strong data-path-to-node=\"24\" data-index-in-node=\"0\">23. G — a description of how the brain responds when a person stops breathing</strong></p>\n<ul data-path-to-node=\"25\">\n<li>\n<p data-path-to-node=\"25,0,0\"><strong data-path-to-node=\"25,0,0\" data-index-in-node=\"0\">Dẫn chứng câu tốt nhất:</strong> &gt; <em data-path-to-node=\"25,0,0\" data-index-in-node=\"26\">“When the brain realizes it is not getting oxygen, it sends a signal to the body to wake up.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"25,1,0\"><strong data-path-to-node=\"25,1,0\" data-index-in-node=\"0\">Giải thích:</strong> \"Stops breathing\" (ngừng thở) tương ứng với hiện tượng tắt đường thở trong chứng ngưng thở khi ngủ (<em data-path-to-node=\"25,1,0\" data-index-in-node=\"112\">apnea</em>). Khi đó, phản ứng của não bộ (<strong data-path-to-node=\"25,1,0\" data-index-in-node=\"149\">how the brain responds</strong>) được mô tả rõ: khi nhận ra không có oxy (<em data-path-to-node=\"25,1,0\" data-index-in-node=\"214\">not getting oxygen</em>), não sẽ phát tín hiệu bắt cơ thể phải tỉnh giấc (<em data-path-to-node=\"25,1,0\" data-index-in-node=\"283\">sends a signal to the body to wake up</em>).</p>\n</li>\n</ul>"}]', 1);
INSERT INTO public.questions VALUES ('121e4441-3e17-4f9d-a850-0432a8d0bfc2', '25fe44bf-bad5-4e27-b3c3-9259eae07e9e', 'matching', 'Questions 24–26', '', '<p>Look at the following statements (Questions 11–13) and the list of people below.</p>
<p>Match each statement with the correct person, <strong>A</strong>–<strong>E</strong>.<br><br></p>', 'matching_name', 'null', 'null', '{"layoutType": "standard", "summaryText": "", "optionsTitle": "List of People", "answerOptions": [{"optionText": "A. Giulio Tononi"}, {"optionText": "B. William Dement"}, {"optionText": "C. Clete Kushida"}, {"optionText": "D. Charles Czeisler"}, {"optionText": "E. John Winkelman"}], "matchingItems": [{"questionPart": "Research tells us that we sleep as reaction to our body''s signals", "correctAnswer": "B"}, {"questionPart": "People suffering from insomnia are easily recognisable", "correctAnswer": "C"}, {"questionPart": "Therapy does not always enable people to achieve good quality sleep", "correctAnswer": "E"}]}', 'null', '[{"content": "<p data-path-to-node=\"28\"><strong data-path-to-node=\"28\" data-index-in-node=\"0\">24. B (William Dement) — Research tells us that we sleep as reaction to our body''s signals.</strong></p>\n<ul data-path-to-node=\"29\">\n<li>\n<p data-path-to-node=\"29,0,0\"><strong data-path-to-node=\"29,0,0\" data-index-in-node=\"0\">Dẫn chứng câu tốt nhất:</strong> &gt; <em data-path-to-node=\"29,0,0\" data-index-in-node=\"26\">“''As far as I know,'' he said, ''the only reason we need to sleep that is really, really solid is because we get sleepy.''”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"29,1,0\"><strong data-path-to-node=\"29,1,0\" data-index-in-node=\"0\">Giải thích:</strong> \"Body''s signals\" (tín hiệu của cơ thể) tương ứng với trạng thái chúng ta cảm thấy buồn ngủ (<em data-path-to-node=\"29,1,0\" data-index-in-node=\"104\">we get sleepy</em>). Giáo sư William Dement khẳng định lý do vững chắc nhất của việc ngủ đơn giản là vì cơ thể phát tín hiệu buồn ngủ.</p>\n</li>\n</ul>\n<p data-path-to-node=\"30\"><strong data-path-to-node=\"30\" data-index-in-node=\"0\">25. C (Clete Kushida) — People suffering from insomnia are easily recognisable.</strong></p>\n<ul data-path-to-node=\"31\">\n<li>\n<p data-path-to-node=\"31,0,0\"><strong data-path-to-node=\"31,0,0\" data-index-in-node=\"0\">Dẫn chứng câu tốt nhất:</strong> &gt; <em data-path-to-node=\"31,0,0\" data-index-in-node=\"26\">“However, Clete Kushida, the clinic director, told me he can spot most people''s sleep problems right at the intake interview.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"31,1,0\"><strong data-path-to-node=\"31,1,0\" data-index-in-node=\"0\">Giải thích:</strong> \"Easily recognisable\" (dễ dàng nhận ra) đồng nghĩa với cụm từ \"can spot most people''s sleep problems right at the intake interview\" (có thể phát hiện ra ngay từ vòng phỏng vấn tiếp nhận bệnh nhân đầu tiên). Người đưa ra khẳng định này là Clete Kushida.</p>\n</li>\n</ul>\n<p data-path-to-node=\"32\"><strong data-path-to-node=\"32\" data-index-in-node=\"0\">26. E (John Winkelman) — Therapy does not always enable people to achieve good quality sleep.</strong></p>\n<ul data-path-to-node=\"33\">\n<li>\n<p data-path-to-node=\"33,0,0\"><strong data-path-to-node=\"33,0,0\" data-index-in-node=\"0\">Dẫn chứng câu tốt nhất:</strong> &gt; <em data-path-to-node=\"33,0,0\" data-index-in-node=\"26\">“''Some people continue in my experience to struggle,'' says John Winkelman, another sleep center director. ''They''re not super-satisfied with their sleep.''”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"33,1,0\"><strong data-path-to-node=\"33,1,0\" data-index-in-node=\"0\">Giải thích:</strong> \"Therapy\" (liệu pháp điều trị) ở đây đang nói đến liệu pháp hành vi nhận thức (CBT) ở đoạn I. John Winkelman chỉ ra thực tế là phương pháp này không phải lúc nào cũng mang lại hiệu quả tuyệt đối, một số bệnh nhân vẫn phải vật lộn (<em data-path-to-node=\"33,1,0\" data-index-in-node=\"243\">continue to struggle</em>) và không cực kỳ thỏa mãn với giấc ngủ của mình (<em data-path-to-node=\"33,1,0\" data-index-in-node=\"313\">not super-satisfied</em>).</p>\n</li>\n</ul>"}]', 2);
INSERT INTO public.questions VALUES ('1c6113d9-4bb3-40cc-8147-fa35eb8cc720', 'd348c5ae-4a25-40cf-b462-67f67dc00aa5', 'radio', 'Questions 1-5', '', '<p>Choose <strong>TRUE</strong> if the statement agrees with the information given in the text, choose <strong>FALSE</strong> if the statement contradicts the information, or choose <strong>NOT GIVEN</strong> if there is no information on this.</p>', 'true_false_not_given', '[{"correct": 1, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": " In Robert FitzRoy’s time, weather forecasting was a respected skill"}, {"correct": 0, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "When FitzRoy retired from the navy, he had already had a successful career at sea"}, {"correct": 2, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "FitzRoy faced competition from other applicants for the chief statistician’s job"}, {"correct": 1, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "The British Parliament supported the idea of regular weather forecasts in 1854"}, {"correct": 0, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": " Progress in technology made it a good time for publicly available weather forecasting to begin"}]', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"1\"><strong data-path-to-node=\"1\" data-index-in-node=\"0\">1. In Robert FitzRoy’s time, weather forecasting was a respected skill</strong></p>\n<ul data-path-to-node=\"2\">\n<li>\n<p data-path-to-node=\"2,0,0\"><strong data-path-to-node=\"2,0,0\" data-index-in-node=\"0\">Đáp án:</strong> <strong data-path-to-node=\"2,0,0\" data-index-in-node=\"8\">FALSE</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"2,1,0\"><strong data-path-to-node=\"2,1,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 1):</strong> “…in those days predicting the weather had gained a reputation <strong data-path-to-node=\"2,1,0\" data-index-in-node=\"85\">similar to astrology or fortune-telling</strong>. The few people who attempted it had become a <strong data-path-to-node=\"2,1,0\" data-index-in-node=\"171\">national joke</strong>…”</p>\n</li>\n<li>\n<p data-path-to-node=\"2,2,0\"><strong data-path-to-node=\"2,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài đọc khẳng định vào thời của FitzRoy, dự báo thời tiết bị coi thường, bị đánh đồng với bói toán (fortune-telling). Những người thực hiện nó thường bị coi là “trò cười cho cả nước” (national joke) khi dự báo sai. Do đó, nó <strong data-path-to-node=\"2,2,0\" data-index-in-node=\"237\">không</strong> phải là một kỹ năng được tôn trọng (respected skill).</p>\n</li>\n</ul>\n<p data-path-to-node=\"3\"><strong data-path-to-node=\"3\" data-index-in-node=\"0\">2. When FitzRoy retired from the navy, he had already had a successful career at sea</strong></p>\n<ul data-path-to-node=\"4\">\n<li>\n<p data-path-to-node=\"4,0,0\"><strong data-path-to-node=\"4,0,0\" data-index-in-node=\"0\">Đáp án:</strong> <strong data-path-to-node=\"4,0,0\" data-index-in-node=\"8\">TRUE</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"4,1,0\"><strong data-path-to-node=\"4,1,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 2):</strong> “His background was faultless, most famously his <strong data-path-to-node=\"4,1,0\" data-index-in-node=\"69\">captaining of the ship HMS Beagle</strong> on Charles Darwin’s voyage around the world… When FitzRoy retired from active service as an <strong data-path-to-node=\"4,1,0\" data-index-in-node=\"197\">admiral</strong>…”</p>\n</li>\n<li>\n<p data-path-to-node=\"4,2,0\"><strong data-path-to-node=\"4,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Việc ông từng là thuyền trưởng của con tàu nổi tiếng HMS Beagle và nghỉ hưu với quân hàm Đô đốc (admiral) — cấp bậc rất cao trong hải quân — chứng minh rằng ông đã có một sự nghiệp đi biển thành công và lẫy lừng.</p>\n</li>\n</ul>\n<p data-path-to-node=\"5\"><strong data-path-to-node=\"5\" data-index-in-node=\"0\">3. FitzRoy faced competition from other applicants for the chief statistician’s job</strong></p>\n<ul data-path-to-node=\"6\">\n<li>\n<p data-path-to-node=\"6,0,0\"><strong data-path-to-node=\"6,0,0\" data-index-in-node=\"0\">Đáp án:</strong> <strong data-path-to-node=\"6,0,0\" data-index-in-node=\"8\">NOT GIVEN</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"6,1,0\"><strong data-path-to-node=\"6,1,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 2):</strong> “He subsequently <strong data-path-to-node=\"6,1,0\" data-index-in-node=\"37\">secured a job as chief statistician</strong> at the Meteorological Department…”</p>\n</li>\n<li>\n<p data-path-to-node=\"6,2,0\"><strong data-path-to-node=\"6,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài đọc chỉ cho biết ông đã đảm nhận công việc trưởng ban thống kê sau khi nghỉ hưu. Văn bản <strong data-path-to-node=\"6,2,0\" data-index-in-node=\"105\">không đề cập</strong> đến việc có những ứng viên khác hay ông có phải cạnh tranh với ai để có được vị trí này hay không. Thông tin về “sự cạnh tranh” hoàn toàn thiếu vắng.</p>\n</li>\n</ul>\n<p data-path-to-node=\"7\"><strong data-path-to-node=\"7\" data-index-in-node=\"0\">4. The British Parliament supported the idea of regular weather forecasts in 1854</strong></p>\n<ul data-path-to-node=\"8\">\n<li>\n<p data-path-to-node=\"8,0,0\"><strong data-path-to-node=\"8,0,0\" data-index-in-node=\"0\">Đáp án:</strong> <strong data-path-to-node=\"8,0,0\" data-index-in-node=\"8\">FALSE</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"8,1,0\"><strong data-path-to-node=\"8,1,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 2):</strong> “…the British Government was <strong data-path-to-node=\"8,1,0\" data-index-in-node=\"51\">not impressed</strong> with the idea… and the suggestion by one Member of Parliament for this was <strong data-path-to-node=\"8,1,0\" data-index-in-node=\"142\">met with laughter</strong> from the other MPs.”</p>\n</li>\n<li>\n<p data-path-to-node=\"8,2,0\"><strong data-path-to-node=\"8,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Mặc dù Nghị viện (Parliament) đã chi tiền thành lập Cục Khí tượng vào năm 1854, nhưng mục đích ban đầu chỉ là để lập bản đồ hàng hải an toàn. Khi có ý kiến đề xuất làm dự báo thời tiết thường xuyên, các nghị sĩ đã cười nhạo (met with laughter) và không hề ủng hộ ý tưởng này.</p>\n</li>\n</ul>\n<p data-path-to-node=\"9\"><strong data-path-to-node=\"9\" data-index-in-node=\"0\">5. Progress in technology made it a good time for publicly available weather forecasting to begin</strong></p>\n<ul data-path-to-node=\"10\">\n<li>\n<p data-path-to-node=\"10,0,0\"><strong data-path-to-node=\"10,0,0\" data-index-in-node=\"0\">Đáp án:</strong> <strong data-path-to-node=\"10,0,0\" data-index-in-node=\"8\">TRUE</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"10,1,0\"><strong data-path-to-node=\"10,1,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 4):</strong> “This was just the right moment for a national forecasting service. …the invention of the <strong data-path-to-node=\"10,1,0\" data-index-in-node=\"112\">electric telegraph and Morse code</strong> in 1844 gave <strong data-path-to-node=\"10,1,0\" data-index-in-node=\"159\">instant communication</strong> for the first time.”</p>\n</li>\n<li>\n<p data-path-to-node=\"10,2,0\"><strong data-path-to-node=\"10,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài đọc xác nhận đây là “thời điểm thích hợp” (right moment) nhờ sự tiến bộ của công nghệ, cụ thể là máy điện báo và mã Morse giúp truyền tin tức thời giữa các trạm, kết hợp với các thiết bị đo đạc chính xác hơn.</p>\n</li>\n</ul>"}]', 0);
INSERT INTO public.questions VALUES ('d3f0cdec-59ec-4314-b48f-32af556c36fe', 'c83739b5-ac91-4cba-b414-63d1de290544', 'fillup', 'Questions 31–40', '<p data-start="120" data-end="188"><strong data-start="148" data-end="188">Write ONE WORD ONLY for each answer.</strong></p>
<p style="text-align: left;" data-start="195" data-end="256"><span style="font-size: 14pt;"><strong>Research in the area around the Chembe Bird Sanctuary</strong></span></p>
<p data-start="258" data-end="323"><strong data-start="263" data-end="323">The importance of birds of prey to the local communities</strong></p>
<ul data-start="325" data-end="597">
<li data-start="325" data-end="376">
<p data-start="327" data-end="376">They destroy <strong>{rats}</strong> and other rodents.</p>
</li>
<li data-start="377" data-end="448">
<p data-start="379" data-end="448">They help to prevent farmers from being bitten by <strong>{snakes}</strong> .</p>
</li>
<li data-start="449" data-end="522">
<p data-start="451" data-end="522">They have been an important part of the local culture for many years.</p>
</li>
<li data-start="523" data-end="597">
<p data-start="525" data-end="597">They now support the economy by encouraging <strong>{tourism}</strong> in the area.</p>
</li>
</ul>
<p data-start="604" data-end="644"><strong data-start="608" data-end="644">Falling numbers of birds of prey</strong></p>
<ul data-start="646" data-end="926">
<li data-start="646" data-end="860">
<p data-start="648" data-end="686">The birds may be accidentally killed</p>
<ul data-start="689" data-end="860">
<li data-start="689" data-end="745">
<p data-start="691" data-end="745">by <strong>{traffic}</strong> when they are hunting or sleeping</p>
</li>
<li data-start="748" data-end="860">
<p data-start="750" data-end="860">by electrocution from contact with power lines, especially at times when there is a lot of <strong>{rain} </strong>.</p>
</li>
</ul>
</li>
<li data-start="861" data-end="926">
<p data-start="863" data-end="926">Local farmers may illegally shoot them or <strong>{poison}</strong> them.</p>
</li>
</ul>
<p data-start="933" data-end="987"><strong data-start="937" data-end="987">Ways of protecting chickens from birds of prey</strong></p>
<ul data-start="989" data-end="1280">
<li data-start="989" data-end="1043">
<p data-start="991" data-end="1043">clearing away vegetation from the area (unhelpful)</p>
</li>
<li data-start="1044" data-end="1100">
<p data-start="1046" data-end="1100">providing a <strong>{building}</strong> for chickens (expensive)</p>
</li>
<li data-start="1101" data-end="1222">
<p data-start="1103" data-end="1133">frightening birds of prey by</p>
<ul data-start="1136" data-end="1222">
<li data-start="1136" data-end="1165">
<p data-start="1138" data-end="1165">keeping a <strong>{dog}</strong></p>
</li>
<li data-start="1168" data-end="1222">
<p data-start="1170" data-end="1222">making a <strong>{noise}</strong> , e.g. with metal objects</p>
</li>
</ul>
</li>
<li data-start="1223" data-end="1280">
<p data-start="1225" data-end="1280">A <strong>{combination}</strong> of methods is usually most effective.</p>
</li>
</ul>', NULL, 'summary_completion', 'null', 'null', 'null', 'null', '[{"content": "<p data-start=\"118\" data-end=\"678\">We’ve been looking at different types of conflicts that may arise between wildlife and humans at the boundaries of protected areas such as national parks and animal sanctuaries. I’d like to illustrate this by telling you about some research that I’ve been involved in recently in the central African country of Zambia – the area around the Chembe Bird Sanctuary, which contains over three hundred of the listed birds of Zambia. These include a number of birds of prey, such as eagles, hawks and owls, that live by hunting and killing other birds and animals.</p>\n<p data-start=\"680\" data-end=\"1757\">Now, most of the people living in the local communities near to the bird sanctuary are small-scale farmers, and these birds of prey provide important social and ecological benefits to them. For example, a lot of damage can be caused to farmers’ crops by rodents such as <span style=\"background-color: #f1c40f;\"><strong>(31) </strong><strong>rats</strong></span>, which would consume the crops as they grow in the fields as well as after harvesting if they weren’t hunted and killed by the birds. And the predatory habits of these birds also protect farmers in other ways. For example, a major danger to rural workers is <strong><span style=\"background-color: #f1c40f;\">(32) snakes</span></strong>, whose bite may be dangerous or even fatal, and birds of prey have a major role in keeping their populations under control. Local people have always been aware of these benefits and for years, even before the sanctuary was opened in 1973, the birds played a key role in the culture of the region. However, more recently, the sanctuary and its birds have also become increasingly important to the community in economic terms, because at present, after a relatively slow start, <span style=\"background-color: #f1c40f;\"><strong>(33) tourism</strong></span> has become an important source of revenue for them.</p>\n<p data-start=\"1759\" data-end=\"2349\">However, although these birds of prey are protected by the government, their numbers are falling. Some of these deaths are accidental. Fatalities occur when birds land on roads to catch and eat their prey, and are hit by fast-moving <span style=\"background-color: #f1c40f;\"><strong>(34) traffic</strong></span>. Drivers in Zambia have to take special care at night, as birds may regard the quieter roads as safe places to sleep. Accidental deaths may also occur if these birds fly close to high-voltage power lines, as they may be electrocuted. This is a particular danger in the heavy <strong><span style=\"background-color: #f1c40f;\">(35) rain</span></strong> which can occur in the region in the months from December to April.</p>\n<p data-start=\"2351\" data-end=\"2804\">And local farmers also pose a threat to these birds. As well as growing crops, small-scale farmers in the area also rear chickens. These provide food for the farmers’ families, as well as being an important source of income. But they’re also an easy target for birds of prey, and so farmers may shoot these birds, which is illegal but understandable, or they may <strong><span style=\"background-color: #f1c40f;\">(36) poison</span></strong> the birds, which again is illegal and can have negative effects on the ecosystem.</p>\n<p data-start=\"2806\" data-end=\"3351\">So how else can farmers protect their chickens from birds of prey? Some people believe that to prevent the predators from settling near where the chickens are kept it’s best to keep this area free from vegetation. But in fact this is counter-productive as it means the chickens have no cover to hide in and they’ll be easier for the birds to see. Another possibility would be to prevent the chickens from going outside at all, and to keep them safe from predators inside a <strong><span style=\"background-color: #f1c40f;\">(37) building</span></strong>, but this would cost far too much to be a practical solution.</p>\n<p data-start=\"3353\" data-end=\"4242\">Nearly all the farmers reported that they spent a lot of time and effort trying to frighten off the birds of prey without actually harming them. Most of the farmers had at least one <strong><span style=\"background-color: #f1c40f;\">(38) dog</span></strong>, and said this was a big help at scaring away the predators. Some of the farmers also reported that during the breeding season, when the chickens were particularly vulnerable, they encouraged their children to watch over the chickens with a hat pan and a metal spoon so that the resulting <strong><span style=\"background-color: #f1c40f;\">(39) noise</span></strong> would succeed in driving away birds that were trying to seize young chicks. None of these methods was a hundred per cent effective, so as a result, the village people told us that rather than just using one method, they were forced to use a <strong><span style=\"background-color: #f1c40f;\">(40) combination</span></strong> of them to have any effect. And even so, these birds of prey remain a major threat to chickens’ survival and cause considerable economic loss to farmers.</p>\n<p data-start=\"4244\" data-end=\"4308\">So we looked at the possibility of a longer-term solution to …</p>"}]', 0);
INSERT INTO public.questions VALUES ('87f02ff9-36e1-44ca-958c-0f6c957d2a5a', '8c3f6ab2-4ae5-482a-b137-2f2b191e482b', 'matrix', 'Questions 14-17', NULL, '<p>Reading Passage 2 has six paragraphs A-F. Which paragraph contains the following information?</p>
<p>Choose the correct letter, A-F, in boxes 14-17.</p>
', 'other', 'null', 'null', 'null', '{"layoutType": "simple", "legendTitle": null, "matrixItems": [{"itemText": "an explanation of research aimed at restoring the health of the heirloom tomato", "correctCategoryLetter": "F"}, {"itemText": "a reference to a false belief about the heirloom tomato", "correctCategoryLetter": "A"}, {"itemText": "a description of the flavour of the heirloom tomato", "correctCategoryLetter": "E"}, {"itemText": "a reference to a single gene that significantly improves the cultivation of tomatoes", "correctCategoryLetter": "D"}], "matrixCategories": [{"categoryText": "A", "categoryLetter": "A"}, {"categoryText": "B", "categoryLetter": "B"}, {"categoryText": "C", "categoryLetter": "C"}, {"categoryText": "D", "categoryLetter": "D"}, {"categoryText": "E", "categoryLetter": "E"}, {"categoryText": "F", "categoryLetter": "F"}]}', '[{"content": "<p>14. an explanation of research aimed at restoring the health of the heirloom tomato</p>\n<ul data-path-to-node=\"5\">\n<li>\n<p data-path-to-node=\"5,0,0\"><strong>Đáp án:</strong> <strong>F</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"5,1,0\"><strong>Dẫn chứng:</strong> (Đoạn F) &#8220;In 1999 a tomato breeder&#8230; Doug Heath began a favorite project. After 12 years of traditional breeding with the help of molecular markers, <strong>he created a new multi-colored tomato less prone to cracking and also endowed with 12 disease-resistant genes</strong>.&#8221;</p>\n</li>\n<li>\n<p data-path-to-node=\"5,2,0\"><strong>Giải thích:</strong> Đoạn F mô tả nghiên cứu lai tạo kéo dài 12 năm của Doug Heath nhằm khôi phục các gen kháng bệnh (restoring the health) cho cà chua heirloom, tạo ra giống mới ít bị nứt và có nhiều gen kháng bệnh hơn.</p>\n</li>\n</ul>\n<p>15. a reference to a false belief about the heirloom tomato</p>\n<ul data-path-to-node=\"8\">\n<li>\n<p data-path-to-node=\"8,0,0\"><strong>Đáp án:</strong> <strong>A</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"8,1,0\"><strong>Dẫn chứng:</strong> (Đoạn A) &#8220;The tomato enthusiast might conclude that, given the immense varieties, heirlooms must base a more diverse and superior set of genes&#8230; <strong>However, their seeming diversity is only skin-deep: heirlooms are actually feeble and inbred</strong>&#8230;&#8221;</p>\n</li>\n<li>\n<p data-path-to-node=\"8,2,0\"><strong>Giải thích:</strong> Đoạn A bác bỏ niềm tin phổ biến (false belief) rằng cà chua heirloom có bộ gen đa dạng và vượt trội.</p>\n</li>\n</ul>\n<p>16. a description of the flavour of the heirloom tomato</p>\n<ul data-path-to-node=\"11\">\n<li>\n<p data-path-to-node=\"11,0,0\"><strong>Đáp án:</strong> <strong>E</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"11,1,0\"><strong>Dẫn chứng:</strong> (Đoạn E) &#8220;Any plant that produces only two fruits&#8230; is highly likely to produce <strong>juicier, sweeter and more flavorful fruit</strong> than varieties that produce 100, as commercial types do. In addition, heirlooms are sold <strong>ripened on the vine</strong>, a certain way to get tastier results&#8230;&#8221;</p>\n</li>\n<li>\n<p data-path-to-node=\"11,2,0\"><strong>Giải thích:</strong> Đoạn E mô tả chi tiết hương vị của cà chua heirloom (juicier, sweeter, more flavorful) và yếu tố môi trường ảnh hưởng đến hương vị đó.</p>\n</li>\n</ul>\n<p>17. a reference to a single gene that significantly improves the cultivation of tomatoes</p>\n<ul data-path-to-node=\"14\">\n<li>\n<p data-path-to-node=\"14,0,0\"><strong>Đáp án:</strong> <strong>D</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"14,1,0\"><strong>Dẫn chứng:</strong> (Đoạn D) &#8220;&#8230;Tanksley and his colleagues reported that they found <strong>a gene that increases fruit size by 50 percent</strong>. <strong>It was probably the most important event in domestication</strong>.&#8221;</p>\n</li>\n<li>\n<p data-path-to-node=\"14,2,0\"><strong>Giải thích:</strong> Đoạn D đề cập đến một gen duy nhất làm tăng đáng kể (significantly improves) kích thước quả cà chua lên 50%.</p>\n</li>\n</ul>\n"}]', 0);
INSERT INTO public.questions VALUES ('e2e6b2f1-48d6-4da5-b2f0-911bc950a31c', '7b6de520-6d06-4d45-8864-0bd3dcf195fc', 'fillup', 'Questions 1-10', '<p>Write <strong>ONE WORD AND/OR A NUMBER</strong> for each answer.</p>
<table style="width: 78.174%; height: 1204.8px; border-collapse: collapse; border: 1px solid #000000;" border="1" data-path-to-node="4">
<thead>
<tr style="height: 64px;">
<td style="width: 17.6038%; border-width: 1px; border-color: #000000;"></td>
<td style="width: 77.127%; text-align: center; border-width: 1px; border-color: #000000;"><span style="font-size: 12pt;"><strong>Riverdale Pre-school</strong></span></td>
</tr>
</thead>
<tbody>
<tr style="height: 61.2px;">
<td style="width: 17.6038%; border-width: 1px; border-color: #000000;"><span data-path-to-node="4,1,0,0"><strong>Example</strong></span></td>
<td style="width: 77.127%; border-width: 1px; border-color: #000000;"></td>
</tr>
<tr style="height: 61.2px;">
<td style="width: 17.6038%; border-width: 1px; border-color: #000000;"><span data-path-to-node="4,2,0,0"><strong>Children:</strong></span></td>
<td style="width: 77.127%; border-width: 1px; border-color: #000000;"><span data-path-to-node="4,2,1,0"><strong>20</strong> in class</span></td>
</tr>
<tr style="height: 61.2px;">
<td style="width: 17.6038%; border-width: 1px; border-color: #000000;"><span data-path-to-node="4,3,0,0"><strong>Classes:</strong></span></td>
<td style="width: 77.127%; border-width: 1px; border-color: #000000;"><span data-path-to-node="4,3,1,0">First group – Mrs. Oliver</span></td>
</tr>
<tr style="height: 61.2px;">
<td style="width: 17.6038%; border-width: 1px; border-color: #000000;"></td>
<td style="width: 77.127%; border-width: 1px; border-color: #000000;"><span data-path-to-node="4,4,1,0">Second group – Mrs. {Keogh}</span></td>
</tr>
<tr style="height: 80.8px;">
<td style="width: 17.6038%; border-width: 1px; border-color: #000000;"><span data-path-to-node="4,5,0,0"><strong>Hours &amp; Days:</strong></span></td>
<td style="width: 77.127%; border-width: 1px; border-color: #000000;"><span data-path-to-node="4,5,1,0">Suzie will attend 3 days a week for a total of {15} hours</span></td>
</tr>
<tr style="height: 61.2px;">
<td style="width: 17.6038%; border-width: 1px; border-color: #000000;"><span data-path-to-node="4,6,0,0"><strong>Activities:</strong></span></td>
<td style="width: 77.127%; border-width: 1px; border-color: #000000;"><span data-path-to-node="4,6,1,0"><strong>Outside time</strong></span></td>
</tr>
<tr style="height: 61.2px;">
<td style="width: 17.6038%; border-width: 1px; border-color: #000000;"></td>
<td style="width: 77.127%; border-width: 1px; border-color: #000000;"><span data-path-to-node="4,7,1,0">– running, playing, or something quieter</span></td>
</tr>
<tr style="height: 61.2px;">
<td style="width: 17.6038%; border-width: 1px; border-color: #000000;"></td>
<td style="width: 77.127%; border-width: 1px; border-color: #000000;"><span data-path-to-node="4,8,1,0">– just got a new piece of equipment</span></td>
</tr>
<tr style="height: 61.2px;">
<td style="width: 17.6038%; border-width: 1px; border-color: #000000;"></td>
<td style="width: 77.127%; border-width: 1px; border-color: #000000;"><span data-path-to-node="4,9,1,0">– intend to make a {garden}</span></td>
</tr>
<tr style="height: 61.2px;">
<td style="width: 17.6038%; border-width: 1px; border-color: #000000;"></td>
<td style="width: 77.127%; border-width: 1px; border-color: #000000;"><span data-path-to-node="4,10,1,0"><strong>Indoors</strong></span></td>
</tr>
<tr style="height: 61.2px;">
<td style="width: 17.6038%; border-width: 1px; border-color: #000000;"></td>
<td style="width: 77.127%; border-width: 1px; border-color: #000000;"><span data-path-to-node="4,11,1,0">– this year, {music} activities are popular</span></td>
</tr>
<tr style="height: 61.2px;">
<td style="width: 17.6038%; border-width: 1px; border-color: #000000;"></td>
<td style="width: 77.127%; border-width: 1px; border-color: #000000;"><span data-path-to-node="4,12,1,0">– they hear a {story} everyday</span></td>
</tr>
<tr style="height: 61.2px;">
<td style="width: 17.6038%; border-width: 1px; border-color: #000000;"><span data-path-to-node="4,13,0,0"><strong>Fees:</strong></span></td>
<td style="width: 77.127%; border-width: 1px; border-color: #000000;"><span data-path-to-node="4,13,1,0">Now costs $ {470} per term</span></td>
</tr>
<tr style="height: 61.2px;">
<td style="width: 17.6038%; border-width: 1px; border-color: #000000;"></td>
<td style="width: 77.127%; border-width: 1px; border-color: #000000;"><span data-path-to-node="4,14,1,0">Fees include:</span></td>
</tr>
<tr style="height: 61.2px;">
<td style="width: 17.6038%; border-width: 1px; border-color: #000000;"></td>
<td style="width: 77.127%; border-width: 1px; border-color: #000000;"><span data-path-to-node="4,15,1,0">– a trip to a {farm} this year</span></td>
</tr>
<tr style="height: 61.2px;">
<td style="width: 17.6038%; border-width: 1px; border-color: #000000;"></td>
<td style="width: 77.127%; border-width: 1px; border-color: #000000;"><span data-path-to-node="4,16,1,0">– chance to take home a {toy} every week</span></td>
</tr>
<tr style="height: 80.8px;">
<td style="width: 17.6038%; border-width: 1px; border-color: #000000;"><span data-path-to-node="4,17,0,0"><strong>Do not forget:</strong></span></td>
<td style="width: 77.127%; border-width: 1px; border-color: #000000;"><span data-path-to-node="4,17,1,0">– Put a {pillow} in Suzie’s bag</span></td>
</tr>
<tr style="height: 61.2px;">
<td style="width: 17.6038%; border-width: 1px; border-color: #000000;"></td>
<td style="width: 77.127%; border-width: 1px; border-color: #000000;"><span data-path-to-node="4,18,1,0">– Arrange a visit; phone number: {0914638520}</span></td>
</tr>
</tbody>
</table>
', NULL, 'gap_filling', NULL, NULL, '{"layoutType": ["standard"], "summaryText": null, "answerOptions": null, "matchingItems": null}', '{"layoutType": ["standard"], "legendTitle": null, "matrixItems": null, "matrixCategories": null}', '[{"content": "<p data-path-to-node=\"3\"><strong>Narrator:</strong> You will hear a telephone conversation between a man who’s finding out about a preschool for his young daughter and a woman who works there. First you have some time to look at questions 1 to 5 on page two. You will see that there is an example that has been done for you. Now listen carefully and answer questions 1 to five.</p>\n<p data-path-to-node=\"4\"><strong>Woman (Sally):</strong> Good morning, Riverdale Preschool, Sally speaking.</p>\n<p data-path-to-node=\"5\"><strong>Man (Robert):</strong> Hello, my name is Robert. I’ve got a four year old daughter called Susie and I’d like to get some information about your preschool please.</p>\n<p data-path-to-node=\"6\"><strong>Sally:</strong> Sure Robert. Well Susie’s the right age. We take three and four year olds in classes of <strong>20</strong> students. Oh great. And how many teachers do you have? We have two, the first group is taught by Mrs Oliver and the second group is taken by Mrs <strong>(1) KEOgH</strong>. Just a moment, I’ll write that down. Could you spell the last name please? It’s an unusual one, isn’t it? Yes, it’s K-E-O-G-H. Okay, I’ve got that now.</p>\n<p data-path-to-node=\"7\"><strong>Robert:</strong> I know the children attend for two or three days a week. That’s right.</p>\n<p data-path-to-node=\"8\"><strong>Sally:</strong> The older ones like Susie are here for three days, which means <strong>(2) 15</strong> hours a week. The younger ones, the three year olds, attend two days a week, that’s a total of 10 hours.</p>\n<p data-path-to-node=\"9\"><strong>Robert:</strong> And what do they do during that time?</p>\n<p data-path-to-node=\"10\"><strong>Sally:</strong> Well half the day is spent outside and the children can run around and play games with their friends or do a calmer activity like painting for example. We have a great outside play area that we’re improving all the time. And are you thinking of adding anything else outdoors? Well we were hoping to build a playhouse, but that was too expensive, so we’re now making plans for a <strong>(3) garden</strong> where the children will be able to grow flowers and vegetables. Lovely.</p>\n<p data-path-to-node=\"11\"><strong>Robert:</strong> And what else do the children do?</p>\n<p data-path-to-node=\"12\"><strong>Sally:</strong> Well the other half of the day is spent indoors. This year, the children seem to be very interested in <strong>(4) music</strong>, so the teachers are doing a lot of activities related to that. The teachers may sometimes play quiet games with the children, but we always make time for a <strong>(5) story</strong> each day. It’s a very important part of the program here. Yes, of course.</p>\n<hr data-path-to-node=\"13\" />\n<p data-path-to-node=\"14\"><strong>Narrator:</strong> Before you hear the rest of the conversation, you have some time to look at questions 6 to 10 on page two. Now listen and answer questions 6 to ten.</p>\n<p data-path-to-node=\"15\"><strong>Robert:</strong> Now I’d like to ask you about the fees, if that’s okay.</p>\n<p data-path-to-node=\"16\"><strong>Sally:</strong> Sure. We actually had to put them up this term, I’m afraid. I heard from a friend of mine that it used to be $420 for the term, but it’s just gone up to <strong>(6)</strong> $<strong>470</strong>. Is that right? Yes, we had to add the extra $<strong>470</strong> to cover costs. I understand.</p>\n<p data-path-to-node=\"17\"><strong>Robert:</strong> My friend also told me that his daughter went on a trip to the local zoo and that the cost of that was covered in the fees. Is that right?</p>\n<p data-path-to-node=\"18\"><strong>Sally:</strong> Yes, we did that last year, but we’ll be going to a <strong>(7) farm</strong> this year instead. Also included in the price is membership of a special library. Children can borrow a <strong>(8) toy</strong> and keep it for a week and choose a different one the following week. It’s very popular. What a great idea!</p>\n<p data-path-to-node=\"19\"><strong>Robert:</strong> Now is there anything else I should know?</p>\n<p data-path-to-node=\"20\"><strong>Sally:</strong> Well, the children have a rest here during the day and we make up a little bed for them with sheets and blankets, but we advise parents to pack a <strong>(9) pillow</strong> in the child’s bag as we don’t provide one. Okay, I’ll make a note of that. So what should I do if I want to come and look around the school during the day and meet the staff? The best thing is to call the teacher on the classroom mobile and she’ll tell you which time is best to visit. Shall I give you the number? Yes, please. Okay, it’s <strong>(10) 0914638520</strong>.</p>\n<p data-path-to-node=\"21\"><strong>Robert:</strong> Thanks for all your help Sally and we hope to see you soon.</p>\n<p data-path-to-node=\"22\"><strong>Sally:</strong> No problem, bye for now.</p>\n<p data-path-to-node=\"23\"><strong>Narrator:</strong> That is the end of Section 1. You now have half a minute to check your answers.</p>\n"}]', 0);
INSERT INTO public.questions VALUES ('df3b6541-f80a-4264-90ec-8ce390cb1876', '0d78bc92-e925-46c5-9ef8-0664e6cfbc3d', 'matrix', 'Questions 14–17', '', '<p>Write the correct letter, <strong>A–E</strong>, in boxes 14–17 on your answer sheet.</p>
<p><strong>NB</strong> You may use any letter more than once. </p>', 'choose_a_title', 'null', 'null', 'null', '{"layoutType": "standard", "matrixItems": [{"itemText": "a reference to the interest shown by large corporations in herbal remedies", "correctCategoryLetter": "D"}, {"itemText": "examples of the uses of one particular herbal medicine", "correctCategoryLetter": "A"}, {"itemText": "a warning that small companies cannot afford stricter controls of the herbal medicine industry", "correctCategoryLetter": "E"}, {"itemText": "a statement by one expert about the effectiveness and limitations of herbal medicines", "correctCategoryLetter": "D"}], "matrixCategories": [{"categoryText": "A", "categoryLetter": "A"}, {"categoryText": "B", "categoryLetter": "B"}, {"categoryText": "C", "categoryLetter": "C"}, {"categoryText": "D", "categoryLetter": "D"}, {"categoryText": "E", "categoryLetter": "E"}]}', '[{"content": "<p data-path-to-node=\"4\"><strong data-path-to-node=\"4\" data-index-in-node=\"0\">14. D — {a reference to the interest shown by large corporations in herbal remedies}</strong></p>\n<ul data-path-to-node=\"5\">\n<li>\n<p data-path-to-node=\"5,0,0\"><strong data-path-to-node=\"5,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"5,0,0\" data-index-in-node=\"11\">“Natural health products are big sellers in pharmacies, and <strong data-path-to-node=\"5,0,0\" data-index-in-node=\"71\">global pharmaceutical companies are buying up natural supplement brands or developing their own</strong>.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"5,1,0\"><strong data-path-to-node=\"5,1,0\" data-index-in-node=\"0\">Giải thích:</strong> \"Large corporations\" (các tập đoàn lớn) được cụ thể hóa bằng cụm từ \"global pharmaceutical companies\" (các công ty dược phẩm toàn cầu). Việc các tập đoàn này đi thu mua lại các thương hiệu thực phẩm bổ sung tự nhiên hoặc tự phát triển dòng sản phẩm riêng chính là minh chứng rõ ràng cho sự quan tâm (<strong data-path-to-node=\"5,1,0\" data-index-in-node=\"312\">interest</strong>) của họ đối với các phương thuốc thảo dược (<strong data-path-to-node=\"5,1,0\" data-index-in-node=\"365\">herbal remedies / natural supplement</strong>).</p>\n</li>\n</ul>\n<p data-path-to-node=\"6\"><strong data-path-to-node=\"6\" data-index-in-node=\"0\">15. A — {examples of the uses of one particular herbal medicine}</strong></p>\n<ul data-path-to-node=\"7\">\n<li>\n<p data-path-to-node=\"7,0,0\"><strong data-path-to-node=\"7,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"7,0,0\" data-index-in-node=\"11\">“Take <strong data-path-to-node=\"7,0,0\" data-index-in-node=\"17\">arnica</strong>, for example, <strong data-path-to-node=\"7,0,0\" data-index-in-node=\"38\">a popular pharmaceutical herb used to treat bruises and joint problems</strong>.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"7,1,0\"><strong data-path-to-node=\"7,1,0\" data-index-in-node=\"0\">Giải thích:</strong> \"One particular herbal medicine\" (một loại thảo dược cụ thể) ở đây chính là cây kim sa (<strong data-path-to-node=\"7,1,0\" data-index-in-node=\"100\">arnica</strong>). Đoạn A đã đưa ra các ví dụ về công dụng của nó (<strong data-path-to-node=\"7,1,0\" data-index-in-node=\"157\">examples of the uses</strong>) là dùng để chữa trị các vết bầm tím (<em data-path-to-node=\"7,1,0\" data-index-in-node=\"216\">treat bruises</em>) và các vấn đề về xương khớp (<em data-path-to-node=\"7,1,0\" data-index-in-node=\"260\">joint problems</em>).</p>\n</li>\n</ul>\n<p data-path-to-node=\"8\"><strong data-path-to-node=\"8\" data-index-in-node=\"0\">16. E — {a warning that small companies cannot afford stricter controls of the herbal medicine industry}</strong></p>\n<ul data-path-to-node=\"9\">\n<li>\n<p data-path-to-node=\"9,0,0\"><strong data-path-to-node=\"9,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"9,0,0\" data-index-in-node=\"11\">“But others argue that <strong data-path-to-node=\"9,0,0\" data-index-in-node=\"34\">more regulation would be prohibitively expensive for all but the largest manufacturers – a change, cautions Clair, that would probably put some local companies out of business</strong>.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"9,1,0\"><strong data-path-to-node=\"9,1,0\" data-index-in-node=\"0\">Giải thích:</strong> \"Stricter controls\" (sự kiểm soát chặt chẽ hơn) tương ứng với cụm từ \"more regulation\" (nhiều quy định pháp lý hơn). \"Small companies\" (các công ty nhỏ) tương ứng với từ \"local companies\" (các công ty địa phương, phân biệt với <em data-path-to-node=\"9,1,0\" data-index-in-node=\"239\">largest manufacturers</em>). Lời cảnh báo (<strong data-path-to-node=\"9,1,0\" data-index-in-node=\"277\">a warning / cautions Clair</strong>) chỉ ra rằng việc thắt chặt này sẽ vô cùng đắt đỏ (<em data-path-to-node=\"9,1,0\" data-index-in-node=\"355\">prohibitively expensive</em> - không thể chi trả nổi / <em data-path-to-node=\"9,1,0\" data-index-in-node=\"405\">cannot afford</em>) và có thể khiến các công ty này bị phá sản (<em data-path-to-node=\"9,1,0\" data-index-in-node=\"464\">put out of business</em>).</p>\n</li>\n</ul>\n<p data-path-to-node=\"10\"><strong data-path-to-node=\"10\" data-index-in-node=\"0\">17. D — {a statement by one expert about the effectiveness and limitations of herbal medicines}</strong></p>\n<ul data-path-to-node=\"11\">\n<li>\n<p data-path-to-node=\"11,0,0\"><strong data-path-to-node=\"11,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"11,0,0\" data-index-in-node=\"11\">“‘<strong data-path-to-node=\"11,0,0\" data-index-in-node=\"13\">It doesn’t do everything</strong>,’ he [Rasmussen] says, ‘<strong data-path-to-node=\"11,0,0\" data-index-in-node=\"62\">but there’s a lot it does do, particularly in terms of preventative health care</strong>.’”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"11,1,0\"><strong data-path-to-node=\"11,1,0\" data-index-in-node=\"0\">Giải thích:</strong> \"One expert\" (một chuyên gia) ở đây là ông Phil Rasmussen. Phát biểu của ông chứa đựng cả hai mặt: Sự hiệu quả (<strong data-path-to-node=\"11,1,0\" data-index-in-node=\"124\">effectiveness</strong> - <em data-path-to-node=\"11,1,0\" data-index-in-node=\"140\">there’s a lot it does do / preventative health care</em>) và mặt hạn chế (<strong data-path-to-node=\"11,1,0\" data-index-in-node=\"209\">limitations</strong> - <em data-path-to-node=\"11,1,0\" data-index-in-node=\"223\">It doesn’t do everything / nó không phải là vạn năng</em>). Do đó thông tin này hoàn toàn thuộc về đoạn D.</p>\n</li>\n</ul>"}]', 0);
INSERT INTO public.questions VALUES ('f7f7e964-77f2-4e4f-9cca-130a1f14ff78', 'cb0d737c-34e4-4f9a-9f0a-d8ea017c9c23', 'matrix', 'Questions 16–20', '', '<p data-path-to-node="4">Label the map below.</p>
<p data-path-to-node="5">Write the correct letter, <strong data-path-to-node="5" data-index-in-node="26">A–H</strong>, next to Questions 16–20.</p>
<p data-path-to-node="5"><em data-path-to-node="5" data-index-in-node="0"><img src="https://thesol.edu.vn/datafiles/35996/upload/images/image-20240815181131-1.png" alt="đề cam ielts 19 test 1"></em></p>', 'choose_a_title', 'null', 'null', 'null', '{"layoutType": "simple", "matrixItems": [{"itemText": "Farm shop", "correctCategoryLetter": "G"}, {"itemText": "Disabled entry", "correctCategoryLetter": "C"}, {"itemText": "Adventure playground", "correctCategoryLetter": "B"}, {"itemText": "Kitchen gardens", "correctCategoryLetter": "D"}, {"itemText": "The Temple of the Four Winds", "correctCategoryLetter": "A"}], "matrixCategories": [{"categoryText": "A", "categoryLetter": "A"}, {"categoryText": "B", "categoryLetter": "B"}, {"categoryText": "C", "categoryLetter": "C"}, {"categoryText": "D", "categoryLetter": "D"}, {"categoryText": "E", "categoryLetter": "E"}, {"categoryText": "F", "categoryLetter": "F"}, {"categoryText": "G", "categoryLetter": "G"}, {"categoryText": "H", "categoryLetter": "H"}]}', '[{"content": "<p>1</p>"}]', 1);
INSERT INTO public.questions VALUES ('b154bf6c-d6e7-4086-ada3-8e2b5d513c3a', '1a22bea1-67c8-4ced-a7bf-1cdd27cc1f7f', 'fillup', 'Questions 1–4', '<p>Label the diagram below.</p>
<p>Write <strong>ONE WORD ONLY</strong> from the passage for each answer.</p>
<p style="text-align: center;" data-path-to-node="10"><span style="font-size: 12pt;"><strong data-path-to-node="10" data-index-in-node="0">Jethro Tull’s seed drill</strong></span></p>
<p style="text-align: center;" data-path-to-node="10"><span style="font-size: 12pt;"><strong data-path-to-node="10" data-index-in-node="0"><img src="data:image/png;base64," width="615" height="478" loading="lazy"></strong></span></p>
<ul data-path-to-node="11">
<li>1. {hopper}<strong data-path-to-node="11,0,0" data-index-in-node="0"> </strong></li>
<li>2. {cylinder}</li>
<li>3. {funnel}</li>
<li>4. {spikes}<strong data-path-to-node="11,3,0" data-index-in-node="0"> </strong></li>
</ul>', '', 'summary_completion', 'null', 'null', 'null', 'null', '[{"content": "<ul>\n<li>\n<p data-path-to-node=\"3,0,0\"><strong data-path-to-node=\"3,0,0\" data-index-in-node=\"0\">1. {hopper}</strong></p>\n<ul data-path-to-node=\"3,0,1\">\n<li>\n<p data-path-to-node=\"3,0,1,0,0\"><strong data-path-to-node=\"3,0,1,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…allowed seed to pass evenly from the <strong data-path-to-node=\"3,0,1,0,0\" data-index-in-node=\"52\">hopper</strong> above…”</p>\n</li>\n<li>\n<p data-path-to-node=\"3,0,1,1,0\"><strong data-path-to-node=\"3,0,1,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Đây là bộ phận nằm ở trên cùng của máy, đóng vai trò như một thùng chứa hoặc phễu lớn để đổ hạt giống vào trước khi bắt đầu gieo.</p>\n</li>\n</ul>\n</li>\n<li>\n<p data-path-to-node=\"3,1,0\"><strong data-path-to-node=\"3,1,0\" data-index-in-node=\"0\">2. {cylinder}</strong></p>\n<ul data-path-to-node=\"3,1,1\">\n<li>\n<p data-path-to-node=\"3,1,1,0,0\"><strong data-path-to-node=\"3,1,1,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…the <strong data-path-to-node=\"3,1,1,0,0\" data-index-in-node=\"19\">cylinder</strong> rotated against a spring-held tongue.”</p>\n</li>\n<li>\n<p data-path-to-node=\"3,1,1,1,0\"><strong data-path-to-node=\"3,1,1,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Hạt từ hopper rơi xuống và được điều tiết bởi một khối <strong data-path-to-node=\"3,1,1,1,0\" data-index-in-node=\"67\">hình trụ</strong> xoay tròn. Bộ phận này giúp hạt được phân phối đều đặn thay vì rơi tự do.</p>\n</li>\n</ul>\n</li>\n<li>\n<p data-path-to-node=\"3,2,0\"><strong data-path-to-node=\"3,2,0\" data-index-in-node=\"0\">3. {funnel}</strong></p>\n<ul data-path-to-node=\"3,2,1\">\n<li>\n<p data-path-to-node=\"3,2,1,0,0\"><strong data-path-to-node=\"3,2,1,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…to a <strong data-path-to-node=\"3,2,1,0,0\" data-index-in-node=\"20\">funnel</strong> below. From here, the seed was directed at regular intervals into three channels…”</p>\n</li>\n<li>\n<p data-path-to-node=\"3,2,1,1,0\"><strong data-path-to-node=\"3,2,1,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Sau khi đi qua cylinder, hạt giống rơi vào một cái <strong data-path-to-node=\"3,2,1,1,0\" data-index-in-node=\"63\">phễu dẫn</strong> phía dưới để hướng hạt vào đúng các rãnh đất đã được đào sẵn.</p>\n</li>\n</ul>\n</li>\n<li>\n<p data-path-to-node=\"3,3,0\"><strong data-path-to-node=\"3,3,0\" data-index-in-node=\"0\">4. {spikes}</strong></p>\n<ul data-path-to-node=\"3,3,1\">\n<li>\n<p data-path-to-node=\"3,3,1,0,0\"><strong data-path-to-node=\"3,3,1,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “<strong data-path-to-node=\"3,3,1,0,0\" data-index-in-node=\"12\">Spikes</strong> at the back of the machine then turned the soil over to immediately cover the seeds.”</p>\n</li>\n<li>\n<p data-path-to-node=\"3,3,1,1,0\"><strong data-path-to-node=\"3,3,1,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Đây là bộ phận nằm ở phía sau cùng của máy. Những chiếc <strong data-path-to-node=\"3,3,1,1,0\" data-index-in-node=\"68\">gai/răng sắt</strong> này có nhiệm vụ gạt đất lấp đầy các rãnh, đảm bảo hạt giống được bảo vệ dưới lòng đất ngay lập tức.</p>\n</li>\n</ul>\n</li>\n</ul>"}]', 0);
INSERT INTO public.questions VALUES ('b617ae1a-b7a2-4895-b294-380d024a83a4', '17f17493-09b2-4398-9692-ff581b8c8baa', 'fillup', 'Questions 33-36', '<p>Complete the summary below.</p>
<p>Write <strong>NO MORE THAN THREE WORDS</strong> from the passage for each answer.</p>
<p>Using visual imagery and spatial navigation to remember numbers are investigated and explained. A {specific human being| human being} , an action, and a thing are assigned to consecutive cards in the pack. Combining these images allows Cooke to memorise {three cards} at a time. The mind pictures are then positioned on a {specific familiar path} . The pack of cards is remembered by going for a {mental walk} . While the pictures are converted back into cards.</p>
', NULL, 'gap_filling', 'null', 'null', 'null', 'null', '[{"content": "<p><strong data-path-to-node=\"1\" data-index-in-node=\"0\">33. human being</strong> (hoặc <strong data-path-to-node=\"1\" data-index-in-node=\"22\">specific human being</strong>)</p>\n<ul data-path-to-node=\"2\">\n<li><strong data-path-to-node=\"2,0,0\" data-index-in-node=\"0\">Dẫn chứng</strong>: Đoạn D, câu 1: &#8220;To enable himself to memorize quickly, Ed Cooke has memorized a <strong data-path-to-node=\"2,0,0\" data-index-in-node=\"91\">specific human being</strong>, verb, and object that he associates with every card in the deck.&#8221;</li>\n<li><strong data-path-to-node=\"2,1,0\" data-index-in-node=\"0\">Giải thích</strong>: Để ghi nhớ nhanh, Ed Cooke gán cho mỗi lá bài một con người cụ thể (<strong data-path-to-node=\"2,1,0\" data-index-in-node=\"80\">human being</strong>), một động từ (hành động) và một đồ vật.</li>\n</ul>\n<p><strong data-path-to-node=\"3\" data-index-in-node=\"0\">34. three cards</strong></p>\n<ul data-path-to-node=\"4\">\n<li><strong data-path-to-node=\"4,0,0\" data-index-in-node=\"0\">Dẫn chứng</strong>: Đoạn D, câu 3: &#8220;When Cooke commits a deck to memory, he does it <strong data-path-to-node=\"4,0,0\" data-index-in-node=\"75\">three cards</strong> in one go&#8230;&#8221;</li>\n<li><strong data-path-to-node=\"4,1,0\" data-index-in-node=\"0\">Giải thích</strong>: Bằng cách kết hợp các hình ảnh đã gán, Cooke có thể ghi nhớ được <strong data-path-to-node=\"4,1,0\" data-index-in-node=\"77\">3 lá bài</strong> cùng một lúc thay vì nhớ từng lá đơn lẻ.</li>\n</ul>\n<p><strong data-path-to-node=\"5\" data-index-in-node=\"0\">35. specific familiar path</strong></p>\n<ul data-path-to-node=\"6\">\n<li><strong data-path-to-node=\"6,0,0\" data-index-in-node=\"0\">Dẫn chứng</strong>: Đoạn D, câu 5: &#8220;He then places those images along a <strong data-path-to-node=\"6,0,0\" data-index-in-node=\"63\">specific familiar path</strong> in his mind&#8230;&#8221;</li>\n<li><strong data-path-to-node=\"6,1,0\" data-index-in-node=\"0\">Giải thích</strong>: Sau khi tạo ra các hình ảnh phức hợp, ông đặt chúng dọc theo một <strong data-path-to-node=\"6,1,0\" data-index-in-node=\"77\">con đường quen thuộc cụ thể</strong> trong tâm trí để lưu trữ.</li>\n</ul>\n<p><strong data-path-to-node=\"7\" data-index-in-node=\"0\">36. mental walk</strong></p>\n<ul data-path-to-node=\"8\">\n<li><strong data-path-to-node=\"8,0,0\" data-index-in-node=\"0\">Dẫn chứng</strong>: Đoạn D, câu 6: &#8220;When it comes to recall, Cooke takes a <strong data-path-to-node=\"8,0,0\" data-index-in-node=\"66\">mental walk</strong> along his route and translates the images into cards&#8230;&#8221;</li>\n<li><strong data-path-to-node=\"8,1,0\" data-index-in-node=\"0\">Giải thích</strong>: Khi cần nhớ lại, ông thực hiện một <strong data-path-to-node=\"8,1,0\" data-index-in-node=\"47\">chuyến đi bộ trong tâm trí</strong> dọc theo con đường đó để chuyển đổi các hình ảnh ngược lại thành các lá bài.</li>\n</ul>\n"}]', 1);
INSERT INTO public.questions VALUES ('8fb40e21-02ed-4f0f-b63e-5e3bc7ec5470', '1a22bea1-67c8-4ced-a7bf-1cdd27cc1f7f', 'fillup', 'Questions 5–8', '<p>Answer the questions below.</p>
<p>Choose <strong>NO MORE THAN TWO WORDS</strong> from the passage for each answer.</p>
<p>What name was given to the traditional technique of seed-sowing? {broadcasting}</p>
<p>What type of agriculture gave Tull inspiration on his second tour of Europe? {vine-growing methods}</p>
<p>What traditional addition to soil did Tull believe to be unnecessary? {manure}</p>
<p>What animals did Tull recommend farmers should use to pull their machinery? {horses}</p>', '', 'short_answer', 'null', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"4\"><strong data-path-to-node=\"4\" data-index-in-node=\"0\">5. What name was given to the traditional technique of seed-sowing?</strong></p>\n<ul data-path-to-node=\"5\">\n<li>\n<p data-path-to-node=\"5,0,0\"><strong data-path-to-node=\"5,0,0\" data-index-in-node=\"0\">Đáp án:</strong> {broadcasting}</p>\n</li>\n<li>\n<p data-path-to-node=\"5,1,0\"><strong data-path-to-node=\"5,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…in a traditional method known as <strong data-path-to-node=\"5,1,0\" data-index-in-node=\"48\">broadcasting</strong>.” (Đoạn B)</p>\n</li>\n<li>\n<p data-path-to-node=\"5,2,0\"><strong data-path-to-node=\"5,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Trước khi có máy móc, nông dân thường vung hạt bằng tay một cách ngẫu nhiên, kỹ thuật này được gọi là “broadcasting”.</p>\n</li>\n</ul>\n<p data-path-to-node=\"6\"><strong data-path-to-node=\"6\" data-index-in-node=\"0\">6. What type of agriculture gave Tull inspiration on his second tour of Europe?</strong></p>\n<ul data-path-to-node=\"7\">\n<li>\n<p data-path-to-node=\"7,0,0\"><strong data-path-to-node=\"7,0,0\" data-index-in-node=\"0\">Đáp án:</strong> {vine-growing methods}</p>\n</li>\n<li>\n<p data-path-to-node=\"7,1,0\"><strong data-path-to-node=\"7,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “Following practices he had observed in the <strong data-path-to-node=\"7,1,0\" data-index-in-node=\"55\">vine-growing methods</strong> of southern Europe…” (Đoạn D)</p>\n</li>\n<li>\n<p data-path-to-node=\"7,2,0\"><strong data-path-to-node=\"7,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Việc quan sát cách người châu Âu trồng nho đã giúp Tull nảy ra ý tưởng xới đất giữa các hàng cây để diệt cỏ và cung cấp dưỡng chất.</p>\n</li>\n</ul>\n<p data-path-to-node=\"8\"><strong data-path-to-node=\"8\" data-index-in-node=\"0\">7. What traditional addition to soil did Tull believe to be unnecessary?</strong></p>\n<ul data-path-to-node=\"9\">\n<li>\n<p data-path-to-node=\"9,0,0\"><strong data-path-to-node=\"9,0,0\" data-index-in-node=\"0\">Đáp án:</strong> {manure}</p>\n</li>\n<li>\n<p data-path-to-node=\"9,1,0\"><strong data-path-to-node=\"9,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…eliminate the need for <strong data-path-to-node=\"9,1,0\" data-index-in-node=\"38\">manure</strong> to be used to fertilise the soil.” (Đoạn D)</p>\n</li>\n<li>\n<p data-path-to-node=\"9,2,0\"><strong data-path-to-node=\"9,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Tull tin rằng việc xới đất kỹ (pulverisation) là đủ để nuôi cây, do đó không cần dùng đến phân chuồng (manure) truyền thống.</p>\n</li>\n</ul>\n<p data-path-to-node=\"10\"><strong data-path-to-node=\"10\" data-index-in-node=\"0\">8. What animals did Tull recommend farmers should use to pull their machinery?</strong></p>\n<ul data-path-to-node=\"11\">\n<li>\n<p data-path-to-node=\"11,0,0\"><strong data-path-to-node=\"11,0,0\" data-index-in-node=\"0\">Đáp án:</strong> {horses}</p>\n</li>\n<li>\n<p data-path-to-node=\"11,1,0\"><strong data-path-to-node=\"11,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “Tull also advocated the use of <strong data-path-to-node=\"11,1,0\" data-index-in-node=\"43\">horses</strong> over the oxen…” (Đoạn E)</p>\n</li>\n<li>\n<p data-path-to-node=\"11,2,0\"><strong data-path-to-node=\"11,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Thay vì dùng bò (oxen) chậm chạp, Tull khuyến khích dùng ngựa để kéo máy móc nhằm tăng hiệu suất.</p>\n</li>\n</ul>"}]', 1);
INSERT INTO public.questions VALUES ('968d630e-1b07-4176-9703-222986481909', '6a45cfea-1f8b-4031-82fd-b931cebd3ecb', 'matching', 'Questions 27 - 30', '', '<p>Which comment did most students make about each of the following aspects of performance?</p>
<p>Choose <strong>FOUR </strong>answers from the box and write the correct letter, <strong>A-G</strong>, next to questions <strong>27- 30</strong>.</p>', 'summary_completion', 'null', 'null', '{"layoutType": "summary", "summaryText": "<p>Performing solo {B. This is difficult but enjoyable}</p>\n<p> </p>\n<p>Deciding which pieces to perform {E. This is time-consuming}</p>\n<p> </p>\n<p>Performing with musicians from a different genre {G. This happens infrequently}</p>\n<p> </p>\n<p>Performing with musicians who play the same instrument {A. This is very beneficial}</p>", "answerOptions": [{"optionText": "A. This is very beneficial"}, {"optionText": "B. This is difficult but enjoyable"}, {"optionText": "C. This can affect relationships"}, {"optionText": "D. This makes them very nervous"}, {"optionText": "E. This is time-consuming"}, {"optionText": "F. This is easy"}, {"optionText": "G. This happens infrequently"}], "matchingItems": []}', 'null', '[{"content": "<p>1</p>"}]', 3);
INSERT INTO public.questions VALUES ('bf1af3d0-23aa-4e27-b1d9-fa88ed595b6a', 'a3a37e43-58a0-4926-8fea-b8360816b266', 'radio', 'Questions 9–13', NULL, '<p>Choose <strong>TRUE</strong> if the statement agrees with the information given in the text, choose <strong>FALSE</strong> if the statement contradicts the information, or choose <strong>NOT GIVEN</strong> if there is no information on this.</p>
', 'multiple_choice_single', '[{"correct": 1, "options": [{"content": "TRUE"}, {"content": "FALSE"}, {"content": "NOT GIVEN"}], "question": "Bernard Silver was invited to develop a system for capturing product information by the president of a food chain."}, {"correct": 0, "options": [{"content": "TRUE"}, {"content": "FALSE"}, {"content": "NOT GIVEN"}], "question": "A committee set up in the 1970s said bar codes should be easy to use and not too expensive."}, {"correct": 2, "options": [{"content": "TRUE"}, {"content": "FALSE"}, {"content": "NOT GIVEN"}], "question": "Alan Haberman disagreed with government policies on business matters."}, {"correct": 2, "options": [{"content": "TRUE"}, {"content": "FALSE"}, {"content": "NOT GIVEN"}], "question": "Many grocery outlets were unable to afford the necessary scanning equipment."}, {"correct": 0, "options": [{"content": "TRUE"}, {"content": "FALSE"}, {"content": "NOT GIVEN"}], "question": "The advantages of the new bar-code scanner took some time to be accepted by users."}]', NULL, '{"layoutType": ["standard"], "summaryText": null, "answerOptions": null, "matchingItems": null}', '{"layoutType": ["standard"], "legendTitle": null, "matrixItems": null, "matrixCategories": null}', '[{"content": "<p data-path-to-node=\"22\"><strong data-path-to-node=\"22\" data-index-in-node=\"0\">9. Bernard Silver was invited to develop a system for capturing product information by the president of a food chain.</strong></p>\n<ul data-path-to-node=\"23\">\n<li>\n<p data-path-to-node=\"23,0,0\"><strong data-path-to-node=\"23,0,0\" data-index-in-node=\"0\">Đáp án:</strong> <strong data-path-to-node=\"23,0,0\" data-index-in-node=\"8\">FALSE</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"23,1,0\"><strong data-path-to-node=\"23,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> Đoạn A nói rằng Bernard Silver chỉ tình cờ <strong data-path-to-node=\"23,1,0\" data-index-in-node=\"54\">nghe lỏm (overheard)</strong> cuộc trò chuyện giữa vị chủ tịch chuỗi thực phẩm và một giáo sư. Vị chủ tịch nài nỉ giáo sư nghiên cứu, giáo sư từ chối, sau đó Silver mới kể lại cho Woodland.</p>\n</li>\n<li>\n<p data-path-to-node=\"23,2,0\"><strong data-path-to-node=\"23,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Silver không được “mời” mà tự mình chủ động nghiên cứu sau khi nghe trộm thông tin.</p>\n</li>\n</ul>\n<p data-path-to-node=\"24\"><strong data-path-to-node=\"24\" data-index-in-node=\"0\">10. A committee set up in the 1970s said bar codes should be easy to use and not too expensive.</strong></p>\n<ul data-path-to-node=\"25\">\n<li>\n<p data-path-to-node=\"25,0,0\"><strong data-path-to-node=\"25,0,0\" data-index-in-node=\"0\">Đáp án:</strong> <strong data-path-to-node=\"25,0,0\" data-index-in-node=\"8\">TRUE</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"25,1,0\"><strong data-path-to-node=\"25,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> Đoạn C liệt kê các nguyên tắc của ủy ban: mã vạch phải đọc được từ mọi góc độ (dễ dùng cho thu ngân) và nhãn phải <strong data-path-to-node=\"25,1,0\" data-index-in-node=\"125\">“cheap and easy to print”</strong> (rẻ và dễ in).</p>\n</li>\n<li>\n<p data-path-to-node=\"25,2,0\"><strong data-path-to-node=\"25,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Thông tin này hoàn toàn khớp với các tiêu chí về tính tiện dụng và chi phí thấp mà ủy ban đưa ra.</p>\n</li>\n</ul>\n<p data-path-to-node=\"26\"><strong data-path-to-node=\"26\" data-index-in-node=\"0\">11. Alan Haberman disagreed with government policies on business matters.</strong></p>\n<ul data-path-to-node=\"27\">\n<li>\n<p data-path-to-node=\"27,0,0\"><strong data-path-to-node=\"27,0,0\" data-index-in-node=\"0\">Đáp án:</strong> <strong data-path-to-node=\"27,0,0\" data-index-in-node=\"8\">NOT GIVEN</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"27,1,0\"><strong data-path-to-node=\"27,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> Đoạn D chỉ trích lời Alan Haberman rằng doanh nghiệp không cần chính phủ phải “đẩy” họ đi đúng hướng (<strong data-path-to-node=\"27,1,0\" data-index-in-node=\"113\">“business didn’t need the government to shove them…”</strong>).</p>\n</li>\n<li>\n<p data-path-to-node=\"27,2,0\"><strong data-path-to-node=\"27,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Haberman nói về việc doanh nghiệp có thể tự hợp tác mà không cần chính phủ can thiệp, nhưng bài đọc <strong data-path-to-node=\"27,2,0\" data-index-in-node=\"112\">không nói</strong> ông có “bất đồng với các chính sách của chính phủ” về các vấn đề kinh doanh khác hay không.</p>\n</li>\n</ul>\n<p data-path-to-node=\"28\"><strong data-path-to-node=\"28\" data-index-in-node=\"0\">12. Many grocery outlets were unable to afford the necessary scanning equipment.</strong></p>\n<ul data-path-to-node=\"29\">\n<li>\n<p data-path-to-node=\"29,0,0\"><strong data-path-to-node=\"29,0,0\" data-index-in-node=\"0\">Đáp án:</strong> <strong data-path-to-node=\"29,0,0\" data-index-in-node=\"8\">NOT GIVEN</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"29,1,0\"><strong data-path-to-node=\"29,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> Đoạn E đề cập rằng chi phí đầu tư là rất lớn (<strong data-path-to-node=\"29,1,0\" data-index-in-node=\"57\">$200,000 cho mỗi cửa hàng</strong>).</p>\n</li>\n<li>\n<p data-path-to-node=\"29,2,0\"><strong data-path-to-node=\"29,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài đọc chỉ nêu con số đầu tư đắt đỏ, nhưng <strong data-path-to-node=\"29,2,0\" data-index-in-node=\"56\">không cung cấp thông tin</strong> về việc có nhiều cửa hàng “không đủ khả năng chi trả” hay không.</p>\n</li>\n</ul>\n<p data-path-to-node=\"30\"><strong data-path-to-node=\"30\" data-index-in-node=\"0\">13. The advantages of the new bar-code scanner took some time to be accepted by users.</strong></p>\n<ul data-path-to-node=\"31\">\n<li>\n<p data-path-to-node=\"31,0,0\"><strong data-path-to-node=\"31,0,0\" data-index-in-node=\"0\">Đáp án:</strong> <strong data-path-to-node=\"31,0,0\" data-index-in-node=\"8\">TRUE</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"31,1,0\"><strong data-path-to-node=\"31,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> Đoạn G dòng 1: “The advantages of the system were <strong data-path-to-node=\"31,1,0\" data-index-in-node=\"61\">not clear immediately</strong>, as wholesalers, retailers and customers <strong data-path-to-node=\"31,1,0\" data-index-in-node=\"124\">remained suspicious</strong>.”</p>\n</li>\n<li>\n<p data-path-to-node=\"31,2,0\"><strong data-path-to-node=\"31,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Lợi ích không được thấy ngay lập tức vì người dùng vẫn còn nghi ngờ (thậm chí nghi bị theo dõi), mãi sau này các lợi ích mới trở nên rõ ràng.</p>\n</li>\n</ul>\n"}]', 1);
INSERT INTO public.questions VALUES ('682bf377-b92c-4fbc-b8e0-f030e6a3f572', '85bc1de6-c424-4dbb-ba35-7d3f4f87da44', 'radio', 'Questions 1 – 7', '', '<p data-path-to-node="5,0,0">Choose<strong data-path-to-node="5,0,0" data-index-in-node="0"> TRUE</strong> if the statement agrees with the information,<strong data-path-to-node="5,1,0" data-index-in-node="0">FALSE</strong> if the statement contradicts the information,<strong data-path-to-node="5,2,0" data-index-in-node="0">NOT GIVEN</strong> if there is no information on this</p>', 'true_false_not_given', '[{"correct": 0, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "Grass skiing was used in the 1960s to help snow skiers practise their technique."}, {"correct": 2, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "The most important grass skiing competitions are still held in France."}, {"correct": 0, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "Interest in grass skiing was slow to develop."}, {"correct": 1, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "People who want to do grass skiing must know how to snow ski."}, {"correct": 0, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "Grass skiing can take place on home-made slopes."}, {"correct": 2, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "Some ski camps allow beginners to try grass skiing free for a weekend."}, {"correct": 0, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "Track skis are intended to help people ski faster on ordinary grass slopes."}]', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"3\"><strong data-path-to-node=\"3\" data-index-in-node=\"0\">1. Grass skiing was used in the 1960s to help snow skiers practise their technique. — TRUE</strong></p>\n<ul data-path-to-node=\"4\">\n<li>\n<p data-path-to-node=\"4,0,0\"><strong data-path-to-node=\"4,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “In 1968 he took the idea to France, where it immediately became popular as a useful way of continuing <strong data-path-to-node=\"4,0,0\" data-index-in-node=\"114\">Alpine skiing skills training in the summer months</strong>.”</p>\n</li>\n<li>\n<p data-path-to-node=\"4,1,0\"><strong data-path-to-node=\"4,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài đọc xác nhận vào những năm 1960 (cụ thể là 1968), trượt cỏ được dùng để luyện tập kỹ năng trượt tuyết (Alpine skiing) khi không có tuyết.</p>\n</li>\n</ul>\n<p data-path-to-node=\"5\"><strong data-path-to-node=\"5\" data-index-in-node=\"0\">2. The most important grass skiing competitions are still held in France. — NOT GIVEN</strong></p>\n<ul data-path-to-node=\"6\">\n<li>\n<p data-path-to-node=\"6,0,0\"><strong data-path-to-node=\"6,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> Bài chỉ nói Richard Martin mang ý tưởng đến Pháp vào năm 1968 và hiện nay có giải “Grass Skiing World Cup”.</p>\n</li>\n<li>\n<p data-path-to-node=\"6,1,0\"><strong data-path-to-node=\"6,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Không có thông tin nào khẳng định các cuộc thi quan trọng nhất <strong data-path-to-node=\"6,1,0\" data-index-in-node=\"75\">hiện nay vẫn (still)</strong> được tổ chức tại Pháp.</p>\n</li>\n</ul>\n<p data-path-to-node=\"7\"><strong data-path-to-node=\"7\" data-index-in-node=\"0\">3. Interest in grass skiing was slow to develop. — TRUE</strong></p>\n<ul data-path-to-node=\"8\">\n<li>\n<p data-path-to-node=\"8,0,0\"><strong data-path-to-node=\"8,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “<strong data-path-to-node=\"8,0,0\" data-index-in-node=\"12\">Until 2003, the following for grass skiing was not that large</strong>. It has become more popular recently…”</p>\n</li>\n<li>\n<p data-path-to-node=\"8,1,0\"><strong data-path-to-node=\"8,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “The following was not that large” nghĩa là lượng người quan tâm/theo dõi không nhiều cho đến tận năm 2003. Điều này đồng nghĩa với việc sự quan tâm phát triển chậm (slow to develop).</p>\n</li>\n</ul>\n<p data-path-to-node=\"9\"><strong data-path-to-node=\"9\" data-index-in-node=\"0\">4. People who want to do grass skiing must know how to snow ski. — FALSE</strong></p>\n<ul data-path-to-node=\"10\">\n<li>\n<p data-path-to-node=\"10,0,0\"><strong data-path-to-node=\"10,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…it is <strong data-path-to-node=\"10,0,0\" data-index-in-node=\"21\">great fun for beginners</strong> and even children can do it.”</p>\n</li>\n<li>\n<p data-path-to-node=\"10,1,0\"><strong data-path-to-node=\"10,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài viết nói người mới bắt đầu và trẻ em đều làm được, và trượt cỏ giúp họ có “bước khởi đầu” (head start) trước khi học trượt tuyết. Vậy không bắt buộc phải biết trượt tuyết trước.</p>\n</li>\n</ul>\n<p data-path-to-node=\"11\"><strong data-path-to-node=\"11\" data-index-in-node=\"0\">5. Grass skiing can take place on home-made slopes. — TRUE</strong></p>\n<ul data-path-to-node=\"12\">\n<li>\n<p data-path-to-node=\"12,0,0\"><strong data-path-to-node=\"12,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “However, many people have successfully <strong data-path-to-node=\"12,0,0\" data-index-in-node=\"51\">created small grass runs on their own property</strong>.”</p>\n</li>\n<li>\n<p data-path-to-node=\"12,1,0\"><strong data-path-to-node=\"12,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “On their own property” (trên đất riêng của họ) chính là “home-made slopes” (dốc tự làm).</p>\n</li>\n</ul>\n<p data-path-to-node=\"13\"><strong data-path-to-node=\"13\" data-index-in-node=\"0\">6. Some ski camps allow beginners to try grass skiing free for a weekend. — NOT GIVEN</strong></p>\n<ul data-path-to-node=\"14\">\n<li>\n<p data-path-to-node=\"14,0,0\"><strong data-path-to-node=\"14,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…you can visit weekend ski camps… which often organise courses…”</p>\n</li>\n<li>\n<p data-path-to-node=\"14,1,0\"><strong data-path-to-node=\"14,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài đọc có nhắc đến các trại trượt tuyết cuối tuần, nhưng <strong data-path-to-node=\"14,1,0\" data-index-in-node=\"70\">không nhắc đến việc nó có miễn phí (free)</strong> hay không.</p>\n</li>\n</ul>\n<p data-path-to-node=\"15\"><strong data-path-to-node=\"15\" data-index-in-node=\"0\">7. Track skis are intended to help people ski faster on ordinary grass slopes. — TRUE</strong></p>\n<ul data-path-to-node=\"16\">\n<li>\n<p data-path-to-node=\"16,0,0\"><strong data-path-to-node=\"16,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “The track skiing are for the more <strong data-path-to-node=\"16,0,0\" data-index-in-node=\"46\">competitive skier</strong> because they are designed for <strong data-path-to-node=\"16,0,0\" data-index-in-node=\"94\">downhill</strong>…” (Lưu ý: Đoạn cuối văn bản của bạn bị khuyết một chút, nhưng trong ngữ cảnh chuyên môn, “track skis” mô phỏng xích xe tăng để giảm ma sát và tăng tốc độ).</p>\n</li>\n<li>\n<p data-path-to-node=\"16,1,0\"><strong data-path-to-node=\"16,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Dành cho người thi đấu (competitive) và trượt xuống dốc (downhill) ngụ ý mục đích đạt tốc độ cao hơn.</p>\n</li>\n</ul>"}]', 0);
INSERT INTO public.questions VALUES ('0a09cc3f-9af0-4c9c-9da0-a0b46fdece37', 'cd88bdfd-28b0-464c-9429-cc3d3bd82092', 'radio', 'Questions 27-30', NULL, '<p>Choose the correct answers</p>
', 'multiple_choice_single', '[{"correct": 2, "options": [{"content": "A Comparing the old NGV with the new NGV"}, {"content": "B Describing the role of art museums in Australian culture"}, {"content": "C Considering the influence of gallery design on art appreciation"}, {"content": "D Suggesting there has been little recent change in gallery design"}], "question": "What is the writer doing in the first paragraph?"}, {"correct": 1, "options": [{"content": "A The permanent collection was poorly displayed"}, {"content": "B The building tended to make art seem remote"}, {"content": "C Asian and Pacific art was neglected"}, {"content": "D The foyer resembled a shop"}], "question": "The writer criticises the old NGV because"}, {"correct": 2, "options": [{"content": "A He thinks the ticket booths are well positioned"}, {"content": "B He is upset that he is made to move so quickly"}, {"content": "C He is frustrated because the art is obscured by the entrance"}, {"content": "D He thinks the redevelopment fails to keep up with international trends"}], "question": "What does the writer notice about the new NGV?"}, {"correct": 1, "options": [{"content": "A Should be cheaper"}, {"content": "B Are a financial necessity"}, {"content": "C Should be increased in number"}, {"content": "D Allow the museum to present an original programme"}], "question": "The writer argues that rental \"blockbuster\" exhibitions"}]', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"1\"><strong data-path-to-node=\"1\" data-index-in-node=\"0\">27. considering the influence of gallery design on art appreciation</strong></p>\n<ul data-path-to-node=\"2\">\n<li>\n<p data-path-to-node=\"2,0,0\"><strong data-path-to-node=\"2,0,0\" data-index-in-node=\"0\">Vị trí:</strong> Đoạn 1, dòng 2–4.</p>\n</li>\n<li>\n<p data-path-to-node=\"2,1,0\"><strong data-path-to-node=\"2,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> &#8220;Do any of these newly developed spaces indicate a <strong data-path-to-node=\"2,1,0\" data-index-in-node=\"62\">fundamental shift in the ways we engage with art</strong> at the beginning of the twenty-first century? The answer is a qualified Yes and also&#8230; No.&#8221;</p>\n</li>\n<li>\n<p data-path-to-node=\"2,2,0\"><strong data-path-to-node=\"2,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Trong đoạn đầu tiên, tác giả đặt ra câu hỏi liệu những không gian bảo tàng mới được phát triển (gallery design) có phản ánh một sự thay đổi cơ bản trong <strong data-path-to-node=\"2,2,0\" data-index-in-node=\"165\">cách chúng ta tiếp cận/thưởng thức nghệ thuật</strong> (engage with art/art appreciation) hay không. Việc tác giả sử dụng ví dụ về sự cải tạo của bảo tàng NGV năm 2003 để trả lời câu hỏi này cho thấy mục đích chính của đoạn văn là xem xét mối quan hệ giữa thiết kế không gian và trải nghiệm nghệ thuật của công chúng.</p>\n</li>\n</ul>\n<p data-path-to-node=\"6\"><strong data-path-to-node=\"6\" data-index-in-node=\"0\">28. The writer criticises the old NGV because:</strong></p>\n<ul data-path-to-node=\"7\">\n<li>\n<p data-path-to-node=\"7,0,0\"><strong data-path-to-node=\"7,0,0\" data-index-in-node=\"0\">Đáp án:</strong> <strong data-path-to-node=\"7,0,0\" data-index-in-node=\"8\">B (The building tended to make art seem remote.)</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"7,1,0\"><strong data-path-to-node=\"7,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…huge expanse of the exterior’s windowless wall and the surrounding moat, which creates a rather unwelcoming expression of the institution.”</p>\n</li>\n<li>\n<p data-path-to-node=\"7,2,0\"><strong data-path-to-node=\"7,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Tác giả chê tòa nhà cũ có những bức tường không cửa sổ và con hào bao quanh, tạo cảm giác “unwelcoming” (không chào đón), khiến nghệ thuật bên trong trở nên xa cách với công chúng.</p>\n</li>\n</ul>\n<p data-path-to-node=\"8\"><strong data-path-to-node=\"8\" data-index-in-node=\"0\">29. What does the writer notice about the new NGV?</strong></p>\n<ul data-path-to-node=\"9\">\n<li>\n<p data-path-to-node=\"9,0,0\"><strong data-path-to-node=\"9,0,0\" data-index-in-node=\"0\">Đáp án:</strong> <strong data-path-to-node=\"9,0,0\" data-index-in-node=\"8\">C (He is frustrated because the art is obscured by the entrance.)</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"9,1,0\"><strong data-path-to-node=\"9,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…where has the art gone? We are not allowed to see the exhibitions until we have completed the necessary inductions. We are greeted by a hugely expanded cloakroom, screening off our vision…”</p>\n</li>\n<li>\n<p data-path-to-node=\"9,2,0\"><strong data-path-to-node=\"9,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Tác giả cảm thấy “frustrated” (bực bội) vì khi vào bảo tàng mới, tầm nhìn bị che khuất bởi phòng gửi đồ, quầy thông tin, cửa hàng… làm cho nghệ thuật bị lu mờ ngay từ lối vào.</p>\n</li>\n</ul>\n<p data-path-to-node=\"10\"><strong data-path-to-node=\"10\" data-index-in-node=\"0\">30. The writer argues that rental “blockbuster” exhibitions:</strong></p>\n<ul data-path-to-node=\"11\">\n<li>\n<p data-path-to-node=\"11,0,0\"><strong data-path-to-node=\"11,0,0\" data-index-in-node=\"0\">Đáp án:</strong> <strong data-path-to-node=\"11,0,0\" data-index-in-node=\"8\">B (Are a financial necessity.)</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"11,1,0\"><strong data-path-to-node=\"11,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “Entrance to the NGV permanent collection is now free, so the NGV needs something to keep the paying public coming back. The answer lies in the international ‘blockbuster’ exhibition.”</p>\n</li>\n<li>\n<p data-path-to-node=\"11,2,0\"><strong data-path-to-node=\"11,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Vì bộ sưu tập cố định giờ đã miễn phí, bảo tàng buộc phải tổ chức các triển lãm “bom tấn” (blockbuster) để thu hút khách trả phí, phục vụ mục đích tài chính.</p>\n</li>\n</ul>\n"}]', 0);
INSERT INTO public.questions VALUES ('473c11fe-9374-4ec3-a78c-73fae762dde0', '85bc1de6-c424-4dbb-ba35-7d3f4f87da44', 'matrix', 'Questions 8 – 14', '', '<p data-path-to-node="5">Write the correct letter, <strong data-path-to-node="5" data-index-in-node="26">A-F</strong>, in boxes 8-14 on your answer sheet.</p>
<p data-path-to-node="6"><strong data-path-to-node="6" data-index-in-node="0">NB</strong> <em data-path-to-node="6" data-index-in-node="3">You may use any letter more than once.</em></p>', 'choose_a_title', 'null', 'null', 'null', '{"layoutType": "simple", "matrixItems": [{"itemText": "The help of local people is required here at times.", "correctCategoryLetter": "F"}, {"itemText": "Schoolchildren do not have to pay full admission fees here.", "correctCategoryLetter": "D"}, {"itemText": "It is possible to purchase some handmade items here.", "correctCategoryLetter": "D"}, {"itemText": "People can buy the things they need to produce art work here.", "correctCategoryLetter": "A"}, {"itemText": "Special refreshments for children are available here.", "correctCategoryLetter": "C"}, {"itemText": "There is no charge to see art exhibitions here.", "correctCategoryLetter": "F"}, {"itemText": "It may not be possible for disabled people to get to certain parts of this centre.", "correctCategoryLetter": "E"}], "matrixCategories": [{"categoryText": "A", "categoryLetter": "A"}, {"categoryText": "B", "categoryLetter": "B"}, {"categoryText": "C", "categoryLetter": "C"}, {"categoryText": "D", "categoryLetter": "D"}, {"categoryText": "E", "categoryLetter": "E"}, {"categoryText": "F", "categoryLetter": "F"}]}', '[{"content": "<p data-path-to-node=\"19\"><strong data-path-to-node=\"19\" data-index-in-node=\"0\">8. {F} – Castle Park Arts Centre</strong></p>\n<ul data-path-to-node=\"20\">\n<li>\n<p data-path-to-node=\"20,0,0\"><strong data-path-to-node=\"20,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “The Centre relies on volunteers from the area to assist with various events and tasks.”</p>\n</li>\n<li>\n<p data-path-to-node=\"20,1,0\"><strong data-path-to-node=\"20,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “Volunteers from the area” (tình nguyện viên trong vùng) chính là sự giúp đỡ của người dân địa phương.</p>\n</li>\n</ul>\n<p data-path-to-node=\"21\"><strong data-path-to-node=\"21\" data-index-in-node=\"0\">9. {D} – Lakeside Arts Centre</strong></p>\n<ul data-path-to-node=\"22\">\n<li>\n<p data-path-to-node=\"22,0,0\"><strong data-path-to-node=\"22,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “Concessionary rates are available for young people.”</p>\n</li>\n<li>\n<p data-path-to-node=\"22,1,0\"><strong data-path-to-node=\"22,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “Concessionary rates” là giá ưu đãi, đồng nghĩa với việc không phải trả toàn bộ phí (<strong data-path-to-node=\"22,1,0\" data-index-in-node=\"97\">not have to pay full fees</strong>).</p>\n</li>\n</ul>\n<p data-path-to-node=\"23\"><strong data-path-to-node=\"23\" data-index-in-node=\"0\">10. {D} – Lakeside Arts Centre</strong></p>\n<ul data-path-to-node=\"24\">\n<li>\n<p data-path-to-node=\"24,0,0\"><strong data-path-to-node=\"24,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…craft cabinets selling original works by leading craftmakers, it is the ideal place to take time out…”</p>\n</li>\n<li>\n<p data-path-to-node=\"24,1,0\"><strong data-path-to-node=\"24,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “Original works by craftmakers” chính là các món đồ làm bằng tay (<strong data-path-to-node=\"24,1,0\" data-index-in-node=\"78\">handmade items</strong>).</p>\n</li>\n</ul>\n<p data-path-to-node=\"25\"><strong data-path-to-node=\"25\" data-index-in-node=\"0\">11. {A} – Newcastle Arts Centre</strong></p>\n<ul data-path-to-node=\"26\">\n<li>\n<p data-path-to-node=\"26,0,0\"><strong data-path-to-node=\"26,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “It also includes a well-stocked art materials store.”</p>\n</li>\n<li>\n<p data-path-to-node=\"26,1,0\"><strong data-path-to-node=\"26,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “Art materials” (họa cụ) là những thứ cần thiết để tạo ra tác phẩm nghệ thuật.</p>\n</li>\n</ul>\n<p data-path-to-node=\"27\"><strong data-path-to-node=\"27\" data-index-in-node=\"0\">12. {C} – Warwick Arts Centre</strong></p>\n<ul data-path-to-node=\"28\">\n<li>\n<p data-path-to-node=\"28,0,0\"><strong data-path-to-node=\"28,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “We are proud to offer a wide variety of healthy snacks, including a kids’ menu.”</p>\n</li>\n<li>\n<p data-path-to-node=\"28,1,0\"><strong data-path-to-node=\"28,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “Healthy snacks” và “kids’ menu” tương ứng với đồ ăn nhẹ đặc biệt cho trẻ em (<strong data-path-to-node=\"28,1,0\" data-index-in-node=\"90\">special refreshments for children</strong>).</p>\n</li>\n</ul>\n<p data-path-to-node=\"29\"><strong data-path-to-node=\"29\" data-index-in-node=\"0\">13. {F} – Castle Park Arts Centre</strong></p>\n<ul data-path-to-node=\"30\">\n<li>\n<p data-path-to-node=\"30,0,0\"><strong data-path-to-node=\"30,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “Visitors can also enjoy, for free, a changing visual arts programme by regional and international artists.”</p>\n</li>\n<li>\n<p data-path-to-node=\"30,1,0\"><strong data-path-to-node=\"30,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “For free” đồng nghĩa với việc không tính phí (<strong data-path-to-node=\"30,1,0\" data-index-in-node=\"59\">no charge</strong>) để xem triển lãm.</p>\n</li>\n</ul>\n<p data-path-to-node=\"31\"><strong data-path-to-node=\"31\" data-index-in-node=\"0\">14. {E} – Plymouth Arts Centre</strong></p>\n<ul data-path-to-node=\"32\">\n<li>\n<p data-path-to-node=\"32,0,0\"><strong data-path-to-node=\"32,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…facilities are spread over three floors in a historic building and some of these are accessible only by stairs.”</p>\n</li>\n<li>\n<p data-path-to-node=\"32,1,0\"><strong data-path-to-node=\"32,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “Accessible only by stairs” (chỉ lên được bằng cầu thang bộ) gây khó khăn cho người khuyết tật tiếp cận một số khu vực.</p>\n</li>\n</ul>"}]', 1);
INSERT INTO public.questions VALUES ('db08ab97-ebaa-4603-adb9-a852026a8f15', 'cd88bdfd-28b0-464c-9429-cc3d3bd82092', 'radio', 'Questions 31-35', NULL, '<p>Choose <strong>YES </strong>if the statement agrees with the information given in the text, choose <strong>NO </strong>if the statement contradicts the information, or choose <strong>NOT GIVEN </strong>if there is no information on this.</p>
', 'multiple_choice_single', '[{"correct": 1, "options": [{"content": "YES"}, {"content": "NO"}, {"content": "NOT GIVEN"}], "question": "Roy Grounds’s design failed to recognise the importance of functions and performances in museums"}, {"correct": 1, "options": [{"content": "YES"}, {"content": "NO"}, {"content": "NOT GIVEN"}], "question": "Mario Bellini’s new NGV rejects international museum design trends"}, {"correct": 2, "options": [{"content": "YES"}, {"content": "NO"}, {"content": "NOT GIVEN"}], "question": "Mario Bellini’s work on subsequent museum projects has been less successful than that on the NGV"}, {"correct": 2, "options": [{"content": "YES"}, {"content": "NO"}, {"content": "NOT GIVEN"}], "question": "The NGV monitors the number of first-time visitors to permanent collections"}, {"correct": 0, "options": [{"content": "YES"}, {"content": "NO"}, {"content": "NOT GIVEN"}], "question": "Too much change may have negative impacts on museums"}]', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"14\"><strong data-path-to-node=\"14\" data-index-in-node=\"0\">31. Roy Grounds’s design failed to recognise the importance of functions and performances in museums.</strong></p>\n<ul data-path-to-node=\"15\">\n<li>\n<p data-path-to-node=\"15,0,0\"><strong data-path-to-node=\"15,0,0\" data-index-in-node=\"0\">Đáp án:</strong> <strong data-path-to-node=\"15,0,0\" data-index-in-node=\"8\">NO</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"15,1,0\"><strong data-path-to-node=\"15,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…a vast Great Hall, which represented an unprecedented emphasis on the ancillary roles of corporate functions and public performances…”</p>\n</li>\n<li>\n<p data-path-to-node=\"15,2,0\"><strong data-path-to-node=\"15,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Ngược lại với câu hỏi, thiết kế của Roy Grounds đã rất chú trọng đến các chức năng phụ trợ và biểu diễn công cộng thông qua sảnh Great Hall.</p>\n</li>\n</ul>\n<p data-path-to-node=\"16\"><strong data-path-to-node=\"16\" data-index-in-node=\"0\">32. Mario Bellini’s new NGV rejects international museum design trends.</strong></p>\n<ul data-path-to-node=\"17\">\n<li>\n<p data-path-to-node=\"17,0,0\"><strong data-path-to-node=\"17,0,0\" data-index-in-node=\"0\">Đáp án:</strong> <strong data-path-to-node=\"17,0,0\" data-index-in-node=\"8\">NO</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"17,1,0\"><strong data-path-to-node=\"17,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…his design reflects what the new, improved, twenty-first-century global museum feels it should be emphasizing to its visitors.”</p>\n</li>\n<li>\n<p data-path-to-node=\"17,2,0\"><strong data-path-to-node=\"17,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Thiết kế của Bellini thực chất là đang “phản ánh” (reflects) các xu hướng bảo tàng toàn cầu thế kỷ 21 chứ không phải bác bỏ chúng.</p>\n</li>\n</ul>\n<p data-path-to-node=\"18\"><strong data-path-to-node=\"18\" data-index-in-node=\"0\">33. Mario Bellini’s work on subsequent museum projects has been less successful than that on the NGV.</strong></p>\n<ul data-path-to-node=\"19\">\n<li>\n<p data-path-to-node=\"19,0,0\"><strong data-path-to-node=\"19,0,0\" data-index-in-node=\"0\">Đáp án:</strong> <strong data-path-to-node=\"19,0,0\" data-index-in-node=\"8\">NOT GIVEN</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"19,1,0\"><strong data-path-to-node=\"19,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài đọc chỉ tập trung vào công việc của Bellini tại NGV, không có thông tin so sánh với các dự án sau đó của ông.</p>\n</li>\n</ul>\n<p data-path-to-node=\"20\"><strong data-path-to-node=\"20\" data-index-in-node=\"0\">34. The NGV monitors the number of first-time visitors to permanent collections.</strong></p>\n<ul data-path-to-node=\"21\">\n<li>\n<p data-path-to-node=\"21,0,0\"><strong data-path-to-node=\"21,0,0\" data-index-in-node=\"0\">Đáp án:</strong> <strong data-path-to-node=\"21,0,0\" data-index-in-node=\"8\">NOT GIVEN</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"21,1,0\"><strong data-path-to-node=\"21,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Mặc dù bài đọc có nhắc đến “first-time visitors”, nhưng không có thông tin nào nói về việc bảo tàng có “monitor” (theo dõi/giám sát) con số này hay không.</p>\n</li>\n</ul>\n<p data-path-to-node=\"22\"><strong data-path-to-node=\"22\" data-index-in-node=\"0\">35. Too much change may have negative impacts on museums.</strong></p>\n<ul data-path-to-node=\"23\">\n<li>\n<p data-path-to-node=\"23,0,0\"><strong data-path-to-node=\"23,0,0\" data-index-in-node=\"0\">Đáp án:</strong> <strong data-path-to-node=\"23,0,0\" data-index-in-node=\"8\">YES</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"23,1,0\"><strong data-path-to-node=\"23,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…and the effect of too much innovation in museums can be disastrous.”</p>\n</li>\n<li>\n<p data-path-to-node=\"23,2,0\"><strong data-path-to-node=\"23,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Tác giả khẳng định việc đổi mới quá mức có thể gây ra những hậu quả thảm khốc (disastrous), tương ứng với “negative impacts”.</p>\n</li>\n</ul>\n"}]', 1);
INSERT INTO public.questions VALUES ('95adf211-e040-420f-a155-1fd86ed628de', 'a9ae40e8-ea16-461f-b107-21307b1f3c03', 'fillup', 'Questions 21 – 27', '<p>Complete the notes below.</p>
<p>Choose <strong>NO MORE THAN TWO WORDS AND/OR A NUMBER</strong> from the text for each answer.</p>
<p>Write your answers in boxes 21-27 on your answer sheet.</p>
<p style="text-align: center;"><span style="font-size: 12pt;"><strong><br>New Zealand Police Entry Requirements</strong></span></p>
<p><strong>Fitness requirements </strong></p>
<p>Applicants must:</p>
<ul>
<li>
<p>be healthy and fit, but there’s no restriction on {height}</p>
</li>
<li>
<p>be able to perform a minimum number of {press-ups} without stopping</p>
</li>
<li>
<p>have a powerful {grip} in order to arrest offenders</p>
</li>
<li>
<p>be able to swim {50 meters} in a specified time</p>
</li>
</ul>
<p><strong>Psychometric &amp; Personality Assessment</strong></p>
<ul>
<li>
<p>test of ability to understand relationships and find solutions</p>
</li>
<li>
<p>assessments of personality focus on {emotional characteristics } as well as the way you communicate with other people</p>
</li>
</ul>
<p><strong>Other requirements</strong></p>
<ul>
<li>
<p>must be able to achieve at least 25 words a minute when {copy tying}</p>
</li>
<li>
<p>{driving license}essential prior to application</p>
</li>
<li>
<p>minimum of three referees to guarantee how appropriate applicants are for a police career</p>
</li>
</ul>', '', 'summary_completion', 'null', 'null', 'null', 'null', '[{"content": "<p><strong data-path-to-node=\"4\" data-index-in-node=\"0\">21. be healthy and fit, but there’s no restriction on {height}</strong></p>\n<ul data-path-to-node=\"5\">\n<li><strong data-path-to-node=\"5,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"5,0,0\" data-index-in-node=\"11\">“Applicants must be in good physical condition and in excellent health. There isn’t a minimum <strong data-path-to-node=\"5,0,0\" data-index-in-node=\"105\">height</strong> requirement.”</em></li>\n<li><strong data-path-to-node=\"5,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “No restriction” (không hạn chế) đồng nghĩa với việc không có yêu cầu tối thiểu (<em data-path-to-node=\"5,1,0\" data-index-in-node=\"93\">no minimum requirement</em>) về chiều cao.</li>\n</ul>\n<p><strong data-path-to-node=\"6\" data-index-in-node=\"0\">22. be able to perform a minimum number of {press-ups} without stopping</strong></p>\n<ul data-path-to-node=\"7\">\n<li><strong data-path-to-node=\"7,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"7,0,0\" data-index-in-node=\"11\">“How many correctly executed continuous <strong data-path-to-node=\"7,0,0\" data-index-in-node=\"51\">press-ups</strong> you can do. For men this should be 34 or more; for women, 20 or more.”</em></li>\n<li><strong data-path-to-node=\"7,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “Continuous” (liên tục) tương ứng với “without stopping” (không dừng lại). Bài tập cần thực hiện ở đây là chống đẩy (<strong data-path-to-node=\"7,1,0\" data-index-in-node=\"129\">press-ups</strong>).</li>\n</ul>\n<p><strong data-path-to-node=\"8\" data-index-in-node=\"0\">23. have a powerful {grip} in order to arrest offenders</strong></p>\n<ul data-path-to-node=\"9\">\n<li><strong data-path-to-node=\"9,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"9,0,0\" data-index-in-node=\"11\">“A test of your <strong data-path-to-node=\"9,0,0\" data-index-in-node=\"27\">grip</strong> which ensures you are strong enough to operate firearms and to restrain and handcuff people.”</em></li>\n<li><strong data-path-to-node=\"9,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “Arrest offenders” (bắt giữ tội phạm) là cách nói khái quát của việc khống chế và còng tay người khác (<em data-path-to-node=\"9,1,0\" data-index-in-node=\"115\">restrain and handcuff</em>). Để làm việc này, ứng viên cần có lực nắm bàn tay (<strong data-path-to-node=\"9,1,0\" data-index-in-node=\"189\">grip</strong>) mạnh mẽ.</li>\n</ul>\n<p><strong data-path-to-node=\"10\" data-index-in-node=\"0\">24. be able to swim {50 metres} in a specified time</strong></p>\n<ul data-path-to-node=\"11\">\n<li><strong data-path-to-node=\"11,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"11,0,0\" data-index-in-node=\"11\">“This involves covering <strong data-path-to-node=\"11,0,0\" data-index-in-node=\"35\">50 metres</strong> within 54 seconds…”</em></li>\n<li><strong data-path-to-node=\"11,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “Covering” trong bơi lội nghĩa là bơi được quãng đường đó. “Within 54 seconds” chính là một khoảng thời gian xác định (<em data-path-to-node=\"11,1,0\" data-index-in-node=\"131\">specified time</em>).</li>\n</ul>\n<p><strong data-path-to-node=\"12\" data-index-in-node=\"0\">25. assessments of personality focus on {emotional characteristics} as well as the way you communicate with other people</strong></p>\n<ul data-path-to-node=\"13\">\n<li><strong data-path-to-node=\"13,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"13,0,0\" data-index-in-node=\"11\">“The personality assessment provides… a guide as to what motivates you, what <strong data-path-to-node=\"13,0,0\" data-index-in-node=\"90\">emotional characteristics</strong> you have, and how you handle interpersonal interactions.”</em></li>\n<li><strong data-path-to-node=\"13,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “Interpersonal interactions” (tương tác giữa cá nhân) đồng nghĩa với “the way you communicate with other people”. Yếu tố còn lại được nhấn mạnh là đặc điểm cảm xúc (<strong data-path-to-node=\"13,1,0\" data-index-in-node=\"177\">emotional characteristics</strong>).</li>\n</ul>\n<p><strong data-path-to-node=\"14\" data-index-in-node=\"0\">26. must be able to achieve at least 25 words a minute when {copy typing}</strong></p>\n<ul data-path-to-node=\"15\">\n<li><strong data-path-to-node=\"15,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"15,0,0\" data-index-in-node=\"11\">“…do a 10-minute test to assess <strong data-path-to-node=\"15,0,0\" data-index-in-node=\"45\">copy typing</strong>. The minimum speed is 25 words per minute.”</em></li>\n<li><strong data-path-to-node=\"15,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài kiểm tra kỹ năng máy tính yêu cầu tốc độ tối thiểu (<em data-path-to-node=\"15,1,0\" data-index-in-node=\"68\">at least</em>) là 25 từ/phút đối với kỹ năng đánh máy văn bản có sẵn (<strong data-path-to-node=\"15,1,0\" data-index-in-node=\"133\">copy typing</strong>).</li>\n</ul>\n<p><strong data-path-to-node=\"16\" data-index-in-node=\"0\">27. {driving licence} essential prior to application</strong></p>\n<ul data-path-to-node=\"17\">\n<li><strong data-path-to-node=\"17,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"17,0,0\" data-index-in-node=\"11\">“…you do need a <strong data-path-to-node=\"17,0,0\" data-index-in-node=\"29\">driving licence</strong> before you apply.”</em></li>\n<li><strong data-path-to-node=\"17,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “Essential” (cần thiết/bắt buộc) tương ứng với “do need”, và “prior to application” (trước khi nộp đơn) tương ứng với “before you apply”.</li>\n</ul>"}]', 1);
INSERT INTO public.questions VALUES ('cac9c126-307a-4e94-b4ea-fd31c24bab2b', 'a6870343-14eb-4b90-9abd-db97958fe03c', 'checkbox', 'Questions 21 and 22', '', '<p>Choose <strong data-path-to-node="13" data-index-in-node="7">TWO</strong> letters, <strong data-path-to-node="13" data-index-in-node="20">A–E</strong>.</p>
<p>Which <strong data-path-to-node="4" data-index-in-node="6">TWO</strong> things did Colin find most satisfying about his bread reuse project?</p>', 'multiple_choice', 'null', '[{"correct": false, "option_text": "A receiving support from local restaurants"}, {"correct": true, "option_text": "B finding a good way to prevent waste"}, {"correct": false, "option_text": "C overcoming problems in a basic process"}, {"correct": true, "option_text": "D experimenting with designs and colours"}, {"correct": false, "option_text": "E learning how to apply 3-D printing"}]', 'null', 'null', 'null', 0);
INSERT INTO public.questions VALUES ('5941555b-cae2-45b4-8db3-5c6adb8cc264', '1a22bea1-67c8-4ced-a7bf-1cdd27cc1f7f', 'radio', 'Questions 9–13 ', '', '<p>Choose <strong>TRUE </strong>if the statement agrees with the information . <strong>FALSE </strong>if the statement contradicts the information . <strong>NOT GIVEN </strong>if there is no information on this</p>', 'true_false_not_given', '[{"correct": 2, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "Tull was employed in the legal profession before taking up farming."}, {"correct": 0, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "The staff on Tull''s farm were unwilling to follow his instructions."}, {"correct": 0, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "Tull reduced the amount of weeds in his Wheatfield. "}, {"correct": 1, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "Tull lived to see his ideas finally accepted. "}, {"correct": 2, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "Tull''s original book, published in 1731, sold very few copies."}]', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"25\"><strong data-path-to-node=\"25\" data-index-in-node=\"0\">9. Tull was employed in the legal profession before taking up farming.</strong> </p>\n<ul>\n<li style=\"line-height: 1.5;\"><strong data-path-to-node=\"28,0,0\" data-index-in-node=\"0\">Đáp án: </strong><strong>NOT GIVEN</strong> </li>\n<li style=\"line-height: 1.5;\"><strong>Dẫn chứng</strong> (Đoạn 1)<strong>:</strong> “He studied first at Oxford University and then at the Inns of Court, London, in preparation for a legal or political career. However, his health issues forced him to postpone these plans, and after qualifying as a barrister in 1699… the young Tull married, then began farming with his father…”</li>\n<li style=\"line-height: 1.5;\"><strong>Giải thích: </strong>Bài đọc chỉ cho biết Tull học để chuẩn bị cho nghề luật/chính trị và sau đó đủ điều kiện trở thành một barrister (luật sư). Tuy nhiên, bài không hề nói ông thực sự làm việc hay được tuyển dụng trong ngành luật trước khi chuyển sang làm nông. Vì vậy, thông tin trong câu hỏi không được đề cập rõ trong bài.</li>\n</ul>\n<p data-path-to-node=\"14\"><strong data-path-to-node=\"16\" data-index-in-node=\"0\">10. The staff on Tull’s farm were unwilling to follow his instructions.</strong></p>\n<ul data-path-to-node=\"17\">\n<li>\n<p data-path-to-node=\"17,0,0\"><strong data-path-to-node=\"17,0,0\" data-index-in-node=\"0\">Đáp án:</strong> {TRUE}</p>\n</li>\n<li>\n<p data-path-to-node=\"17,1,0\"><strong data-path-to-node=\"17,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…his frustration with their <strong data-path-to-node=\"17,1,0\" data-index-in-node=\"42\">lack of co-operation</strong> prompted him to invent a machine…” (Đoạn B)</p>\n</li>\n<li>\n<p data-path-to-node=\"17,2,0\"><strong data-path-to-node=\"17,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Việc nhân viên thiếu hợp tác (lack of co-operation) chính là sự “không sẵn lòng” (unwilling) tuân thủ hướng dẫn gieo hạt mật độ thấp của Tull.</p>\n</li>\n</ul>\n<p data-path-to-node=\"18\"><strong data-path-to-node=\"18\" data-index-in-node=\"0\">11. Tull reduced the amount of weeds in his Wheatfield.</strong></p>\n<ul data-path-to-node=\"19\">\n<li>\n<p data-path-to-node=\"19,0,0\"><strong data-path-to-node=\"19,0,0\" data-index-in-node=\"0\">Đáp án:</strong> {TRUE}</p>\n</li>\n<li>\n<p data-path-to-node=\"19,1,0\"><strong data-path-to-node=\"19,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…it is more likely that it was the turning over… that <strong data-path-to-node=\"19,1,0\" data-index-in-node=\"70\">cut down on the volume of weeds</strong>…” (Đoạn D)</p>\n</li>\n<li>\n<p data-path-to-node=\"19,2,0\"><strong data-path-to-node=\"19,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Mặc dù Tull nhầm về việc xới đất thay thế được phân bón, nhưng hành động này thực tế đã giúp giảm đáng kể lượng cỏ dại (cut down on the volume of weeds).</p>\n</li>\n</ul>\n<p data-path-to-node=\"20\"><strong data-path-to-node=\"20\" data-index-in-node=\"0\">12. Tull lived to see his ideas finally accepted.</strong></p>\n<ul data-path-to-node=\"21\">\n<li>\n<p data-path-to-node=\"21,0,0\"><strong data-path-to-node=\"21,0,0\" data-index-in-node=\"0\">Đáp án:</strong> {FALSE}</p>\n</li>\n<li>\n<p data-path-to-node=\"21,1,0\"><strong data-path-to-node=\"21,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “Another <strong data-path-to-node=\"21,1,0\" data-index-in-node=\"20\">century would pass</strong> before his eventual vindication. …in his lifetime Tull’s methods… were <strong data-path-to-node=\"21,1,0\" data-index-in-node=\"114\">dismissed and ridiculed</strong>.” (Đoạn E)</p>\n</li>\n<li>\n<p data-path-to-node=\"21,2,0\"><strong data-path-to-node=\"21,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Suốt đời ông chỉ bị chế giễu và bác bỏ. Phải một thế kỷ sau khi ông mất, các ý tưởng của ông mới được chấp nhận rộng rãi.</p>\n</li>\n</ul>\n<p data-path-to-node=\"22\"><strong data-path-to-node=\"22\" data-index-in-node=\"0\">13. Tull’s original book, published in 1731, sold very few copies.</strong></p>\n<ul data-path-to-node=\"23\">\n<li>\n<p data-path-to-node=\"23,0,0\"><strong data-path-to-node=\"23,0,0\" data-index-in-node=\"0\">Đáp án:</strong> {NOT GIVEN}</p>\n</li>\n<li>\n<p data-path-to-node=\"23,1,0\"><strong data-path-to-node=\"23,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “The book caused <strong data-path-to-node=\"23,1,0\" data-index-in-node=\"28\">great controversy</strong> when it appeared…” (Đoạn E)</p>\n</li>\n<li>\n<p data-path-to-node=\"23,2,0\"><strong data-path-to-node=\"23,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài đọc chỉ nói cuốn sách gây ra “tranh cãi lớn”, nhưng <strong data-path-to-node=\"23,2,0\" data-index-in-node=\"68\">không cung cấp số liệu</strong> hay thông tin nào về việc doanh số bán sách là cao hay thấp.</p>\n</li>\n</ul>"}]', 2);
INSERT INTO public.questions VALUES ('828439c8-538a-4ab4-90de-082317080285', 'cd88bdfd-28b0-464c-9429-cc3d3bd82092', 'matching', 'Questions 36-40', '', '<p>Complete each sentence with the correct ending, A–G, below.</p>', 'matching_sentence_endings', 'null', 'null', '{"layoutType": "standard", "summaryText": "", "answerOptions": [{"optionText": "The museum programme will lose its individuality"}, {"optionText": "The museum will lose credibility"}, {"optionText": "The art loses its importance"}, {"optionText": "It will have to balance opposing demands"}, {"optionText": "This will encourage museum visitors in the future"}, {"optionText": "It will have the capability of increasing revenue"}, {"optionText": "The architect’s reputation might suffer"}], "matchingItems": [{"questionPart": "If a large space is available in the museum", "correctAnswer": "F"}, {"questionPart": "If children are allowed to move freely in parts of the gallery", "correctAnswer": "E"}, {"questionPart": "If too much emphasis is placed on the museum building itself", "correctAnswer": "C"}, {"questionPart": "If there is an over-reliance on blockbuster exhibitions", "correctAnswer": "A"}, {"questionPart": "If the NGV wants to continue to be successful", "correctAnswer": "D"}]}', 'null', '[{"content": "<p data-path-to-node=\"26\"><strong data-path-to-node=\"26\" data-index-in-node=\"0\">36. If a large space is available in the museum, (F)</strong></p>\n<ul data-path-to-node=\"27\">\n<li>\n<p data-path-to-node=\"27,0,0\"><strong data-path-to-node=\"27,0,0\" data-index-in-node=\"0\">Đáp án:</strong> <strong data-path-to-node=\"27,0,0\" data-index-in-node=\"8\">F (It will have the capability of increasing revenue.)</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"27,1,0\"><strong data-path-to-node=\"27,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…emphasis on corporate sponsorship and the need to generate additional funds via room hire [in the Great Hall].”</p>\n</li>\n<li>\n<p data-path-to-node=\"27,2,0\"><strong data-path-to-node=\"27,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Không gian lớn (như Great Hall) cho phép bảo tàng cho thuê phòng để tổ chức sự kiện, từ đó tăng doanh thu.</p>\n</li>\n</ul>\n<p data-path-to-node=\"28\"><strong data-path-to-node=\"28\" data-index-in-node=\"0\">37. If children are allowed to move freely in parts of the gallery, (E)</strong></p>\n<ul data-path-to-node=\"29\">\n<li>\n<p data-path-to-node=\"29,0,0\"><strong data-path-to-node=\"29,0,0\" data-index-in-node=\"0\">Đáp án:</strong> <strong data-path-to-node=\"29,0,0\" data-index-in-node=\"8\">E (This will encourage museum visitors in the future.)</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"29,1,0\"><strong data-path-to-node=\"29,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “As an unintimidating introduction to the lifelong rigors of visiting art museums, its impact on attendance cannot be overestimated.”</p>\n</li>\n<li>\n<p data-path-to-node=\"29,2,0\"><strong data-path-to-node=\"29,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Việc trẻ em được tự do khám phá giúp chúng không cảm thấy sợ bảo tàng, tạo thói quen đi bảo tàng suốt đời (lifelong rigors).</p>\n</li>\n</ul>\n<p data-path-to-node=\"30\"><strong data-path-to-node=\"30\" data-index-in-node=\"0\">38. If too much emphasis is placed on the museum building itself, (C)</strong></p>\n<ul data-path-to-node=\"31\">\n<li>\n<p data-path-to-node=\"31,0,0\"><strong data-path-to-node=\"31,0,0\" data-index-in-node=\"0\">Đáp án:</strong> <strong data-path-to-node=\"31,0,0\" data-index-in-node=\"8\">C (The art loses its importance.)</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"31,1,0\"><strong data-path-to-node=\"31,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…construction of new buildings that supplant the artworks inside them, becoming the major attractions themselves.”</p>\n</li>\n<li>\n<p data-path-to-node=\"31,2,0\"><strong data-path-to-node=\"31,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Khi tòa nhà trở thành điểm thu hút chính, nó sẽ “thay thế” (supplant) và làm giảm đi tầm quan trọng của các tác phẩm nghệ thuật bên trong.</p>\n</li>\n</ul>\n<p data-path-to-node=\"32\"><strong data-path-to-node=\"32\" data-index-in-node=\"0\">39. If there is an over-reliance on blockbuster exhibitions, (A)</strong></p>\n<ul data-path-to-node=\"33\">\n<li>\n<p data-path-to-node=\"33,0,0\"><strong data-path-to-node=\"33,0,0\" data-index-in-node=\"0\">Đáp án:</strong> <strong data-path-to-node=\"33,0,0\" data-index-in-node=\"8\">A (The museum programme will lose its individuality.)</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"33,1,0\"><strong data-path-to-node=\"33,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…cannot help but introduce a certain ‘off-the-rack’ feeling to the institution’s exhibition program.”</p>\n</li>\n<li>\n<p data-path-to-node=\"33,2,0\"><strong data-path-to-node=\"33,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Các triển lãm thuê mướn (rental blockbusters) làm chương trình của bảo tàng trở nên “may sẵn” (off-the-rack), đánh mất đi bản sắc riêng (individuality).</p>\n</li>\n</ul>\n<p data-path-to-node=\"34\"><strong data-path-to-node=\"34\" data-index-in-node=\"0\">40. If the NGV wants to continue to be successful, (D)</strong></p>\n<ul data-path-to-node=\"35\">\n<li>\n<p data-path-to-node=\"35,0,0\"><strong data-path-to-node=\"35,0,0\" data-index-in-node=\"0\">Đáp án:</strong> <strong data-path-to-node=\"35,0,0\" data-index-in-node=\"8\">D (It will have to balance opposing demands.)</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"35,1,0\"><strong data-path-to-node=\"35,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…needs to be able to juggle numerous, often conflicting priorities…”</p>\n</li>\n<li>\n<p data-path-to-node=\"35,2,0\"><strong data-path-to-node=\"35,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Để thành công, bảo tàng phải “tung hứng” (juggle) hay chính là cân bằng giữa các ưu tiên trái ngược nhau (học thuật vs tiếp cận đại chúng).</p>\n</li>\n</ul>\n"}]', 2);
INSERT INTO public.questions VALUES ('c87a9b44-b7ce-40aa-b2c2-0c952f761777', '619fba5b-6c8a-4832-b674-507928c622a3', 'matrix', 'Questions 27–31', NULL, '<p>Reading Passage 3 has seven paragraphs, <strong>A–G</strong>.</p>
<p>Which paragraph contains the following information?</p>
<p><strong>NB</strong> You may use any letter more than once.</p>
', 'other', NULL, '[{"option": "A", "correct": false}, {"option": "B", "correct": false}, {"option": "C", "correct": false}, {"option": "D", "correct": false}, {"option": "E", "correct": false}, {"option": "F", "correct": false}, {"option": "G", "correct": false}]', '{"layoutType": "standard", "summaryText": null, "answerOptions": null, "matchingItems": null}', '{"layoutType": "simple", "legendTitle": null, "matrixItems": [{"itemText": "an example of how one predator has been protected by the introduction of livestock guard dogs", "correctCategoryLetter": "D"}, {"itemText": "an optimistic suggestion about the possible positive developments in the use of livestock guard dogs", "correctCategoryLetter": "G"}, {"itemText": "a description of how the methods used by livestock guard dogs help to keep predators away", "correctCategoryLetter": "B"}, {"itemText": "claims by different academics that the use of livestock guard dogs is a successful way of protecting farmers’ herds", "correctCategoryLetter": "C"}, {"itemText": "a reference to how livestock guard dogs gain their skills", "correctCategoryLetter": "B"}], "matrixCategories": [{"categoryText": "A", "categoryLetter": "A"}, {"categoryText": "B", "categoryLetter": "B"}, {"categoryText": "C", "categoryLetter": "C"}, {"categoryText": "D", "categoryLetter": "D"}, {"categoryText": "E", "categoryLetter": "E"}, {"categoryText": "F", "categoryLetter": "F"}, {"categoryText": "G", "categoryLetter": "G"}]}', '[{"content": "<p>27. D<br />(Đoạn D: “In Namibia… When guard dogs were introduced, more than 90% of farmers reported a dramatic reduction in livestock losses, and said that as a result they were less likely to kill predators.”)<br />→ Nhờ có chó bảo vệ gia súc, nông dân ở Namibia ngừng giết báo cheetah – giúp loài săn mồi này được bảo tồn. → D.</p>\n<p> <br />28. G<br />(Đoạn G: “&#8230;there may be a bright future for guard dogs in promoting harmonious coexistence between humans and wildlife.”)<br />→ Câu thể hiện niềm lạc quan về triển vọng tích cực của việc sử dụng chó bảo vệ trong tương lai. → G.</p>\n<p> <br />29. B<br />(Đoạn B: “&#8230;they will place themselves between the livestock and any threat, barking loudly. If necessary, they will chase away predators, but often their mere presence is sufficient.”)<br />→ Mô tả cách chó bảo vệ gia súc hoạt động: đứng chắn giữa đàn và kẻ thù, sủa to, đuổi hoặc chỉ cần xuất hiện. → B.</p>\n<p> <br />30. C<br />(Đoạn C: “&#8230;more than 90% of farmers&#8230; rate the performance of the dogs as very good or excellent&#8230; In Australia&#8230; predation stopped completely&#8230;” và “&#8230;most efficient control method.”)<br />→ Có dẫn chứng từ nhiều nhà khoa học khác nhau (Ribeiro, van Bommel) khẳng định chó bảo vệ là biện pháp hiệu quả. → C.</p>\n<p> <br />31. B<br />(Đoạn B: “These dogs are raised from an early age with the animals they will be watching&#8230; ‘Their initial training is to make them understand that livestock is going to be their life.’”)<br />→ Giải thích cách chó bảo vệ học kỹ năng – được nuôi cùng vật nuôi từ nhỏ để coi chúng là “gia đình”. → B.</p>\n"}, {"content": "<p>1</p>\n"}, {"content": "<p>1</p>\n"}, {"content": "<p>1</p>\n"}, {"content": "<p>1</p>\n"}]', 0);
INSERT INTO public.questions VALUES ('b66e17b6-d4a1-47fe-b994-d5763a6c0197', '47b99efa-22f0-40a8-97f6-c7890d0324e6', 'radio', 'Questions 25–30', NULL, '<p><strong data-start="74" data-end="115">Choose the correct letter, A, B or C.</strong></p>
<p style="text-align: center;" data-start="117" data-end="145"><strong data-start="121" data-end="145">Teaching handwriting</strong></p>
', 'multiple_choice_single', '[{"correct": 2, "options": [{"content": "A. Children often lack motivation to learn that way."}, {"content": "B. Children become fluent relatively quickly."}, {"content": "C. Children react more positively if they make a mistake."}], "question": "25. What does the woman say about using laptops to teach writing to children with dyslexia?"}, {"correct": 0, "options": [{"content": "A. cursive writing disadvantages a certain group of children."}, {"content": "B. print writing is associated with lower academic performance."}, {"content": "C. most teachers in the UK prefer a traditional approach to handwriting."}], "question": "26. When discussing whether to teach cursive or print writing, the woman thinks that"}, {"correct": 0, "options": [{"content": "A. There is evidence to suggest grades are affected by poor handwriting."}, {"content": "B. Neat handwriting is less important now than it used to be."}, {"content": "C. Candidates write more slowly and produce shorter answers."}], "question": "27. According to the students, what impact does poor handwriting have on exam performance?"}, {"correct": 1, "options": [{"content": "A. Touch typing will be taught before writing by hand."}, {"content": "B. Children will continue to learn to write by hand."}, {"content": "C. People will dislike handwriting on digital devices."}], "question": "28. What prediction does the man make about the future of handwriting?"}, {"correct": 1, "options": [{"content": "A. take detailed notes."}, {"content": "B. spell and punctuate."}, {"content": "C. read old documents."}], "question": "29. The woman is concerned that relying on digital devices has made it difficult for her to"}, {"correct": 2, "options": [{"content": "A. concerned they are unable to write quickly"}, {"content": "B. embarrassed by comments made about it"}, {"content": "C. regretful that they have lost the habit"}], "question": "30. How do the students feel about their own handwriting?"}]', NULL, '{"layoutType": ["standard"], "summaryText": null, "answerOptions": null, "matchingItems": null}', '{"layoutType": ["standard"], "legendTitle": null, "matrixItems": null, "matrixCategories": null}', '[{"content": "<p>1</p>\n"}, {"content": "<p>1</p>\n"}, {"content": "<p>1</p>\n"}, {"content": "<p>1</p>\n"}, {"content": "<p>1</p>\n"}, {"content": "<p>1</p>\n"}]', 2);
INSERT INTO public.questions VALUES ('d81600a2-131a-4786-907b-8eab8a23aaf2', '67f52183-7612-453f-999e-03cde874f5f6', 'radio', 'Questions 1–7', NULL, '<p>Choose <strong>TRUE </strong>if the statement agrees with the information given in the text, choose <strong>FALSE </strong>if the statement contradicts the information, or choose <strong>NOT GIVEN</strong> if there is no information on this.</p>
', 'multiple_choice_single', '[{"correct": 1, "options": [{"content": "TRUE"}, {"content": "FALSE"}, {"content": "NOT GIVEN"}], "question": "The Pyramid of Cestius has always been one of Rome''s most popular tourist attractions."}, {"correct": 2, "options": [{"content": "TRUE"}, {"content": "FALSE"}, {"content": "NOT GIVEN"}], "question": "The construction of the Pyramid was completed before Cestius'' death."}, {"correct": 0, "options": [{"content": "TRUE"}, {"content": "FALSE"}, {"content": "NOT GIVEN"}], "question": "In the Middle Ages, people thought an original founder of Rome was buried in the Pyramid of Cestius."}, {"correct": 1, "options": [{"content": "TRUE"}, {"content": "FALSE"}, {"content": "NOT GIVEN"}], "question": "Today the height of the Pyramid is something that tourists and residents immediately notice."}, {"correct": 2, "options": [{"content": "TRUE"}, {"content": "FALSE"}, {"content": "NOT GIVEN"}], "question": "Japanese businessman Yuzo Yagi was an admirer of both Italian and Egyptian architecture."}, {"correct": 0, "options": [{"content": "TRUE"}, {"content": "FALSE"}, {"content": "NOT GIVEN"}], "question": "The restoration of the Pyramid of Cestius, which was funded by Yuzo Yagi, finished earlier than expected."}, {"correct": 1, "options": [{"content": "TRUE"}, {"content": "FALSE"}, {"content": "NOT GIVEN"}], "question": "Most of the original frescoes inside Cestius'' tomb have survived to this day."}]', 'null', 'null', 'null', '[{"content": "<h3 data-path-to-node=\"2\"><strong data-path-to-node=\"2\" data-index-in-node=\"0\">1 The Pyramid of Cestius has always been one of Rome’s most popular tourist attractions.</strong></h3>\n<ul data-path-to-node=\"3\">\n<li>\n<p data-path-to-node=\"3,0,0\"><strong data-path-to-node=\"3,0,0\" data-index-in-node=\"0\">Đáp án: FALSE</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"3,1,0\"><strong data-path-to-node=\"3,1,0\" data-index-in-node=\"0\">Vị trí:</strong> Đoạn A, dòng 1–3.</p>\n</li>\n<li>\n<p data-path-to-node=\"3,2,0\"><strong data-path-to-node=\"3,2,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “Though Rome draws tourists from around the world to its many impressive sites, <strong data-path-to-node=\"3,2,0\" data-index-in-node=\"91\">one notable monument there has never attracted nearly as much interest: The Pyramid of Cestius.</strong>“</p>\n</li>\n<li>\n<p data-path-to-node=\"3,3,0\"><strong data-path-to-node=\"3,3,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài đọc khẳng định rằng kim tự tháp này <strong data-path-to-node=\"3,3,0\" data-index-in-node=\"52\">chưa bao giờ</strong> thu hút được nhiều sự quan tâm như các địa điểm khác ở Rome. Câu hỏi nói rằng nó “luôn là một trong những điểm thu hút khách nhất” là trái ngược hoàn toàn với thông tin trong bài.</p>\n</li>\n</ul>\n<h3 data-path-to-node=\"4\"><strong data-path-to-node=\"4\" data-index-in-node=\"0\">2 The construction of the Pyramid was completed before Cestius’ death.</strong></h3>\n<ul data-path-to-node=\"5\">\n<li>\n<p data-path-to-node=\"5,0,0\"><strong data-path-to-node=\"5,0,0\" data-index-in-node=\"0\">Đáp án: NOT GIVEN</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"5,1,0\"><strong data-path-to-node=\"5,1,0\" data-index-in-node=\"0\">Vị trí:</strong> Đoạn A, câu cuối.</p>\n</li>\n<li>\n<p data-path-to-node=\"5,2,0\"><strong data-path-to-node=\"5,2,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…the Pyramid of Cestius, was designed as the burial pyramid for a Roman politician named Caius Cestius, who <strong data-path-to-node=\"5,2,0\" data-index-in-node=\"122\">ordered that the building work be completed within a period of 330 days.</strong>“</p>\n</li>\n<li>\n<p data-path-to-node=\"5,3,0\"><strong data-path-to-node=\"5,3,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài đọc chỉ cho biết Cestius đã ra lệnh hoàn thành công trình trong vòng 330 ngày. Văn bản không cung cấp thông tin liệu việc xây dựng thực tế có xong trước khi ông qua đời hay không.</p>\n</li>\n</ul>\n<h3 data-path-to-node=\"6\"><strong data-path-to-node=\"6\" data-index-in-node=\"0\">3 In the Middle Ages, people thought an original founder of Rome was buried in the Pyramid of Cestius.</strong></h3>\n<ul data-path-to-node=\"7\">\n<li>\n<p data-path-to-node=\"7,0,0\"><strong data-path-to-node=\"7,0,0\" data-index-in-node=\"0\">Đáp án: TRUE</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"7,1,0\"><strong data-path-to-node=\"7,1,0\" data-index-in-node=\"0\">Vị trí:</strong> Đoạn D, dòng 1–4.</p>\n</li>\n<li>\n<p data-path-to-node=\"7,2,0\"><strong data-path-to-node=\"7,2,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “By the Middle Ages… popular myth had developed that it might be a <strong data-path-to-node=\"7,2,0\" data-index-in-node=\"80\">tomb for one of the twin brothers Romulus and Remus, who were regarded as the men who had established the city of Rome.</strong>“</p>\n</li>\n<li>\n<p data-path-to-node=\"7,3,0\"><strong data-path-to-node=\"7,3,0\" data-index-in-node=\"0\">Giải thích:</strong> Vào thời Trung cổ, có lời đồn rằng đây là mộ của Romulus hoặc Remus – những người được coi là đã sáng lập (established/founded) ra thành phố Rome. Điều này khớp hoàn toàn với câu hỏi.</p>\n</li>\n</ul>\n<h3 data-path-to-node=\"8\"><strong data-path-to-node=\"8\" data-index-in-node=\"0\">4 Today the height of the Pyramid is something that tourists and residents immediately notice.</strong></h3>\n<ul data-path-to-node=\"9\">\n<li>\n<p data-path-to-node=\"9,0,0\"><strong data-path-to-node=\"9,0,0\" data-index-in-node=\"0\">Đáp án: FALSE</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"9,1,0\"><strong data-path-to-node=\"9,1,0\" data-index-in-node=\"0\">Vị trí:</strong> Đoạn E, dòng 1–3.</p>\n</li>\n<li>\n<p data-path-to-node=\"9,2,0\"><strong data-path-to-node=\"9,2,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…passing <strong data-path-to-node=\"9,2,0\" data-index-in-node=\"23\">tourists and residents could easily fail to notice its full height</strong> of 119 feet.”</p>\n</li>\n<li>\n<p data-path-to-node=\"9,3,0\"><strong data-path-to-node=\"9,3,0\" data-index-in-node=\"0\">Giải thích:</strong> Do móng của kim tự tháp nằm dưới mặt đường và ở nơi giao thông đông đúc, du khách và người dân <strong data-path-to-node=\"9,3,0\" data-index-in-node=\"107\">rất dễ không nhận ra</strong> chiều cao đầy đủ của nó. Câu hỏi nói họ “nhận ra ngay lập tức” (immediately notice) là sai.</p>\n</li>\n</ul>\n<h3 data-path-to-node=\"10\"><strong data-path-to-node=\"10\" data-index-in-node=\"0\">5 Japanese businessman Yuzo Yagi was an admirer of both Italian and Egyptian architecture.</strong></h3>\n<ul data-path-to-node=\"11\">\n<li>\n<p data-path-to-node=\"11,0,0\"><strong data-path-to-node=\"11,0,0\" data-index-in-node=\"0\">Đáp án: NOT GIVEN</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"11,1,0\"><strong data-path-to-node=\"11,1,0\" data-index-in-node=\"0\">Vị trí:</strong> Đoạn E, dòng 6–8.</p>\n</li>\n<li>\n<p data-path-to-node=\"11,2,0\"><strong data-path-to-node=\"11,2,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “‘It’s an act of gratitude,’ he later told journalists. ‘<strong data-path-to-node=\"11,2,0\" data-index-in-node=\"68\">Our company has grown thanks to Italy.</strong>‘”</p>\n</li>\n<li>\n<p data-path-to-node=\"11,3,0\"><strong data-path-to-node=\"11,3,0\" data-index-in-node=\"0\">Giải thích:</strong> Ông Yagi tài trợ vì lòng biết ơn với nước Ý nơi công ty ông phát triển. Bài đọc không đề cập đến việc ông có ngưỡng mộ kiến trúc Ai Cập hay kiến trúc Ý hay không.</p>\n</li>\n</ul>\n<h3 data-path-to-node=\"12\"><strong data-path-to-node=\"12\" data-index-in-node=\"0\">6 The restoration of the Pyramid of Cestius, which was funded by Yuzo Yagi, finished earlier than expected.</strong></h3>\n<ul data-path-to-node=\"13\">\n<li>\n<p data-path-to-node=\"13,0,0\"><strong data-path-to-node=\"13,0,0\" data-index-in-node=\"0\">Đáp án: TRUE</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"13,1,0\"><strong data-path-to-node=\"13,1,0\" data-index-in-node=\"0\">Vị trí:</strong> Đoạn E, câu cuối.</p>\n</li>\n<li>\n<p data-path-to-node=\"13,2,0\"><strong data-path-to-node=\"13,2,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…and was <strong data-path-to-node=\"13,2,0\" data-index-in-node=\"23\">completed ahead of schedule</strong> thanks to his 2-million-euro contribution.”</p>\n</li>\n<li>\n<p data-path-to-node=\"13,3,0\"><strong data-path-to-node=\"13,3,0\" data-index-in-node=\"0\">Giải thích:</strong> Cụm từ “completed ahead of schedule” (hoàn thành trước thời hạn) đồng nghĩa với “finished earlier than expected” (xong sớm hơn dự kiến).</p>\n</li>\n</ul>\n<h3 data-path-to-node=\"14\"><strong data-path-to-node=\"14\" data-index-in-node=\"0\">7 Most of the original frescoes inside Cestius’ tomb have survived to this day.</strong></h3>\n<ul data-path-to-node=\"15\">\n<li>\n<p data-path-to-node=\"15,0,0\"><strong data-path-to-node=\"15,0,0\" data-index-in-node=\"0\">Đáp án: FALSE</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"15,1,0\"><strong data-path-to-node=\"15,1,0\" data-index-in-node=\"0\">Vị trí:</strong> Đoạn F, câu cuối.</p>\n</li>\n<li>\n<p data-path-to-node=\"15,2,0\"><strong data-path-to-node=\"15,2,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “We know from the writings of earlier visitors that there used to be more here, but the <strong data-path-to-node=\"15,2,0\" data-index-in-node=\"99\">majority have disappeared over time.</strong>“</p>\n</li>\n<li>\n<p data-path-to-node=\"15,3,0\"><strong data-path-to-node=\"15,3,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài đọc cho biết phần lớn (majority) các bức tranh tường đã biến mất theo thời gian. Câu hỏi nói “phần lớn vẫn còn tồn tại đến ngày nay” (most… survived) là sai.</p>\n</li>\n</ul>\n"}]', 0);
INSERT INTO public.questions VALUES ('2fd13d5a-575b-4235-98d7-ff089fa5d20e', 'e4316663-fc09-4a3a-ae32-f092a0fb2ac5', 'matrix', 'Questions 28 – 36', '', '<p data-path-to-node="3"><em data-path-to-node="3" data-index-in-node="94">Write the correct letter, <strong data-path-to-node="3" data-index-in-node="120">A-I</strong>, in boxes 28-36 on your answer sheet.</em></p>
<p data-path-to-node="4"><strong data-path-to-node="4" data-index-in-node="0">NB</strong> <em data-path-to-node="4" data-index-in-node="3">You may use any letter more than once.</em></p>', 'choose_a_title', 'null', 'null', 'null', '{"layoutType": "simple", "matrixItems": [{"itemText": "the disappearance of a traditional use of tidal power", "correctCategoryLetter": "B"}, {"itemText": "the predicted amount of power one tidal area could provide", "correctCategoryLetter": "A"}, {"itemText": "a decision to invest money in tidal power", "correctCategoryLetter": "B"}, {"itemText": "a general explanation of how tidal currents are created", "correctCategoryLetter": "C"}, {"itemText": "the damage that tidal power systems could cause", "correctCategoryLetter": "F"}, {"itemText": "the main benefits of placing equipment beneath the surface of the sea", "correctCategoryLetter": "H"}, {"itemText": "a nickname given to a dangerous area of water", "correctCategoryLetter": "A"}, {"itemText": "the ongoing testing of types of tidal power systems", "correctCategoryLetter": "I"}, {"itemText": "a way of dealing with periodic decreases in the energy produced by tidal power", "correctCategoryLetter": "E"}], "matrixCategories": [{"categoryText": "A", "categoryLetter": "A"}, {"categoryText": "B", "categoryLetter": "B"}, {"categoryText": "C", "categoryLetter": "C"}, {"categoryText": "D", "categoryLetter": "D"}, {"categoryText": "E", "categoryLetter": "E"}, {"categoryText": "F", "categoryLetter": "F"}, {"categoryText": "G", "categoryLetter": "G"}, {"categoryText": "H", "categoryLetter": "H"}, {"categoryText": "I", "categoryLetter": "I"}]}', '[{"content": "<p><strong data-path-to-node=\"4\" data-index-in-node=\"0\">28. The disappearance of a traditional use of tidal power — {B}</strong></p>\n<ul data-path-to-node=\"5\">\n<li><strong data-path-to-node=\"5,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"5,0,0\" data-index-in-node=\"11\">“People first started harnessing the sea’s powers over a thousand years ago, with water mills… But when the industrial revolution came along, the sea lost out to coal and oil.”</em></li>\n<li><strong data-path-to-node=\"5,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Việc sử dụng cối xay nước chạy bằng thủy triều là cách dùng truyền thống. Sự “biến mất” (disappearance) ở đây là do cuộc cách mạng công nghiệp khiến năng lượng biển bị thay thế bởi than đá và dầu mỏ.</li>\n</ul>\n<p><strong data-path-to-node=\"6\" data-index-in-node=\"0\">29. The predicted amount of power one tidal area could provide — {A}</strong></p>\n<ul data-path-to-node=\"7\">\n<li><strong data-path-to-node=\"7,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"7,0,0\" data-index-in-node=\"11\">“…enough energy in these flows alone to supply up to 10 per cent of Britain’s electricity.”</em></li>\n<li><strong data-path-to-node=\"7,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “10% điện năng của Anh” chính là con số dự đoán (predicted amount) về năng lượng mà khu vực Pentland Firth có thể cung cấp.</li>\n</ul>\n<p><strong data-path-to-node=\"8\" data-index-in-node=\"0\">30. A decision to invest money in tidal power — {G}</strong></p>\n<ul data-path-to-node=\"9\">\n<li><strong data-path-to-node=\"9,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"9,0,0\" data-index-in-node=\"11\">“…in the last three years both government and private financiers have finally made up their minds to back tidal energy projects.”</em></li>\n<li><strong data-path-to-node=\"9,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Cụm “made up their minds to back” (quyết định ủng hộ/hỗ trợ tài chính) chính là quyết định đầu tư tiền (invest money).</li>\n</ul>\n<p><strong data-path-to-node=\"10\" data-index-in-node=\"0\">31. A general explanation of how tidal currents are created — {C}</strong></p>\n<ul data-path-to-node=\"11\">\n<li><strong data-path-to-node=\"11,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"11,0,0\" data-index-in-node=\"11\">“Tidal currents are caused as the oceans bulge in response to the gravitational pull of the Moon and Sun.”</em></li>\n<li><strong data-path-to-node=\"11,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Câu này giải thích cơ chế hình thành dòng chảy thủy triều do lực hấp dẫn của Mặt Trăng và Mặt Trời.</li>\n</ul>\n<p><strong data-path-to-node=\"12\" data-index-in-node=\"0\">32. The damage that tidal power systems could cause — {F}</strong></p>\n<ul data-path-to-node=\"13\">\n<li><strong data-path-to-node=\"13,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"13,0,0\" data-index-in-node=\"11\">“They prevent fish migration and destroy highly sensitive marine habitats… could produce the world’s dirtiest stretch of water.”</em></li>\n<li><strong data-path-to-node=\"13,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Đoạn F liệt kê các tác hại (damage) như ngăn cản cá di cư, phá hủy môi trường sống và gây ô nhiễm nguồn nước.</li>\n</ul>\n<p><strong data-path-to-node=\"14\" data-index-in-node=\"0\">33. The main benefits of placing equipment beneath the surface of the sea — {H}</strong></p>\n<ul data-path-to-node=\"15\">\n<li><strong data-path-to-node=\"15,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"15,0,0\" data-index-in-node=\"11\">“The principal advantage is that the underwater environment is calm… water is 800 times denser than air… minimal intrusion on the view.”</em></li>\n<li><strong data-path-to-node=\"15,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Đoạn H nêu các lợi ích (benefits) của tuabin dưới nước: môi trường yên tĩnh, mật độ nước cao giúp thu nhiều năng lượng hơn và không gây mất mỹ quan (eyesore).</li>\n</ul>\n<p><strong data-path-to-node=\"16\" data-index-in-node=\"0\">34. A nickname given to a dangerous area of water — {A}</strong></p>\n<ul data-path-to-node=\"17\">\n<li><strong data-path-to-node=\"17,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"17,0,0\" data-index-in-node=\"11\">“…a hazardous stretch of water called the Pentland Firth… long known to sailors as ‘Hellsmouth’…”</em></li>\n<li><strong data-path-to-node=\"17,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “Hellsmouth” (Cửa địa ngục) chính là biệt danh (nickname) của vùng nước nguy hiểm này.</li>\n</ul>\n<p><strong data-path-to-node=\"18\" data-index-in-node=\"0\">35. The ongoing testing of types of tidal power systems — {I}</strong></p>\n<ul data-path-to-node=\"19\">\n<li><strong data-path-to-node=\"19,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"19,0,0\" data-index-in-node=\"11\">“Extensive trials of both the British and Norwegian designs are currently underway.”</em></li>\n<li><strong data-path-to-node=\"19,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “Trials… currently underway” tương ứng với việc thử nghiệm đang tiếp diễn (ongoing testing).</li>\n</ul>\n<p><strong data-path-to-node=\"20\" data-index-in-node=\"0\">36. A way of dealing with periodic decreases in the energy produced by tidal power — {E}</strong></p>\n<ul data-path-to-node=\"21\">\n<li><strong data-path-to-node=\"21,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"21,0,0\" data-index-in-node=\"11\">“…when there is a slowing in the speed… backup power from other sources can be fed into the power grid to meet demand.”</em></li>\n<li><strong data-path-to-node=\"21,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Cách giải quyết khi năng lượng giảm sút (periodic decreases) là sử dụng nguồn điện dự phòng (backup power) từ các nguồn khác.</li>\n</ul>"}]', 0);
INSERT INTO public.questions VALUES ('a66d1619-312f-4be3-b676-6cd2959325cf', '2a652167-fe58-4517-a8e2-1ada73982b30', 'matching', 'Questions 34-36', NULL, '<p>Complete each sentence with the correct ending, A–D, below.</p>
', 'matching_features', '[{"correct": null, "options": [{"content": null}], "question": null}]', '[{"option": "A", "correct": false}, {"option": "B", "correct": false}, {"option": "C", "correct": false}, {"option": "D", "correct": false}]', '{"layoutType": "standard", "summaryText": null, "answerOptions": [{"optionText": "robots to explore outer space."}, {"optionText": "advances made in machine intelligence so far."}, {"optionText": "changes made to other planets for our own benefit."}, {"optionText": "the harm already done by artificial intelligence."}], "matchingItems": [{"questionPart": "Richardson and Rees express similar views regarding the ethical aspect of", "correctAnswer": "changes made to other planets for our own benefit.", "sectionContent": null}, {"questionPart": "Rees and Wolpert share an opinion about the extent of", "correctAnswer": "advances made in machine intelligence so far.", "sectionContent": null}, {"questionPart": "Wolpert disagrees with Richardson on the question of", "correctAnswer": "the harm already done by artificial intelligence.", "sectionContent": null}]}', '{"layoutType": "standard", "legendTitle": null, "matrixItems": null, "matrixCategories": null}', '[{"content": "<p>34. Richardson and Rees express similar views regarding the ethical aspect of → C. advances made in machine intelligence so far<br />→ Cả hai đều nhấn mạnh yếu tố đạo đức trong sự phát triển trí tuệ nhân tạo.</p>\n<p> <br />35. Rees and Wolpert share an opinion about the extent of → B. robots to explore outer space<br />→ Cả hai đều thảo luận về việc robot được dùng để thám hiểm và khai thác không gian.</p>\n<p> <br />36. Wolpert disagrees with Richardson on the question of → D. the harm already done by artificial intelligence<br />→ Wolpert nói AI đã gây hại (virus, nhưng lợi ích vẫn lớn hơn), trong khi Richardson cho rằng robot chưa bao giờ gây hại thực sự.</p>\n"}, {"content": "<p>1</p>\n"}, {"content": "<p>1</p>\n"}]', 1);
INSERT INTO public.questions VALUES ('ef1acbfe-0fe8-4a65-818c-a61ca20e208f', 'bcceea6b-be4d-4e33-8c96-b175eafa0f51', 'radio', 'Questions 32-35', '', '<p id="p-rc_9f4a80f2939625f8-83" data-path-to-node="12,0,0"><span class="citation-2923">Choose</span><strong data-path-to-node="12,0,0" data-index-in-node="0"><span class="citation-2923"> YES</span></strong><span class="citation-2923 citation-end-2923"> if the statement agrees with the claims of the writer,<sup class="superscript" data-turn-source-index="3"><!----></sup></span><strong data-path-to-node="12,1,0" data-index-in-node="0"><span class="citation-2922">NO</span></strong><span class="citation-2922 citation-end-2922"> if the statement cont<sup class="superscript" data-turn-source-index="4"><!----></sup></span>radicts the claims of the writer,<!----><!----><!----><!----><!----><!----><!----><!----><strong data-path-to-node="12,2,0" data-index-in-node="0">NOT GIVEN</strong> if it is impossible to say what the writer thinks about this</p>
<div class="source-inline-chip-container ng-star-inserted"><!----><!----></div>
<p><!----><!----><!----><!----><!----><!----><!----><!----></p>
<div class="source-inline-chip-container ng-star-inserted"> </div>', 'yes_no_not_given', '[{"correct": 0, "options": [{"option_text": "YES"}, {"option_text": "NO"}, {"option_text": "NOT GIVEN"}], "question": "Game theory software may be unhelpful when dealing with political issues."}, {"correct": 1, "options": [{"option_text": "YES"}, {"option_text": "NO"}, {"option_text": "NOT GIVEN"}], "question": "Dr Milgrom was confident about applying his software to an auction in 2006."}, {"correct": 2, "options": [{"option_text": "YES"}, {"option_text": "NO"}, {"option_text": "NOT GIVEN"}], "question": "Dr Ponsati believes ''mediation machines'' are an inappropriate method of negotiation in areas other than business."}, {"correct": 2, "options": [{"option_text": "YES"}, {"option_text": "NO"}, {"option_text": "NOT GIVEN"}], "question": "Military organisations refuse to accept that software based on game theory could prevent wars."}]', 'null', 'null', 'null', '[{"content": "<p><strong data-path-to-node=\"4\" data-index-in-node=\"0\">32. Game theory software may be unhelpful when dealing with political issues. — {YES}</strong></p>\n<ul data-path-to-node=\"5\">\n<li><strong data-path-to-node=\"5,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 2):</strong> <em data-path-to-node=\"5,0,0\" data-index-in-node=\"20\">“…feeding software with accurate data on all the players involved is <strong data-path-to-node=\"5,0,0\" data-index-in-node=\"91\">especially tricky for political matters</strong>… Reinier van Oosten… notes that <strong data-path-to-node=\"5,0,0\" data-index-in-node=\"167\">predictions may become unreliable</strong> when people unexpectedly give in to ‘non-rational emotions’…”</em></li>\n<li><strong data-path-to-node=\"5,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Cụm “especially tricky” (đặc biệt khó khăn) và “unreliable” (không đáng tin cậy) đồng nghĩa với việc phần mềm có thể “không giúp ích nhiều” (<strong data-path-to-node=\"5,1,0\" data-index-in-node=\"153\">unhelpful</strong>) trong các vấn đề chính trị do yếu tố cảm xúc chi phối.</li>\n</ul>\n<p><strong data-path-to-node=\"6\" data-index-in-node=\"0\">33. Dr Milgrom was confident about applying his software to an auction in 2006. — {NO}</strong></p>\n<ul data-path-to-node=\"7\">\n<li><strong data-path-to-node=\"7,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 3):</strong> <em data-path-to-node=\"7,0,0\" data-index-in-node=\"20\">“<strong data-path-to-node=\"7,0,0\" data-index-in-node=\"21\">He was apprehensive at first</strong>, but the result was a triumph.”</em></li>\n<li><strong data-path-to-node=\"7,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Câu hỏi nói ông ấy “tự tin” (<strong data-path-to-node=\"7,1,0\" data-index-in-node=\"41\">confident</strong>), nhưng bài đọc lại dùng từ “<strong data-path-to-node=\"7,1,0\" data-index-in-node=\"80\">apprehensive</strong>” (lo lắng, e ngại). Vì hai thông tin này trái ngược nhau hoàn toàn nên đáp án là <strong data-path-to-node=\"7,1,0\" data-index-in-node=\"174\">NO</strong>.</li>\n</ul>\n<p><strong data-path-to-node=\"8\" data-index-in-node=\"0\">34. Dr Ponsati believes ‘mediation machines’ are an inappropriate method of negotiation in areas other than business. — {NOT GIVEN}</strong></p>\n<ul data-path-to-node=\"9\">\n<li><strong data-path-to-node=\"9,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 6):</strong> <em data-path-to-node=\"9,0,0\" data-index-in-node=\"20\">“Could mediation which has been achieved using software… spread from auction bids… to <strong data-path-to-node=\"9,0,0\" data-index-in-node=\"110\">resolving political and military disputes</strong>? Today’s game theory software is <strong data-path-to-node=\"9,0,0\" data-index-in-node=\"185\">not yet sufficiently advanced</strong> to mediate between warring countries.”</em></li>\n<li><strong data-path-to-node=\"9,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài đọc có nhắc đến việc hiện nay phần mềm chưa đủ tiên tiến để hòa giải các cuộc xung đột quốc gia, nhưng <strong data-path-to-node=\"9,1,0\" data-index-in-node=\"119\">không hề nói</strong> Dr Ponsati tin rằng đó là một phương pháp “không phù hợp” (<strong data-path-to-node=\"9,1,0\" data-index-in-node=\"191\">inappropriate</strong>). Thực tế, bà còn kỳ vọng vào khả năng của nó trong tương lai.</li>\n</ul>\n<p><strong data-path-to-node=\"10\" data-index-in-node=\"0\">35. Military organisations refuse to accept that software based on game theory could prevent wars. — {NOT GIVEN}</strong></p>\n<ul data-path-to-node=\"11\">\n<li><strong data-path-to-node=\"11,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 6):</strong> <em data-path-to-node=\"11,0,0\" data-index-in-node=\"20\">“According to some game theorists, opponents could learn how a war would turn out, skip the fighting and strike a deal.”</em></li>\n<li><strong data-path-to-node=\"11,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Tác giả có nêu ý tưởng của các nhà lý thuyết trò chơi về việc dùng phần mềm để ngăn chặn chiến tranh, nhưng <strong data-path-to-node=\"11,1,0\" data-index-in-node=\"120\">không có thông tin</strong> nào nói về phản ứng của các tổ chức quân sự (<strong data-path-to-node=\"11,1,0\" data-index-in-node=\"184\">military organisations</strong>) hay việc họ “từ chối chấp nhận” (<strong data-path-to-node=\"11,1,0\" data-index-in-node=\"241\">refuse to accept</strong>) điều này.</li>\n</ul>"}]', 1);
INSERT INTO public.questions VALUES ('bad93618-9022-4c78-b9bb-ce2b6125c346', 'e4316663-fc09-4a3a-ae32-f092a0fb2ac5', 'fillup', 'Questions 37 – 40', '<p>Complete the sentences below.</p>
<p>Choose <strong>NO MORE THAN TWO WORDS</strong> from the text for each answer.</p>
<p>Write your answers in boxes 37-40 on your answer sheet.</p>
<p><br> Stephen Salter invented a generator driven by {wave} energy.</p>
<p> It is feared that the construction of {barrages} may interfere with the migration of fish.</p>
<p> The motion of the {blades} of marine current turbines does not harm marine life.</p>
<p> A British firm has produced a {prototype} of a marine current turbine.</p>', '', 'summary_completion', 'null', 'null', 'null', 'null', '[{"content": "<p><strong data-path-to-node=\"4\" data-index-in-node=\"0\">37. Stephen Salter invented a generator driven by {wave} energy.</strong></p>\n<ul data-path-to-node=\"5\">\n<li><strong data-path-to-node=\"5,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"5,0,0\" data-index-in-node=\"11\">“Over thirty years ago, a Scottish professor, <strong data-path-to-node=\"5,0,0\" data-index-in-node=\"57\">Stephen Salter</strong>, led efforts to exploit <strong data-path-to-node=\"5,0,0\" data-index-in-node=\"96\">wave</strong> energy.”</em> (Đoạn D)</li>\n<li><strong data-path-to-node=\"5,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Giáo sư Stephen Salter nổi tiếng với thiết bị “Salter Duck” được thiết kế để khai thác năng lượng từ sóng biển (<strong data-path-to-node=\"5,1,0\" data-index-in-node=\"124\">wave energy</strong>).</li>\n</ul>\n<p><strong data-path-to-node=\"6\" data-index-in-node=\"0\">38. It is feared that the construction of {barrages} may interfere with the migration of fish.</strong></p>\n<ul data-path-to-node=\"7\">\n<li><strong data-path-to-node=\"7,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"7,0,0\" data-index-in-node=\"11\">“But such schemes (<strong data-path-to-node=\"7,0,0\" data-index-in-node=\"30\">barrages</strong>) can cause serious environmental problems. They prevent <strong data-path-to-node=\"7,0,0\" data-index-in-node=\"95\">fish migration</strong>…”</em> (Đoạn F)</li>\n<li><strong data-path-to-node=\"7,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Việc xây dựng các đập ngăn triều (<strong data-path-to-node=\"7,1,0\" data-index-in-node=\"46\">barrages</strong>) được cảnh báo là sẽ gây cản trở quá trình di cư của các loài cá.</li>\n</ul>\n<p><strong data-path-to-node=\"8\" data-index-in-node=\"0\">39. The motion of the {blades} of marine current turbines does not harm marine life.</strong></p>\n<ul data-path-to-node=\"9\">\n<li><strong data-path-to-node=\"9,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"9,0,0\" data-index-in-node=\"11\">“…the <strong data-path-to-node=\"9,0,0\" data-index-in-node=\"19\">blades</strong> move so slowly that marine creatures can easily swim through.”</em> (Đoạn H)</li>\n<li><strong data-path-to-node=\"9,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Chuyển động của các cánh quạt (<strong data-path-to-node=\"9,1,0\" data-index-in-node=\"43\">blades</strong>) trong tuabin dòng chảy biển rất chậm, giúp sinh vật biển có thể bơi qua an toàn mà không bị tổn thương.</li>\n</ul>\n<p><strong data-path-to-node=\"10\" data-index-in-node=\"0\">40. A British firm has produced a {prototype} of a marine current turbine.</strong></p>\n<ul data-path-to-node=\"11\">\n<li><strong data-path-to-node=\"11,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> <em data-path-to-node=\"11,0,0\" data-index-in-node=\"11\">“A <strong data-path-to-node=\"11,0,0\" data-index-in-node=\"14\">British company</strong>… has installed their <strong data-path-to-node=\"11,0,0\" data-index-in-node=\"53\">prototype</strong> off the coast of north Devon at Lynmouth.”</em> (Đoạn I)</li>\n<li><strong data-path-to-node=\"11,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Một công ty Anh (British company/firm) đã chế tạo và lắp đặt mô hình thử nghiệm đầu tiên (<strong data-path-to-node=\"11,1,0\" data-index-in-node=\"102\">prototype</strong>) cho loại tuabin này.</li>\n</ul>"}]', 1);
INSERT INTO public.questions VALUES ('8464894b-c198-4c72-9965-adfaa9c0f288', '169663be-90b6-4abd-80d7-5e993b51e7ef', 'fillup', 'Questions 1-10', '<p>Write <strong>NO MORE THAN TWO WORDS AND/OR A NUMBER</strong> for each answer.</p>
<p><strong>Caller record card</strong></p>
<p>Caller’s phone number: 03786 439 251</p>
<p>Caller’s name: Robert {Ridyard }</p>
<p>Address: {27 station road}, Moortown</p>
<p>Postcode: DP17 5HJ</p>
<p>Date of birth: {25th February| February 25th}</p>
<p>Doctor’s name: Dr. Craven</p>
<p>Doctor’s address: Moortown Health Centre</p>
<p>Reason for call: Pain in his {lower} back</p>
<p>Previous history: Similar back problem in June last year<br /><strong>Details of present problem:</strong></p>
<p>– Started {3 days} ago</p>
<p>– Got worse this {afternoon}</p>
<p>– No abdominal pain</p>
<p><strong>Possible cause: </strong>Lifting up a heavy {box}</p>
<p><strong>Treatment already applied:</strong></p>
<p>– Has applied heat</p>
<p>– Has taken {painkillers}</p>
<p><strong>Advice given:</strong></p>
<p>– Try using {ice}</p>
<p>– Go to doctor tomorrow</p>
<p>– Ask for information about {exercises}</p>
', NULL, 'gap_filling', 'null', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"3\"><strong>Narrator:</strong> You will hear a man with a problem with his back and a medical advisor. First you have some time to look at questions one to seven. Now listen carefully and answer questions one to seven.</p>\n<p data-path-to-node=\"4\"><strong>Advisor:</strong> Hello, this is Medical Help Direct, how can I help you?</p>\n<p data-path-to-node=\"5\"><strong>Robert:</strong> Oh hello, I’ve got a problem with my back, and with it being the middle of the night, I can’t go to the doctor, and I wonder if you can give me some advice.</p>\n<p data-path-to-node=\"6\"><strong>Advisor:</strong> Certainly, but first can I have your telephone number please? It’s 03786 439 251. Okay, and if you could give me your first name please.</p>\n<p data-path-to-node=\"7\"><strong>Robert:</strong> Robert.</p>\n<p data-path-to-node=\"8\"><strong>Advisor:</strong> And your surname.</p>\n<p data-path-to-node=\"9\"><strong>Robert:</strong> <strong>(1) Ridyard</strong>. That’s R-I-D-Y-A-R-D. And now your address please.</p>\n<p data-path-to-node=\"10\"><strong>Robert:</strong> It’s <strong>(2) 27 Station Road</strong>, okay, Moortown.</p>\n<p data-path-to-node=\"11\"><strong>Advisor:</strong> And do you need the postcode?</p>\n<p data-path-to-node=\"12\"><strong>Robert:</strong> Yes please. DP17 5HJ.</p>\n<p data-path-to-node=\"13\"><strong>Advisor:</strong> And your date of birth.</p>\n<p data-path-to-node=\"14\"><strong>Robert:</strong> The <strong>(3) 25th of February 1975</strong>.</p>\n<p data-path-to-node=\"15\"><strong>Advisor:</strong> Fine. Now I just need to take details of your doctor. She’s called Doctor Craven, and the surgery, it’s Moortown Health Centre. Thanks. Now, can you tell me a bit more about what the problem is?</p>\n<p data-path-to-node=\"16\"><strong>Robert:</strong> Well, like I said, it’s my back.</p>\n<p data-path-to-node=\"17\"><strong>Advisor:</strong> Okay, can you tell me which part of the back?</p>\n<p data-path-to-node=\"18\"><strong>Robert:</strong> <strong>(4) lower</strong>.</p>\n<p data-path-to-node=\"19\"><strong>Advisor:</strong> And have you had any problems with your back before?</p>\n<p data-path-to-node=\"20\"><strong>Robert:</strong> Yes, I had a bit of trouble last year in June I think, or was it July? No, we went on holiday at the beginning of July, and it had cleared up by then.</p>\n<p data-path-to-node=\"21\"><strong>Advisor:</strong> And when did it start this time? Has it just come on?</p>\n<p data-path-to-node=\"22\"><strong>Robert:</strong> No, I’ve had it, let’s see, since <strong>(5) Monday</strong> so that’s <strong>three Days</strong> now, but it wasn’t too bad at first. I mean I could just about get around, though I couldn’t drive the car or anything. Then this <strong>(6) afternoon</strong> the pain suddenly got so bad that I went to bed. I’ve been in bed since, but that hasn’t helped. And do you have any pain elsewhere, in your stomach or abdomen for example?</p>\n<p data-path-to-node=\"23\"><strong>Robert:</strong> No.</p>\n<hr data-path-to-node=\"24\">\n<p data-path-to-node=\"25\"><strong>Narrator:</strong> Before you hear the rest of the conversation, you have some time to look at questions seven to ten. Now listen and answer questions seven to ten.</p>\n<p data-path-to-node=\"26\"><strong>Advisor:</strong> Okay, now have you any idea what caused the problem?</p>\n<p data-path-to-node=\"27\"><strong>Robert:</strong> Well, I was tidying up my office, and I lifted a <strong>(7) box</strong> up from the floor that was heavier than I thought, and I think that’s what did it.</p>\n<p data-path-to-node=\"28\"><strong>Advisor:</strong> Yes, it’s easily done, isn’t it? So you’re in bed now? Have you tried applying heat to the back?</p>\n<p data-path-to-node=\"29\"><strong>Robert:</strong> Yes, I’ve got a hot water bottle, that’s usually the first thing I try.</p>\n<p data-path-to-node=\"30\"><strong>Advisor:</strong> And have you taken any <strong>(8) painkillers</strong>?</p>\n<p data-path-to-node=\"31\"><strong>Robert:</strong> Yes.</p>\n<p data-path-to-node=\"32\"><strong>Advisor:</strong> And other than that, you feel quite well?</p>\n<p data-path-to-node=\"33\"><strong>Robert:</strong> I do, yes.</p>\n<p data-path-to-node=\"34\"><strong>Advisor:</strong> Right, now I can’t diagnose or prescribe any medication, but I can offer you some advice. One thing you could do now is to see if <strong>(9) ice</strong> makes any difference. That sometimes helps, but don’t put it directly onto your skin, wrap it up in a towel or something, and don’t leave it on for longer than twenty minutes.</p>\n<p data-path-to-node=\"35\"><strong>Robert:</strong> All right, I haven’t tried that before.</p>\n<p data-path-to-node=\"36\"><strong>Advisor:</strong> It can be useful sometimes. Now have you seen your doctor about this?</p>\n<p data-path-to-node=\"37\"><strong>Robert:</strong> No, I just thought, well, everyone has back pain, but I’ve never had it as bad as this before.</p>\n<p data-path-to-node=\"38\"><strong>Advisor:</strong> I think you should go and see your doctor tomorrow, and she may be able to give you something to help. And you might get some advice from her about <strong>(10) exercises</strong>. That’s often the best way of dealing with this sort of problem.</p>\n<p data-path-to-node=\"39\"><strong>Robert:</strong> Okay, I’ll ask her. Right, now if you’re worried about anything before tomorrow, you can always phone back. Our lines are open twenty four hours.</p>\n<p data-path-to-node=\"40\"><strong>Robert:</strong> Thanks very much.</p>\n<p data-path-to-node=\"41\"><strong>Narrator:</strong> That is the end of Section One. You now have half a minute to check your answers.</p>\n"}]', 0);
INSERT INTO public.questions VALUES ('8c162fd0-3f03-454f-a3b5-0a98ed16e47a', '17f17493-09b2-4398-9692-ff581b8c8baa', 'matrix', 'Questions 37-40', NULL, '<p class="MsoNormal">Complete each sentence with the correct ending, <strong>A-F, </strong>below.</p>
', 'classification', 'null', 'null', 'null', '{"layoutType": "standard", "legendTitle": null, "matrixItems": [{"itemText": "Valentine, Wilding and Maguire’s experiment shows that the memory Contestants  .", "correctCategoryLetter": "B"}, {"itemText": "After Simonides discovered the loci method in 477 BC, it was .", "correctCategoryLetter": "C"}, {"itemText": "Ericsson finds out that natural memorisers are better than strategic memorisers at  .", "correctCategoryLetter": "E"}, {"itemText": "According to K. Anders Ericson, Shereshevski’s skills were .", "correctCategoryLetter": "D"}], "matrixCategories": [{"categoryText": "used mainly for educational purposes.", "categoryLetter": "A"}, {"categoryText": "activated brain areas associated with visual and spatial memory.", "categoryLetter": "B"}, {"categoryText": "became widespread in ancient Greece for memorizing speeches and texts.", "categoryLetter": "C"}, {"categoryText": "the result of techniques and extensive practice.", "categoryLetter": "D"}, {"categoryText": "retaining a wide variety of tasks.", "categoryLetter": "E"}, {"categoryText": "benefited from additional cognitive abilities.", "categoryLetter": "F"}]}', '[{"content": "<p data-path-to-node=\"2\"><strong data-path-to-node=\"2\" data-index-in-node=\"0\">37. Valentine, Wilding and Maguire’s experiment shows that the memory contestants&#8230;</strong></p>\n<ul data-path-to-node=\"3\">\n<li>\n<p data-path-to-node=\"3,0,0\"><strong data-path-to-node=\"3,0,0\" data-index-in-node=\"0\">Đáp án: B. activated brain areas associated with visual and spatial memory.</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"3,1,0\"><strong data-path-to-node=\"3,1,0\" data-index-in-node=\"0\">Dẫn chứng</strong>: Đoạn C, câu cuối: &#8220;&#8230;they found that the memory champions were activating some <strong data-path-to-node=\"3,1,0\" data-index-in-node=\"91\">brain regions</strong>&#8230; These regions are known to be involved in <strong data-path-to-node=\"3,1,0\" data-index-in-node=\"150\">visual memory and spatial navigation</strong>.&#8221;</p>\n</li>\n<li>\n<p data-path-to-node=\"3,2,0\"><strong data-path-to-node=\"3,2,0\" data-index-in-node=\"0\">Giải thích</strong>: Thí nghiệm của nhóm nhà khoa học này (sử dụng ảnh quét não) đã chứng minh rằng khi ghi nhớ, các thí sinh kích hoạt các vùng não liên quan đến hình ảnh và định hướng không gian (spatial navigation = spatial memory).</p>\n</li>\n</ul>\n<p data-path-to-node=\"5\"><strong data-path-to-node=\"5\" data-index-in-node=\"0\">38. After Simonides discovered the loci method in 477 BC, it was&#8230;</strong></p>\n<ul data-path-to-node=\"6\">\n<li>\n<p data-path-to-node=\"6,0,0\"><strong data-path-to-node=\"6,0,0\" data-index-in-node=\"0\">Đáp án: C. became widespread in ancient Greece for memorizing speeches and texts.</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"6,1,0\"><strong data-path-to-node=\"6,1,0\" data-index-in-node=\"0\">Dẫn chứng</strong>: Đoạn B, câu 6 &amp; 7: &#8220;After Simonides’s discovery, the loci method became <strong data-path-to-node=\"6,1,0\" data-index-in-node=\"83\">widely embraced across ancient Greece</strong>, serving as a fundamental technique for <strong data-path-to-node=\"6,1,0\" data-index-in-node=\"161\">orators and scholars</strong>.&#8221;</p>\n</li>\n<li>\n<p data-path-to-node=\"6,2,0\"><strong data-path-to-node=\"6,2,0\" data-index-in-node=\"0\">Giải thích</strong>: Sau khi Simonides tìm ra phương pháp Loci, nó đã trở nên phổ biến ở Hy Lạp cổ đại, đặc biệt là dành cho các nhà hùng biện (orators &#8211; những người phải nhớ bài diễn văn/speech) và học giả.</p>\n</li>\n</ul>\n<p data-path-to-node=\"8\"><strong data-path-to-node=\"8\" data-index-in-node=\"0\">39. Ericsson finds out that natural memorisers are better than strategic memorisers at&#8230;</strong></p>\n<ul data-path-to-node=\"9\">\n<li>\n<p data-path-to-node=\"9,0,0\"><strong data-path-to-node=\"9,0,0\" data-index-in-node=\"0\">Đáp án: E. retaining a wide variety of tasks.</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"9,1,0\"><strong data-path-to-node=\"9,1,0\" data-index-in-node=\"0\">Dẫn chứng</strong>: Đoạn G, câu cuối: &#8220;Strategists are usually outstanding at remembering only certain kinds of material, whereas <strong data-path-to-node=\"9,1,0\" data-index-in-node=\"121\">naturals exhibit strong memory across many types of tasks</strong> and can retain those memories more easily.&#8221;</p>\n</li>\n<li>\n<p data-path-to-node=\"9,2,0\"><strong data-path-to-node=\"9,2,0\" data-index-in-node=\"0\">Giải thích</strong>: Nghiên cứu của Ericsson chỉ ra sự khác biệt: những người có trí nhớ tự nhiên (naturals) có khả năng ghi nhớ tốt ở nhiều dạng nhiệm vụ khác nhau, trong khi những người dùng chiến thuật (strategists) thường chỉ giỏi ở một vài lĩnh vực cụ thể.</p>\n</li>\n</ul>\n<p data-path-to-node=\"11\"><strong data-path-to-node=\"11\" data-index-in-node=\"0\">40. According to K. Anders Ericsson, Shereshevski’s skills were&#8230;</strong></p>\n<ul data-path-to-node=\"12\">\n<li>\n<p data-path-to-node=\"12,0,0\"><strong data-path-to-node=\"12,0,0\" data-index-in-node=\"0\">Đáp án: D. actually based on the use of specific techniques and extensive practice.</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"12,1,0\"><strong data-path-to-node=\"12,1,0\" data-index-in-node=\"0\">Dẫn chứng</strong>: Đoạn G, câu 4: &#8220;&#8230;he discovered that their remarkable abilities were <strong data-path-to-node=\"12,1,0\" data-index-in-node=\"81\">actually based on the use of specific techniques</strong> — sometimes unconsciously — combined with <strong data-path-to-node=\"12,1,0\" data-index-in-node=\"172\">extensive practice</strong>.&#8221;</p>\n</li>\n<li>\n<p data-path-to-node=\"12,2,0\"><strong data-path-to-node=\"12,2,0\" data-index-in-node=\"0\">Giải thích</strong>: Mặc dù Shereshevski được coi là người có trí nhớ tự nhiên, nhưng Ericsson cho rằng thực chất những kỹ năng đó vẫn dựa trên việc sử dụng các kỹ thuật cụ thể và quá trình rèn luyện chuyên sâu (extensive practice).</p>\n</li>\n</ul>\n"}]', 2);
INSERT INTO public.questions VALUES ('5beaf344-9851-4377-aa76-8e407f9e67dd', '13e9db28-9740-4ba0-ab71-ff220e3fe82f', 'radio', 'Questions 1–8', NULL, '<p>Choose the correct answer.</p>
', 'multiple_choice_single', '[{"correct": 2, "options": [{"content": "18 people."}, {"content": "20 people."}, {"content": "38 people."}], "question": "The centre has enough accommodation for"}, {"correct": 0, "options": [{"content": "unavailable."}, {"content": "flooded."}, {"content": "booked."}], "question": "The meeting room is currently"}, {"correct": 1, "options": [{"content": "use the centre’s kitchen."}, {"content": "have meals cooked for them."}, {"content": "eat at restaurants outside."}], "question": "Visitors must tell the centre in advance if they want to"}, {"correct": 0, "options": [{"content": "get information about organic farming."}, {"content": "help to feed the animals."}, {"content": "watch a tractor demonstration."}], "question": "All visitors on the farm can"}, {"correct": 1, "options": [{"content": "learn to use map."}, {"content": "find their own food."}, {"content": "run through woodland."}], "question": "On the survival course people have to"}, {"correct": 2, "options": [{"content": "Exmoor National Park."}, {"content": "the beach."}, {"content": "a cycling route."}], "question": "From the centre it is easy to walk to"}, {"correct": 2, "options": [{"content": "cinema."}, {"content": "theatre."}, {"content": "museum."}], "question": "If the weather is bad visitors can go to a"}, {"correct": 0, "options": [{"content": "part of the cost in advance."}, {"content": "all the cost in advance."}, {"content": "all of the cost on arrival."}], "question": "Group who wish to stay at the centre must pay"}]', 'null', 'null', 'null', '[{"content": "<p class=\"MsoNormal\"><strong>SECTION 1</strong></p>\n<p class=\"MsoNormal\"><strong>Staff:</strong> Hello, Wincham Farm Centre.</p>\n<p class=\"MsoNormal\"><strong>Caller:</strong> Oh, hello. I want to arrange a weekend away for myself and some people from work, and we heard about your centre. I wonder if you could give me some details.</p>\n<p class=\"MsoNormal\"><strong>Staff:</strong> Yes, certainly. We are a residential centre attached to a working farm, and we organise educational activities for those guests who want them. Um, what else would you like to know?</p>\n<p class=\"MsoNormal\"><strong>Caller:</strong> Well firstly, what kind of accommodation have you got?</p>\n<p class=\"MsoNormal\"><strong>Staff:</strong> We&#8217;ve got eight rooms altogether, and <span style=\"text-decoration: underline;\"><span style=\"background-color: #ffe786;\"><strong>(1) we can sleep 38 at any one time (C: 38 people)</strong></span></span>. Three of the rooms have got 6 bunks and five of them have got 4 bunks.</p>\n<p class=\"MsoNormal\"><strong>Caller:</strong> Right, and what other facilities are there?</p>\n<p class=\"MsoNormal\"><strong>Staff:</strong> We have separate toilets and showers for each of the rooms. There&#8217;s a large dining room and a large meeting room which can be booked by groups in advance. But I&#8217;m afraid we had a flood in there last month and the floor was slightly damaged, so<span style=\"text-decoration: underline;\"> <span style=\"background-color: #ffe786;\"><strong>(2) unfortunately it&#8217;s out of use just now (A: unavailable)</strong></span></span>. We&#8217;ve got workmen coming in next week.</p>\n<p class=\"MsoNormal\"><strong>Caller:</strong> When were you thinking of staying? In three weeks&#8217; time, September 28th.</p>\n<p class=\"MsoNormal\"><strong>Staff:</strong> Oh, it should be OK by then.</p>\n<p class=\"MsoNormal\"><strong>Caller:</strong> Oh well, that&#8217;s okay then. Uh, and what about food? Do you provide meals or is it self-catering?</p>\n<p class=\"MsoNormal\"><strong>Staff:</strong> We&#8217;re very flexible. <span style=\"text-decoration: underline; background-color: #ffe786;\"><strong>(3) As long as you give us enough notice, we can cater for you (B: have meals cooked for them)</strong></span>, or if you prefer, you can just bring your own food and use the kitchen facilities. And some people prefer to eat out, which is also fine.</p>\n<p class=\"MsoNormal\"><strong>Caller:</strong> Fine. And I heard that your farm is organic. Does that mean that you only have crops and no animals?</p>\n<p class=\"MsoNormal\"><strong>Staff:</strong> Haha, it doesn&#8217;t actually. A lot of people seem to think that, but we do rear livestock as well. Organic means it&#8217;s all produced without the use of artificial fertilizers or pesticides.</p>\n<p class=\"MsoNormal\"><strong>Caller:</strong> I see, that sounds good. Um, could you tell me what sort of recreational activities are available either at the centre or in the area?</p>\n<p class=\"MsoNormal\"><strong>Staff:</strong> Yes, here at the centre, we offer farm tours; they&#8217;re very popular. <span style=\"text-decoration: underline; background-color: #ffe786;\"><strong>(4) One of the farm managers shows people around and explains some of the principles of organic farming (A: get information about organic farming)</strong>.</span> And for any visitors who are really keen, you let them drive a tractor or feed the animals and so on—with supervision, of course.</p>\n<p class=\"MsoNormal\"><strong>Caller:</strong> I think a lot of our group would be interested in that. It&#8217;d make a change from factory work.</p>\n<p class=\"MsoNormal\"><strong>Staff:</strong> Well, if they fancy it, tell them to come prepared. Plenty of old clothing, especially footwear. It can be very messy and wet.</p>\n<p class=\"MsoNormal\"><strong>Caller:</strong> OK, I&#8217;ll warn them.</p>\n<div class=\"MsoNormal\" style=\"text-align: center;\" align=\"center\">\n<hr align=\"center\" size=\"2\" width=\"100%\" />\n</div>\n<p class=\"MsoNormal\"><strong>Staff:</strong> And another type of activity we do is survival courses, but that&#8217;s only for groups of five or more.</p>\n<p class=\"MsoNormal\"><strong>Caller:</strong> What do they involve? Things like map reading?</p>\n<p class=\"MsoNormal\"><strong>Staff:</strong> Well, not exactly. What it is, we&#8217;ve got a large area of woodland on the farm and we run this course there. <span style=\"text-decoration: underline; background-color: #ffe786;\"><strong>(5) It&#8217;s mainly about collecting food and water (B: find their own food)</strong></span>, lighting a fire without any equipment, that kind of thing.</p>\n<p class=\"MsoNormal\"><strong>Caller:</strong> Hmm, this weekend could be hard work! Um, what about the area around the centre? What is there to do?</p>\n<p class=\"MsoNormal\"><strong>Staff:</strong> If you look at a map, you&#8217;ll see that we&#8217;re very well situated here. Our centre is about midway between the Exmoor National Park and the south coast.</p>\n<p class=\"MsoNormal\"><strong>Caller:</strong> Are they both within walking distance?</p>\n<p class=\"MsoNormal\"><strong>Staff:</strong> Well, they&#8217;re both a bit far unless you&#8217;re very fit, but they&#8217;re only about 30 minutes by road. And <span style=\"text-decoration: underline; background-color: #ffe786;\"><strong>(6) there&#8217;s also a cycle path which starts quite near here, about 10 minutes&#8217; walk away (C: a cycling route)</strong></span>. You can hire bikes at the starting point.</p>\n<p class=\"MsoNormal\"><strong>Caller:</strong> Um, what is there to do if the weather&#8217;s bad?</p>\n<p class=\"MsoNormal\"><strong>Staff:</strong> Well, on most Saturday evenings we show films here, and then once a month a group of local musicians performs in our meeting room. Hmm, and then Sherborne is only 14 miles away. It&#8217;s only a small town, but <span style=\"text-decoration: underline; background-color: #ffe786;\"><strong>(7) it&#8217;s got a very good museum (C: museum)</strong> and an old abbey, which is well worth a visit.</span></p>\n<p class=\"MsoNormal\"><strong>Caller:</strong> Well, it sounds perfect for our purposes. Uh, one last thing, what about prices?</p>\n<p class=\"MsoNormal\"><strong>Staff:</strong> We charge a standard £14 a head for accommodation.</p>\n<p class=\"MsoNormal\"><strong>Caller:</strong> Right well, I&#8217;ve made a note of all that. I&#8217;ll get back to you with a firm booking. Can I do that by phone?</p>\n<p class=\"MsoNormal\"><strong>Staff:</strong> <span style=\"text-decoration: underline; background-color: #ffe786;\">Yes, you can, but <strong>(8) once you&#8217;ve made a booking, we would need a deposit within 5 days to secure it (A: part of the cost in advance)</strong>.</span> Then you just pay the balance when you&#8217;re here.</p>\n<p class=\"MsoNormal\"><strong>Caller:</strong> Oh yes, of course. Could you give me the address please?</p>\n<p class=\"MsoNormal\"><strong>Staff:</strong> Yes, it&#8217;s Wincham Farm, <span style=\"text-decoration: underline; background-color: #ffe786;\"><strong>(9) Cotehele</strong> Road—that&#8217;s <strong>C-O-T-E-H-E-L-E</strong></span>—near Sherborne. And the postcode is <span style=\"text-decoration: underline; background-color: #ffe786;\"><strong>(10) SH12 1LQ</strong>.</span></p>\n<p class=\"MsoNormal\"><strong>Caller:</strong> Thank you.</p>\n"}]', 0);
INSERT INTO public.questions VALUES ('ec52a881-da18-4ce5-9e60-6aae5edb18d0', 'bcceea6b-be4d-4e33-8c96-b175eafa0f51', 'matching', 'Questions 36-40', '', '<p>Complete each sentence with the correct ending, <strong>A-F</strong>, below.</p>
<p>Write the correct letter, <strong>A-F</strong>, in boxes 10-14 on your answer sheet.</p>', 'matching_sentence_endings', 'null', 'null', '{"layoutType": "standard", "summaryText": "", "answerOptions": [{"optionText": "something is thought to be worth more than it really is."}, {"optionText": "discussions between the parties begin to break down."}, {"optionText": "too much information is given to the other parties early on."}, {"optionText": "businesses consider possible future developments."}, {"optionText": "people allow their feelings to influence decisions."}, {"optionText": "a solution requires face-to-face negotiation."}], "matchingItems": [{"questionPart": "According to Reinier van Oosten, game theory software fails when-", "correctAnswer": "E"}, {"questionPart": "Dr Milgrom''s software is successful in detecting if", "correctAnswer": "A"}, {"questionPart": "Dr Black''s game theory software is a helpful tool when", "correctAnswer": "D"}, {"questionPart": "According to Dr Ponsati, negotiators fall behind if", "correctAnswer": "C"}, {"questionPart": "Dr Ponsati''s mediation machine is useful when", "correctAnswer": "B"}]}', 'null', '[{"content": "<p data-path-to-node=\"4\"><strong data-path-to-node=\"4\" data-index-in-node=\"0\">36. According to Reinier van Oosten, game theory software fails when — {E. people allow their feelings to influence decisions.}</strong></p>\n<ul data-path-to-node=\"5\">\n<li>\n<p data-path-to-node=\"5,0,0\"><strong data-path-to-node=\"5,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 2):</strong> <em data-path-to-node=\"5,0,0\" data-index-in-node=\"20\">“…predictions may become <strong data-path-to-node=\"5,0,0\" data-index-in-node=\"47\">unreliable</strong> when people unexpectedly give in to <strong data-path-to-node=\"5,0,0\" data-index-in-node=\"94\">‘non-rational emotions’</strong>, such as hatred…”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"5,1,0\"><strong data-path-to-node=\"5,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Phần mềm “thất bại” (fails/unreliable) khi con người để cho “cảm xúc không lý trí” (non-rational emotions/feelings) như sự thù hận chi phối quyết định của mình.</p>\n</li>\n</ul>\n<p data-path-to-node=\"6\"><strong data-path-to-node=\"6\" data-index-in-node=\"0\">37. Dr Milgrom’s software is successful in detecting if — {A. something is thought to be worth more than it really is.}</strong></p>\n<ul data-path-to-node=\"7\">\n<li>\n<p data-path-to-node=\"7,0,0\"><strong data-path-to-node=\"7,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 3):</strong> <em data-path-to-node=\"7,0,0\" data-index-in-node=\"20\">“…the software estimated the secret values bidders placed on specific licences, and determined that certain <strong data-path-to-node=\"7,0,0\" data-index-in-node=\"130\">big licences were being overvalued</strong>.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"7,1,0\"><strong data-path-to-node=\"7,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Phần mềm của Milgrom phát hiện ra các giấy phép lớn đang bị “định giá quá cao” (overvalued), tương ứng với việc chúng được cho là “có giá trị hơn thực tế” (<strong data-path-to-node=\"7,1,0\" data-index-in-node=\"168\">worth more than it really is</strong>).</p>\n</li>\n</ul>\n<p data-path-to-node=\"8\"><strong data-path-to-node=\"8\" data-index-in-node=\"0\">38. Dr Black’s game theory software is a helpful tool when — {D. businesses consider possible future developments.}</strong></p>\n<ul data-path-to-node=\"9\">\n<li>\n<p data-path-to-node=\"9,0,0\"><strong data-path-to-node=\"9,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 4):</strong> <em data-path-to-node=\"9,0,0\" data-index-in-node=\"20\">“…the use of modelling makes clients <strong data-path-to-node=\"9,0,0\" data-index-in-node=\"59\">more inclined to look at future repercussions</strong> when making business decisions, Black says.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"9,1,0\"><strong data-path-to-node=\"9,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Phần mềm của Dr Black giúp khách hàng cân nhắc các “hệ quả trong tương lai” (future repercussions), tương ứng với cụm “<strong data-path-to-node=\"9,1,0\" data-index-in-node=\"131\">future developments</strong>” (những phát triển trong tương lai) khi đưa ra quyết định kinh doanh.</p>\n</li>\n</ul>\n<p data-path-to-node=\"10\"><strong data-path-to-node=\"10\" data-index-in-node=\"0\">39. According to Dr Ponsati, negotiators fall behind if — {C. too much information is given to the other parties early on.}</strong></p>\n<ul data-path-to-node=\"11\">\n<li>\n<p data-path-to-node=\"11,0,0\"><strong data-path-to-node=\"11,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 5):</strong> <em data-path-to-node=\"11,0,0\" data-index-in-node=\"20\">“…the <strong data-path-to-node=\"11,0,0\" data-index-in-node=\"28\">first side to disclose the maximum amount</strong> that it is willing to pay <strong data-path-to-node=\"11,0,0\" data-index-in-node=\"96\">loses considerable bargaining power</strong>. Without leverage, it can be <strong data-path-to-node=\"11,0,0\" data-index-in-node=\"161\">pushed backwards</strong>…”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"11,1,0\"><strong data-path-to-node=\"11,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Người đàm phán sẽ “bị tụt lại phía sau/yếu thế” (fall behind/pushed backwards) nếu là bên đầu tiên tiết lộ giá tối đa (<strong data-path-to-node=\"11,1,0\" data-index-in-node=\"131\">disclose the maximum amount</strong>) quá sớm (early on).</p>\n</li>\n</ul>\n<p data-path-to-node=\"12\"><strong data-path-to-node=\"12\" data-index-in-node=\"0\">40. Dr Ponsati’s mediation machine is useful when — {B. discussions between the parties begin to break down.}</strong></p>\n<ul data-path-to-node=\"13\">\n<li>\n<p data-path-to-node=\"13,0,0\"><strong data-path-to-node=\"13,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 5):</strong> <em data-path-to-node=\"13,0,0\" data-index-in-node=\"20\">“But if neither side reveals the concessions… <strong data-path-to-node=\"13,0,0\" data-index-in-node=\"68\">negotiations can become very slow or collapse</strong>. However, difficult negotiations can often be <strong data-path-to-node=\"13,0,0\" data-index-in-node=\"160\">pushed along by neutral mediators</strong>…”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"13,1,0\"><strong data-path-to-node=\"13,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Máy hòa giải (mediation machine) hữu ích khi các cuộc đàm phán trở nên trì trệ hoặc “đổ vỡ” (<strong data-path-to-node=\"13,1,0\" data-index-in-node=\"105\">collapse/break down</strong>), giúp thúc đẩy quá trình này tiến triển lại.</p>\n</li>\n</ul>"}]', 2);
INSERT INTO public.questions VALUES ('6c54d2ef-d000-4322-ab72-a6baa10a53a7', '52f04971-e253-4ad5-ae74-3ea8118e5169', 'radio', 'Questions 27-30', NULL, '<p>Choose the correct answers</p>
', 'multiple_choice_single', '[{"correct": 2, "options": [{"content": "A Comparing the old NGV with the new NGV"}, {"content": "B Describing the role of art museums in Australian culture"}, {"content": "C Considering the influence of gallery design on art appreciation"}, {"content": "D Suggesting there has been little recent change in gallery design"}], "question": "What is the writer doing in the first paragraph?"}, {"correct": 1, "options": [{"content": "A The permanent collection was poorly displayed"}, {"content": "B The building tended to make art seem remote"}, {"content": "C Asian and Pacific art was neglected"}, {"content": "D The foyer resembled a shop"}], "question": "The writer criticises the old NGV because"}, {"correct": 2, "options": [{"content": "A He thinks the ticket booths are well positioned"}, {"content": "B He is upset that he is made to move so quickly"}, {"content": "C He is frustrated because the art is obscured by the entrance"}, {"content": "D He thinks the redevelopment fails to keep up with international trends"}], "question": "What does the writer notice about the new NGV?"}, {"correct": 1, "options": [{"content": "A Should be cheaper"}, {"content": "B Are a financial necessity"}, {"content": "C Should be increased in number"}, {"content": "D Allow the museum to present an original programme"}], "question": "The writer argues that rental \"blockbuster\" exhibitions"}]', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"1\"><strong data-path-to-node=\"1\" data-index-in-node=\"0\">27. considering the influence of gallery design on art appreciation</strong></p>\n<ul data-path-to-node=\"2\">\n<li>\n<p data-path-to-node=\"2,0,0\"><strong data-path-to-node=\"2,0,0\" data-index-in-node=\"0\">Vị trí:</strong> Đoạn 1, dòng 2–4.</p>\n</li>\n<li>\n<p data-path-to-node=\"2,1,0\"><strong data-path-to-node=\"2,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “Do any of these newly developed spaces indicate a <strong data-path-to-node=\"2,1,0\" data-index-in-node=\"62\">fundamental shift in the ways we engage with art</strong> at the beginning of the twenty-first century? The answer is a qualified Yes and also… No.”</p>\n</li>\n<li>\n<p data-path-to-node=\"2,2,0\"><strong data-path-to-node=\"2,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Trong đoạn đầu tiên, tác giả đặt ra câu hỏi liệu những không gian bảo tàng mới được phát triển (gallery design) có phản ánh một sự thay đổi cơ bản trong <strong data-path-to-node=\"2,2,0\" data-index-in-node=\"165\">cách chúng ta tiếp cận/thưởng thức nghệ thuật</strong> (engage with art/art appreciation) hay không. Việc tác giả sử dụng ví dụ về sự cải tạo của bảo tàng NGV năm 2003 để trả lời câu hỏi này cho thấy mục đích chính của đoạn văn là xem xét mối quan hệ giữa thiết kế không gian và trải nghiệm nghệ thuật của công chúng.</p>\n</li>\n</ul>\n<p data-path-to-node=\"6\"><strong data-path-to-node=\"6\" data-index-in-node=\"0\">28. The writer criticises the old NGV because:</strong></p>\n<ul data-path-to-node=\"7\">\n<li>\n<p data-path-to-node=\"7,0,0\"><strong data-path-to-node=\"7,0,0\" data-index-in-node=\"0\">Đáp án:</strong> <strong data-path-to-node=\"7,0,0\" data-index-in-node=\"8\">B (The building tended to make art seem remote.)</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"7,1,0\"><strong data-path-to-node=\"7,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…huge expanse of the exterior’s windowless wall and the surrounding moat, which creates a rather unwelcoming expression of the institution.”</p>\n</li>\n<li>\n<p data-path-to-node=\"7,2,0\"><strong data-path-to-node=\"7,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Tác giả chê tòa nhà cũ có những bức tường không cửa sổ và con hào bao quanh, tạo cảm giác “unwelcoming” (không chào đón), khiến nghệ thuật bên trong trở nên xa cách với công chúng.</p>\n</li>\n</ul>\n<p data-path-to-node=\"8\"><strong data-path-to-node=\"8\" data-index-in-node=\"0\">29. What does the writer notice about the new NGV?</strong></p>\n<ul data-path-to-node=\"9\">\n<li>\n<p data-path-to-node=\"9,0,0\"><strong data-path-to-node=\"9,0,0\" data-index-in-node=\"0\">Đáp án:</strong> <strong data-path-to-node=\"9,0,0\" data-index-in-node=\"8\">C (He is frustrated because the art is obscured by the entrance.)</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"9,1,0\"><strong data-path-to-node=\"9,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…where has the art gone? We are not allowed to see the exhibitions until we have completed the necessary inductions. We are greeted by a hugely expanded cloakroom, screening off our vision…”</p>\n</li>\n<li>\n<p data-path-to-node=\"9,2,0\"><strong data-path-to-node=\"9,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Tác giả cảm thấy “frustrated” (bực bội) vì khi vào bảo tàng mới, tầm nhìn bị che khuất bởi phòng gửi đồ, quầy thông tin, cửa hàng… làm cho nghệ thuật bị lu mờ ngay từ lối vào.</p>\n</li>\n</ul>\n<p data-path-to-node=\"10\"><strong data-path-to-node=\"10\" data-index-in-node=\"0\">30. The writer argues that rental “blockbuster” exhibitions:</strong></p>\n<ul data-path-to-node=\"11\">\n<li>\n<p data-path-to-node=\"11,0,0\"><strong data-path-to-node=\"11,0,0\" data-index-in-node=\"0\">Đáp án:</strong> <strong data-path-to-node=\"11,0,0\" data-index-in-node=\"8\">B (Are a financial necessity.)</strong></p>\n</li>\n<li>\n<p data-path-to-node=\"11,1,0\"><strong data-path-to-node=\"11,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “Entrance to the NGV permanent collection is now free, so the NGV needs something to keep the paying public coming back. The answer lies in the international ‘blockbuster’ exhibition.”</p>\n</li>\n<li>\n<p data-path-to-node=\"11,2,0\"><strong data-path-to-node=\"11,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Vì bộ sưu tập cố định giờ đã miễn phí, bảo tàng buộc phải tổ chức các triển lãm “bom tấn” (blockbuster) để thu hút khách trả phí, phục vụ mục đích tài chính.</p>\n</li>\n</ul>\n"}]', 0);
INSERT INTO public.questions VALUES ('b5a889dd-ac3f-40e8-b296-d089ee11e328', '8f9eec03-5894-4b7d-9b5a-ae64fd8c45a5', 'matching', 'Questions 14–19', '', '<p>The text has six paragraphs. Choose the correct heading for each paragraph and move it into the gap.</p>', 'matching_headings', 'null', 'null', '{"layoutType": "heading", "summaryText": "", "answerOptions": [{"optionText": "Sending messages underground"}, {"optionText": "Potential advantages for farmers"}, {"optionText": "The widespread rejection of an idea"}, {"optionText": "One species accelerating growth in another"}, {"optionText": "Some obstacles to plant communication"}, {"optionText": "Evidence leading to renewed belief in a theory"}, {"optionText": "New technologies which helped researchers"}, {"optionText": "A suggested benefit to the sender of plant communication"}], "matchingItems": []}', 'null', '[{"content": "<ul>\n<li><strong data-path-to-node=\"5,0,0\" data-index-in-node=\"0\">14.</strong></li>\n<li>\n<p data-path-to-node=\"5,0,0\"><strong data-path-to-node=\"5,0,0\" data-index-in-node=\"0\">Đoạn 1: {The widespread rejection of an idea}</strong></p>\n<ul data-path-to-node=\"5,0,1\">\n<li>\n<p data-path-to-node=\"5,0,1,0,0\"><strong data-path-to-node=\"5,0,1,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…the plant research community <strong data-path-to-node=\"5,0,1,0,0\" data-index-in-node=\"44\">did not accept this</strong>. …most ecologists felt that Schultz and Baldwin’s ideas had been <strong data-path-to-node=\"5,0,1,0,0\" data-index-in-node=\"131\">discredited</strong>.”</p>\n</li>\n<li>\n<p data-path-to-node=\"5,0,1,1,0\"><strong data-path-to-node=\"5,0,1,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Đoạn này nói về việc các nhà khoa học ban đầu bác bỏ ý tưởng thực vật biết “báo động” cho nhau.<strong data-path-to-node=\"5,1,0\" data-index-in-node=\"0\">.</strong></p>\n</li>\n</ul>\n</li>\n<li><strong data-path-to-node=\"5,1,0\" data-index-in-node=\"0\">15.</strong></li>\n<li>\n<p data-path-to-node=\"5,1,0\"><strong data-path-to-node=\"5,1,0\" data-index-in-node=\"0\">Đoạn 2: {Evidence leading to renewed belief in a theory}</strong></p>\n<ul data-path-to-node=\"5,1,1\">\n<li>\n<p data-path-to-node=\"5,1,1,0,0\"><strong data-path-to-node=\"5,1,1,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…a number of more <strong data-path-to-node=\"5,1,1,0,0\" data-index-in-node=\"32\">carefully designed experiments</strong> began to yield <strong data-path-to-node=\"5,1,1,0,0\" data-index-in-node=\"78\">convincing indications to the contrary</strong>.”</p>\n</li>\n<li>\n<p data-path-to-node=\"5,1,1,1,0\"><strong data-path-to-node=\"5,1,1,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Sau một thập kỷ, các thí nghiệm của Richard Karban và các cộng sự đã đưa ra bằng chứng thuyết phục để hồi sinh lý thuyết này.</p>\n</li>\n</ul>\n</li>\n<li><strong data-path-to-node=\"5,2,0\" data-index-in-node=\"0\">16.</strong></li>\n<li>\n<p data-path-to-node=\"5,2,0\"><strong data-path-to-node=\"5,2,0\" data-index-in-node=\"0\">Đoạn 3: {A suggested benefit to the sender of plant communication}</strong></p>\n<ul data-path-to-node=\"5,2,1\">\n<li>\n<p data-path-to-node=\"5,2,1,0,0\"><strong data-path-to-node=\"5,2,1,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “One hypothesis is that external communication channels are merely an <strong data-path-to-node=\"5,2,1,0,0\" data-index-in-node=\"81\">extension of within-plant signaling</strong>… to protect itself.”</p>\n</li>\n<li>\n<p data-path-to-node=\"5,2,1,1,0\"><strong data-path-to-node=\"5,2,1,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Đoạn này giải thích lợi ích của chính cái cây phát tín hiệu (để tự bảo vệ các phần khác của chính nó) chứ không chỉ giúp hàng xóm.</p>\n</li>\n</ul>\n</li>\n<li><strong data-path-to-node=\"5,3,0\" data-index-in-node=\"0\">17.</strong></li>\n<li>\n<p data-path-to-node=\"5,3,0\"><strong data-path-to-node=\"5,3,0\" data-index-in-node=\"0\">Đoạn 4: {Sending messages underground}</strong></p>\n<ul data-path-to-node=\"5,3,1\">\n<li>\n<p data-path-to-node=\"5,3,1,0,0\"><strong data-path-to-node=\"5,3,1,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…distress signals can be passed through the <strong data-path-to-node=\"5,3,1,0,0\" data-index-in-node=\"58\">plants’ roots</strong>. …labyrinths of hair-like <strong data-path-to-node=\"5,3,1,0,0\" data-index-in-node=\"100\">fungi</strong> that occur around the roots…”</p>\n</li>\n<li>\n<p data-path-to-node=\"5,3,1,1,0\"><strong data-path-to-node=\"5,3,1,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Tập trung vào kênh giao tiếp dưới lòng đất qua rễ và mạng lưới nấm.</p>\n</li>\n</ul>\n</li>\n<li><strong data-path-to-node=\"5,4,0\" data-index-in-node=\"0\">18.</strong></li>\n<li>\n<p data-path-to-node=\"5,4,0\"><strong data-path-to-node=\"5,4,0\" data-index-in-node=\"0\">Đoạn 5: {One species accelerating growth in another}</strong></p>\n<ul data-path-to-node=\"5,4,1\">\n<li>\n<p data-path-to-node=\"5,4,1,0,0\"><strong data-path-to-node=\"5,4,1,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…chili plant seedlings grown next to fennel plants <strong data-path-to-node=\"5,4,1,0,0\" data-index-in-node=\"65\">developed more quickly</strong> than seedlings grown with other chili plants.”</p>\n</li>\n<li>\n<p data-path-to-node=\"5,4,1,1,0\"><strong data-path-to-node=\"5,4,1,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Ví dụ về việc cây ớt phát triển nhanh hơn khi ở gần cây thì là (fennel).</p>\n</li>\n</ul>\n</li>\n<li><strong data-path-to-node=\"5,5,0\" data-index-in-node=\"0\">19.</strong></li>\n<li>\n<p data-path-to-node=\"5,5,0\"><strong data-path-to-node=\"5,5,0\" data-index-in-node=\"0\">Đoạn 6: {Potential advantages for farmers}</strong></p>\n<ul data-path-to-node=\"5,5,1\">\n<li>\n<p data-path-to-node=\"5,5,1,0,0\"><strong data-path-to-node=\"5,5,1,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…could eventually be <strong data-path-to-node=\"5,5,1,0,0\" data-index-in-node=\"35\">applied to agriculture</strong>, and lead to the cultivation of <strong data-path-to-node=\"5,5,1,0,0\" data-index-in-node=\"90\">hardier crops</strong>.”</p>\n</li>\n<li>\n<p data-path-to-node=\"5,5,1,1,0\"><strong data-path-to-node=\"5,5,1,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Nói về triển vọng ứng dụng kiến thức này vào nông nghiệp để tạo ra cây trồng chống chịu tốt hơn.</p>\n</li>\n</ul>\n</li>\n</ul>"}]', 0);
INSERT INTO public.questions VALUES ('1ba283de-0c5f-4364-9622-1484a3f927aa', 'a6870343-14eb-4b90-9abd-db97958fe03c', 'checkbox', 'Questions 23 and 24', '', '<p><span class="citation-64091">Choose </span><strong><span class="citation-64091">TWO</span></strong><span class="citation-64091"> letters, </span><strong><span class="citation-64091">A–E</span></strong><span class="citation-64091 citation-end-64091">.</span></p>
<p><span class="citation-64091 citation-end-64091">Which <strong data-path-to-node="9" data-index-in-node="6">TWO</strong> ways do the students agree that touch-sensitive sensors for food labels could be developed in future?</span></p>', 'multiple_choice', 'null', '[{"correct": true, "option_text": "A for use on medical products"}, {"correct": false, "option_text": "B to show that food is no longer fit to eat"}, {"correct": false, "option_text": "C for use with drinks as well as foods"}, {"correct": false, "option_text": "D to provide applications for blind people"}, {"correct": true, "option_text": "E to indicate the weight of certain foods"}]', 'null', 'null', '[{"content": "<p>1</p>"}]', 1);
INSERT INTO public.questions VALUES ('7851dce4-12f9-4b5a-a9fc-438a0deac4f2', '637547b9-126d-4a91-9268-e5e10c93463c', 'fillup', 'Questions 31–40', '<div class="quests-inner-desc">
<div class="txt">
<p>Complete the notes below.</p>
<p>Write <strong>ONE WORD ONLY</strong> for each answer.</p>
</div>
</div>
<div class="quests-des">
<div class="content-write">
<p class="ql-align-center"><strong>BOAR AND RED DEER</strong></p>
<p><strong>Boar</strong></p>
<p>– Boar is not a <span class="fill-history-correct">{protected}</span> species.</p>
<p>– Their number should be controlled as a result of their damage to the {environment}.</p>
<p>– They also spread <span class="fill-history-correct">{diseases}</span>.</p>
<p>– Law was passed regarding banning use of {poison} in killing boars.</p>
<p>– Measures should be taken to keep the boars in the {forest} away from people in urban areas.</p>
<p>– The early 1990s witnessed a significant population rise of boars due to their escape from <span class="fill-history-correct">{farms}</span>.</p>
<p><strong>Red Deer</strong></p>
<p>– Red deer can also damage agricultural produce, such as grain and <span class="fill-history-correct">{potatoes}</span>.</p>
<p>– In winter the red deer come out to the villages for <span class="fill-history-correct">{food}</span>.</p>
<p>– The number of deer keep stable for <span class="fill-history-correct">{hunting}</span>.</p>
<p>– Deer can have a devastating effect on the local <span class="fill-history-correct">{crops}</span>.</p>
</div>
</div>', '', 'summary_completion', 'null', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"2\"><strong data-path-to-node=\"2\" data-index-in-node=\"0\">PART 4: CONTROL OF WILD ANIMALS (BOAR AND RED DEER)</strong></p>\n<p data-path-to-node=\"3\"><strong data-path-to-node=\"3\" data-index-in-node=\"0\">Jim Robinson:</strong> Good morning. My name’s Jim Robinson and today we’re going to look at the control of wild animals, specifically wild boar.</p>\n<p id=\"p-rc_56e5fcb74799d450-33\" data-path-to-node=\"4\">Now, boar have been natural inhabitants of Western Europe for thousands of years, but in recent years there has been a surge in boar activity that poses a real threat. Boars are not currently on the <strong data-path-to-node=\"4\" data-index-in-node=\"199\">(31) <span class=\"citation-954 citation-955\">protected</span></strong><span class=\"citation-954 citation-955 citation-end-955\"> animals list, which is perhaps why there has been a spike in their breeding activity.</span></p>\n<p id=\"p-rc_56e5fcb74799d450-34\" data-path-to-node=\"5\"><span class=\"citation-952 citation-953 citation-end-953\">Boars are an indigenous species and are particularly plentiful in rural France and the Bavarian uplands of Germany. Boar hunting is a European tradition that goe</span><span class=\"citation-952 citation-end-952\">s back to Roman times and became particularly popular among courtiers during the Middle Ages. Even during the 20th century, boar hunting was seen as an integral part of</span> rural life.</p>\n<p id=\"p-rc_56e5fcb74799d450-35\" data-path-to-node=\"6\">The decline in boar hunting has obviously led to a rise in the boar populations of Europe, and the situation has reached a critical point with boar posing a critical threat to the <strong data-path-to-node=\"6\" data-index-in-node=\"180\">(32) <span class=\"citation-951\">environment</span></strong><span class=\"citation-951 citation-end-951\">. Proponents of boar hunting cite this factor as a major reason why boar populations should be contained. Boar also pose a threat to humans too, with countless reports of people being injured dur</span>ing boar attacks.</p>\n<p id=\"p-rc_56e5fcb74799d450-36\" data-path-to-node=\"7\">The origins of the wild boar have roots in Germanic, and this perhaps explains their prevalence in Germany. The problems with the boar population in Germany have ramifications for the rest of Europe as boar packs migrate towards central and Eastern Europe. One of the main issues that is of great concern is the transmission of <strong data-path-to-node=\"7\" data-index-in-node=\"328\">(33) <span class=\"citation-949 citation-950\">diseases</span></strong><span class=\"citation-949 citation-950 citation-end-950\"> that infect other species. Dairy farmers in France are particularly concerned as many of them have seen their herds depleted by infections.</span></p>\n<p id=\"p-rc_56e5fcb74799d450-37\" data-path-to-node=\"8\"><span class=\"citation-947 citation-948 citation-end-948\">The methods for containing boar populations have been looked at in great detail and numerous options are avai</span><span class=\"citation-947 citation-end-947\">lable. One is to encourage more boar hunting in wild regions such as mountains and forests. Hunters would be given lic</span>ences to hunt either for food or sport. Of course, boar do pose a threat to human life, so this possibility must be looked at with caution.</p>\n<p id=\"p-rc_56e5fcb74799d450-38\" data-path-to-node=\"9\">One method that must be ruled out is <strong data-path-to-node=\"9\" data-index-in-node=\"37\">(34) <span class=\"citation-945 citation-946\">poison</span></strong><span class=\"citation-945 citation-946 citation-end-946\">, as legislation has been introduced prohibiting this. Such methods were tried with rabbits in the 1960s and this had a disastrous impact on the food chain. The introduction of natural predators into the ecosystem is also an option that can’t be considered. The only known predators of boar in the world are wild cat</span><span class=\"citation-945 citation-end-945\">s like lions and tigers. Obviously, there’s no way such animals can be allowed to roam the mountains and forests of Europe.</span></p>\n<p id=\"p-rc_56e5fcb74799d450-39\" data-path-to-node=\"10\"><span class=\"citation-944 citation-end-944\">Given the threat</span> that boars pose to humans, it is imperative that forest-dwelling boar are kept well away from people in cities. This is absolutely essential as human safety must be the main priority of policy makers. In several European countries, boars were becoming increasingly rare by the 11th century. In Great Britain, King Charles attempted to reintroduce boars in the New <strong data-path-to-node=\"10\" data-index-in-node=\"381\">(35) <span class=\"citation-942 citation-943\">forest</span></strong><span class=\"citation-942 citation-943 citation-end-943\"> area of the country, yet the entire population was almost wiped out during the battles of the English Civil War when roaming soldiers hunted them for food.</span></p>\n<p id=\"p-rc_56e5fcb74799d450-40\" data-path-to-node=\"11\"><span class=\"citation-940 citation-941 citation-end-941\">During the 1980s, wild boar rearing was encouraged and boar populations began to ri</span><span class=\"citation-940 citation-end-940\">se again. By the 1990s, there was a huge rise in the number of boar across England due in large part to the species no longer</span> being forced to live in captivity. Many boar have broken free from <strong data-path-to-node=\"11\" data-index-in-node=\"276\">(36) farms</strong> across England and are breeding at a rapid rate.</p>\n<hr data-path-to-node=\"12\">\n<p data-path-to-node=\"13\"><strong data-path-to-node=\"13\" data-index-in-node=\"0\">RED DEER</strong></p>\n<p id=\"p-rc_56e5fcb74799d450-41\" data-path-to-node=\"14\"><strong data-path-to-node=\"14\" data-index-in-node=\"0\">Jim Robinson:</strong> Aside from their environmental threats, boars also pose a problem for farmers growing crops and vegetables. Other species such as red deer are a threat to farm produce like grain and <strong data-path-to-node=\"14\" data-index-in-node=\"197\">(37) <span class=\"citation-938 citation-939\">potatoes</span></strong><span class=\"citation-938 citation-939 citation-end-939\">, but boars certainly present the most serious risk. The damage done to the farming industry is estimated to cost millions of pounds, and insurance payments as a result of this have spiked in the last decade.</span></p>\n<p id=\"p-rc_56e5fcb74799d450-42\" data-path-to-node=\"15\"><span class=\"citation-936 citation-937 citation-end-937\">Red deer are predominantly confined </span><span class=\"citation-936 citation-end-936\">to forest areas and it is unusual to see them outside their habitats during the summer months. However, as the weather gets colder, they can be seen looking for</span> <strong data-path-to-node=\"15\" data-index-in-node=\"197\">(38) food</strong> around local villages and fields. Red deer have their origins in Asia and are <span class=\"citation-934 citation-935 citation-end-935\">a ruminant species, which means they have a stomach that consists of four compartments, much like cows. They are slaughtered for food and their meat is sold as venison and is increasingly popular among consume</span><span class=\"citation-934 citation-end-934\">rs.</span></p>\n<p id=\"p-rc_56e5fcb74799d450-43\" data-path-to-node=\"16\"><span class=\"citation-933 citation-end-933\">There are nine subspecies of red deer, with three of them on the endangered species list. The deer population doesn’t pose the same threat as the boar populatio</span>n, but it certainly needs to be addressed. Forest areas are their main habitats and they are now breeding at a much higher rate than in previous years.</p>\n<p id=\"p-rc_56e5fcb74799d450-44\" data-path-to-node=\"17\">Of course, deer are an important part of the food chain and are an important part of the <strong data-path-to-node=\"17\" data-index-in-node=\"89\">(39) hunting</strong> traditions of the UK, so it is important that their population is kept stable for this reason. Though the real concern is the problems that deer present for farmers who have seen their <strong data-path-to-node=\"17\" data-index-in-node=\"287\">(40) <span class=\"citation-932\">crops</span></strong><span class=\"citation-932 citation-end-932\"> suffer in devastating ways. Protection needs to be offered, and many farmers report building large perimeter fences around their fields to keep deer out, which cost them a huge amount of money. Government funding is so far inadequate to offer the protection farmers need, but ways are being looked at to provide subsidies through other mean</span>s.</p>"}]', 0);
INSERT INTO public.questions VALUES ('64444bb7-fc98-4992-b7dd-920362c8ee91', 'c4743f7a-0642-44e7-b449-8bfc876472d1', 'fillup', 'Questions 1–6', '<div class="quests-inner-desc">
